INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('1', 'Hebrew-1000-Aleppo-Codex-HighRes-Manuscript', 'HBOALEP', 'Hebrew (1000) Aleppo Codex (HighRes) Manuscript', 'עברית - כתב יד חלב (1000, ברזולוציה גבוהה)', 'The Aleppo Codex, also known as the ''Crown of Aleppo'' (Hebrew: כֶּתֶר אֲרָם צוֹבָא, Keṯer ʾĂrām-Ṣōḇāʾ), is a significant medieval bound manuscript of the Hebrew Bible. Written in Tiberias in the 10th century CE (circa 920) during the Abbasid Caliphate era, it is particularly renowned for its accuracy, a feature that was endorsed by the famed Jewish philosopher and scholar Maimonides. The Aleppo Codex, along with the Leningrad Codex, represents the Ben-Asher Masoretic tradition, a key textual tradition in the history of the Hebrew Bible.<br><br>For five centuries, the codex was kept in the Central Synagogue of Aleppo. However, in 1947, during anti-Jewish riots, the synagogue was torched, leading to the codex''s partial destruction. Its whereabouts remained largely unknown until it resurfaced in Israel in 1958, with about 40% of the manuscript, including most of the Torah section, missing. Only two additional leaves have been recovered since. The initial belief that the missing pages were destroyed in the synagogue fire has been increasingly questioned, leading to speculation that they might still exist in private collections.<br><br>The remaining portion of the Aleppo Codex is currently housed in the Shrine of the Book at the Israel Museum. Despite its partial loss, the codex remains one of the most important manuscripts for the study of the Hebrew Bible, offering invaluable insights into the Masoretic textual tradition and the history of biblical texts.', 'historic', NULL, '119', 'hbo', '1000', 'manuscript', NULL, NULL, NULL, 'HBOALEP_DBS_HS/Hebrew-(1000)-Aleppo-Codex-(HighRes)-Manuscript', 'hbo', 'anci1244', 'Ancient Hebrew', 'עִבְרִית מִקְרָאִית', 'H', 'IL', '31.77607', '35.17248', '9', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('2', 'Greek-English-1830-St.-John-Interlinear-Friederici-John', 'GRCTRE', 'Greek-English (1830) St. John Interlinear (Friederici) John', 'Κατά Ιωάννην Διαγλωσσικό Κείμενο (1830, Friederici)', 'The 1830 "The Gospel of St. John: In Greek and English, Interlined, and Literally Translated" is a specialized edition focused on the Gospel of St. John, offering a unique educational tool for studying this part of the New Testament. This work, designed primarily for use in schools, presents the text of St. John''s Gospel in both Greek and English, with the texts interlined for easy comparison and literal translation.<br><br>One of the notable features of this edition, which sets it apart from standard interlinear translations, is the transposition of words into their correct order of construction. This arrangement aids in understanding the structure of the Greek language and how it translates into English, making it particularly useful for students and educators in the field of biblical languages.<br><br>Additionally, this edition includes a dictionary that defines and parses the Greek words used in the text. This feature is invaluable for learners, as it provides detailed linguistic and grammatical context for the Greek vocabulary of the Gospel of St. John.<br><br>This educational approach to presenting the Gospel of St. John makes it an excellent resource for those beginning to study the New Testament in its original language, as well as for educators seeking comprehensive teaching tools. The combination of interlinear translation, word order transposition, and the included dictionary offers a thorough and accessible means for understanding and teaching the Greek text of the New Testament.', 'historic', NULL, '7', 'grc', '1830', 'study', 'John Wiley', NULL, NULL, 'GRCTRE_DBS_HS/Greek-English-(1830)-St.-John-Interlinear-(Friederici)-John', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('3', 'English-1525-Tyndale-New-Testament-text', 'ENGTYN', 'English (1525) Tyndale New Testament (text)', NULL, 'The Tyndale Bible, primarily the work of William Tyndale (1494–1536), represents a foundational shift in biblical translation. Tyndale, an eminent scholar, is renowned for being the first to translate the Bible into English directly from Hebrew and Greek texts, breaking from the traditional Latin Vulgate. This monumental task was greatly facilitated by the emergence of printing technology, making Tyndale''s Bible the first to be mass-produced, thereby vastly increasing its accessibility.<br><br>However, the term "Tyndale''s Bible" is somewhat misleading. Tyndale himself never published a complete Bible. His untimely execution precluded the completion of his work, leaving only the entire New Testament and a portion of the Old Testament translated. This included the Pentateuch, Jonah, and a revised version of Genesis, all published during his lifetime. The task of completing the full Bible was undertaken by Miles Coverdale, who combined Tyndale''s translations with his own, resulting in the first complete printed English Bible in 1535. Tyndale''s unfinished Old Testament translations notably contributed to the Matthew Bible and profoundly influenced subsequent English translations.<br><br>Tyndale''s translation journey began in 1525 with his New Testament work, initially printed in Cologne. A mere fragment of this effort, ''The Gospel of St. Matthew,'' survives in the British Museum''s Grenville Collection. Fleeing persecution, Tyndale relocated to Worms, where he resumed and completed his New Testament translation in 1526. This pivotal work was later celebrated in a facsimile reprint by the Clarendon Press in 1926, offering a tangible connection to this transformative period in religious and linguistic history.', 'modern', 'https://en.wikipedia.org/wiki/Tyndale_Bible', '2', 'eng', '1525', 'book', NULL, NULL, NULL, 'ENGTYN_DBS_HS/English-(1525)-Tyndale-New-Testament-(text)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('4', 'English-1537-Matthews-Bible-Text', 'ENGMTB', 'English (1537) Matthews Bible Text', NULL, 'English (1537) Matthews Bible Text', 'historic', 'https://en.wikipedia.org/wiki/Matthew_Bible', '374', 'eng', '1537', 'scan', NULL, NULL, NULL, 'ENGMTB_DBS_HS/English-(1537)-Matthews-Bible-Text', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('5', 'English-1822-Epistles-of-Paul-Belsham-Study-Bible-Vol.1-4-NT-Epistles', 'ENGPSB', 'English (1822) Epistles of Paul (Belsham) Study Bible - Vol.1-4 NT Epistles', NULL, 'The 1822 publication "The New Testament, in an Improved Version, upon the Basis of Archbishop Newcome’s New Translation," including the Epistles of Paul, represents a critical and explanatory revision of Newcome''s 1796 translation of the New Testament. This revised version was published anonymously under the auspices of a society named on the title page as "A Society for Promoting Christian Knowledge and the Practice of Virtue by the Distribution of Books." Interestingly, this title seems to have been chosen to evoke associations with the well-known Anglican organization founded in 1698 by Thomas Bray for disseminating orthodox Christian texts.<br><br>However, the introduction to the text omits a crucial detail: the society responsible for this publication was actually the Unitarian Society. This omission was intentional, aiming to avoid deterring potential readers who might be biased against Unitarianism. Thomas Belsham, a prominent Unitarian figure, played a significant role in the creation of this work.<br><br>Belsham''s 1820 article reveals that the main goal of this version was to provide a comprehensive reference for the New Testament, particularly focusing on texts central to Unitarian controversy. It aimed to present translations and interpretations of these texts as understood by eminent Unitarian scholars. However, this statement somewhat obscures the fact that Unitarianism, while claiming to base its doctrines on biblical interpretation, does not rely solely on the Bible as its foundational text.<br><br>This version of the New Testament, therefore, served not only as a translation and commentary but also as a vehicle for promoting Unitarian theology. It illustrates how religious translations can be influenced by doctrinal perspectives and the broader objectives of the groups supporting them.', 'historic', 'http://www.bible-researcher.com/belsham.html', '223', 'eng', '1822', 'study', 'Rev. Thomas Belsham', NULL, NULL, 'ENGPSB_DBS_HS/English-(1822)-Epistles-of-Paul-(Belsham)-Study-Bible-Vol.1-4-NT-Epistles', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('6', 'English-1796-Worchister-Bible-Abriged', 'ENGWOB', 'English (1796) Worchister Bible - Abridged', NULL, 'The 1796 edition of "The Holy Bible Abridged; or, The History of the Old and New Testament," published in Worcester, Massachusetts by Thomas, Son & Thomas, is a significant version designed specifically for children. This edition is noted for being the Second Worcester Edition and bears similarities in textual content to the 1792 New York edition printed by William Durrell. However, it distinguishes itself by featuring a different set of illustrations.<br><br>Key among these illustrations are woodcuts depicting Christ restoring the widow’s son to life (Luke 7:11–18) and Christ stilling the tempest (Luke 8:41–56). These woodcuts not only enhance the visual appeal of the Bible but also serve an educational purpose, helping to convey biblical stories to children in a more engaging and accessible manner.<br><br>This abridged version of the Bible reflects the trend of the late 18th century to make religious texts more accessible to younger audiences. By simplifying the content and adding illustrative elements, this edition aimed to foster religious education and moral development among children. The inclusion of notes and cuts (illustrations) suggests an effort to explain and illuminate the biblical stories, making them more understandable and relatable to a younger audience. This edition is a valuable example of early American efforts to tailor religious education to the needs and comprehension levels of children.', 'historic', 'https://www.smu.edu/Bridwell/SpecialCollectionsandArchives/Exhibitions/Childrens-Books/Bibles/Holy-Bible-Worcester-1796', '30', 'eng', '1796', 'scan', 'Thomas, Son & Thomas', NULL, NULL, 'ENGWOB_DBS_HS/English-(1796)-Worchister-Bible-Abriged', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('7', 'English-1745-Primitive-New-Testament-Whiston', 'ENGWHS', 'English (1745) Primitive New Testament (Whiston)', NULL, 'The "Primitive New Testament" by William Whiston, published in 1745, is a distinctive work in the field of biblical translations. This version, titled "Mr. Whiston''s Primitive New Testament," was divided into four parts: the Four Gospels with the Acts of the Apostles, the XIV Epistles of Paul, the VII Catholic Epistles, and the Revelation of John. It was published in Stamford & London for the author.<br><br>Whiston''s translation was based on the Greek of the Clermont Manuscript, believed to be between 1400 and 1500 years old at the time, held in the King of France''s Library at Paris. This manuscript''s Latin text is part of the Old Italic Version, dating from the early second century. Whiston''s work generally follows the King James Version (KJV), except where Greek manuscripts indicate differences in wording, additions, or omissions. He relied on the Codex Bezae and Codex Claromontanus for his translation.<br><br>Whiston was also known for founding a society promoting primitive Christianity, delivering lectures in support of his theories. His involvement included notable figures like Thomas Chubb, Thomas Emlyn, and others, though some, like Samuel Clarke and Benjamin Hoadley, were skeptical of his reliance on the Apostolical Constitutions.<br><br>Franz Wokenius wrote a Latin work in 1728 critiquing Whiston''s views on primitive Christianity. While Whiston''s challenges to Athanasian teachings led to perceptions of heresy, he was a firm believer in the supernatural aspects of Christianity, defending prophecy and miracles, and supporting practices like anointing the sick.<br><br>Whiston''s religious journey culminated in his departure from the Anglican communion for the Baptists around 1747, a decision made during a church service when the Athanasian Creed was being read. His "Primitive New Testament" is a reflection of his unique theological perspectives and his commitment to exploring early Christian texts and practices.', 'historic', 'https://en.wikipedia.org/wiki/William_Whiston', '18', 'eng', '1752', 'scan', NULL, NULL, NULL, 'ENGWHS_DBS_HS/English-(1745)-Primitive-New-Testament-(Whiston)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('8', 'Greek-Latin-1565-Beza-Bible-NT', 'GRCBEZA', 'Greek-Latin (1565) Beza Bible (NT)', 'Βίβλος του Beza (1565, Καινή Διαθήκη)', 'Theodore Beza, a key figure in the Protestant Reformation and a disciple of John Calvin, made significant contributions to Biblical scholarship with the 1565 Beza Bible (New Testament). Beza, who succeeded Calvin as a spiritual leader in Geneva, released an edition of the Greek New Testament that featured parallel columns of the Latin Vulgate and his own translation, first published in 1556 with the earliest known edition from 1559. This work was distinguished by enriched and expanded annotations.<br><br>For the preparation of this Greek text, and more notably for the second edition in 1582, Beza possibly utilized two important manuscripts: the Codex Bezae or Cantabrigensis, later donated to the University of Cambridge, and the Codex Claromontanus, discovered in Clermont and now in the Bibliothèque Nationale de France in Paris. However, Beza''s work was chiefly influenced by the 1550 edition of Robert Estienne, which was based on Erasmus''s editions. This influence was significant in shaping future Biblical studies.<br><br>Beza''s Latin version and his extensive notes, reputedly published over a hundred times, greatly facilitated a clearer understanding of the New Testament. While some critics argue that Beza''s interpretation was overly influenced by his doctrine of predestination, his contributions to New Testament scholarship are widely recognized as substantial and beneficial.', 'historic', NULL, '143', 'grc', '1565', 'study', NULL, NULL, NULL, 'GRCBEZA_DBS_HS', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('9', 'English-1876-Julia-Smith-Holy-Bible-Translation', 'ENGJESPT', 'English (1876) Julia Smith Holy Bible Translation', NULL, 'The Julia Evelina Smith Parker Translation, published in 1876, marks a historic milestone as the first complete translation of the Bible into English by a woman. This edition, titled "The Holy Bible: Containing the Old and New Testaments; Translated Literally from the Original Tongues," is the brainchild of Julia E. Smith (1792-1886). Her translation journey was rooted in her unique upbringing and her family''s non-conformist religious beliefs.<br><br>Julia was one of five daughters of Zepheniah Smith (1759-1836), a former Congregationalist minister and a Yale-educated lawyer. Zepheniah''s shift towards Sandemanianism, a sect promoting home-based worship and Bible study, heavily influenced his family. After inheriting their father''s estate, Julia and her sisters delved into religious and biblical studies, especially during the Millerite movement''s peak in the 1830s and 40s.<br><br>Self-taught in languages like Greek and Hebrew, Julia embarked on her translation as a personal spiritual exercise, without formal theological training or external scholarly input. Her approach reflected the independence and skepticism of theological tradition typical of Sandemanians. Her translation, more an interlinear gloss than a conventional one, mirrored her self-assured stance and lack of concern for traditional academic methods in biblical translations.<br><br>Julia Evelina Smith Parker''s translation stands out for its embodiment of individualistic religious inquiry and the distinct role of women in biblical scholarship. It serves not just as a religious text but as a symbol of the era''s intellectual and spiritual explorations.', 'historic', NULL, '264', 'eng', '1876', 'scan', NULL, 'american-publishing-company', NULL, 'ENGJESPT_DBS_HS/English-(1876)-Julia-Smith-Holy-Bible-Translation', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('10', 'Assyrian-New-Testament-book', 'AIIWBT', 'Assyrian - New Testament (Book)', 'ܐܬܘܪܝܐ - ܒܪܝܬܐ ܚܕܬܐ (ܟܬܒܐ)', 'An Assyrian translation of the New Testament. Neo-Assurian, or Suret, is a language spoken in Iraq, Iran, and Syria. ', 'modern', NULL, '7', 'aii', '1905', 'book', NULL, NULL, NULL, 'AIIAPNT_DBS_HS/Assyrian-New-Testament-(book)', 'aii', 'assy1241', 'Assyrian Neo-Aramaic', 'Sūreṯ', 'L', 'IQ', '36.75', '43', '6b', NULL, '626000', 'Iraq', 'Northern Iraq, Baghdad, Basrah, Karkuk, Arbil. Also in Armenia, Australia, Austria, Azerbaijan, Belgium, Brazil, Canada, Cyprus, France, Georgia, Germany, Greece, Iran, Italy, Lebanon, Netherlands, New Zealand, Russian Federation (Europe), Sweden, Switzerland, Syria, Turkey (Asia), United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('11', 'Aramaic-Peshitta-Bible-New-Testament-Romanized', 'AIIWBT', 'Aramaic Peshitta Bible - New Testament', 'ܐܪܡܝܐ ܦܫܝܛܬܐ ܟܬܒܐ - ܚܕܬܐ ܕܝܬܩܐ', 'In the Syriac (Eastern Aramaic) language the Peshitta (Syriac: "common version") is the standard version of the Christian Bible. It continues to serve as the Bible of churches in the Syriac tradition (Church of the East, Chaldean Catholic, and Syriac Orthodox) to this day. The history of Christian Translations of the Bible into Syriac language includes the Diatessaron, the Old Syriac versions (Curetonian and Sinaitic), the Peshitto, the Philoxenian version, the Harklean Version and the recent United Bible Societies'' modern Aramaic New Testament.<br><br>About AD 500 a Christian Palestinian Aramaic version was made. It contains 2 Peter, 2-3 John, Jude, and Apocalypse. It is representative of the Caesarean text type and is a unique translation different from any other which was made into Syriac. These are among the manuscripts used by John Gwynn in 1893 to complete his edition of the Catholic Epistles. In 1892 Agnes Smith Lewis discovered the manuscript of the Palestinian Syriac lectionary in the library of Saint Catherine''s Monastery on Mount Sinai. It is designated by Syr.<br><br>The first revision of the New Testament from the Syriac into Turoyo language (Western Aramaic in Syriac and Latin script) was made by Malphono Yuhanun Üzel (Bar Shabo), Benjamin Bar Shabo, and Yahkup Bilgic in 2009 with notes from Harclean and Philoxenios. This commission "Sihto du Kthovo Qadisho Suryoyo" works especially to preach the Gospel in Aramaic all over the world.', 'historic', NULL, '1', 'aii', '1885', 'scan', NULL, NULL, NULL, 'aramaic_nt_peshitta', 'aii', 'assy1241', 'Assyrian Neo-Aramaic', 'Sūreṯ', 'L', 'IQ', '36.75', '43', '6b', NULL, '626000', 'Iraq', 'Northern Iraq, Baghdad, Basrah, Karkuk, Arbil. Also in Armenia, Australia, Austria, Azerbaijan, Belgium, Brazil, Canada, Cyprus, France, Georgia, Germany, Greece, Iran, Italy, Lebanon, Netherlands, New Zealand, Russian Federation (Europe), Sweden, Switzerland, Syria, Turkey (Asia), United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('12', 'English-1599-Geneva-New-Testament-with-Footnotes-text', 'ENGGNV', 'English (1599) Geneva New Testament (with Footnotes) (text)', NULL, 'The Geneva Bible, first printed in 1560, is one of the most historically significant translations of the Bible into English, predating the King James Version by 51 years. It was the primary Bible for English Protestantism in the 16th century and was used by William Shakespeare, Oliver Cromwell, John Knox, John Donne, and John Bunyan, author of "The Pilgrim''s Progress" (1678). This Bible was also among those taken to America on the Mayflower, as evidenced by collections at the Pilgrim Hall Museum.<br><br>This version was groundbreaking as it was the first mechanically printed, mass-produced Bible available directly to the general public. It included a comprehensive apparatus for scriptural study, such as verse citations for cross-referencing, book introductions, maps, tables, woodcut illustrations, and indices. Its forceful and vigorous language made it more popular than the Great Bible, leading Cleland Boyd McAfee to state that it "drove the Great Bible off the field by the sheer power of excellence."<br><br>Created during Queen Mary I''s reign (1553–58), the Geneva Bible was the work of Protestant scholars who fled England for Geneva, Switzerland. There, under the spiritual leadership of John Calvin and Theodore Beza, William Whittingham supervised the Geneva Bible''s translation, collaborating with Myles Coverdale and others. Whittingham was responsible for the New Testament (published in 1557), while Gilby oversaw the Old Testament.<br><br>The first full edition of the Geneva Bible appeared in 1560, but it wasn''t printed in England until 1575 (New Testament) and 1576 (complete Bible). Over 150 editions were issued, the last probably in 1644. The first Bible printed in Scotland was the Geneva Bible, issued in 1579. Later editions included Laurence Tomson''s revisions of the New Testament and a new "Junius" version of the Book of Revelation.<br><br>The Geneva Bible''s Calvinist and Puritan annotations were disliked by the Church of England and King James I, who commissioned the King James Bible as a replacement. The Geneva Bible influenced the production of the Bishops'' Bible and the later Rheims-Douai edition by the Catholic community. It remained popular among Puritans and in use until after the English Civil War, with its notes even appearing in some editions of the King James version as late as 1715.', 'modern', 'https://en.wikipedia.org/wiki/Geneva_Bible', '12', 'eng', '1610', 'book', NULL, NULL, NULL, 'ENGGNV_DBS_HS/English-(1599)-Geneva-New-Testament-(with-Footnotes)-(text)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('13', 'English-1534-Tyndale-New-Testament', 'ENGTYN', 'English (1534) Tyndale New Testament', NULL, 'The Tyndale Bible generally refers to the body of biblical translations by William Tyndale (1494–1536). Tyndale''s Bible is credited with being the first English translation to work directly from Hebrew and Greek texts. Furthermore, it was the first English biblical translation that was mass-produced as a result of new advances in the art of printing.<br><br>The term Tyndale''s Bible is not strictly correct, because Tyndale never published a complete Bible. That task was completed by Miles Coverdale, who supplemented Tyndale''s translations with his own to produce the first complete printed Bible in English in 1535. Prior to his execution Tyndale had only finished translating the entire New Testament and roughly half of the Old Testament. Of the latter, the Pentateuch, Jonah and a revised version of the book of Genesis were published during his lifetime. His other Old Testament works were first used in the creation of the Matthew Bible and also heavily influenced every major English translation of the Bible that followed.<br><br>1525 Tyndale, William (The New Testament) [Cologne: Peter Quentell, 1525.][Only a fragment, ''The gospell of S. Mathew. The first Chapter [through] the xxii. Chapter.'', still remains in the Grenville Collection of the British Museum. 3,000 copies of the first ten sheets had been secretly printed before Tyndale had to flee Cologne to Worms, where he began his work afresh. Complete edition; Worms: Peter Quentell, 1526. Reprinted; New Testament translated by William Tyndale 1525. Facsimile of unique fragment of the uncompleted Cologne edition. Oxford: Clarendon Press, 1926.', 'historic', NULL, '135', 'eng', '1534', 'scan', 'GreatSite.com', NULL, NULL, 'ENGTYN_DBS_HS', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('14', 'Aramaic-1514-Complutensian-Polyglot-Bible-Vol-3-of-5-Grk-Heb-Lat-Aramaic-StudyWDL-10636', 'AII1514', 'Aramaic (1514) Complutensian Polyglot Bible (Vol 3 of 5) Grk-Heb-Lat-Aramaic Study(WDL-10636)', 'Vetus testamentū multiplici lingua nūc primo impressum, Et imprimis Pentateuchus Hebraico Greco atq[ue] Chaldaico idiomate', 'The third volume of the Complutensian Polyglot Bible, part of the pioneering multilingual edition completed in 1514 under Cardinal Francisco Jiménez de Cisneros''s patronage, represents a monumental effort in biblical scholarship and printing. This volume continues the presentation of the Old Testament, aligning Greek, Latin, and Hebrew texts in parallel columns to facilitate comparative study. The Complutensian Polyglot marked a significant leap forward in making scriptural texts accessible for scholarly study, integrating critical languages for biblical scholarship. Produced by Arnaldo Guillén de Brocar, who crafted new typefaces for this purpose, the work stands as a testament to the typographical artistry of the 16th century. Notably, the Bible includes Aramaic translations, providing scholars with valuable resources for understanding the scriptures in their historical and linguistic contexts. Distributed in 1520 after papal approval, this comprehensive work underscores the Renaissance''s scholarly dedication to understanding the biblical texts'' original languages, offering insights into the scriptures'' complexities with unprecedented clarity and depth.', 'historic', 'https://www.wdl.org/en/item/10636', '133', 'aii', '1514', 'study', 'Arnao Guillén de Brocar, Alcalá de Henares', NULL, 'World Digital Library', 'AII1514_DBS_HS/Aramaic-(1514)-Complutensian-Polyglot-Bible-(Vol-3-of-5)-Grk-Heb-Lat-Aramaic-Study(WDL-10636)', 'aii', 'assy1241', 'Assyrian Neo-Aramaic', 'Sūreṯ', 'L', 'IQ', '36.75', '43', '6b', NULL, '626000', 'Iraq', 'Northern Iraq, Baghdad, Basrah, Karkuk, Arbil. Also in Armenia, Australia, Austria, Azerbaijan, Belgium, Brazil, Canada, Cyprus, France, Georgia, Germany, Greece, Iran, Italy, Lebanon, Netherlands, New Zealand, Russian Federation (Europe), Sweden, Switzerland, Syria, Turkey (Asia), United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('15', 'Coptic-Southen-1910-New-Testament-Sahidic-and-Thebaic-Vol-5-7', 'COPSNT', 'Coptic Southen (1910) New Testament Vol 5-7)', 'Ⲙⲉⲧⲛⲓⲙ ⲛ̀ⲛⲉⲛⲧⲟⲥ (1910) Ⲛⲁⲩ 5-7', 'Sahidic Coptic, the Upper Egyptian dialect of Coptic, was spoken in the Theban (now Luxor) area of Egypt. The first Coptic dialect into which Scriptures are thought to have been translated, the language was extinct by the 10th century', 'historic', NULL, '274', 'cop', '1910', 'scan', 'Henry Frowde-University of Oxford', NULL, NULL, 'COPSNT_DBS_HS/Coptic-Southen-(1910)-New-Testament-(Sahidic-and-Thebaic)-Vol-1-6)', 'cop', 'copt1239', 'Coptic', 'ϯⲙⲉⲧⲣⲉⲙⲛ̀ⲭⲏⲙⲓ ~ ⲧⲙⲛ̄ⲧⲣⲙ̄ⲛ̄ⲕⲏⲙⲉ', 'E', 'EG', '29.47203', '31.2053', '9', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('16', 'Hebrew-1280-ca.-Bible-Latin-Spanish-Toledo-WDL-17841', 'HEBTOLE', 'Hebrew (1280 ca.) Bible (Latin-Spanish) Toledo (WDL-17841)', 'עברית - תנ"ך (1280 בקירוב, לטינית-ספרדית, טולדו) (WDL-17841)', 'This Hebrew Bible manuscript from around 1280, known as the Toledo Bible, is a remarkable artifact of medieval Jewish scholarship and artistry. The manuscript comprises 340 large-format folios of high-quality parchment, written in three columns. It features a beautiful Sephardic square script for the biblical text, with Minor Masorah on the margins and between the columns, and Major Masorah in the upper and lower margins, in three and four lines respectively. The text includes Tiberian Hebrew punctuation, closely resembling that in the best Eastern codices of this tradition. The parashiyyot (annual pericope) are indicated in the margin, and the order of the Bible books aligns with the Babylonian Talmud.<br><br>Notably, the Major Masorah often forms ornamental micrographs with plant and geometric motifs, reminiscent of large candelabra, particularly in the outer margins of the first books of the Pentateuch. This feature has sparked debate about the manuscript''s origin, as candelabra-shaped micrographs are typically associated with the Catalonian Bibles of the 14th century. However, the style in this manuscript differs, suggesting a 13th-century Toledan origin, evidenced by the sedarim (triennial pericope), a typical feature of the Bibles of the Kingdom of Toledo.<br><br>The manuscript includes a note, previously thought to be the colophon, stating that it was purchased by brothers Isaac and Abraham ben Maimón in Toledo in 1280. At the end of the Pentateuch and other sections, there are exhaustive Masoretic notes detailing verse counts and other textual information. The verse recount at the end of each book is often within an ornate vignette.<br><br>Interestingly, the manuscript was owned and annotated by Alfonso de Zamora, a convert and teacher of Hebrew in Salamanca and Alcalá de Henares. His ownership is evident in his characteristic way of numbering chapters and naming the books of the Bible. This manuscript was extensively used in composing the Hebrew text of the Complutensian Polyglot Bible of 1514. It features a 16th-century Complutense cloth binding from Alcalá de Henares, with the golden coat of arms of the Complutense University of Madrid.', 'historic', 'https://www.wdl.org/en/item/17841', '287', 'heb', '1280', 'scan', 'Biblioteca Complutense', NULL, 'World Digital Library', 'HEBTOLE_DBS_HS/Hebrew-(1280-ca.)-Bible-(Latin-Spanish)-Toledo-(WDL-17841)', 'heb', 'hebr1245', 'Hebrew', 'Israeli Hebrew', 'L', 'IL', '31.10565', '35.01788', '1', 'he', '5000000', NULL, 'Also in Australia, Canada, Germany, Palestinian West Bank and Gaza, Panama, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('17', 'Greek-1906-Hexaglot-Bible-Eng-Fre-Ger-Lat-Heb-Vol-1-6', 'GRCVATI', 'Greek (1906) Hexaglot Bible (Eng Fre Ger Lat Heb) Vol 1-6', 'Εξαγλωττίκη Βίβλος (1906, Αγγλικά-Γαλλικά-Γερμανικά-Λατινικά-Εβραϊκά, Τόμος 1-6)', 'The 1906 "Hexaglot Bible" is an extensive and ambitious work that compiles the Holy Scriptures of the Old and New Testaments in six different languages. This multilingual approach provides a comprehensive resource for comparative biblical studies. The Hexaglot Bible features the original texts of the Scriptures in their original tongues, alongside several key translations, all arranged in parallel columns for ease of study and comparison.<br><br>For the Old Testament, the Hexaglot Bible includes the original Hebrew text, the Greek Septuagint (an ancient Greek translation of the Hebrew Bible), the Latin Vulgate, and translations in English, German, and French. The New Testament is presented in the original Greek, the Syriac version (which is an early Christian translation), the Latin Vulgate, and translations in English, German, and French.<br><br>This comprehensive arrangement allows for an in-depth comparison of texts across different languages and translations. By including a variety of translations, the Hexaglot Bible serves as a valuable tool for scholars, theologians, and students who are interested in understanding the nuances of biblical texts in different linguistic and cultural contexts. The inclusion of translations that have been historically significant in Christianity, such as the Vulgate, the Authorized English version, and key European translations, makes this work an important resource for the study of the history of biblical interpretation and translation.', 'historic', NULL, '580', 'grc', '1906', 'study', 'Apud Funk et Wagnalls', NULL, NULL, 'GRCVATI_DBS_HS/Greek-(1906)-Hexaglot-Bible-(Eng-Fre-Ger-Lat-Heb)-Vol-1-6', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('18', 'English-1551-Taverners-Bible', 'ENGTVB', 'English (1551) Taverners Bible', NULL, 'Taverner''s Bible, more accurately titled The Most Sacred Bible whiche is the holy scripture, conteyning the old and new testament, translated into English, and newly recognized with great diligence after most faythful exemplars by Rychard Taverner, is a revision of Matthew''s Bible. Edited by Richard Taverner, it was first published in 1539, and its first editions are considered extremely rare today.<br><br>The emergence of Taverner''s Bible posed a commercial threat to the successful sale of Matthew''s Bible, initially a private venture by printers Grafton and Whitchurch. Taverner''s version, published in 1539 in folio (Herbert #45) by "John Byddell for Thomas Barthlet", represented a form of "piracy," as it was essentially Grafton''s Matthew Bible revised by Taverner. Taverner, known as a learned member of the Inner Temple and a renowned Greek scholar, introduced numerous changes to the Matthew Bible. These alterations were marked by his critical insight and a preference for strong, idiomatic expressions.<br><br>Despite these revisions, Taverner''s Bible did not significantly influence subsequent translations. Only a few phrases from this version found their way into the later King James Bible. As summarized by Daniell, Taverner''s Bible was "indeed a version which had no influence," highlighting its limited impact on the evolution of English Bible translations.', 'historic', NULL, '502', 'eng', '1551', 'scan', 'GreatSite.com', NULL, NULL, 'ENGTVB_DBS_HS', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('19', 'English-1913-American-Bible-Union-Baptist', 'ENGAME', 'English (1913) American Bible Union (Baptist) Bible', NULL, 'The American Bible Union, established with the ambitious goal of revising the King James Version, embarked on a significant biblical revision project in the mid-19th century, culminating in the publication of the New Testament in 1862-1864. Following some initial work on the Old Testament post-1865, the Union eventually dissolved, transferring its assets and mission to The American Baptist Publication Society in 1883.<br><br>This Society took up the mantle, publishing a revised New Testament in 1891 and later releasing both the Old and New Testaments in 1912, with the title: "Holy Bible, Containing the Old and New Testaments, An Improved Edition (Based in part on the Bible Union Version)." This edition, reprinted in 1913, is notable for incorporating insights from more recently available manuscripts, such as the Codex Sinaiticus and Codex Vaticanus, yet largely adhering to the Textus Receptus tradition.<br><br>Characterized by its literal translation approach, this version is distinguished for preserving the traditional usage of ''thee'' and ''you,'' adding to its textual authenticity. As one of the last complete Bibles to enter the public domain, it represents a significant historical artifact in biblical scholarship. This edition, through its rigorous and scholarly approach, stands as a testament to the enduring effort to make biblical texts more accurate and accessible, bridging the gap between ancient manuscripts and contemporary readers.', 'historic', NULL, '208', 'eng', '1913', 'scan', NULL, NULL, NULL, 'ENGAME_DBS_HS/English-(1913)-American-Bible-Union-(Baptist)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('20', 'English-1872-Polyglot-Study-Bible', 'ENGKJV', 'English (1872) Polyglot Study Bible', NULL, 'The 1872 edition of the "Polyglot Study Bible" stands as a monumental work in the realm of biblical translations, curated and published by the renowned Samuel Bagster. Born on 26 December 1772 and educated under Rev. John Ryland at Northampton, Bagster began his career in the book trade on 19 April 1794. He quickly established himself as a visionary in the field, bringing out "The English Version of the Polyglot Bible" in 1816, a work noted for its over 60,000 parallel references meticulously selected and verified by Bagster himself. <br><br> This edition was not only a commercial success but also a testament to Bagster''s commitment to quality and detail. He introduced innovations in binding, using the finest Turkey Morocco and prepared sealskins, which were known for their distinctive ''pin-head grain.’ <br><br> Among Bagster''s many significant publications, two stand out. The first is the "English Hexapla," published in 1841, presenting six pivotal English versions of the New Testament (Wycliffe, Tyndale, Cranmer, Genevan, Anglo-Rhemish, and the Authorized Version) alongside the Greek text as per Scholz, accompanied by an extensive historical account of English Bible translations. The second, the "Bible of Every Land," showcases over 270 different language versions of the Bible, demonstrating Bagster''s dedication to making the Scriptures accessible to a global audience. <br><br> The "Polyglot Study Bible" is an emblem of Bagster''s lifelong dedication to biblical scholarship, offering a rich tapestry of textual variations and insights, making it an invaluable resource for scholars, theologians, and devout readers alike.', 'historic', NULL, '299', 'eng', '1872', 'study', 'Samuel Bagster and Sons', NULL, NULL, 'ENGKJV_DBS_HS/English-(1872)-Polyglot-Study-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('21', 'English-1752-Douay-Rheims-Challoner-Bible-Vol.1-2', 'ENGDRBCR', 'English (1752) Douay-Rheims (Challoner) Bible - Vol.1-2', NULL, 'The Douay-Rheims Bible, revised by Richard Challoner, is a pivotal work in the history of English Bible translations. Originally translated from the Latin Vulgate and first published by the English College at Douay in 1609, it underwent several revisions by Challoner: <br><br> 1749: The first revision of the New Testament, incorporating changes from the 1738 edition by Richard Challoner and Francis Blyth.<br> 1750: The first revision of the Old Testament in two volumes, followed by the second revision of the New Testament in one volume.<br> 1752: The third revision of the New Testament in two volumes.<br> 1763 - 1764: The second revision of the Old Testament in four volumes.<br> 1764: The fourth revision of the New Testament.<br> 1772: The fifth revision of the New Testament.<br><br> This work also saw several notable editions:<br> 1790: The first American edition, based on Challoner''s Second Edition (1763-64), published in Philadelphia by Carey, Stewart & Co. in two volumes.<br> 1796: A four-volume edition published in Edinburgh by John Moir.<br> 1942: The New Testament, as revised by Dr. Challoner in 1752, published in New York by The Douay Bible House. This edition was praised by the Pope as the best text in the American tradition.<br><br> These revisions and editions reflect the enduring impact of Challoner''s work, making the Douay-Rheims Bible more accessible and understandable for English-speaking Catholics. The Douay-Rheims Bible, especially the Challoner revision, continues to hold significance in religious studies and practices.', 'historic', 'https://en.wikipedia.org/wiki/Douay%E2%80%93Rheims_Bible', '135', 'eng', '1752', 'scan', NULL, NULL, NULL, 'ENGDRBCR_DBS_HS/English-(1752)-Douay-Rheims-(Challoner)-Bible-Vol.1-2', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('22', 'English-1390-Wycliffe-Bible-NT', 'ENGWYC', 'English (1390) Wycliffe Bible New Testament', NULL, 'Wycliffe''s Bible, named after John Wycliffe, encompasses a series of pioneering Bible translations into Middle English, undertaken between approximately 1382 and 1395. These translations heralded a significant shift in religious and linguistic practices of the time, as they were the first to make the Bible accessible to a wider English-speaking audience. The driving force behind this movement was to break the monopoly of Latin, which was the exclusive language of scripture and liturgy in the Western Christian world during the early Middle Ages. Wycliffe''s vision was to democratize religious knowledge by translating the Bible into the vernacular, believing it would enable Christians to better understand the teachings of Christ.<br><br>Long attributed directly to Wycliffe, modern scholarship now suggests these translations were the collaborative effort of several scholars. Notable contributors included Nicholas of Hereford, who translated a substantial portion, and possibly John Purvey and John Trevisa. These translators primarily relied on the Vulgate, the Latin text that was the standard Biblical scripture in Western Christianity. Their translations were comprehensive, including texts that Protestants later termed the Apocrypha and additional books like 3 Esdras (now known as 2 Esdras) and Paul’s epistle to the Laodiceans.<br><br>Despite being unauthorized, Wycliffe''s Bible translations profoundly impacted the Middle Ages, catalyzing the Lollard movement—a group critical of many Roman Catholic doctrines—and becoming the most prevalent manuscript literature in Middle English. Over 250 manuscripts of the Wycliffe Bible survive, testifying to its widespread popularity and enduring legacy.', 'historic', NULL, '168', 'eng', '1390', 'manuscript', 'GreatSite.com', NULL, NULL, 'ENGWYC_DBS_HS', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('23', 'English-1922-Yawist-Bible-OT-Portions', 'ENGYAW', 'English (1922) Yawist Bible - OT Portions', NULL, 'The 1922 edition of "The Book of Yahweh" represents a compelling and pioneering approach to biblical texts, focusing on what is known as the "Yahwist" or "J" source, one of the oldest narrative strains in the Hebrew Bible. This groundbreaking work attempts to isolate and reconstruct fragments from what scholars believe to be a primitive document, dating back to the ninth century B.C., within the first seven books of the Old Testament. <br><br> The Yahwist source, identified by its characteristic use of the name Yahweh for God, is thought to be one of the four main sources of the Torah, as postulated by the Documentary Hypothesis. The hypothesis suggests that the Pentateuch was derived from multiple sources, each with its own theological and stylistic traits. The "Book of Yahweh" thus offers an intriguing window into one of these foundational sources, providing insights into the earliest layers of biblical narrative and theology. <br><br> This edition is particularly remarkable for its historical and literary significance. By attempting to extract and piece together the fragments of the Yahwist source, it not only offers a unique perspective on the ancient texts but also reflects the evolving understanding of biblical authorship and composition in the early 20th century. This work, attributed to an "unknown genius of the ninth century B.C.", underscores the rich complexity of biblical texts and the enduring quest to understand their origins and meanings.', 'historic', NULL, '33', 'eng', '1922', 'scan', 'The Cornhill Publishing Company', NULL, NULL, 'ENGYAW_DBS_HS/English-(1922)-Yawist-Bible-OT-Portions', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('24', 'Greek-1809-Novum-Testamentum-Griesbach-Vol.-1-2', 'GRCGRIE', 'Greek (1809) Novum Testamentum (Griesbach) Vol. 1-2', 'Novum Testamentum (1809, Griesbach, Τόμος 1-2)', 'The 1809 "Novum Testamentum Graece" (Volumes 1-2) represents a significant edition in the history of biblical scholarship, co-published in Halle and London in 1796 and 1806. This work is the second edition of Griesbach''s two-volume "Novum Testamentum Graece," initially released in 1774-1775. Johann Jakob Griesbach, a Professor of the New Testament at the University of Jena in Germany, is acknowledged as one of the pioneering figures in modern textual criticism of the Bible.<br><br>Griesbach''s groundbreaking theory categorized various versions of New Testament texts into three distinct families: Western, Alexandrian, and Constantinopolitan. He developed a set of fifteen criteria for this classification, which he detailed in the Latin Prolegomena of volume 1 in the second edition. This methodological approach was a significant advancement in understanding the textual variations and transmission of the New Testament.<br><br>Volume 2 of this edition encompasses the Book of Acts, the Pauline epistles, the Catholic epistles, and the Book of Revelation. Griesbach''s work laid foundational principles for textual criticism, influencing subsequent scholarship in biblical studies and contributing to a more nuanced understanding of the New Testament''s textual history.', 'historic', NULL, '28', 'grc', '1809', 'scan', 'Dommer', NULL, NULL, 'GRCGRIE_DBS_HS/Greek-(1809)-Novum-Testamentum-(Griesbach)-Vol.-1-2', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('25', 'English-1788-Hieroglyphick-Bible-Portions-Isaiah-Thomas-WDL-19331', 'ENGHBP', 'English (1788) Hieroglyphick Bible Portions - Isaiah Thomas (WDL-19331)', NULL, 'The 1788 Hieroglyphick Bible, "A Curious Hieroglyphick Bible, or, Select Passages in the Old and New Testaments," is the first American hieroglyphic Bible, produced by Isaiah Thomas (1749‒1831), a leading early American printer and a pioneer publisher of children''s literature. This Bible is a significant piece in the history of American book illustration, featuring nearly 500 woodcuts by American artists, making it the most ambitious woodcut book produced in America at that time.<br><br>Hieroglyphic Bibles replace some of the words in the text with pictures, and were popular in Great Britain and America for teaching Scripture to children in a simple and engaging manner. Thomas, in his preface, presents the book not only as a means of imparting Bible lessons to children but also as an aid in developing their reading skills. Thomas learned engraving during his apprenticeship with Boston printer Zechariah Fowle and was primarily based in Worcester, Massachusetts. He produced 65 children''s books and is revered as America''s first enlightened printer of such books, often likened to John Newbery of London, England. Both shared the motto "Instruction with delight."<br><br>This Hieroglyphick Bible was inscribed by its first owner, "Enoch Brooks'' Book, Princeton, March 13th, 1789." It remains a rare artifact, with only four copies known to exist today. Its significance lies not only in its content and educational approach but also as a landmark in the history of American printing and children''s literature.', 'historic', 'https://www.wdl.org/en/item/19331', '45', 'eng', '1788', 'scan', 'Isaiah Thomas, Worcester, Massachusetts', NULL, 'World Digital Library', 'ENGHBP_DBS_HS/English-(1788)-Hieroglyphick-Bible-Portions-Isaiah-Thomas-(WDL-19331)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('26', 'Hebrew-0900-Damascus-Codex-HighRes-Manuscript', 'HBODAMA', 'Hebrew (0900) Damascus Codex (Pentateuch) Manuscript', 'עברית - כתב יד דמשק (0900, חמשה חומשי תורה)', 'The Damascus Pentateuch, also known as Keter Dameseq or Crown of Damascus, is an important 10th-century Hebrew Bible codex. This manuscript primarily consists of the almost complete Pentateuch, which includes the Five Books of Moses. One of the notable aspects of the Damascus Pentateuch is that it was copied by an unknown scribe and is replete with Masoretic annotations, which are critical for understanding the textual transmission of the Hebrew Bible.<br><br>However, the manuscript is not complete; it is defective at the beginning, starting from Genesis 9:26, and also missing the section from Exodus 18:1–23. Despite these omissions, the Damascus Pentateuch is a valuable resource for biblical scholars and historians.<br><br>In 1975, the manuscript was acquired by the Jewish National and University Library in Jerusalem, an institution that later changed its name to the National Library of Israel in 2008. The significance of the Damascus Pentateuch was recognized with its publication in a large, two-volume facsimile edition in 1978, making it accessible for scholarly study.<br><br>It is important to note that the Damascus Pentateuch should not be confused with another manuscript known as the Damascus Crown (Damascus Keter) of medieval Spanish origin, which contains 24 canonical books. The Damascus Pentateuch, with its rich annotations and historical value, remains an important artifact in the study of the Hebrew Bible and the Masoretic tradition.', 'historic', 'https://www.wdl.org/en/item/13016', '406', 'hbo', '900', 'manuscript', 'David Solomon Sassoon', NULL, 'World Digital Library', 'HBODAMA_DBS_HS/Hebrew-(0900)-Damascus-Codex-(HighRes)-Manuscript', 'hbo', 'anci1244', 'Ancient Hebrew', 'עִבְרִית מִקְרָאִית', 'H', 'IL', '31.77607', '35.17248', '9', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('27', 'English-1923-Ballantine-Riverside-New-Testament', 'ENGBALL', 'English (1923) Ballantine Riverside New Testament', NULL, 'The 1923 "Riverside New Testament," translated by William G. Ballantine, represents a significant contribution to biblical scholarship, offering a modern English rendition of the New Testament. Ballantine''s translation, based on the critical Nestle text, aimed to bring the ancient scriptures closer to the contemporary reader by employing the vernacular of the early 20th century. This approach was somewhat revolutionary for its time, as it broke away from the more traditional and archaic language typically used in biblical translations. <br><br> William G. Ballantine, a respected scholar, recognized the need for a version of the New Testament that resonated with the linguistic sensibilities of his era. His work reflects a meticulous engagement with the original Greek texts, coupled with an effort to ensure that the translation was both accessible and faithful to the original meanings. The Riverside New Testament was slightly revised in 1934, indicating its ongoing relevance and the enduring interest in making the scriptures comprehensible to modern audiences. <br><br> Ballantine''s translation is noteworthy for its clarity and simplicity, striving to convey the teachings and narratives of the New Testament in a language that is both understandable and meaningful to contemporary readers. His work exemplifies the continuing evolution of biblical translation, highlighting the balance between scholarly fidelity to ancient texts and the adaptation of these texts to the evolving language and culture of the readers.', 'historic', NULL, '9', 'eng', '1923', 'scan', NULL, NULL, NULL, 'ENGBALL_DBS_HS/English-(1923)-Ballantine-Riverside-New-Testament', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('28', 'English-1781-Psalms-The-book-of-Psalms-by-English-poets', 'ENGPOET', 'English (1781) Psalms by Poets', NULL, 'The 1781 publication "The Book of Psalms by Some of the Most Eminent English Poets" presents a unique blend of biblical scripture and artistic expression. This work features interpretations of the Psalms, traditionally known for their lyrical quality, rendered into verse by distinguished English poets of the era. This approach highlights the poetic nature of these ancient hymns, offering a new and artistic perspective on these well-known texts. The edition is significant for showcasing the Psalms in a way that appeals not only to religious audiences but also to aficionados of English literature, emphasizing the timeless and versatile nature of biblical literature.', 'historic', NULL, '124', 'eng', '1781', 'scan', NULL, NULL, NULL, 'ENGPOET_DBS_HS/English-(1781)-Psalms-(The-book-of-Psalms-by-some-of-the-most-eminent-English-poets)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('29', 'Hebrew-1817-Hebrew-New-Testament-Alexander', 'HEBALXE', 'Hebrew (1817) Hebrew New Testament (Alexander)', 'עברית - הברית החדשה (1817, אלכסנדר)', 'The 1817 Hebrew New Testament, translated by Alexander and published by the London Society for Promoting Christianity amongst the Jews, represents a pivotal moment in biblical translation history. Printed by A. Macintosh in Spitalfields, London, this work aimed to make Christian scriptures accessible to Jewish audiences in their native language. The initiative was part of a broader 19th-century movement by missionary organizations to spread Christianity within Jewish communities.<br><br>The London Society for Promoting Christianity amongst the Jews, also known as the London Jews'' Society, spearheaded these efforts, including translating Christian texts into Hebrew and establishing educational institutions for outreach. This edition holds linguistic and cultural significance, as it sought to present the Christian message within a familiar framework to Jewish people, thus exemplifying the complex interplay of language, religion, and cultural engagement in missionary activities during this period.', 'historic', NULL, '24', 'heb', '1817', 'scan', 'A. Macintosh', NULL, NULL, 'HEBALXE_DBS_HS/Hebrew-(1817)-Hebrew-New-Testament-(Alexander)', 'heb', 'hebr1245', 'Hebrew', 'Israeli Hebrew', 'L', 'IL', '31.10565', '35.01788', '1', 'he', '5000000', NULL, 'Also in Australia, Canada, Germany, Palestinian West Bank and Gaza, Panama, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('30', 'English-1800-Christian''s-New-and-Complete-British-Family-Bible-Study', 'ENGCNC', 'English (1800) Christian''s New and Complete British Family Bible (Study)', NULL, 'The Christian''s New and Complete British Family Bible, printed around 1800 for Alex. Hogg in London, is a distinguished example of an early 19th-century family Bible. This folio-sized edition, measuring approximately 9-1/2 by 15 inches, is bound in contemporary full tree calf with gilt decoration, featuring a richly decorated spine with raised bands, a red morocco spine label, and marbled endpapers.<br><br>Notable for its use of the King James text, first published in 1611, this Bible has had a profound influence on English piety, language, and literature. It is emblematic of the versions commonly found in family Bibles of the period, intended for both use and display in the home. This edition is enhanced by 82 copper-engraved plates, including an allegorical frontispiece, adding a visual dimension to the scriptural text. These engravings depict dramatic moments and significant figures from the Bible.<br><br>Accompanying the biblical text is extensive historical and theological commentary compiled by Paul Wright, known as the "Vicar of Oakley and Rector of Snoreham." The inclusion of the Apocrypha adds to its comprehensiveness. This Bible''s first publication was in 1782 as The Complete British Family Bible (Herbert 1278), making it a valuable piece of religious and literary history. Its combination of scriptural content, scholarly commentary, and artistic illustration makes it a significant artifact from the turn of the 19th century, reflecting the era''s approach to biblical interpretation and family devotion.', 'historic', NULL, '287', 'eng', '1800', 'study', 'Paul Wright', NULL, NULL, 'ENGCNC_DBS_HS/English-(1800)-Christian''s-New-and-Complete-British-Family-Bible-(Study)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('31', 'English-1824-A-New-Family-Bible-Vol.-1-of-3-Boothroyd-Study', 'ENGNFB', 'English (1824) A New Family Bible (Vol. 1 of 3) Boothroyd (Study)', NULL, 'English (1824) A New Family Bible (Vol. 1 of 3) Boothroyd (Study) Bible. English. Boothroyd. 1824. New family Bible, and improved version, from corrected texts of the originals. Huddersfield: William Moore, 1824<br><br>“Boothroyd, Benjamin A New Family Bible, and improved version, from corrected texts of the originals; with notes critical and explanatory, and short practical reflections...with a general introduction...By the Rev. B. Boothroyd... 3 Vols. Huddersfield: Printed for the Author, and others, by William Moore, 1817 and again in 1824. New edition, revised, 1835. An Abridged Edition; London: James Duncan, 1836. Another edition; Translated from Corrected Texts. London: Partridge & Oakey, 1853.”<br><br>(From: William J. Chamberlin. “Catalogue of English Bible Translations”.<br><br>Benjamin Boothroyd (1768 – 8 September 1836) was an English Independent minister and Hebrew scholar. He had the degrees of D.D. and L.L.D. In 1818 Boothroyd (who had accepted the degree of LL.D.) became co-pastor at Highfield Chapel, Huddersfield, with the Rev. William Moorhouse. In 1818 Booth completed his New Family Bible and Improved Version in three vols. 4to, which had been suggested to him on a visit to York by Henry Tuke, a Quaker. He printed many copies of it at his own press. It contained notes, and in recognition of his achievement the university of Glasgow conferred on Boothroyd the degree of D.D. in 1824. In 1835 he completed an octavo edition of the Family Bible. On 10 January 1836 he went down with a violent illness; he died on 8 September and was buried at Huddersfield.', 'historic', 'https://en.wikipedia.org/wiki/Benjamin_Boothroyd', '268', 'eng', '1824', 'study', 'Rev. B. Boothroyd, L. L. D.', NULL, NULL, 'ENGNFB_DBS_HS/English-(1824)-A-New-Family-Bible-(Vol.-1-of-3)-Boothroyd-(Study)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('32', 'English-1935-Westminster-New-Testament', 'ENGWEST', 'English (1935) Westminster New Testament', NULL, 'The Westminster New Testament, a distinguished Roman Catholic translation in England, emerged as a notable scholarly endeavor, initiated in 1913 and culminating with the completion of the New Testament in 1936. Spearheaded by General Editors Cuthbert Lattey (1877-1954) and Joseph Keating (1865-1939), the project demonstrated meticulous translation efforts, releasing parts of each volume as separate fascicles. This approach underscored the comprehensive and detailed nature of the project.<br><br>Marked by its adherence to Roman Catholic teachings, the Westminster New Testament offers a unique lens within the realm of biblical translations. Post the New Testament''s completion, the team embarked on translating the Old Testament, with portions appearing in the 1940s and 50s. However, following Lattey''s passing in 1954, the Old Testament translation ceased. Ultimately, a complete Bible was published in 1958 and reissued in 1966, combining the Westminster New Testament and Psalms with the Old Testament from Challoner''s revision of the Douay-Rheims Version. This edition not only stands as a scholarly contribution but also bridges traditional Roman Catholic doctrine with contemporary biblical interpretations.', 'historic', NULL, '11', 'eng', '1935', 'scan', 'Longmans, Green and Co.', NULL, NULL, 'ENGWEST_DBS_HS/English-(1935)-Westminster-New-Testament', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('33', 'English-1820-Wakefield-New-Testament', 'ENGWNT', 'English (1820) Wakefield New Testament', NULL, 'The 1820 edition of the New Testament translated by Gilbert Wakefield is a notable work in the history of biblical scholarship. Wakefield, born in 1756, was a graduate of Cambridge and was ordained as a deacon in the Anglican Church around 1776. However, his journey with the Anglican Church was short-lived as he soon found himself in ideological conflict with the Church''s doctrines.<br><br>Wakefield’s inability to subscribe to the Anglican articles of faith led him to teach at various schools that espoused Unitarian views, aligning more closely with his personal beliefs. Beyond his religious pursuits, Wakefield was also politically vocal, advocating against war and critiquing the prevailing forms of government and ecclesiastical authority, which he viewed as a “bond of iniquity.”<br><br>The first edition of his New Testament translation appeared in 1791, followed by a revised edition in 1795. The 1820 edition represents the third edition of his work and reflects his ongoing engagement with biblical texts. His translations were informed not just by his linguistic expertise but also by his theological and political convictions, offering a perspective that was distinct from mainstream Anglican interpretations of the time.<br><br>Wakefield''s work on the New Testament is significant not only for its scholarly contributions to biblical studies but also for reflecting the broader intellectual and religious currents of his time. His translation is a testament to the diversity of religious thought and the critical engagement with biblical texts that characterized the late 18th and early 19th centuries.', 'historic', 'http://bibles.wikidot.com/wakefield', '90', 'eng', '1820', 'scan', 'Gilbert Wakerfield, B. A.', NULL, NULL, 'ENGWNT_DBS_HS/English-(1820)-Wakefield-New-Testament', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('34', 'Greek-1882-He-Kaine-Diatheke-Novum-Testamentum-with-references', 'GRCWHT', 'Greek (1882) He Kaine Diatheke Novum Testamentum (with references)', 'Η Καινή Διαθήκη - Novum Testamentum (1882, με αναφορές)', 'The 1882 publication "He Kaine Diatheke. Novum Testamentum Graecum Editionis Receptae Cum Lectionibus Variantibus" is a notable edition of the Greek New Testament. This work, which includes an extensive commentary by Joannis-Jacobi Wetstenii, is an important resource in the field of biblical scholarship.<br><br>The edition features the Greek text of the New Testament according to the Textus Receptus, an influential Greek text that formed the basis of many early Protestant Bible translations. Additionally, this edition is enriched with variant readings, providing scholars and students with a comprehensive view of the textual variations found in different manuscripts.<br><br>Wetstenii''s commentary offers in-depth analysis and interpretation of the New Testament text, making this edition particularly valuable for those studying the Greek New Testament in detail. The inclusion of variant readings and thorough commentary provides a deeper understanding of the textual history and critical analysis of the New Testament. This edition serves as a significant tool for those engaged in biblical studies, theology, and the history of biblical interpretation.', 'historic', NULL, '841', 'grc', '1882', 'scan', 'The Clarendon Press-Oxford University Press', NULL, NULL, 'GRCWHT_DBS_HS/Greek-(1882)-He-Kaine-Diatheke-Novum-Testamentum-(with-references)', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('35', 'English-1537-Matthews-Bible', 'ENGMTB', 'English (1537) Matthews Bible', NULL, 'The Matthew Bible, also known as Matthew''s Version, is a significant historical text in the lineage of English Bible translations. First published in 1537 by John Rogers, using the pseudonym "Thomas Matthew," this Bible occupies a crucial position in the evolution of English scriptures. It amalgamated the New Testament, translated by William Tyndale, with the sections of the Old Testament that Tyndale had managed to complete before his capture and execution. The translation of the remaining portions of the Old Testament and the Biblical Apocrypha was undertaken by Myles Coverdale, who primarily relied on German and Latin texts. However, the Prayer of Manasseh was translated by Rogers himself and incorporated into the Coverdale Bible.<br><br>This publication stands as a pivotal connection in the series of English Bible translations, seamlessly merging the works of Tyndale and Coverdale. The Matthew Bible is particularly notable because it represents a collaborative effort that brought together the translations of these two prominent figures, bridging the gap between Tyndale''s pioneering work and the subsequent translations that would follow. The Matthew Bible''s influence extends beyond its initial publication, as it served as a foundational text for later translations and significantly impacted the development of the English language and religious literature.', 'historic', NULL, '7', 'eng', '1537', 'scan', 'GreatSite.com', NULL, NULL, 'ENGMTB_DBS_HS', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('36', 'English-1871-Folsom-Four-Gospels-Gospels', 'ENGFOLS', 'English (1871) Folsom Four Gospels - Gospels', NULL, 'The 1871 edition of "The Four Gospels" is a distinguished translation that stands out for its scholarly rigor and attention to textual details. Translated from the Greek text of the eminent scholar Constantin von Tischendorf, it offers a critical analysis of the Gospels, enriched by the incorporation of various readings from other notable biblical scholars such as Griesbach, Lachmann, Tregelles, Meyer, and Alford. <br><br> Nathaniel S. Folsom, the translator, brings a meticulous approach to this work, ensuring that the nuances and complexities of the original Greek texts are faithfully rendered into English. His translation is not just a mere replication of the Greek text but an informed interpretation that takes into account the diversity of scholarly opinions and textual variations. Folsom''s critical and expository notes are a highlight of this edition, providing insightful commentary and analysis that deepen the understanding of the Gospels. <br><br> This edition is particularly notable for its comprehensive use of the Tischendorf text, which is revered for its accuracy and scholarly integrity. Folsom’s careful consideration of the various readings from renowned scholars makes this translation a valuable resource for those seeking a deeper, more nuanced understanding of the Gospels. The blend of rigorous scholarship with accessible translation makes this work a significant contribution to biblical literature and an essential tool for students, theologians, and scholars alike.', 'historic', NULL, '51', 'eng', '1871', 'study', 'A. Williams and Company', NULL, NULL, 'ENGFOLS_DBS_HS/English-(1871)-Folsom-Four-Gospels-Gospels', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('37', 'English-1841-Hexapla-Study-Bible-6-Full-Versions', 'ENGKJV', 'English (1841) Hexapla Study Bible - 6 Full Versions', NULL, 'English (1841) Hexapla Study Bible - 6 Full Versions: The 1841 edition of the Hexapla Study Bible, published by Samuel Bagster in London, is a significant compilation featuring the New Testament in both the original Greek text and six English translations. These English versions include those by Wycliffe, Tyndale, Cranmer, as well as translations from the Geneva Bible, the Douai Bible, and the King James Bible. Presented in parallel columns, this format allows for an easy comparison across the six translations and the Greek text. The Hexapla Study Bible provides a unique and comprehensive view of the progression and variation in Biblical translation into English. This notable work was reprinted in 1990 by Vintage Archives in Columbus, Ohio, offering accessibility to this important resource for historical and comparative studies of Biblical texts.', 'historic', NULL, '330', 'eng', '1841', 'study', 'Samuel Bagster and Sons, Paternoster Kon', NULL, NULL, 'ENGKJV_DBS_HS/English-(1841)-Hexapla-Study-Bible-6-Full-Versions', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('38', 'Hebrew-2005-Old-Testament-OT-Massoretic-Text', 'HEBOMT', 'Hebrew (2005) Old Testament - OT - Massoretic Text', 'עברית - התנ"ך (2005, נוסח המסורה)', 'The Masoretic Text (Hebrew: נֻסָּח הַמָּסוֹרָה, lit. ''Text of the Tradition'') is the authoritative Hebrew and Aramaic text of the 24 books of the Hebrew Bible (Tanakh) in Rabbinic Judaism. The Masoretic Text defines the Jewish canon and its precise letter text, with its vocalization and accentuation known as the mas''sora. Referring to the Masoretic Text, Mesorah specifically means the diacritic markings of the text of the Hebrew scriptures and the concise marginal notes in manuscripts (and later printings) of the Tanakh which note textual details, usually about the precise spelling of words. It was primarily copied, edited, and distributed by a group of Jews known as the Masoretes between the 7th and 10th centuries of the Common Era (CE). The oldest known complete copy, the Leningrad Codex, dates from the early 11th century CE.', 'modern', NULL, '14', 'heb', '2005', 'book', 'Bibles.org.uk', 'Bibles.org.uk', NULL, 'HEBOMT_DBS_HS/Hebrew-(2005)-Old-Testament-OT-Massoretic-Text', 'heb', 'hebr1245', 'Hebrew', 'Israeli Hebrew', 'L', 'IL', '31.10565', '35.01788', '1', 'he', '5000000', NULL, 'Also in Australia, Canada, Germany, Palestinian West Bank and Gaza, Panama, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('39', 'English-1635-Scottish-Metrical-Psalter-1864-Reprint', 'ENG1650', 'English (1635) Scottish Metrical Psalter (1864 Reprint)', NULL, 'The Scottish Metrical Psalter, often referred to as "The Scottish Psalter of 1650," holds a significant place in religious history, particularly within the Church of Scotland. The General Assembly of the Church of Scotland approved this text for use in 1650, and it has been in continuous use ever since. The Psalter, known for its enduring relevance, has remained largely unchanged from its original form, except for some modernization of the spelling.<br><br>The 1650 Psalter was primarily the work of Francis Rous, who completed his version around 1644. However, before its final approval for use in the Scottish church, the text underwent six years of rigorous scrutiny and revision. This process was undertaken by two different groups of highly learned and devout church leaders, ensuring that each word and phrase was faithfully aligned with the original Hebrew texts. This meticulous approach to translation and revision underscores the Psalter''s significance and the dedication to preserving the integrity of the scriptural texts.', 'historic', NULL, '37', 'eng', '1635', 'reprint', NULL, NULL, NULL, 'ENG1650_DBS_HS/English-(1635)-Scottish-Metrical-Psalter-(1864-Reprint)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('40', 'Greek-1872-Tischendorf-Novum-Testamentum-8th-Edition-book', 'GRCTISH', 'Greek (1872) Tischendorf Novum Testamentum (8th Edition) (Book)', 'Novum Testamentum του Tischendorf (1872, 8η Έκδοση)', 'The 1872 Tischendorf Novum Testamentum, in its 8th edition, is a significant publication in the field of biblical scholarship. This edition of the Greek New Testament was edited by the renowned German biblical scholar Constantin von Tischendorf. Tischendorf''s work on the Greek New Testament is widely recognized for its meticulous scholarship and for incorporating a vast array of textual variants and manuscript evidence.<br><br>Tischendorf is particularly noted for his efforts in discovering and analyzing ancient biblical manuscripts, most famously the Codex Sinaiticus, one of the oldest and most complete manuscripts of the Greek Bible. His work in textual criticism significantly advanced the understanding of the textual history of the New Testament.<br><br>The 8th edition of the Novum Testamentum represents the culmination of Tischendorf''s lifelong dedication to studying the Greek texts of the New Testament. It includes critical apparatus and notes that provide insights into the variations among different manuscripts, offering scholars and theologians a comprehensive resource for studying the New Testament in its original language.<br><br>This edition is considered one of the most important contributions to New Testament textual criticism in the 19th century and continues to be a valuable resource for biblical scholars and students. Tischendorf''s meticulous approach set a high standard for subsequent editions of the Greek New Testament.', 'modern', NULL, '1', 'grc', '1872', 'book', NULL, NULL, NULL, 'GRCTISH_DBS_HS/Greek-(1872)-Tischendorf-Novum-Testamentum-(8th-Edition)-(book)', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('41', 'English-1861-Pictorial-Bible-Vol.-1-Genesis-Joshua-Study', 'ENGPICT', 'English (1861) Pictorial Bible (Vol. 1) Genesis - Joshua (Study)', NULL, 'The 1861 edition of "The Pictorial Bible," edited by John Kitto, D.D., F.S.A., stands as a monumental work in the realm of biblical literature. This volume, part of a four-volume series, covers from Genesis to Joshua, providing a comprehensive visual and scholarly journey through these foundational books of the Old Testament. Kitto''s work is renowned for its integration of steel engravings and numerous woodcuts, which vividly depict landscape scenes, natural history, customs, and antiquities.<br><br>John Kitto, an eminent biblical scholar of his time, augmented the authorized version of the Bible with original notes that explain passages linked to the history, geography, natural history, literature, and antiquities of the Scriptures. These notes are particularly notable for their reliance on the discoveries of contemporary travelers and scholars, making this edition an invaluable resource for understanding the historical and cultural context of the biblical narrative.<br><br>Published in London by W. and R. Chambers, this new edition of "The Pictorial Bible" was aimed at bringing the biblical world to life for its readers. It was designed to be more than just a religious text; it was an educational tool that merged the sacred scriptures with the burgeoning fields of archaeology and oriental studies. The detailed illustrations and comprehensive notes provided a deeper, more textured understanding of the Bible, making it an essential addition to the libraries of scholars, clergy, and laypeople interested in a more profound comprehension of biblical times and teachings.', 'historic', NULL, '735', 'eng', '1861', 'study', 'W. and R.Chambers', NULL, NULL, 'ENGPICT_DBS_HS/English-(1861)-Pictorial-Bible-(Vol.-1)-Genesis-Joshua-(Study)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('42', 'Hebrew-1776-Bible-Vetus-Testamentum-Hebraicum-cum-variis-lectionibus', 'HBOMAS', 'Hebrew (1776) Bible - Vetus Testamentum Hebraicum - cum variis lectionibus', 'עברית - תנ"ך (1776, Vetus Testamentum Hebraicum, עם קריאות שונות)', 'The 1776 "Vetus Testamentum Hebraicum - cum variis lectionibus" is a notable edition of the Hebrew Bible. It presents the consonantal text of the Hebrew Scriptures following the Masoretic tradition, which is the authoritative Jewish text of the Hebrew Bible. This edition is distinguished by its presentation of the Pentateuch – the first five books of the Hebrew Bible, namely Genesis, Exodus, Leviticus, Numbers, and Deuteronomy. What makes this edition particularly significant is its parallel presentation of the Masoretic text of the Pentateuch alongside the Samaritan Pentateuch.<br><br>The inclusion of both the Masoretic and Samaritan versions of the Pentateuch allows for comparative study and highlights the differences between these two textual traditions. The Masoretic text, which forms the basis of most modern Jewish and Christian translations of the Old Testament, is contrasted with the Samaritan Pentateuch, an older version of the Torah preserved by the Samaritan community. This parallel format is invaluable for scholars and students interested in the textual history and variances within ancient Hebrew manuscripts, offering insights into the development and transmission of the biblical text over centuries.', 'historic', NULL, '113', 'hbo', '1776', 'study', NULL, NULL, NULL, 'HBOVTH_DBS_HS', 'hbo', 'anci1244', 'Ancient Hebrew', 'עִבְרִית מִקְרָאִית', 'H', 'IL', '31.77607', '35.17248', '9', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('43', 'English-1841-Hexapla', 'ENGKJV', 'English (1841) Hexapla', NULL, 'English (1841) Hexapla: The English Hexapla, published in 1841, is a remarkable work that presents six of the most significant English translations of the New Testament side by side. These translations are those of Wycliffe (1380), Tyndale (1534), Cranmer (1539), the Geneva Bible (1557), the Anglo-Rhemish (1582), and the Authorized King James Version (1611). Alongside these English translations, the original Greek text as edited by Scholz is included. The Hexapla also provides various readings from the Textus Receptus and key Constantinopolitan and Alexandrine manuscripts, as well as a thorough comparison of Scholz''s Greek text with Griesbach''s 1805 edition. The publication is notable for its comprehensive collation and its historical account of English translations of the Bible. It represents a significant scholarly resource for understanding the development of biblical translation into English and the textual variations across different translations.', 'historic', NULL, '170', 'eng', '1841', 'study', 'GreatSite.com', NULL, NULL, 'ENGHEX_DBS_HS', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('44', 'English-1853-The-Lincoln-Bible-KJV-WDL-11358', 'ENGKJV', 'English (1853) The Lincoln Bible - KJV (WDL-11358)', NULL, 'The Lincoln Bible is a Bible that was owned by William Thomas Carroll, a clerk of the U.S. Supreme Court. The bible was used by President Abraham Lincoln at his inauguration in 1861. It was also used by President Barack Obama at his inaugurations in 2009 and 2013. Finally, it was most recently used by President Donald Trump at his inauguration in 2017. The bible was returned to Caroll after Lincoln''s first inauguration. He later gave it to the Lincoln family sometime after Lincoln''s assassination. The family would later donate the Bible to the Library of Congress in 1928.', 'historic', 'https://www.wdl.org/en/item/11358', '1', 'eng', '1853', 'scan', 'World Digital Library', NULL, 'World Digital Library', 'ENGKJV_DBS_HS/English-(1853)-The-Lincoln-Bible-KJV-(WDL-11358)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('45', 'English-1891-Psalms-DeWitt-Translation-Bible-Psalms', 'ENGDEW', 'English (1891) Psalms (DeWitt) Translation Bible - Psalms', NULL, 'The 1891 edition of "Praise Songs of Israel: A New Rendering of the Book of Psalms" represents a significant contribution to biblical scholarship by John De Witt, a distinguished theologian and member of the Old Testament Revision Committee. Dr. De Witt, affiliated with the Theological Seminary in New Brunswick, New Jersey, brought a fresh perspective to the Psalms, one of the most poetic and spiritually resonant books of the Bible.<br><br>His translation of the Psalms was not just a mere linguistic exercise but a profound endeavor to capture the essence of these ancient songs in a way that resonated with the contemporary reader. De Witt''s deep understanding of Hebrew scripture and his commitment to theological accuracy are evident in this new rendering. His work was part of a larger movement in the late 19th century that sought to make biblical texts more accessible and meaningful to the public while maintaining scholarly integrity.<br><br>The Book of Psalms, often referred to as the "heart" of the Old Testament, consists of a collection of religious songs, prayers, and poems, traditionally attributed to King David. It holds a unique place in both Jewish and Christian liturgical traditions. De Witt''s translation of these Psalms aimed to bring out their lyrical beauty and emotional depth, thus providing a richer, more nuanced spiritual experience for readers and worshipers alike. His contribution to this field underscores the enduring relevance of these ancient texts in modern religious life and scholarship.', 'historic', NULL, '46', 'eng', '1891', 'scan', 'Anson D. F. Randolph and Co.', NULL, NULL, 'ENGDEW_DBS_HS/English-(1891)-Psalms-(DeWitt)-Translation-Bible-Psalms', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('46', 'Greek-Latin-1539-Erasmus-Greek-Latin-NT', 'GRCERAS', 'Greek - Latin (1539) Erasmus-Greek Latin New Testament', 'Ελληνική-Λατινική Καινή Διαθήκη του Έρασμου (1539)', 'The 1539 Erasmus-Greek Latin New Testament represents a pivotal contribution to biblical scholarship by Erasmus of Rotterdam, a leading figure of the Renaissance movement and a revered scholar in Europe. Erasmus, who sought to rejuvenate the Church through the "philosophy of Christ," dedicated his life to studying and publishing the Bible and early Church writings, with a particular focus on the Bible.<br><br>Erasmus''s work involved two major projects: collating Greek texts and creating a fresh Latin New Testament. Beginning in 1512, he embarked on refining the Latin New Testament by collating Vulgate manuscripts to craft a critical edition, aiming to improve the Latin used in biblical texts, famously stating, "It is only fair that Paul should address the Romans in somewhat better Latin."<br><br>While the purpose of publishing a fresh Latin translation was evident, the inclusion of the Greek text alongside it was less clear. Erasmus stated, "There remains the New Testament translated by me, with the Greek facing, and notes on it by me," indicating his intent to allow readers to verify the quality of his Latin version against the Greek. He included the Greek text to address issues of poor translation and textual corruption, highlighting discrepancies caused by translators'' errors or scribes'' alterations.<br><br>Initially named "Novum Instrumentum omne" ("All of the New Teaching") and later "Novum Testamentum omne" ("All of the New Testament"), Erasmus''s work underscores his belief in the importance of a text where the Greek and Latin versions were consistently comparable, forming the core of the church''s New Testament tradition. This work significantly contributed to the understanding and accessibility of biblical texts in the original languages and helped lay the foundation for future biblical scholarship and translations.', 'historic', NULL, '404', 'grc', '1539', 'study', NULL, NULL, NULL, 'GRCERAS_DBS_HS', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('47', 'English-1640-The-Bay-Psalm-Book-WDL-3600', 'ENGBAY', 'English (1640) The Bay Psalm Book (WDL-3600)', NULL, 'The Bay Psalm Book, recognized as the first book printed in British North America, holds a significant place in the history of American printing and literature. This historic book emerged from the Massachusetts Bay Colony, where, in 1638, Reverend Jesse Glover imported the first printing press, 18 years after the first English settlers landed at Plymouth Rock. Stephen Daye, a London printer, accompanied the press and set up a printing office in Cambridge.<br><br>In 1639, colony residents requested John Eliot, Thomas Welde, and Richard Mather to create a new translation from Hebrew of the Book of Psalms for use in the colony''s churches. Richard Mather, a principal author and translator, was assisted by about 30 other New England ministers in this task. The Bay Psalm Book was printed in 1640 and reissued in several editions, remaining in use for over a century.<br><br>One of the eleven known surviving copies of the first edition is housed in the Library of Congress. This particular copy is incomplete, missing 19 leaves, including the title page, but still has its original calf binding with traces of two clasps. This copy of the Bay Psalm Book, previously the last in private hands, was donated to the Library of Congress in May 1966 by Mrs. Adrian Van Sinderen of Washington, Connecticut. The Bay Psalm Book''s existence and endurance illustrate not only a significant moment in printing history but also the early settlers'' dedication to religious practice and literacy.', 'historic', 'https://www.wdl.org/en/item/3600', '57', 'eng', '1731', 'scan', 'Stephen Daye, Cambridge, Massachusetts', NULL, 'World Digital Library', 'ENGBAY_DBS_HS/English-(1640)-The-Bay-Psalm-Book-(WDL-3600)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('48', 'Hebrew-1524-The-Second-Rabbinic-Bible-Mikraot-Gedolot-Volume-4', 'HEBRABB', 'Hebrew (1524) The Second Rabbinic Bible (Mikraot Gedolot) (מקראות גדולות) Volume 4', 'עברית - המקראות הגדולות (1524, התנ"ך הרבני השני, כרך 4)', 'The fourth volume of the Mikraot Gedolot, also known as the Second Rabbinic Bible, continues the notable work of Jacob ben Haim (Yaakov ben Hayyim ibn Adonijah). Published by Daniel Bomberg in Venice between 1524 and 1525, this volume is a key part of a classic printing of the Hebrew Bible, focusing on the Hebrew Masoretic text. The Mikraot Gedolot of ben Hayyim holds a special place in biblical history, as it is believed to have been the source text (Textus Receptus) for the Hebrew Old Testament used in the King James Version of the Bible in 1611.<br><br>Jacob ben Haim was a Jewish Masoretic scholar who later converted to Christianity. His production and editing of the Mikraot Gedolot represent a monumental achievement in the realm of typesetting, especially considering the nascent technology of the printing press at the time. The process involved the meticulous assembly of Hebrew letters, vowels, and accents.<br><br>Ben Hayyim''s commitment to using the best available Hebrew manuscripts has been a subject of debate, with some arguing about his access to quality manuscripts. However, the esteemed Masoretic scholar Ginsburg regarded the Mikraot Gedolot as a good representation of the Ben Asher text. Ginsburg''s own highly-regarded editions of the Hebrew Bible, printed by the British and Foreign Bible Society, were based on ben Hayyim''s Second Rabbinic Bible, highlighting its significance and influence in the study of the Hebrew scriptures.', 'historic', NULL, '380', 'heb', '1524', 'scan', NULL, NULL, NULL, 'HEBRABB_DBS_HS/Hebrew-(1524)-The-Second-Rabbinic-Bible-(Mikraot-Gedolot)-Volume-4', 'heb', 'hebr1245', 'Hebrew', 'Israeli Hebrew', 'L', 'IL', '31.10565', '35.01788', '1', 'he', '5000000', NULL, 'Also in Australia, Canada, Germany, Palestinian West Bank and Gaza, Panama, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('49', 'Hebrew-0300-BC-Isaiah-Dead-Sea-Scrolls', 'HBODSS', 'Hebrew (0300 bc) Isaiah (Dead Sea Scrolls)', 'עברית - ישעיהו (0300 לפנה"ס, מגילות ים המלח)', 'The Isaiah Scroll, designated 1QIsa and also known as the Great Isaiah Scroll, is a pivotal archaeological and religious discovery among the Dead Sea Scrolls. First uncovered by Bedouin shepherds in 1946 in Qumran Cave 1, this scroll is remarkable for containing the entire Book of Isaiah in Hebrew, with only a few small portions damaged. Its significance lies in its age; it is approximately 1000 years older than any previously known Hebrew manuscripts of the Book of Isaiah, dating back to around 300 BC.<br><br>1QIsa holds the distinction of being the only scroll from the Qumran Caves to be almost entirely preserved. The manuscript is written on 17 sheets of parchment, making it notably large. It measures about 734 cm (24 feet) in length and varies from 25.3 to 27 cm (10 to 10.6 inches) in height, with the text spanning across 54 columns. The preservation of the Isaiah Scroll provides invaluable insights into the textual history of the Hebrew Bible and serves as a crucial resource for scholars studying the evolution of biblical texts and the religious practices of the period.', 'historic', NULL, '26', 'hbo', '70', 'manuscript', NULL, NULL, NULL, 'HBODSS_DBS_HS/Hebrew-(0300-BC)-Isaiah-(Dead-Sea-Scrolls).zip', 'hbo', 'anci1244', 'Ancient Hebrew', 'עִבְרִית מִקְרָאִית', 'H', 'IL', '31.77607', '35.17248', '9', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('50', 'English-1807-Christians-Complete-Family-Bible-Study', 'ENGKJV', 'English (1807) Christians Complete Family Bible (Study)', NULL, 'The "Christian''s Complete Family Bible, or Universal Library of Divine Knowledge," printed in Liverpool by Nuttall, Fisher, & Dixon in 1807, is a comprehensive and extensively annotated edition of the Bible. This work stands out for its integration of the sacred texts of the Old and New Testaments, along with the Apocrypha, and is distinguished by its extensive range of notes and annotations.<br><br>The title page elaborates on the content, indicating that this Bible contains not just the complete texts of the Scriptures but also a wealth of supplementary material. This includes practical notes and observations from eminent divines, a general index, a chronological index of biblical events from Adam to Jesus, explanations of proper names found in the Scriptures, a geographical index of places mentioned in the Bible, a brief account of the Apostles and their successors, as well as tables for Jewish timekeeping, and biblical weights, measures, and money.<br><br>The description further emphasizes the depth and breadth of the annotations and supplementary materials. The notes and annotations cover historical, chronological, biographical, geographical, theological, moral, systematical, practical, admonitory, divine, and explanatory aspects. This comprehensive approach aims to clarify difficult passages, reconcile contradictions, rectify mistranslations, confirm important truths, and provide enlightenment and guidance for readers. The goal is to impart divine knowledge essential for salvation and to offer a complete treasury of divine revelation.<br><br>This Bible is also noted for its visual features, including fifty-five superb embellishments designed and executed by prominent artists, specifically for this work. These engravings depict various transactions recorded in the Scriptures, enhancing the reader''s engagement with the text. The "Christian''s Complete Family Bible" is a remarkable example of early 19th-century religious publishing, offering a rich and multifaceted approach to biblical study and devotion, intended to guide readers toward a deeper understanding of Christian divinity and eternal bliss.', 'historic', NULL, '259', 'eng', '1807', 'study', 'Nuttall, Fisher, & Dixon', NULL, NULL, 'ENGKJV_DBS_HS/English-(1807)-Christians-Complete-Family-Bible-(Study)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('51', 'Aramaic-Peshitta-Bible-New-Testament', 'AIIWBT', 'Aramaic Peshitta Bible - New Testament (Romanized)', 'ܐܪܡܝܐ ܦܫܝܛܬܐ ܟܬܒܐ - ܚܕܬܐ ܕܝܬܩܐ (ܪܘܡܐܝܙܕ)', 'In the Syriac (Eastern Aramaic) language the Peshitta (Syriac: "common version") is the standard version of the Christian Bible. It continues to serve as the Bible of churches in the Syriac tradition (Church of the East, Chaldean Catholic, and Syriac Orthodox) to this day. The history of Christian Translations of the Bible into Syriac language includes the Diatessaron, the Old Syriac versions (Curetonian and Sinaitic), the Peshitto, the Philoxenian version, the Harklean Version and the recent United Bible Societies'' modern Aramaic New Testament.<br><br>About AD 500 a Christian Palestinian Aramaic version was made. It contains 2 Peter, 2-3 John, Jude, and Apocalypse. It is representative of the Caesarean text type and is a unique translation different from any other which was made into Syriac. These are among the manuscripts used by John Gwynn in 1893 to complete his edition of the Catholic Epistles. In 1892 Agnes Smith Lewis discovered the manuscript of the Palestinian Syriac lectionary in the library of Saint Catherine''s Monastery on Mount Sinai. It is designated by Syr.<br><br>The first revision of the New Testament from the Syriac into Turoyo language (Western Aramaic in Syriac and Latin script) was made by Malphono Yuhanun Üzel (Bar Shabo), Benjamin Bar Shabo, and Yahkup Bilgic in 2009 with notes from Harclean and Philoxenios. This commission "Sihto du Kthovo Qadisho Suryoyo" works especially to preach the Gospel in Aramaic all over the world.', 'historic', NULL, '1', 'aii', '1885', 'scan', NULL, NULL, NULL, 'peshitta_nt_roman', 'aii', 'assy1241', 'Assyrian Neo-Aramaic', 'Sūreṯ', 'L', 'IQ', '36.75', '43', '6b', NULL, '626000', 'Iraq', 'Northern Iraq, Baghdad, Basrah, Karkuk, Arbil. Also in Armenia, Australia, Austria, Azerbaijan, Belgium, Brazil, Canada, Cyprus, France, Georgia, Germany, Greece, Iran, Italy, Lebanon, Netherlands, New Zealand, Russian Federation (Europe), Sweden, Switzerland, Syria, Turkey (Asia), United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('52', 'English-1883-Newberry-Study-Bible', 'ENGKJV', 'English (1883) Newberry Study Bible', NULL, 'The 1883 Newberry Study Bible, created by Thomas Newberry (1811 – 16 January 1901), is a seminal work in the field of Biblical scholarship. Newberry, an esteemed English Bible scholar and writer, is renowned for his groundbreaking "interlinear Englishman''s Bible." This innovative work juxtaposes the authoritative and time-honored Authorised Version of the Bible with the original Hebrew and Koine Greek texts, offering a profound comparative study that was a significant achievement for its time.<br><br>Published by Hodder and Stoughton in London, the Newberry Study Bible reflects Newberry''s dedication to providing a deeper understanding of the scriptures. His work stands out for its meticulous attention to the nuances of the original languages, illuminating the richness and complexity of the Biblical texts. This interlinear approach allows readers to appreciate the translation process and the interpretive choices made in the Authorised Version, fostering a more nuanced understanding of the Biblical narrative.<br><br>Newberry''s contribution to Biblical studies is not just academic; it offers a valuable tool for theologians, scholars, and lay readers alike, who seek to delve into the depths of Biblical language and meaning. His work remains a testament to the enduring quest for a comprehensive and accurate interpretation of the sacred scriptures, bridging the gap between ancient texts and modern readers. The Newberry Study Bible is a classic example of scholarly rigor and dedication to the faithful transmission of Biblical knowledge.', 'historic', NULL, '391', 'eng', '1883', 'study', 'Hodder and Stoughton', NULL, NULL, 'ENGKJV_DBS_HS/English-(1883)-Newberry-Study-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('53', 'English-1772-KJV-1769-Revision', 'ENGKJV69', 'English (1772) KJV (1769 Revision)', NULL, 'By the mid-18th century, variations in modernized texts of the Authorized Version (AV) of the King James Bible, along with an accumulation of misprints, led Oxford and Cambridge Universities to seek an updated standard text. The Cambridge edition of 1760, the result of Francis Sawyer Parris''s 20 years of work, was the first. Parris died in May of that year, but his edition was reprinted in 1762 and in John Baskerville''s 1763 folio edition.<br><br>However, the 1769 Oxford edition, edited by Benjamin Blayney, became the standard text, even though it had comparatively few changes from Parris''s edition. Both Parris and Blayney aimed to correct printer-induced variations from the 1611 and subsequent editions, incorporating most revised readings from the Cambridge editions of 1629 and 1638, along with their own improvements. They standardized punctuation and spelling, making many minor text changes. Blayney''s 1769 text differed from the 1611 text in around 24,000 places.<br><br>Blayney worked from the 1550 Stephanus edition of the Textus Receptus, differing from the later editions of Theodore Beza favored by the 1611 New Testament translators. The 1769 Oxford edition, like the 1611 edition, included the Apocrypha, but Blayney tended to remove cross-references to Apocrypha books.<br><br>While Cambridge continued to issue Bibles using the Parris text for a time, they eventually adapted Blayney''s work, omitting some Oxford spellings. By the mid-19th century, most printings of the AV derived from the 1769 Oxford text. Exceptions include Oxford''s 1833 original-spelling reprint of the 1611 edition and the 1873 Cambridge Paragraph Bible, revised by F. H. A. Scrivener.<br><br>In 2005, Cambridge University Press released the New Cambridge Paragraph Bible with Apocrypha, edited by David Norton, following Scrivener''s work but updating spelling and reintroducing some original wording.<br><br>The AV remained largely unchanged through the early 19th century. The 1870 Convocation of Canterbury''s revision, the Revised Version, didn''t find popular favor. By the early 20th century, the Cambridge text had undergone at least 6 changes since 1769 and was preferred by scholars.<br><br>The AV''s dominance lasted until the second half of the 20th century, when new translations emerged. Nonetheless, the King James Only movement continues to support the AV.', 'historic', 'https://en.wikipedia.org/wiki/King_James_Version#Standard_text_of_1769', '180', 'eng', '1772', 'scan', NULL, NULL, NULL, 'ENGKJV69_DBS_HS/English-(1772)-KJV-(1769-Revision)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('54', 'English-1851-Murdoch-New-Testament-Syriac-Peshito', 'ENGMUR', 'English (1851) Murdoch New Testament (Syriac Peshito)', NULL, 'English (1851) Murdoch New Testament (Syriac Peshito): James Murdock''s translation of the New Testament, titled "The New Testament; or, The book of the holy Gospel of our Lord and our God, Jesus the Messiah," is a remarkable work that presents a literal translation from the Syriac Peshitto version. This version, originating from the 5th century, holds significant importance as it is derived from an Aramaic dialect closely related to that spoken by Jesus and his Apostles. Murdock, a respected scholar with a Doctorate in Sacred Theology (S.T.D.), took the unique approach of using Aramaic as his primary source text instead of the more commonly used Koine Greek.<br><br>This approach is particularly valuable for biblical scholars and enthusiasts as it offers a glimpse into the linguistic environment of the time of Jesus. Murdock''s translation highlights the subtleties, idioms, and cultural nuances inherent in the original language, many of which can be lost or misinterpreted when translated from Greek. His work provides a deeper and arguably more authentic insight into the New Testament, making it a vital resource for understanding the context and meaning behind the teachings and events described in the Christian scriptures.', 'historic', NULL, '63', 'eng', '1851', 'scan', 'Stanford and Swords', NULL, NULL, 'ENGMUR_DBS_HS/English-(1851)-Murdoch-New-Testament-(Syriac-Peshito)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('55', 'English-1890-Darby-Bible-text', 'ENGDBY', 'English (1890) Darby Bible (text)', NULL, 'John Nelson Darby, often referred to by his initials JND, was a pivotal figure in the history of Christian theology and Bible translation. Born in 1800 in London, Darby exhibited remarkable academic prowess, earning the University Medal in Classics from Trinity College, Dublin, in 1818. His journey into the ecclesiastical realm began with his ordination as a deacon of the Anglican Church of Ireland in 1825, and he became a priest the following year. However, Darby''s religious path took a significant turn as he later emerged as a leading figure in the Plymouth Brethren movement.<br><br>Darby''s ministry in the 1830s and 1840s spanned various European countries including England, Ireland, France, Germany, and Switzerland. His linguistic skills were notable, with proficiency in Hebrew, Greek, Latin, French, and German. Darby passed away in Bournemouth in 1882.<br><br>His translation of the New Testament from Greek, "The Holy Scriptures: A New Translation from the Original Languages by J. N. Darby," first published in 1867 and revised in 1871, is particularly renowned for its precision and attention to the nuances of the original texts. This translation also featured detailed footnotes exploring textual variants. Posthumously, the final edition was released in 1884. Darby''s linguistic expertise extended beyond English; he also translated the Bible into French and German with the assistance of his colleagues.<br><br>The complete Darby Bible, noted for its literal and faithful adherence to the original Hebrew and Greek languages, was first published in English in 1890. In this translation, the name Jehovah is used for the Hebrew YHWH, and distinct Hebrew terms for God, such as Elohim, Eloah, and El, are translated with specific English equivalents. Darby''s translation remains a significant contribution to biblical scholarship, reflecting his commitment to capturing the essence of the original scriptures.', 'modern', NULL, '2', 'eng', '1890', 'book', NULL, NULL, NULL, 'ENGDBY_DBS_HS/English-(1890)-Darby-Bible-(text)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('56', 'English-1900-KJV-Pure-Cambridge-Edition-book', 'ENGKJVPCE', 'English (1900) KJV - Pure Cambridge Edition (Book)', NULL, 'The Pure Cambridge Edition of the Bible, emerging around 1900, signifies a remarkable phase in the evolution of the King James Version (KJV). This edition, a collaboration between Cambridge University Press and Collins publishers, became renowned as the Standard Text. Its inception marked a continuation of the textual refinement process initiated with the completion of the Authorized Version in 1611. This version was widely accepted and utilized, with millions of copies disseminated by various Bible and missionary societies throughout the twentieth century.<br><br>One of the distinguishing features of the Pure Cambridge Edition is its adherence to the original styling, including the use of standard Cambridge spelling. The editors of this edition took meticulous care to ensure accuracy in every aspect, from italics to punctuation, striving for a rendition that remained true to the original text''s nuances and intentions. This dedication to precision and faithfulness rendered the Pure Cambridge Edition a reliable and authentic version of the Bible, maintaining the sanctity and integrity of the scriptures.<br><br>This edition stands in stark contrast to other versions that emerged during the same period, particularly those that underwent modernization or editorial reinterpretation. Its commitment to preserving the original textual elements made it a preferred choice for scholars and lay readers alike, seeking an unaltered and authentic biblical experience. The Pure Cambridge Edition thus represents a significant chapter in the history of the Bible, embodying a blend of historical fidelity and scholarly rigor.', 'modern', NULL, '5', 'eng', '1900', 'book', NULL, NULL, NULL, 'ENGKJVPCE_DBS_HS/English-(1900)-KJV-Pure-Cambridge-Edition-(book)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('57', 'Syriac-1905-New-Testament', 'SYROLD', 'Syriac (1905) New Testament', 'ܣܘܪܝܝܐ (1905) ܐܘܢܓܠܝܘܢ', 'Syriac (1905) New Testament The Syriac language, also known as Syriac Aramaic (Syrian Aramaic, Syro-Aramaic) and Classical Syriac ܠܫܢܐ ܥܬܝܩܐ (in its literary and liturgical form), is an Aramaic dialect that emerged during the first century AD from a local Aramaic dialect spoken by Arameans in the ancient Aramean kingdom of Osroene, centered in Edessa. It became the main literary language of various Aramaic-speaking Christian communities in Ancient Syria and the Near East during the Early Christian period. As a liturgical language of Syriac Christianity, it played a significant role among Eastern Christian communities using Eastern and Western Syriac rites and spread as far as India and China. Flourishing from the 4th to the 8th century, it remained important in subsequent centuries but was gradually reduced to liturgical use by the end of the Middle Ages due to the rise of Neo-Aramaic dialects.<br><br>Script variations include Estrangelo (E), Jacobite (J), Hebrew (H), and Nestorian (N). The 1555 New Testament (J) in Vienna was edited from Ms. Peshitta texts by Johann A. Widmanstadt. The 1569 New Testament (H) in Geneva, edited by Immanuel Tremcllius, was published alongside Greek and Latin texts. Syriac versions also appeared in the 1575 Antwerp, H99 Nürnberg, Paris, and London Polyglots. The 1625 Psalms (J) in Paris, edited by Gabriel Sionita, coincided with a Syriac Psalter in Leiden. The first publications of omitted Syriac canon books like 2 Peter, 2-3 John, Jude (J & H) were edited by E. Pococke in Leiden in 1630. The first complete Syriac printed Bible appeared in the 1629-1645 Paris Polyglot (J), edited by G. Sionita.<br><br>Early critical editions include the 1708 New Testament (J) in Leiden by J. Leusden and C. Schaaf. The 1778 Gospels (J) and 1799-1803 Acts Epistles (J) in Oxford were edited by Joseph White. The 1823 Old Testament (J) in London for the BFBS was edited by S. Lee, based on the London Polyglot. The 1820 Psalms (J) in Milan was the Syro-Hcxaplar text, edited by C. Bugatus. The 1858 Gospels (E) in London, edited by William Cureton, was the Curetonian Old Syriac text. The 1861-1874 Old Testament (J) in Milan, the Syro-Hexaplar Ambrosianus, was edited by A. M. Ceriani. The 1901 Gospels (J) in Oxford was a critical edition of the Peshitta text by G. H. Gwilliam. The 1904 Psalms (E) in Cambridge was a critical edition of the Peshitta Psalter by W. E. Barnes. The 1905-1920 New Testament (J) in London for the BFBS was the Peshitta text edited by G. H. Gwilliam and J. Gwynn. Notable publications also include the 1899 Gospels (E) in London, re-edited by Agnes Smith Lewis and Margaret Dunlop Gibson, and the 1861-1864 Gospels in Verona, the Vatican Gospel lectionary edited by Francesca Miniscalchi-Erizzo.', 'historic', NULL, '508', 'syr', '1905', 'scan', 'The British and Foreign Bible Society', 'british-and-foreign-bible-society', NULL, 'SYROLD_DBS_HS/Syriac-(1905)-New-Testament', 'syr', 'syr', 'Syriac', NULL, 'L', 'IQ', NULL, NULL, NULL, NULL, '858080', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('58', 'English-1841-New-Literal-Translation-of-Epistles-Macknight-Epistles', 'ENGMAC', 'English (1841) New Literal Translation of Epistles (Macknight) Epistles', NULL, 'English (1841) New Literal Translation of Epistles (Macknight): James Macknight, a notable minister in the Church of Scotland during the eighteenth century, is renowned for his comprehensive commentary on the apostolic epistles. Initially published in 1795, Macknight''s work represents the culmination of 30 years of extensive study and scholarship. This significant commentary offers in-depth analysis and interpretation of the New Testament epistles, ranging from Romans to Jude. T. F. Dibdin, a respected English biographer and churchman, praised Macknight’s commentary for its blend of scholarly insight and accessibility, highlighting its importance as an indispensable resource for theological studies. Dibdin remarked that "no theological collection can be perfect without them," emphasizing the commentary''s value and influence in religious and academic circles.', 'historic', NULL, '46', 'eng', '1841', 'scan', 'G. Lane & C. B. Tippett', NULL, NULL, 'ENGMAC_DBS_HS/English-(1841)-New-Literal-Translation-of-Epistles-(Macknight)-Epistles', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('59', 'English-1773-New-Literal-Old-Testament-Translation-Bate-OT-Portions', 'ENGLIT', 'English (1773) New Literal Old Testament Translation (Bate) OT Portions', NULL, 'The 1773 publication "A New and Literal Translation, from the Original Hebrew of the Pentateuch of Moses, and of the Historical Books of the Old Testament to the end of the Second Book of Kings," by Julius Bate, represents a unique attempt in the field of Bible translations. Published in London by W. Faden, this work focuses on a highly literal translation of significant portions of the Old Testament.<br><br>Bate''s translation, covering the Pentateuch and the historical books up to the Second Book of Kings, is noted for its strict adherence to the literal sense of the Hebrew text. However, this approach led to a translation that the Monthly Review OS, Vol. 1 described as "so very literal as to be really unintelligible to a plain English reader." This critique highlights the challenge of producing a translation that is both faithful to the original language and comprehensible to contemporary readers.<br><br>Julius Bate''s work, while a noteworthy effort in translating the Hebrew Scriptures, exemplifies the difficulties translators face in balancing literal accuracy with readability. His translation remains an interesting contribution to the history of English Bible translations, particularly in its pursuit of a literal interpretation of the Hebrew text.', 'historic', 'https://en.wikipedia.org/wiki/Julius_Bate', '14', 'eng', '1773', 'scan', NULL, NULL, NULL, 'ENGLIT_DBS_HS/English-(1773)-New-Literal-Old-Testament-Translation-(Bate)-OT-Portions', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('60', 'Greek-1885-Westcot-and-Hort-New-Testament', 'GRCWHT', 'Greek (1885) Westcot and Hort New Testament', 'Καινή Διαθήκη του Westcott και Hort (1885)', 'The 1885 Westcott and Hort New Testament text is known for its strong alignment with the Alexandrian text-type, particularly the Codex Vaticanus (B). This approach by Hort, who was the chief architect of the textual theory of the edition, has led to some criticism, with accusations that he constructed his text merely by favoring readings from Codex Vaticanus. However, the editorial process was more nuanced than this criticism suggests. While the edition did use Codex Vaticanus as a proof text, Hort was willing to consider other witnesses if the internal evidence was robust enough.<br><br>One of the most notable instances of this methodology is the handling of the Western Non-Interpolations, indicating a willingness to diverge from Codex Vaticanus when warranted. Nonetheless, it is accurate to say that Hort''s text is more closely aligned with Codex Vaticanus than any other critical edition.<br><br>The Westcott and Hort edition is unique in its approach to textual criticism, resembling methods used in non-Biblical criticism where editing is based on a proof text. This edition does not have a traditional critical apparatus; no manuscripts are cited in the main text. Variant readings are provided in the margins, which include instances where the editors either disagreed with the text or were uncertain of the original readings. They also compiled a list of "interesting" variants but did not provide a comprehensive list of witnesses for these variants. The only textual evidence offered is in the introduction and appendix, but this evidence is difficult to utilize as manuscripts are cited using Tischendorf numbers.<br><br>This approach to the New Testament text by Westcott and Hort marks a significant contribution to biblical scholarship, particularly in the realm of textual criticism, even as it presents challenges due to its unique methodology and presentation of textual evidence.', 'historic', NULL, '13', 'grc', '1885', 'scan', 'MacMillian and Co.-The University Press', NULL, NULL, 'GRCWHT_DBS_HS/Greek-(1885)-Westcot-and-Hort-New-Testament', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('61', 'English-1872-Pronouncing-Study-Bible-Family', 'ENGKJV', 'English (1872) Pronouncing Study Bible (Family)', NULL, 'The 1872 edition of the "Comprehensive Pronouncing Bible Dictionary," compiled by A.J. Holman and Co., Philadelphia, represents a significant contribution to the field of biblical studies and lexicography. This work, legally recognized under the Act of Congress in the same year, stands as a testament to the enduring commitment to making biblical texts more accessible and comprehensible to a wider audience. <br><br> Drawing from the latest editions of renowned biblical scholars like Smith, Kitto, and Fairbairn, this dictionary distinguishes itself with its emphasis on pronunciation, catering to the needs of readers and educators alike. The inclusion of nearly 500 fine engravings further enhances its appeal, offering visual aids to better understand the biblical world and its complex narratives. <br><br> This dictionary not only serves as a practical tool for understanding the Bible but also acts as a bridge connecting the historical and cultural context of the scriptures to the modern reader. Its comprehensive nature covers a wide range of topics, from characters and places in the Bible to significant theological concepts, making it a valuable asset for family study, scholarly research, and religious education. <br><br> The "Pronouncing Bible Dictionary" of 1872 thus represents the culmination of a rigorous and thoughtful process of compilation and editing, aimed at delivering a richer, more nuanced understanding of the Bible''s contents and its relevance in contemporary times.', 'historic', NULL, '1', 'eng', '1872', 'study', 'A. J. Holman Co.', NULL, 'Internet Archive', 'ENGKJV_DBS_HS/English-(1872)-Pronouncing-Study-Bible-(Family)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('62', 'English-1874-Polyglot-Gospels-Bible-4-Versions-Gospels', 'ENGKJV', 'English (1874) Polyglot Gospels Bible - 4 Versions Gospels', NULL, 'The 1874 edition of "The Gospels: Gothic, Anglo-Saxon, Wycliffe, and Tyndale versions arranged in parallel columns" represents a remarkable scholarly endeavor in biblical literature, offering a unique comparative study of four significant translations of the Gospels. This work was meticulously arranged and annotated by Rev. Joseph Bosworth, D.D.F.R.S.F.S.A., Professor of Anglo-Saxon at Oxford University, with the assistance of George Waring, Esq. M.A., of Trinity College, Cambridge, and Magdalen Hall, Oxford. <br><br> First published in 1865, this edition is particularly notable for its second release in 1874. The text juxtaposes the Gothic version, an early Germanic language translation, with the Anglo-Saxon version, providing insights into the linguistic evolution of English. Additionally, it features the translations of John Wycliffe and William Tyndale, two pivotal figures in the history of the English Bible. Wycliffe''s version, known as the first complete English translation of the Bible, and Tyndale''s, which significantly influenced the King James Version, are presented in parallel columns for comparative analysis. <br><br> This edition serves not only as a religious document but also as a linguistic and historical artifact, tracing the development of Bible translation in the context of English language history. The scholarly work of Bosworth and Waring offers readers an opportunity to explore the nuances and variations across these translations, highlighting the evolution of biblical interpretation and language over centuries. Subsequent editions in 1888 and 1907 further emphasize the enduring relevance and scholarly interest in this comparative study of the Gospels.', 'historic', NULL, '95', 'eng', '1874', 'study', 'John Russell Smith', NULL, NULL, 'ENGKJV_DBS_HS/English-(1874)-Polyglot-Gospels-Bible-4-Versions-Gospels', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('63', 'French-1896-New-Testament', 'FRALSB', 'French (1896) New Testament)', 'Nouveau Testament (1896)', 'French (1896) New Testament) Louis Segond (October 3, 1810 – June 18, 1885), was a Swiss theologian who translated the Bible into French from the original texts in Hebrew and Greek.<br><br>He was born in Plainpalais, near Geneva. After studying theology in Geneva, Strasbourg, and Bonn, he was pastor of the Geneva National Church in Chêne-Bougeries, then from 1872, Professor of Old Testament in Geneva.<br><br>The translation of the Old Testament, commissioned by the Vénérable Compagnie des Pasteurs de Genève, was published in two volumes in 1871 (Meusel has 1874 as the publication date), followed by the New Testament, translated as a private venture, in 1880. The text was then reviewed by experts. The result is the 1910 revision that is now freely available on the Internet.', 'historic', NULL, '19', 'fra', '1896', 'scan', NULL, NULL, NULL, 'FRALSB_DBS_HS/French-(1896)-New-Testament)', 'fra', 'stan1290', 'French', 'français', 'L', 'FR', '48', '2', '1', 'fr', '77200000', 'Andorra and France', 'Also in Algeria, Andorra, Austria, Belgium, Benin, Burkina Faso, Burundi, Cambodia, Cameroon, Canada, Central African Republic, Chad, Comoros, Congo, Côte d’Ivoire, Democratic Republic of the Congo, Djibouti, Equatorial Guinea, French Guiana, French Polynesia, Gabon, Guadeloupe, Guinea, Haiti, India, Israel, Italy, Lebanon, Libya, Luxembourg, Madagascar, Mali, Martinique, Mauritania, Mauritius, Mayotte, Monaco, Morocco, Mozambique, New Caledonia, Niger, Philippines, Puerto Rico, Réunion, Rwanda, Saint Pierre and Miquelon, Saudi Arabia, Senegal, Seychelles, South Africa, Switzerland, Togo, Tunisia, United Arab Emirates, United Kingdom, United States, U.S. Virgin Islands, Vanuatu, Wallis and Futuna.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('64', 'English-1860-Bagsters-Polyglott-Study-Bible', 'ENGKJV', 'English (1860) Bagsters Polyglott Study Bible', NULL, 'Samuel Bagster''s "The Holy Bible, Containing The Old And New Testaments, Translated Out Of The Original Tongues; And With The Former Translations Diligently Compared And Revised" is a seminal work in the realm of biblical studies and translations. Born on December 26, 1772, Bagster, after his education under Rev. John Ryland and a foundational apprenticeship with William Otridge, embarked on a distinguished career as a bookseller and publisher, starting his own business in the Strand in 1794. <br><br>Bagster''s magnum opus, the "English version of the polyglot bible," released in 1816, stands out for its meticulous compilation of over 60,000 parallel references, each carefully selected and verified by Bagster himself. The publication, in foolscap octavo size, was a pioneering effort, notable for its selection and presentation of references, and for its innovative binding styles including Turkey Morocco leather and prepared sealskins with a unique ''pin-head grain''.<br><br>Among Bagster''s numerous subsequent publications, the quarto edition of 1841, "The English Hexapla," is particularly remarkable. It presents six pivotal English versions of the New Testament (Wyclif, Tyndale, Cranmer, Genevan, Anglo-Rhemish, and the authorized King James Version of 1611) alongside the Greek text after Scholz. This edition also includes a comprehensive historical account of English translations of the Bible. Another significant work by Bagster is the "Bible of every land," a 4to volume offering specimens of the Bible in over 270 different languages and versions, underlining Bagster''s commitment to making biblical texts accessible and comprehensible to a wide and diverse audience.', 'historic', NULL, '299', 'eng', '1860', 'study', 'Samuel Bagster and Sons', NULL, NULL, 'ENGKJV_DBS_HS/English-(1860)-Bagsters-Polyglott-Study-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('65', 'Latin-1904-Jefferson-Gospels-Latin-French-Grk-Eng-Gospels', 'LATCLV', 'Latin (1904) Jefferson Gospels (Latin French Grk Eng) - Gospels', 'Evangelia Jeffersoniana (1904, Latin-French-Greek-English)', 'Latin (1904) Jefferson Gospels (Latin French Grk Eng) - Gospels<br><br>The Life and Morals of Jesus of Nazareth, commonly known as the Jefferson Bible, is a unique religious work created by Thomas Jefferson. Though Jefferson compiled the manuscripts, they were never published during his lifetime. The first, The Philosophy of Jesus of Nazareth, completed in 1804, has no surviving copies. The second, The Life and Morals of Jesus of Nazareth, was finished in 1820 through a process of cutting and pasting sections from the New Testament to extract Jesus''s doctrine. Jefferson''s version notably omits all miracles attributed to Jesus and most supernatural elements, including the Resurrection and portrayals of Jesus as divine.<br><br>In 1895, the Smithsonian Institution, led by librarian Cyrus Adler, acquired the original Jefferson Bible from Jefferson''s great-granddaughter, Carolina Randolph, for $400. A conservation project in 2009, spearheaded by Senior Paper Conservator Janice Stagnitto Ellis, culminated in a public exhibit at the National Museum of American History from November 11, 2011, to May 28, 2012. The exhibit displayed Jefferson''s source books, the 1904 edition of the Jefferson Bible commissioned by the U.S. Congress, and featured an interactive digital facsimile on the museum''s website. The Smithsonian Channel also released the documentary "Jefferson''s Secret Bible" on February 20, 2012.', 'historic', NULL, '123', 'lat', '1904', 'study', 'Thomas Jefferson-Government Printing Office', NULL, NULL, 'LATHEX_DBS_HS/Latin-(1904)-Jefferson-Gospels-(Latin-French-Grk-Eng)-Gospels', 'lat', 'lati1261', 'Latin', 'lingua latīna', 'A', 'VA', '41.90264', '12.45021', '3', 'la', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('66', 'Greek-1860-Novum-Testamentum-Alexandrinus-Codex', 'GRCALEX', 'Greek (1860) Novum Testamentum (Alexandrinus Codex)', 'Novum Testamentum (1860, Κώδικας Αλεξανδρινός)', 'The Codex Alexandrinus, a significant manuscript of the Greek Bible dating back to the 5th century, is an eminent source in biblical scholarship. This manuscript, written on parchment, was critically examined and edited by B.H. Cowper in 1860, following the earlier description by C.G. Woide. Utilizing paleography, a study of comparative writing styles, scholars have ascertained its creation in the fifth century.<br><br>It encompasses most of the Greek Old Testament and the complete Greek New Testament, making it a crucial witness to the biblical text''s early form. The Codex Alexandrinus is classified among the four Great uncial codices, a term referring to manuscripts containing the entirety of both the Old and New Testaments in uncial, or large, script. This codex, along with Codex Sinaiticus and Vaticanus, is among the earliest and most comprehensive manuscripts of the Bible, providing invaluable insight into the text''s history and transmission. Its significance lies not only in its age but also in its contribution to our understanding of the biblical text in its early forms.', 'historic', NULL, '19', 'grc', '1860', 'scan', 'Edinburgae, Williams & Norgate', NULL, NULL, 'GRCALEX_DBS_HS/Greek-(1860)-Novum-Testamentum-(Alexandrinus-Codex)', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('67', 'English-1911-Hexaplar-Psalter-Bible-Psalms', 'ENGHPB', 'English (1911) Hexaplar Psalter Bible - Psalms', NULL, 'The "Hexaplar Psalter Bible," a comprehensive compilation of six English translations of the Psalms, was first published in 1911. This remarkable work showcases the evolution of biblical translation through different historical eras. It includes the Coverdale translation (1535), the Great Bible (1539), the Geneva Bible (1560), the Bishops'' Bible (1568), the Authorised King James Version (1611), and the Revised Version (1885).<br><br>Edited by William Aldis Wright, a distinguished nonconformist writer and critic, this collection is a treasure trove for scholars, theologians, and anyone interested in the study of the Psalms and the art of biblical translation. Wright''s work in compiling these translations offers a unique opportunity to observe the nuances and shifts in language, interpretation, and theological emphasis across different versions. The "Hexaplar Psalter Bible" is not just a testament to the enduring significance of the Psalms but also a testament to the rich history of English biblical translation. Its value extends beyond religious study, providing insights into the linguistic and cultural transformations that have shaped the way the biblical text is understood and appreciated over centuries.', 'historic', NULL, '59', 'eng', '1911', 'scan', 'University Press', NULL, NULL, 'ENGHPB_DBS_HS/English-(1911)-Hexaplar-Psalter-Bible-Psalms', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('68', 'English-1731-Wycliffe-New-Testament-John-Lewis-Edition', 'ENGWYC', 'English (1731) Wycliffe New Testament (John Lewis Edition)', NULL, 'The 1731 edition of the Wycliffe New Testament, known as the John Lewis Edition, is a notable work in the history of religious texts and biblical scholarship. This edition, titled "The New Testament, translated out of the Latin Vulgat by John Wiclif, S.T.P., about 1378," is prefaced with a comprehensive history of the translations of the Bible and New Testament into English. John Lewis, the editor of this edition, made significant contributions to religious history and bibliography with this publication.<br><br>Lewis''s work includes not only the translation of the New Testament by John Wyclif but also an extensive historical account of the various English translations of the Bible, both in manuscript and print. This account, "A History of the Translations of the Bible and New Testament, &c. into English," was later issued separately with additions as "A Complete History of the several Translations of the Holy Bible and New Testament into English." This detailed history was published in its second edition in 1739 and saw a third edition in 1818, further illustrating the enduring interest in the topic.<br><br>An interleaved copy of Lewis''s 1731 edition, with manuscript additions by Lewis and notes by Sir Peter Thompson, fetched a notable sum at the sale of Heber''s library. Additionally, in 1738, Lewis published "A brief History of the Rise and Progress of Anabaptism in England," which included an account of Dr. John Wicliffe and a defense of him from accusations of denying infant baptism. His manuscript additions for a new edition of this work are preserved in the Bodleian Library.<br><br>The 1731 John Lewis Edition of the Wycliffe New Testament, with its comprehensive historical context and scholarly additions, represents a significant contribution to the study of English biblical translations and the legacy of John Wyclif.', 'historic', 'https://en.wikisource.org/wiki/Lewis,_John_(1675-1747)_(DNB00)', '51', 'eng', '1745', 'scan', 'Wycliffe', 'wycliffe-bible-translators-inc', NULL, 'ENGWYC_DBS_HS/English-(1731)-Wycliffe-New-Testament-(John-Lewis-Edition)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('69', 'English-2016-King-James-Version-NT', 'ENGKJV', 'English (2016) King James Version New Testament', NULL, 'Nick Sayers 2016 updated version of the King James Version', 'modern', NULL, '3', 'eng', '2016', 'book', NULL, NULL, NULL, 'ENGKJV_DBS_HS', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('70', 'Greek-1810-Modern-Ancient-New-Testament-He-kaine-diatheke-tou-kuriou-kai-soteros-hemon-''Ie-sou-Christou-diglottos', 'GRCGRIE', 'Greek (1810) Modern-Ancient New Testament', 'Νεοελληνική-Αρχαία Καινή Διαθήκη (1810)', 'The 1810 "Modern-Ancient New Testament," also known as "The Greek Testament," is a notable work by Henry Alford, an esteemed biblical scholar and theologian. Alford''s version, titled "The Greek Testament: with a critically revised text: a digest of various readings: marginal references to verbal and idiomatic usage: prolegomena: and a critical and exegetical commentary," represents a significant contribution to New Testament studies.<br><br>Alford''s work is characterized by its critically revised text of the New Testament in Greek. This revision was based on a thorough examination of various textual readings, demonstrating Alford''s commitment to textual accuracy and scholarly rigor. Additionally, the publication features a comprehensive digest of various readings, providing insights into textual variations and interpretations.<br><br>Notably, Alford included marginal references to verbal and idiomatic usage, aiding in the understanding of the Greek language''s nuances and the contextual meaning of the text. The prolegomena and the critical and exegetical commentary offered in this work are particularly valuable for scholars and students, providing in-depth analysis and interpretation of the New Testament.<br><br>Henry Alford''s "The Greek Testament" is renowned for its scholarly depth and has been influential in the field of biblical studies, particularly in the realm of New Testament exegesis and textual criticism.', 'historic', NULL, '33', 'grc', '1810', 'scan', 'Georg Joachim Göschen', NULL, 'Google', 'GRCGRIE_DBS_HS/Greek-(1810)-Modern-Ancient-New-Testament-(He-kaine-diatheke-tou-kuriou-kai-soteros-hemon-''Ie-sou-Christou-diglottos)', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('71', 'English-1888-KJV-with-Anglican-Commentary-Vol-1-2-with-App', 'ENGKJV', 'English (1888) KJV (with Anglican Commentary) Vol.1 -2 with App', NULL, 'The history of Bible printing in America, particularly during the seventeenth and early eighteenth centuries, was marked by limited domestic production. During this period, most Bibles were imported from British and European printers or brought to the new continent by immigrants. However, with the advancement of printing technology and increasing demand, the late eighteenth and early nineteenth centuries saw a significant expansion in Bible publishing within America. Key cities such as Boston, Philadelphia, and New York emerged as major centers for Bible production.<br><br>Bible historian Paul Gutjahr highlights the immense popularity of the Bible in eighteenth-century North America, describing it as the "most printed, most distributed, and most read written text." This period witnessed the Bible not only as a cornerstone of religious and spiritual life but also as a symbol of familial heritage and pride. It served as a bridge connecting families to their distant relatives and ancestors.<br><br>Publishers, recognizing the Bible''s significance in family life and its role as a cherished heirloom, began producing editions with ornate and elaborate designs. These Bibles often featured intricately carved or embossed covers and were sometimes adorned with colored illustrations. This aesthetic enhancement was not merely for decoration but also to reflect the sacredness and reverence with which the text was held. In many households, space was made to display these beautifully crafted Bibles, signifying their importance in the family''s daily life and spiritual journey. This period of American Bible printing history underscores the evolving relationship between religious texts and their societal and cultural significance.', 'historic', NULL, '309', 'eng', '1888', 'study', NULL, NULL, NULL, 'ENGKJV_DBS_HS/English-(1888)-KJV-(with-Anglican-Commentary)-Vol-1-2-with-App', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('72', 'French-1535-Bible-d''Olivetan', 'FRAOLI', 'French (1535) Bible d''Olivétan', 'Bible d''Olivétan (1535)', 'French (1535) Bible d''Olivétan The first French Protestant Bible was translated by Pierre Robert Olivetan and printed in 1535 near Neufchâtel, Switzerland. This edition, known as the Bible d''Olivétan, is rare, with few copies remaining. It underwent several reprints in Geneva and Lyon in the 1540s. A significant revision in 1551 included additions by Theodore Beza and a new Psalms translation by Bude. This edition was frequently reprinted. In 1556, a version specifically for the Vaudois, funded by their substantial donation, was printed in Neufchâtel. Olivetan''s translation was based on the Latin version of Santes Pagninus for the Old Testament, and the New Testament versions by Lefevre and Erasmus. Despite revisions, including Calvin''s, and later emendations, this translation initially fell short of the standards expected of an authorized version.', 'historic', NULL, '39', 'fra', '1535', 'scan', NULL, NULL, NULL, 'FRAOLI_DBS_HS/French-(1535)-Bible-d''Olivetan', 'fra', 'stan1290', 'French', 'français', 'L', 'FR', '48', '2', '1', 'fr', '77200000', 'Andorra and France', 'Also in Algeria, Andorra, Austria, Belgium, Benin, Burkina Faso, Burundi, Cambodia, Cameroon, Canada, Central African Republic, Chad, Comoros, Congo, Côte d’Ivoire, Democratic Republic of the Congo, Djibouti, Equatorial Guinea, French Guiana, French Polynesia, Gabon, Guadeloupe, Guinea, Haiti, India, Israel, Italy, Lebanon, Libya, Luxembourg, Madagascar, Mali, Martinique, Mauritania, Mauritius, Mayotte, Monaco, Morocco, Mozambique, New Caledonia, Niger, Philippines, Puerto Rico, Réunion, Rwanda, Saint Pierre and Miquelon, Saudi Arabia, Senegal, Seychelles, South Africa, Switzerland, Togo, Tunisia, United Arab Emirates, United Kingdom, United States, U.S. Virgin Islands, Vanuatu, Wallis and Futuna.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('73', 'English-1901-ASV-Cross-Reference-Bible', 'ENGASV', 'English (1901) ASV Cross Reference Bible', NULL, 'The American Standard Version (ASV) of the Bible, first published in 1901, marks a significant milestone in the history of Bible printing in the United States. This period was characterized by a notable shift from reliance on British and European printers to a burgeoning domestic Bible publishing industry. The late 18th and early 19th centuries saw a surge in demand, spurring advancements in printing technology and machinery. Major cities like Boston, Philadelphia, and New York emerged as key centers for Bible production, reflecting the growing importance and accessibility of the Bible in American society.<br><br>Paul Gutjahr, a renowned Bible historian, highlights the immense popularity of the Bible during the 18th century, describing it as the most printed, distributed, and read written text in North America. The Bible was not only a cornerstone of religious and spiritual life for many families, but it also served as a tangible connection to their heritage, linking them to distant relatives and honored ancestors. In response to this deep-seated reverence, publishers began to produce Bibles with ornate and artistic features, including carved or embossed covers and intricate, sometimes colored, illustrations. These aesthetic enhancements transformed the Bible into both a sacred text and a cherished family heirloom, often displayed prominently in homes as a symbol of both faith and familial pride. The ASV Cross Reference Bible, emerging in this context, represents both the culmination of these trends and a testament to the enduring importance of the Bible in American cultural and spiritual life.', 'historic', NULL, '270', 'eng', '1901', 'study', 'Harold E. Monser', NULL, NULL, 'ENGASV_DBS_HS/English-(1901)-ASV-Cross-Reference-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('74', 'English-1580-Tyndales-Five-Books-of-Moses-OT-Portions', 'ENGTYN', 'English (1580) Tyndales Five Books of Moses - OT Portions', NULL, 'In 1530, William Tyndale published "The fyrste boke of Moses call Genesis," a significant English translation of the Pentateuch, printed in Marlborow (Hesse) by Hans Luft, although often attributed to Antwerp and Hoochstraten. This edition is notable for rendering the deity as "Jehovah" in several instances. A second edition, corrected and amended by Tyndale, appeared in 1533, with only Genesis receiving significant revisions, while the other books remained unchanged. Subsequent editions were published in London by John Day in 1551 and 1552. Additionally, a verbatim reprint of the 1530 edition was compared with Tyndale''s 1534 Genesis and other sources, providing valuable collations and prolegomena.<br><br>The 1599 Geneva-Towson-Junius Bible, "The Bible, that is... With ...Annotations...," printed in London by the deputies of Christopher Barker, combined the Genevan Old Testament, Laurence Tomson''s New Testament (except Revelation), and Francis Junius'' translation of Revelation by Thomas Barbar. Further editions followed in 1603, 1610 (which contained an error at John 6:67, "Judas" for "Jesus"), 1611, 1612, 1615, 1616, 1633, 1640, and 1644. Another significant publication was "The New Testament of ovr Lord Iesvs Christ, Translated out of Greeke by Theod. Beza," with summaries and annotations by L. Tomson and Fr. Junius on Revelation, printed in London by Robert Barker in 1602 and again in 1610. These works collectively represent important milestones in the history of English Bible translations, as documented in the Catalogue of English Bible Translations by Chambelin.', 'historic', 'https://en.wikipedia.org/wiki/Tyndale_Bible', '34', 'eng', '1599', 'reprint', NULL, NULL, NULL, 'ENGTYN_DBS_HS/English-(1580)-Tyndales-Five-Books-of-Moses-OT-Portions', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('75', 'English-1861-Pictorial-Bible-Vol.-4-New-Tesament-Study', 'ENGPICT', 'English (1861) Pictorial Bible (Vol. 4) New Tesament (Study)', NULL, 'The 1861 edition of "The Pictorial Bible," edited by John Kitto, D.D., F.S.A., stands as a monumental work in the realm of biblical literature. This volume, part of a four-volume series, covers from Genesis to Joshua, providing a comprehensive visual and scholarly journey through these foundational books of the Old Testament. Kitto''s work is renowned for its integration of steel engravings and numerous woodcuts, which vividly depict landscape scenes, natural history, customs, and antiquities.<br><br>John Kitto, an eminent biblical scholar of his time, augmented the authorized version of the Bible with original notes that explain passages linked to the history, geography, natural history, literature, and antiquities of the Scriptures. These notes are particularly notable for their reliance on the discoveries of contemporary travelers and scholars, making this edition an invaluable resource for understanding the historical and cultural context of the biblical narrative.<br><br>Published in London by W. and R. Chambers, this new edition of "The Pictorial Bible" was aimed at bringing the biblical world to life for its readers. It was designed to be more than just a religious text; it was an educational tool that merged the sacred scriptures with the burgeoning fields of archaeology and oriental studies. The detailed illustrations and comprehensive notes provided a deeper, more textured understanding of the Bible, making it an essential addition to the libraries of scholars, clergy, and laypeople interested in a more profound comprehension of biblical times and teachings.', 'historic', NULL, '177', 'eng', '1861', 'study', 'W. and R.Chambers', NULL, NULL, 'ENGPICT_DBS_HS/English-(1861)-Pictorial-Bible-(Vol.-4)-New-Tesament-(Study)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('76', 'English-1807-Negro-Slave-Bible', 'ENGNSB', 'English (1807) Negro Slave Bible', NULL, 'The "Slave Bible," formally titled "Parts of the Holy Bible, Selected for the Use of the Negro Slaves, in the British West-India Islands," is a significantly altered version of the Bible, specifically edited in the early 19th century for slaves in the British West Indies, then under British colonial rule. This edition is notable for its extensive omissions, designed to emphasize obedience and discourage rebellion among the enslaved population.<br><br>Produced in England and used by British missionaries for educating and converting enslaved Africans, this Bible had 90 percent of the Old Testament and half of the New Testament removed. Key passages that referred to freedom, escape from slavery, or equality were excluded due to their potential to incite thoughts of rebellion. For example, Galatians 3:28, highlighting equality in Christ Jesus regardless of status, was omitted, while verses like Ephesians 6:5, encouraging obedience to masters, were kept.<br><br>In 2018, the Museum of the Bible featured this edition in its exhibition "The Slave Bible: Let the Story Be Told." The showcased 1807 copy, one of only three known copies of this version, is owned by Fisk University. It was printed by Law and Gilbert of London for the Society for the Conversion of Negro Slaves.<br><br>The Slave Bible serves as a stark reminder of the manipulation of religious texts for oppressive purposes and stands as a historical testament to the complexities of religion in the context of slavery and colonialism.', 'historic', 'https://en.wikipedia.org/wiki/Slave_bible', '69', 'eng', '1807', 'scan', 'British West India Islands', NULL, NULL, 'ENGNSB_DBS_HS/English-(1807)-Negro-Slave-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('77', 'English-1921-Shorter-Kent-Old-New-Testament-OT', 'ENGKENT', 'English (1921) Shorter (Kent) Old New Testament - OT', NULL, 'The Shorter Bible: The Old Testament Translated and arranged by Charles Foster Kent…Charles Cutler Torrey… Henry A. Sherman… Fredrick Harris… Ethel Cutler.<br><br>Charles Foster Kent (August 13, 1867 - May 2, 1925) was an American Old Testament scholar. He was born at Palmyra, New York, and educated at Yale (A.B., 1889; Ph.D., 1891). He studied at the University of Berlin (1891–92). He was an instructor at the University of Chicago 1893-95 and then professor of Biblical literature at Brown. After 1901, he was Woolsey Professor of Biblical Literature at Yale. Kent was the founding president of the American Academy of Religion from 1910 to 1925.', 'historic', NULL, '65', 'eng', '1921', 'scan', 'Charles Scribner''s Sons', NULL, NULL, 'ENGKENT_DBS_HS/English-(1921)-Shorter-(Kent)-Old-New-Testament-OT', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('78', 'English-1903-The-Numerical-Study-Bible-Vol.1-7-Fill', 'ENGKJV', 'English (1903) The Numerical Study Bible - Vol.1-7 Fill', NULL, 'Frederick W. Grant''s "The Numerical Bible," a seven-volume exploration, presents a unique perspective on the structure and symbolism of the Scriptures. Grant''s work stands out for its compelling argument that the Bible, far from being a collection of fragmented literary pieces or forgeries, is a coherent and divinely inspired work, meticulously structured and symbolically rich. <br><br> Grant draws parallels between the organization of the Bible and the natural world. He posits that just as the natural universe is underpinned by mathematical precision and numeric laws, so too is the structure of the Scripture. This fascinating correlation suggests that the order, structure, and symbolic dimensions of the Bible are not random but reflect a higher divine order. <br><br> "The Numerical Bible" delves into the idea that numbers and the structural design of the Bible are not mere literary tools but carry elements of divine revelation themselves. This perspective offers a new lens through which to view the Bible, not just as a spiritual guide but also as a reflection of the intrinsic order and beauty of the universe. Grant''s work invites readers to see the Bible as a part of the natural order, intricately woven with purpose and intentionality that mirror the fundamental laws governing the world.', 'historic', NULL, '300', 'eng', '1903', 'study', 'Loizeaux Brothers, Bible Truth Depot', NULL, NULL, 'ENGKJV_DBS_HS/English-(1903)-The-Numerical-Study-Bible-Vol.1-7-Fill', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('79', 'Assyrian-Bible-Psalms', 'AIIWBT', 'Assyrian Bible - Psalms', 'ܟܬܒܐ ܩܕܝܫܐ ܐܬܘܪܝܐ - ܡܙܡܘܪ̈ܐ', 'An Assyrian translation of the New Testament. Neo-Assurian, or Suret, is a language spoken in Iraq, Iran, and Syria. ', 'historic', NULL, '1', 'aii', '1905', 'scan', NULL, NULL, NULL, 'assyrian_bible_psalms', 'aii', 'assy1241', 'Assyrian Neo-Aramaic', 'Sūreṯ', 'L', 'IQ', '36.75', '43', '6b', NULL, '626000', 'Iraq', 'Northern Iraq, Baghdad, Basrah, Karkuk, Arbil. Also in Armenia, Australia, Austria, Azerbaijan, Belgium, Brazil, Canada, Cyprus, France, Georgia, Germany, Greece, Iran, Italy, Lebanon, Netherlands, New Zealand, Russian Federation (Europe), Sweden, Switzerland, Syria, Turkey (Asia), United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('80', 'English-1836-Adam-Clarke-Study-Bible-6-Vol.-Vol.-1-4-OT', 'ENGKJV', 'English (1836) Adam Clarke Study Bible 6 Vol. (Vol. 1-4) Old Testament', NULL, 'English (1836) Adam Clarke Study Bible 6 Vol. (Vol. 1-4) - OT Adam Clarke (1762 – 1832) was a British Methodist theologian and a three-time President of the Wesleyan Methodist Conference. He is most renowned for his comprehensive Bible commentary, a work that took 40 years to complete and became a foundational theological resource for Methodists for two centuries. The commentary is notable for its detail and erudition. Clarke, a committed Wesleyan, opposed Calvinistic interpretations, favoring Wesleyan-Arminian views on salvation, predestination, prevenient grace, the universal offer of justification, the possibility of entire sanctification, and the assurance of salvation. His commentary, especially on the Book of Revelation, controversially identified the Catholic Church with the Antichrist. Clarke''s work, almost half the volume of the collaborative twelve-volume The Interpreter''s Bible, is recognized for its academic depth.', 'historic', NULL, '650', 'eng', '1836', 'study', 'G. Lane & C. B. Tippett', NULL, NULL, 'ENGKJV_DBS_HS/English-(1836)-Adam-Clarke-Study-Bible-6-Vol.-(Vol.-1-4)-OT', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('81', 'English-1924-Centenary-Translation-Montgomery-of-New-Testamanet', 'ENGMONT', 'English (1924) Centenary Translation (Montgomery) of New Testament', NULL, 'The "Centenary Translation of the New Testament" by Helen Barrett Montgomery, marks a significant milestone in biblical translation and the American Baptist Publication Society''s history. This translation commemorates the society''s centennial, showcasing Montgomery as the first woman to translate the entire New Testament into English.<br><br>Born in Ohio and raised in Rochester, New York, Montgomery was an influential figure in religious and educational circles. A Wellesley College alumna, she was deeply involved in the Lake Avenue Church and significantly contributed to religious and missionary work. In 1921, she made history as the first woman president of the Northern Baptist Convention, highlighting her leadership within the Baptist community.<br><br>Montgomery''s "Centenary Translation" aimed to make the Bible''s message more accessible to contemporary audiences. Her translation is celebrated for its scholarly rigor and insight. Beyond translation, she authored several books, including "Western Women in Eastern Lands," "The Preaching Value of Missions," and "The Story of Jesus as Told by His Four Friends," enriching discussions on missions and religious education.<br><br>Her contributions as a translator, educator, and religious leader are enduring, emphasizing the need for diverse perspectives in religious scholarship and the dissemination of biblical texts. Her work remains a pivotal part of religious history and scholarship.', 'historic', NULL, '12', 'eng', '1924', 'scan', 'The American Baptist Publication Society', NULL, NULL, 'ENGMONT_DBS_HS/English-(1924)-Centenary-Translation-(Montgomery)-of-New-Testamanet', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('82', 'Hebrew-1669-Lexicon-Heptaglotton-2-Vol-Greek-Amharic-Syriac-Chadean-Latin', 'HEBHEPT', 'Hebrew (1669) Lexicon Heptaglotton (Greek, Amharic, Chaldean, Latin, Syriac) 2Vol', 'עברית - לקסיקון הפטגלוטון (1669, יוונית, אמהרית, כלדית, לטינית, סורית) 2 כרכים', 'The "Lexicon Heptaglotton," published in 1669 by Edmundo Castello and printed by Thomas Roycroft in London, is a landmark work in linguistics and biblical studies. This lexicon, spanning two volumes, offers a comprehensive linguistic resource for seven languages: Hebrew, Chaldean, Syriac, Samaritan, Ethiopian, Arabic, and Persian. Each language is addressed separately, enriching its scholarly value.<br><br>Castello''s ambitious project was significant for compiling an extensive array of lexical entries in these languages, each with deep historical and religious roots. The inclusion of less commonly studied languages like Samaritan and Ethiopian, alongside Hebrew and Arabic, highlights the 17th-century scholarly interest in linguistic diversity. This lexicon was instrumental for scholars, linguists, and theologians in studying and translating biblical and ancient texts, reflecting the period''s intellectual engagement with diverse cultural and religious manuscripts.', 'historic', NULL, '1', 'heb', '1669', 'scan', 'Thomas Roycroft', NULL, NULL, 'HEBHEPT_DBS_HS/Hebrew-(1669)-Lexicon-Heptaglotton-Vol.-1-of-2', 'heb', 'hebr1245', 'Hebrew', 'Israeli Hebrew', 'L', 'IL', '31.10565', '35.01788', '1', 'he', '5000000', NULL, 'Also in Australia, Canada, Germany, Palestinian West Bank and Gaza, Panama, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('83', 'English-1859-Self-Explanatory-Family-Bible-Brown-Study', 'ENGKJV', 'English (1859) Self Explanatory Family Bible (Brown) Study', NULL, '"Brown''s Self-Interpreting Family Bible," containing both the Old and New Testaments, is a remarkable literary and theological accomplishment by John Brown of Haddington (1722 – 1787). Born in Carpow, Perthshire, Brown''s educational journey was extraordinary, being predominantly self-taught. Despite his humble beginnings as a shepherd, Brown acquired a profound knowledge of various ancient and modern languages, including Latin, Greek, Hebrew, French, Italian, German, Arabic, Persian, Syriac, and Ethiopic, showcasing his remarkable linguistic aptitude and intellectual curiosity. His career trajectory was diverse, encompassing roles as a travelling merchant, a soldier in the Edinburgh garrison in 1745, and a schoolmaster, before dedicating his life to religious studies.<br><br>From 1750 until his death, Brown served as a minister of the Burgher branch of the Secession Church in Haddington and was appointed as a professor of divinity for his denomination in 1786. He was instrumental in the training of its ministry and earned a reputable status for his learning and piety. Among his numerous works, the most notable include the ''Self-Interpreting Bible'' and ''Dictionary of the Bible,'' both of which gained widespread popularity and were translated into other languages, including Welsh.<br><br>Published in 1778 in Edinburgh in two volumes, the ''Self-Interpreting Bible'' was designed to make the scriptures accessible to the ''poorer and labouring part of mankind.'' Brown endeavored to make the oracles of God interpret themselves through this work, offering history, chronology, geography, summaries, explanatory notes, and reflections. This comprehensive approach made it an invaluable resource for ordinary readers, effectively serving as a one-volume library. Its clarity, vigor, and practicality ensured its enduring popularity among English-speaking nations, Wales, and the Scottish highlands, cementing its status as a seminal work in biblical literature.', 'historic', NULL, '913', 'eng', '1859', 'study', 'Blackie and Son', NULL, NULL, 'ENGKJV_DBS_HS/English-(1859)-Self-Explanatory-Family-Bible-(Brown)-Study', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('84', 'English-1864-Phonetic-New-Testament', 'ENGPNT', 'English (1864) Phonetic New Testament', NULL, 'The "Phonetic New Testament" is an innovative adaptation of the New Testament scriptures, crafted by Dr. Andrew Comstock, M.D., in 1848. This unique edition stands apart for its use of a phonetic alphabet, meticulously designed by Comstock, who was both a physician and a professor of elocution. His primary objective was to assist students, particularly those grappling with speech impediments, in improving their spoken English.<br><br>Dr. Comstock''s approach involved translating the New Testament from the original Greek and then diligently comparing and revising it against traditional translations. His commitment to developing the phonetic alphabet stemmed from a conviction that it surpassed the effectiveness of seven other known phonetic systems of his time. A notable feature of this edition is the inclusion of a detailed table explaining the sounds represented by each character in his phonetic alphabet.<br><br>Dr. Comstock envisioned his phonetic New Testament as more than an educational tool. He saw it as a means of evangelism, particularly beneficial to those for whom English was not a first language, including "the heathen." This aspect of his work highlights the broader missionary zeal prevalent in the 19th century.<br><br>According to Dr. Paul Keen, this edition of the Phonetic New Testament is a rare first edition, making it a unique and valuable artifact in the history of biblical translations. It embodies an early effort to bridge linguistic barriers and make the scriptures more accessible, reflecting the innovative spirit of its time.', 'historic', NULL, '47', 'eng', '1864', 'scan', 'Eltas Lovjli, Phonetic Publisher', NULL, NULL, 'ENGPNT_DBS_HS/English-(1864)-Phonetic-New-Testament', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('85', 'English-1699-Baxters-Paraphrase-New-Testament', 'ENGBAX', 'English (1699) Baxters Paraphrase New Testament', NULL, 'First printed in 1685, "Baxter’s Paraphrase of the New Testament" is a notable work by Richard Baxter, a Puritan known for his writings on practical piety. This paraphrase of the New Testament reflects Baxter''s intent to make the text more accessible and understandable to a broad audience. He aimed to provide a resource that could aid families in daily reading and help all people, regardless of their educational background, to comprehend the New Testament.<br><br>Baxter''s work, however, was not without controversy. His paraphrase included criticisms of the Church of England, which led to his imprisonment and severe punishment, though he was eventually released. The text is characterized by doctrinal and practical notes throughout, which are marked by their plainness and brevity, designed to assist readers in grasping the meaning of the New Testament.<br><br>The edition mentioned, "A Paraphrase on the New Testament with Notes Doctrinal and Practical," was printed in London in 1685 by B. Simmons and Tho. Simmons. It saw a second edition in 1695 and was reprinted again in 1810. This work not only represents an important aspect of religious literature in the 17th century but also highlights the challenges faced by religious dissenters during this period. The mention of a penned quote from Baxter''s court trial in the copy of the book further adds to its historical significance, offering a glimpse into the contentious religious environment of that era.', 'historic', 'https://library.garrett.edu/collections/special-collections/rare-bible-digital-exhibit/post-1600/baxters-paraphrase-new-testament-1685', '70', 'eng', '1699', 'scan', NULL, NULL, NULL, 'ENGBAX_DBS_HS/English-(1699)-Baxters-Paraphrase-New-Testament', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('86', 'English-1888-KJV-Variorum-Reference-Study-Bible', 'ENGKJV', 'English (1888) KJV Variorum Reference Study Bible', NULL, 'The **Variorum Reference Bible**, published in 1888, is a notable edition of the King James Version (KJV) that offers readers a comprehensive study tool by incorporating various scholarly insights directly into the biblical text. This edition was meticulously edited by a team of esteemed scholars, including Rev. T.K. Cheyne, M.A., D.D., Rev. S.R. Driver, D.D., Rev. R.L. Clarke, M.A., Alfred Goodwin, M.A., and Rev. W. Sanday, M.A., D.D., LL.D.<br><br>The primary feature of the Variorum Reference Bible is its inclusion of **alternative renderings and readings** from authoritative sources. These variations are presented alongside the standard KJV text, allowing readers to compare different interpretations and understandings of specific passages. This approach provides a more nuanced comprehension of the scriptures, highlighting textual differences and the reasons behind them.<br><br>In addition to the alternative readings, this edition offers **extensive cross-references** and **marginal notes**. These tools guide readers to related scriptures, facilitating a deeper and more interconnected study experience. The marginal notes often include historical, linguistic, and cultural insights, enriching the reader''s engagement with the text.<br><br>The Variorum Reference Bible also incorporates the **"Aids to the Student of the Holy Bible,"** a compilation of resources designed to enhance biblical study. This section includes essays, maps, and explanatory articles that provide context and background information, making the scriptures more accessible and understandable.<br><br>For many years, this edition was considered one of the most convenient English sources for information on various biblical readings. Its meticulous compilation of scholarly insights made it an invaluable resource for theologians, scholars, and lay readers interested in a deeper exploration of biblical texts.<br><br>In summary, the 1888 Variorum Reference Bible stands as a significant scholarly work that enriches the traditional KJV text with a wealth of academic resources, offering readers a multifaceted tool for comprehensive Bible study. ', 'historic', NULL, '151', 'eng', '1888', 'study', NULL, NULL, NULL, NULL, 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('87', 'Greek-English-1871-Apocrypha-in-Parallel-Columns-Apocrypha', 'GRCSEPT', 'Greek-English (1871) Apocrypha in Parallel Columns - Apocrypha', 'Απόκρυφα σε Παράλληλες Στήλες (1871)', 'The 1871 publication "The Apocrypha: Greek and English, in Parallel Columns" by Otto Fridolin Fritzsche stands as a notable work in biblical scholarship. Fritzsche, a German Protestant theologian born on September 23, 1812, in Dobrilugk, was recognized for his significant contributions to theological studies.<br><br>Fritzsche''s academic journey began at the University of Halle, where he obtained his habilitation in 1836. He joined the University of Zurich as an associate professor of theology in 1837, later becoming a titular professor in 1842 and a full professor in 1860. Besides his academic roles, he served as the chief librarian at the cantonal library from 1844 until his death.<br><br>His work on the Apocrypha, providing Greek and English texts in parallel columns, is particularly important for those studying these intertestamental books, which are included in the Septuagint and the Latin Vulgate but are not part of the Hebrew Bible. Fritzsche''s edition allows for a comparative study of the texts, offering insights into the translation and interpretation of the Apocrypha. This work reflects his deep engagement with theological studies and his commitment to making religious texts accessible for scholarly examination.', 'historic', NULL, '19', 'grc', '1871', 'scan', 'Samuel Bagster and Sons', NULL, NULL, 'GRCSEPT_DBS_HS/Greek-English-(1871)-Apocrypha-in-Parallel-Columns-Apocrypha', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('88', 'English-1918-Shorter-Kent-New-Testament', 'ENGKENT', 'English (1918) Shorter (Kent) New Testament', NULL, 'English (1918) Shorter (Kent) New Testament The Shorter Bible: The New Testament Translated and arranged by Charles Foster Kent…Charles Cutler Torrey… Henry A. Sherman… Fredrick Harris… Ethel Cutler.<br><br>Charles Foster Kent (August 13, 1867 - May 2, 1925) was an American Old Testament scholar. He was born at Palmyra, New York, and educated at Yale (A.B., 1889; Ph.D., 1891). He studied at the University of Berlin (1891–92). He was an instructor at the University of Chicago 1893-95 and then professor of Biblical literature at Brown. After 1901, he was Woolsey Professor of Biblical Literature at Yale. Kent was the founding president of the American Academy of Religion from 1910 to 1925.', 'historic', NULL, '34', 'eng', '1918', 'scan', 'Charles Scribner''s Sons', NULL, NULL, 'ENGKENT_DBS_HS/English-(1918)-Shorter-(Kent)-New-Testament', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('89', 'English-1866-American-Bible-Union-Baptist-New-Testament', 'ENGABU', 'English (1866) American Bible Union (Baptist) New Testament', NULL, 'The 1865 New Testament, titled "The New Testament of our Lord and Savior Jesus Christ. The Common English Version, Corrected by the Final Committee of the American Bible Union," marks a significant moment in the history of biblical translations. This second revision, a modest refinement of the 1862-4 edition, was a product of the American Bible Union, a group formed in the mid-19th century with strong Baptist affiliations. <br><br>During a period rife with external opposition and internal challenges, the American Bible Union managed to produce this notable revision. The project was led by an esteemed committee of scholars, including Thomas J. Conant, Horatio B. Hackett, and Asahel C. Kendrick. Their collective expertise contributed to a version that sought to enhance the clarity and accuracy of the English translation of the New Testament. <br><br>The revision process involved publishing the New Testament in parts from 1862 to 1864. The aim was to offer a text more closely aligned with the original Greek manuscripts while maintaining the essence of the widely accepted Common English Version. This endeavor reflects the period''s growing interest in biblical scholarship and the desire to make the scriptures more comprehensible and relevant to contemporary readers. The American Bible Union''s version is a testament to the dynamic nature of biblical translation and interpretation during a transformative era in American religious history.', 'historic', NULL, '61', 'eng', '1866', 'scan', NULL, NULL, NULL, 'ENGABU_DBS_HS/', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('90', 'English-1611-King-James-Version-facsimilie', 'ENGKJV', 'English (1611) King James Version (facsimilie)', NULL, 'The King James Version (KJV), also known as the King James Bible (KJB) and the Authorized Version, is a notable English translation of the Christian Bible. Commissioned for the Church of England in 1604 and published in 1611 under the sponsorship of King James VI and I, the KJV is celebrated for its "majesty of style" and profound cultural impact. It includes 39 books of the Old Testament, 14 books of the Apocrypha (as considered by Protestants), and 27 books of the New Testament, totaling 80 books.<br><br>The KJV was the third English translation authorized by the English Church, following the Great Bible (commissioned by King Henry VIII in 1535) and the Bishops'' Bible (commissioned by Queen Elizabeth I in 1568). The Geneva Bible of 1560, produced by Protestant Reformers in Geneva, significantly influenced the writing of the KJV.<br><br>The translation was initiated at the Hampton Court Conference in January 1604, convened by King James in response to the Puritans'' concerns with earlier translations. James set guidelines to align the translation with the ecclesiology and episcopal structure of the Church of England. The translation was undertaken by 47 scholars in six panels, dividing the work of translating the Old Testament, New Testament, and Apocrypha.<br><br>The translators used Hebrew and Aramaic texts for the Old Testament and Greek texts for the New Testament and Apocrypha. The KJV replaced the Great Bible in the 1662 Book of Common Prayer for Epistle and Gospel readings, authorized by Act of Parliament.<br><br>By the 18th century, the KJV became the predominant English translation among Anglican and other English Protestant churches. It also replaced the Latin Vulgate as the standard scripture version for English-speaking scholars. The standard text of the KJV, extensively re-edited by Benjamin Blayney in 1769, became the most widely printed book in history due to stereotype printing in the early 19th century. This version, usually omitting the Apocrypha, is commonly known today as the Oxford standard text of the King James Version.', 'historic', 'https://en.wikipedia.org/wiki/King_James_Version', '138', 'eng', '1611', 'reprint', NULL, NULL, NULL, 'ENGKJV_DBS_HS/English-(1611)-King-James-Version-(facsimilie)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('91', 'Hebrew-1906-Hexaglot-Bible-Eng-Fre-Ger-Lat-Heb-Vol-1-6', 'HEBHEPT', 'Hebrew(1906) Hexaglot Bible (Eng Fre Ger Lat Heb) Vol 1-6', 'עברית - תנ"ך משושה (1906, Hexaglot Bible, אנגלית-צרפתית-גרמנית-לטינית-עברית, כרכים 1-6)', 'The 1906 "Hexaglot Bible" is an extensive and ambitious work that compiles the Holy Scriptures of the Old and New Testaments in six different languages. This multilingual approach provides a comprehensive resource for comparative biblical studies. The Hexaglot Bible features the original texts of the Scriptures in their original tongues, alongside several key translations, all arranged in parallel columns for ease of study and comparison.<br><br>For the Old Testament, the Hexaglot Bible includes the original Hebrew text, the Greek Septuagint (an ancient Greek translation of the Hebrew Bible), the Latin Vulgate, and translations in English, German, and French. The New Testament is presented in the original Greek, the Syriac version (which is an early Christian translation), the Latin Vulgate, and translations in English, German, and French.<br><br>This comprehensive arrangement allows for an in-depth comparison of texts across different languages and translations. By including a variety of translations, the Hexaglot Bible serves as a valuable tool for scholars, theologians, and students who are interested in understanding the nuances of biblical texts in different linguistic and cultural contexts. The inclusion of translations that have been historically significant in Christianity, such as the Vulgate, the Authorized English version, and key European translations, makes this work an important resource for the study of the history of biblical interpretation and translation.', 'historic', NULL, '608', 'heb', '1906', 'study', 'Apud Funk et Wagnalls', NULL, NULL, 'GRCVATI_DBS_HS/Greek-(1906)-Hexaglot-Bible-(Eng-Fre-Ger-Lat-Heb)-Vol-1-6', 'heb', 'hebr1245', 'Hebrew', 'Israeli Hebrew', 'L', 'IL', '31.10565', '35.01788', '1', 'he', '5000000', NULL, 'Also in Australia, Canada, Germany, Palestinian West Bank and Gaza, Panama, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('92', 'Assyrian-Bible-Gospel-of-John', 'AIIWBT', 'Assyrian Bible - Gospel of John', 'ܟܬܒܐ ܩܕܝܫܐ ܐܬܘܪܝܐ - ܣܒܪܬܐ ܕܝܘܚܢܢ', 'An Assyrian translation of the New Testament. Neo-Assurian, or Suret, is a language spoken in Iraq, Iran, and Syria. ', 'historic', NULL, '1', 'aii', '1905', 'scan', NULL, NULL, NULL, 'assyrian_john', 'aii', 'assy1241', 'Assyrian Neo-Aramaic', 'Sūreṯ', 'L', 'IQ', '36.75', '43', '6b', NULL, '626000', 'Iraq', 'Northern Iraq, Baghdad, Basrah, Karkuk, Arbil. Also in Armenia, Australia, Austria, Azerbaijan, Belgium, Brazil, Canada, Cyprus, France, Georgia, Germany, Greece, Iran, Italy, Lebanon, Netherlands, New Zealand, Russian Federation (Europe), Sweden, Switzerland, Syria, Turkey (Asia), United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('93', 'Aramaic-Bible-Gospel-of-John', 'AII1885', 'Aramaic Bible - Gospel of John', 'ܐܪܡܝܐ ܟܬܒܐ - ܐܘܢܓܠܝܘܢ ܕܝܘܚܢܢ', 'In the Syriac (Eastern Aramaic) language the Peshitta (Syriac: "common version") is the standard version of the Christian Bible. It continues to serve as the Bible of churches in the Syriac tradition (Church of the East, Chaldean Catholic, and Syriac Orthodox) to this day. The history of Christian Translations of the Bible into Syriac language includes the Diatessaron, the Old Syriac versions (Curetonian and Sinaitic), the Peshitto, the Philoxenian version, the Harklean Version and the recent United Bible Societies'' modern Aramaic New Testament.<br><br>About AD 500 a Christian Palestinian Aramaic version was made. It contains 2 Peter, 2-3 John, Jude, and Apocalypse. It is representative of the Caesarean text type and is a unique translation different from any other which was made into Syriac. These are among the manuscripts used by John Gwynn in 1893 to complete his edition of the Catholic Epistles. In 1892 Agnes Smith Lewis discovered the manuscript of the Palestinian Syriac lectionary in the library of Saint Catherine''s Monastery on Mount Sinai. It is designated by Syr.<br><br>The first revision of the New Testament from the Syriac into Turoyo language (Western Aramaic in Syriac and Latin script) was made by Malphono Yuhanun Üzel (Bar Shabo), Benjamin Bar Shabo, and Yahkup Bilgic in 2009 with notes from Harclean and Philoxenios. This commission "Sihto du Kthovo Qadisho Suryoyo" works especially to preach the Gospel in Aramaic all over the world.', 'historic', NULL, '205', 'aii', '1885', 'scan', NULL, NULL, NULL, 'aramaic_john', 'aii', 'assy1241', 'Assyrian Neo-Aramaic', 'Sūreṯ', 'L', 'IQ', '36.75', '43', '6b', NULL, '626000', 'Iraq', 'Northern Iraq, Baghdad, Basrah, Karkuk, Arbil. Also in Armenia, Australia, Austria, Azerbaijan, Belgium, Brazil, Canada, Cyprus, France, Georgia, Germany, Greece, Iran, Italy, Lebanon, Netherlands, New Zealand, Russian Federation (Europe), Sweden, Switzerland, Syria, Turkey (Asia), United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('94', 'Greek-English-1920-Harmony-of-the-Gospels-Study', 'GRCWHN', 'Greek-English (1920) Harmony of the Gospels Study', 'Συμφωνία των Ευαγγελίων (1920, Μελέτη)', 'The 1920 publication "A Harmony of The Gospels For Students Of The Life Of Christ" by A. T. Robertson is a significant work for biblical studies, particularly for those interested in the life and teachings of Jesus Christ. This book is based on the Broadus Harmony in the Revised Version and represents a comprehensive effort to synchronize the narratives of the four Gospels – Matthew, Mark, Luke, and John.<br><br>A. T. Robertson, a distinguished scholar and the Chair of New Testament Interpretation at the Southern Baptist Theological Seminary in Louisville, Kentucky, compiled this harmony to facilitate a cohesive and chronological understanding of the Gospels. His work allows students and scholars to study the events of Christ''s life in a streamlined and integrated manner, offering insights into how the different Gospel accounts complement and illuminate each other.<br><br>Robertson''s harmony is particularly valuable for those studying the New Testament, the life of Jesus, and the harmonization of the Gospel narratives. His scholarly approach and expertise in New Testament interpretation make this work a useful resource for theological education and for anyone seeking a deeper understanding of the Gospels'' portrayal of Christ''s life.', 'historic', NULL, '13', 'grc', '1920', 'study', NULL, NULL, NULL, 'GRCWHN_DBS_HS/Greek-English-(1920)-Harmony-of-the-Gospels-Study', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('95', 'Hebrew-1524-The-Second-Rabbinic-Bible-Mikraot-Gedolot-Volume-3', 'HEBRABB', 'Hebrew (1524) The Second Rabbinic Bible (Mikraot Gedolot) (מקראות גדולות) Volume 3', 'עברית - המקראות הגדולות (1524, התנ"ך הרבני השני, כרך 3)', 'The third volume of the Mikraot Gedolot, also known as the Second Rabbinic Bible, is a continuation of the significant work initiated by Jacob ben Haim (Yaakov ben Hayyim ibn Adonijah). Published in Venice between 1524 and 1525 by Daniel Bomberg, this volume is part of a classic printing of the Hebrew Bible, specifically the Hebrew Masoretic text. The Mikraot Gedolot is noted for its historical importance, particularly because it is believed to have been the source text (Textus Receptus) for the Hebrew Old Testament used by the translators of the King James Version of the Bible in 1611.<br><br>Jacob ben Haim, a Jewish Masoretic scholar who later converted to Christianity, was responsible for producing and editing the Mikraot Gedolot. His work represents a monumental achievement in the early days of the printing press. The meticulous assembly of Hebrew letters, vowels, and accents in this edition was an arduous and technologically challenging process.<br><br>Ben Hayyim used the best Hebrew manuscripts available to him at the time, and while there has been some debate over the quality of these manuscripts, the renowned Masoretic scholar Ginsburg has argued that the Mikraot Gedolot was a good representation of the Ben Asher text. Ginsburg''s own respected editions of the Hebrew Bible, printed by the British and Foreign Bible Society, were based on ben Hayyim''s Second Rabbinic Bible, further underscoring the lasting impact and importance of this work in the field of Hebrew biblical scholarship.', 'historic', NULL, '280', 'heb', '1524', 'scan', NULL, NULL, NULL, 'HEBRABB_DBS_HS/Hebrew-(1524)-The-Second-Rabbinic-Bible-(Mikraot-Gedolot)-Volume-3', 'heb', 'hebr1245', 'Hebrew', 'Israeli Hebrew', 'L', 'IL', '31.10565', '35.01788', '1', 'he', '5000000', NULL, 'Also in Australia, Canada, Germany, Palestinian West Bank and Gaza, Panama, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('96', 'French-1900-Bible-La-Sainte-Bible-Polyglotte-GRK-HEB-LAT', 'FRAOST', 'French (1900) Bible - La Sainte Bible Polyglotte (GRK-HEB-LAT)', 'La Sainte Bible Polyglotte (1900, GRK-HEB-LAT)', 'French (1900) "La Sainte Bible Polyglotte" is a significant polyglot edition of the Bible, encompassing the Hebrew original, the Greek Septuagint, the Latin Vulgate, and the French translation by Abbé Glaire. This edition is notable for its scholarly approach, providing readers with a unique opportunity to compare the texts of these different traditions side by side. The inclusion of textual differences between the Hebrew, Greek Septuagint, and Latin Vulgate versions offers invaluable insights into the complex history of biblical texts and their translations. Published in 1900, this work represents a culmination of 19th-century biblical scholarship, catering to theologians, linguists, and serious students of the Bible. It reflects the era''s growing interest in textual criticism and the pursuit of understanding the Scriptures in their original languages and most authoritative translations.', 'historic', NULL, '1', 'fra', '1900', 'study', NULL, NULL, NULL, 'FRAPOLY_DBS_HS', 'fra', 'stan1290', 'French', 'français', 'L', 'FR', '48', '2', '1', 'fr', '77200000', 'Andorra and France', 'Also in Algeria, Andorra, Austria, Belgium, Benin, Burkina Faso, Burundi, Cambodia, Cameroon, Canada, Central African Republic, Chad, Comoros, Congo, Côte d’Ivoire, Democratic Republic of the Congo, Djibouti, Equatorial Guinea, French Guiana, French Polynesia, Gabon, Guadeloupe, Guinea, Haiti, India, Israel, Italy, Lebanon, Libya, Luxembourg, Madagascar, Mali, Martinique, Mauritania, Mauritius, Mayotte, Monaco, Morocco, Mozambique, New Caledonia, Niger, Philippines, Puerto Rico, Réunion, Rwanda, Saint Pierre and Miquelon, Saudi Arabia, Senegal, Seychelles, South Africa, Switzerland, Togo, Tunisia, United Arab Emirates, United Kingdom, United States, U.S. Virgin Islands, Vanuatu, Wallis and Futuna.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('97', 'English-1850-Williams-Gospels-Harmony-of-the-Evangelists', 'ENGWIL', 'English (1850) Williams Gospels (Harmony of the Evangelists)', NULL, 'English (1850) Williams Gospels (Harmony of the Evangelists): Reverend Isaac Williams, a distinguished figure of the Oxford Movement, also known as the "Tractarians," contributed to religious literature through his work "A Harmony of the Four Evangelists," published in 1850 by F. & J. Rivington. Born in 1802, Williams was not only a devoted student but also a disciple of John Keble, a prominent leader in the Oxford Movement. This movement, deeply rooted in the University of Oxford, sought to revive the rich traditions and sacramental life of the Church of England. Williams'' contribution to this movement included both poetry and prose, with one of his most notable works being the tract titled "On Reserve in Communicating Religious Knowledge." His "Harmony of the Four Evangelists" is a testament to his theological depth and commitment to integrating the narratives of Matthew, Mark, Luke, and John into a cohesive and harmonized account of the Gospel. This work reflects Williams'' scholarly approach to Biblical texts and his commitment to the high-church tradition of the Anglican faith. It remains a significant piece in the study of the Gospels, offering insights into the interconnectedness of the Evangelists'' accounts.', 'historic', NULL, '99', 'eng', '1850', 'study', NULL, NULL, NULL, 'ENGWIL_DBS_HS/English-(1850)-Williams-Gospels-(Harmony-of-the-Evangelists)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('98', 'French-1988-Genesis-Portion', 'FRALSG', 'French (1988) Genesis Portion', 'Genèse (1988)', 'La Bible; Ancien et Noveau Testament; The French Bible Alliance Biblique Universelle ', 'genesis', NULL, '219', 'fra', '1988', 'genesis', NULL, NULL, 'The Long Now Foundation', 'FRALSG_DBS_HS/French-(1988)-Genesis-Portion', 'fra', 'stan1290', 'French', 'français', 'L', 'FR', '48', '2', '1', 'fr', '77200000', 'Andorra and France', 'Also in Algeria, Andorra, Austria, Belgium, Benin, Burkina Faso, Burundi, Cambodia, Cameroon, Canada, Central African Republic, Chad, Comoros, Congo, Côte d’Ivoire, Democratic Republic of the Congo, Djibouti, Equatorial Guinea, French Guiana, French Polynesia, Gabon, Guadeloupe, Guinea, Haiti, India, Israel, Italy, Lebanon, Libya, Luxembourg, Madagascar, Mali, Martinique, Mauritania, Mauritius, Mayotte, Monaco, Morocco, Mozambique, New Caledonia, Niger, Philippines, Puerto Rico, Réunion, Rwanda, Saint Pierre and Miquelon, Saudi Arabia, Senegal, Seychelles, South Africa, Switzerland, Togo, Tunisia, United Arab Emirates, United Kingdom, United States, U.S. Virgin Islands, Vanuatu, Wallis and Futuna.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('99', 'Greek-1550-Stephanus-New-Testament-print', 'GRCSTEP', 'Greek (1550) Stephanus New Testament (Print)', 'Καινή Διαθήκη του Στεφάνου (1550, έντυπη)', 'The 1550 Stephanus New Testament, printed by the renowned typographer and scholar Robert Estienne (also known as Robert Stephani or Stephanus in Latin), is a seminal work in the history of biblical texts. Born in Paris in 1503, Robert Estienne was the son of the famous printer Henri Estienne. After his father''s death in 1526, Robert took over the family''s printing business. During the reign of King Francis I of France, he gained prominence as the “Royal Typographer” and the “Printer in Greek to the king,” known for his Greek editions of classical works, grammatical texts, and schoolbooks.<br><br>Stephanus is especially celebrated for his contributions to religious texts, notably the entire Hebrew Bible (1539-43) and his four editions of the Greek New Testament (1546, 1549, 1550, 1551). His 1550 edition, the “Editio Regia” or Royal Edition, was particularly influential. It was based on 15 Greek Byzantine manuscripts, the Complutensian Polyglot, and two Alexandrian Codices, which harmonized well with Erasmus'' Greek text. This concordance affirmed the Erasmus Greek New Testament as the “Received Text” for the subsequent 500 years.<br><br>The 1550 edition was distinguished by its exquisite Greek font and large folio size. It was also the first to include a textual apparatus with readings from the 15 Greek manuscripts used. This edition, along with the fourth edition, standardized the Erasmus text, forming the foundation for all future Bibles up to 1881. Stephanus'' work solidified the dominance of the text begun by Erasmus, which was fundamental for all the translations in the vernacular languages of the Reformation. The 1550 Greek Testament of Stephanus thus played a critical role in the textual criticism of the Bible, affirming the purity and divine authorship of the Word of God.', 'historic', NULL, '2', 'grc', '1550', 'reprint', NULL, NULL, NULL, 'GRCSTEP_DBS_HS/Greek-(1550)-Stephanus-New-Testament-(print)', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('100', 'English-1918-Reference-Passage-New-Testament-Study-Bible', 'ENGKJV', 'English (1918) Reference Passage New Testament Study Bible', NULL, 'The 1918 Reference Passage New Testament Study Bible emerges during a pivotal time in American Bible printing, which saw a remarkable evolution from the 17th to the early 20th century. Initially, Bible production in America was somewhat constrained, with most copies being imported from European publishers or brought by settlers. However, with technological advancements in printing and a surge in demand, the landscape of Bible publishing dramatically transformed by the late 18th and early 19th centuries. Major urban centers like Boston, Philadelphia, and New York emerged as key hubs for Bible publication.<br><br>Paul Gutjahr, a renowned Bible historian, highlights the Bible''s immense popularity during the 18th century in North America, describing it as the most printed, distributed, and read text of the time. The Bible''s significance extended beyond its religious and spiritual importance; it became a cherished family heirloom, symbolizing a connection to distant relatives and ancestors, as well as a source of familial pride. In response to this cultural significance, publishers began crafting Bibles with ornate, embossed covers and elaborate illustrations, sometimes in color. These visually appealing Bibles were often displayed prominently in homes, symbolizing both the owner''s devout faith and their appreciation for the Bible''s aesthetic and cultural value.<br><br>The 1918 Reference Passage New Testament Study Bible stands as a testament to this rich period of development in Bible publishing, representing a harmonious blend of religious importance and cultural appreciation in American society.', 'historic', NULL, '322', 'eng', '1918', 'study', 'The Alpha Publishing Co.', NULL, NULL, 'ENGKJV_DBS_HS/English-(1918)-Reference-Passage-New-Testament-Study-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('101', 'Greek-0565-ca.-Codex-Beratinus-Purpureus-Phi-WDL-21766', 'GRCBERA', 'Greek (0565 ca.) Codex Beratinus Purpureus Phi (WDL-21766)', 'Κώδικας Βερατίνους Πορφυρούς Φι (0565 περ.) (WDL-21766)', 'The Codex Beratinus Purpureus Phi, also known as Codex of Berat number 1 (Gregory-Aland no. 043), is a significant 6th-century manuscript. Believed to have been copied during the reign of Byzantine Emperor Justinian the Great (circa 483–565, reigned 527–65), it was created in an imperial scriptorium, likely in Constantinople or somewhere along the shores of Asia Minor. This manuscript contains the Gospels of Matthew and Mark in their original Greek and is esteemed as the oldest written document housed at the Central State Archive in Tirana, Albania.<br><br>Its journey to Berat, south-central Albania, where it was present since 1356, remains a mystery. The manuscript faced threats during the Communist regime in Albania post-World War II, leading to its concealment in the cathedral church of Berat alongside the Codex Aureus Anthimi. Rediscovered in 1968 after nearly being destroyed by humidity, it underwent restoration in 1971 at the Institute of Archeology in Beijing, China.<br><br>Since its return to Albania in January 1972, the Codex Beratinus Purpureus Phi has been preserved in Tirana. In 2005, it was inscribed on the UNESCO Memory of the World register alongside Codex Aureus Anthimi, highlighting its global cultural significance. The manuscript comprises 190 folios on purple parchment, written in Greek majuscule letters in two columns with 17 lines per page. Notably, the ink is silver and gold, with gold reserved exclusively for the nomina sacra. Its embossed metal plate covers, produced in 1805, were probably attached during a restoration at that time, adding to its historical and aesthetic value.', 'historic', 'https://www.wdl.org/en/item/18191', '58', 'grc', '565', 'manuscript', 'World Digital Library', NULL, 'World Digital Library', 'GRCBERA_DBS_HS/Greek-(0565-ca.)-Codex-Beratinus-Purpureus-Phi-(WDL-21766)', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('102', 'Hebrew-1700-ca.-The-Haftarah-Pentatech-Prophets-and-OT-Portions-Illuminated-WDL-7382', 'HEBHAFT', 'Hebrew (1700 ca.) The Haftarah - Pentatech Prophets and OT Portions - Illuminated (WDL-7382)', 'עברית - ההפטרה (1700 בקירוב, חמשה חומשי תורה, נביאים וקטעי תנ"ך, מואר) (WDL-7382)', 'This illuminated codex, thought to date from the 18th century, is a remarkable example of a Haftarah, a Jewish text traditionally read from the Prophets on the Sabbath, festivals, and holy days. Comprising 263 parchment sheets bound in leather, this Haftarah contains a diverse array of biblical texts. It includes the five books of Moses (Pentateuch), selections from the books of the Prophets, the Hamesh Megillot (Five scrolls) which encompass the Song of Songs, Ruth, Lamentations, Ecclesiastes, and Esther, as well as the Book of Proverbs. Additionally, it contains prayers for everyday use, Sabbaths, and holy days, adhering to Ashkenazi practices.<br><br>The scribe and likely the illuminator of this manuscript was Abraham bar Chizkija ha Lévi. The codex has a documented history of ownership, having previously been in the possession of Samuel Gráf of Csakatorn and Anton Kohn of Zagreb around 1858. A subsequent owner was Moses Issachar, son of Isaac of Schleining. This historically significant manuscript is now housed in the collections of the Slovak National Library, serving as a vital link to the religious and cultural practices of Jewish communities in the 18th century and earlier.', 'historic', 'https://www.wdl.org/en/item/7382', '78', 'heb', '1700', 'illuminated', 'World Digital Library', NULL, 'World Digital Library', 'HEBHAFT_DBS_HS/Hebrew-(1700-ca.)-The-Haftarah-Pentatech-Prophets-and-OT-Portions-Illuminated-(WDL-7382)', 'heb', 'hebr1245', 'Hebrew', 'Israeli Hebrew', 'L', 'IL', '31.10565', '35.01788', '1', 'he', '5000000', NULL, 'Also in Australia, Canada, Germany, Palestinian West Bank and Gaza, Panama, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('103', 'Greek-English-1859-Critical-New-Testament-Scholz-and-Griesbah', 'GRCGRIE', 'Greek-English (1859) Critical New Testament (Scholz and Griesbah)', 'Κριτική Καινή Διαθήκη (1859, Scholz και Griesbach)', 'The 1859 "Critical Greek and English New Testament" is a significant scholarly work that combines the efforts of biblical scholars Scholz and Griesbach. This edition is characterized by its integration of the Greek text of Scholz with the textual and marginal readings of Griesbach, offering a comprehensive view of the New Testament text.<br><br>One of the key features of this critical edition is the inclusion of variations from notable editions of the New Testament, such as those by Stephens (1550), Beza (1598), and the Elzevir edition (1633). This amalgamation of various influential texts provides a rich tapestry of textual variations and interpretations, making it a valuable resource for in-depth biblical study and research.<br><br>Additionally, this work incorporates the English Authorized Version alongside its marginal renderings, allowing for a comparative study between the Greek and English texts. The combination of Greek and English texts in one volume makes it particularly useful for English-speaking scholars and students of the Bible who wish to engage closely with the original Greek language of the New Testament.<br><br>The "Critical Greek and English New Testament" by Scholz and Griesbach stands out as a comprehensive and scholarly resource, contributing significantly to the field of biblical textual criticism and exegesis.', 'historic', NULL, '33', 'grc', '1859', 'scan', 'Fowler & Wells Co., Publishers', NULL, NULL, 'GRCGRIE_DBS_HS/Greek-English-(1859)-Critical-New-Testament-(Scholz-and-Griesbah)', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('104', 'English-1882-Parallel-New-Testament-KJV1611-RV1881-Greek-Scrivener', 'ENGKJV', 'English (1882) Parallel New Testament KJV1611 RV1881 Greek (Scrivener)', NULL, 'The 1882 Parallel New Testament presents a unique tri-columnar arrangement, juxtaposing the King James Version (KJV) of 1611, the Revised Version (RV) of 1881, and the original Greek text. This edition is a remarkable testament to the evolution of Biblical translation and textual scholarship. It showcases the authorized version, set forth in 1611, in one column, providing readers with a direct comparison to the revised version that emerged 270 years later. The revised version, a product of extensive scholarly work, sought to update and correct the earlier KJV based on the best available manuscripts and linguistic understanding of the time.<br><br>The inclusion of the original Greek text, particularly according to the text followed in the authorized version, with variations adopted in the revised version, is of significant scholarly interest. This Greek text, meticulously edited by renowned textual critic F.H.A. Scrivener, offers insights into the textual basis of the English translations and highlights the differences and developments in textual criticism and translation methodologies over the centuries.<br><br>This parallel arrangement not only serves as a valuable tool for comparative study and analysis but also reflects the dynamic nature of Biblical scholarship. It allows readers to trace the changes in translation and interpretation, understand the nuances of linguistic evolution, and appreciate the efforts of scholars in bringing the Biblical text closer to its original form. The 1882 Parallel New Testament stands as a testament to the enduring endeavor to understand and convey the Biblical message with clarity and fidelity.', 'historic', NULL, '137', 'eng', '1882', 'study', 'Rev. F. H. Scrivener, M.A., L.L.D., University Press', NULL, NULL, 'ENGKJV_DBS_HS/English-(1882)-Parallel-New-Testament-KJV1611-RV1881-Greek-(Scrivener)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('105', 'English-1805-National-Comprehensive-Family-Bible-Study', 'ENGKJV', 'English (1805) National Comprehensive Family Bible (Study)', NULL, 'The "National Comprehensive Family Bible: The Holy Bible with the Commentaries of Scott and Henry," edited by the Rev John Eadie and published in 1805, is a significant work in the realm of biblical study and family devotion. This edition of the Bible is unique in its incorporation of commentaries by Scott and Henry, along with thousands of critical and explanatory notes selected from eminent authors across Europe and America. The aim is to provide a comprehensive and in-depth understanding of the Scriptures.<br><br>The preface by Dr. Eadie emphasizes the importance of the Bible in the national and spiritual life of the country. He highlights the significance of the Protestant liberty to study and disseminate biblical truth freely, a privilege secured through the sacrifices of previous generations. Eadie extols the Bible''s influence on the nation''s greatness, attributing the country''s achievements in various fields – from science and commerce to social progress and mechanical inventions – to the ethical and moral framework provided by Christian teachings.<br><br>Eadie''s perspective underscores the belief that Christian civilization leads to true greatness, as it fosters liberty, fraternity, and equality under the influence of Christian principles. He notes that while the Bible''s primary mission is salvation, it also has a profound impact on improving the temporal conditions of mankind. The Bible is seen as a source of healing and refreshment, not only for the individual but also for nations.<br><br>This edition of the Bible, often referred to as the "FAMILY BIBLE," is intended for prominent display and use in Christian households. It reflects the high regard in which Scripture is held and the efforts made to circulate it. Eadie''s preface also touches on the rejection and pity of infidelity, viewing it as antithetical to both patriotism and vital piety. The "National Comprehensive Family Bible" thus stands as a testament to the era''s reverence for the Bible and its role in shaping ecclesiastical and national identity.', 'historic', 'https://www.hbu.edu/publications/museums/Dunham_Bible_Museum/Preface-by-Dr-Eadie-to-National-Illustrated-Family-Bible.pdf', '566', 'eng', '1805', 'study', NULL, NULL, NULL, 'ENGKJV_DBS_HS/English-(1805)-National-Comprehensive-Family-Bible-(Study)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('106', 'English-1709-First-English-American-Bible-portions', 'ENGKJV', 'English (1709) First English American Bible (portions)', NULL, 'The first English American Bible, translated by Experience Mayhew in 1709, is an adaptation of John Eliot''s earlier translation. According to Trumbull, "every verse underwent revision and scarcely one remains without some alteration."<br><br>The Eliot Indian Bible, officially titled "Mamusse Wunneetupanatamwe Up-Biblum God" and commonly known as the Algonquian Bible, was the first translation of the Christian Bible into an indigenous American language and the first Bible published in British North America. John Eliot, an English Puritan missionary, translated the Geneva Bible into the Massachusett language. This groundbreaking work was first printed in Cambridge, Massachusetts, initially with just the New Testament in 1661. A complete edition featuring all 66 books of the Old and New Testaments followed in 1663.<br><br>The 1663 edition''s cover page, inscribed with "Mamusse Wunneetupanatamwe Up Biblum God," translates to "The Whole Holy His-Bible God, both Old Testament and also New Testament. This turned by the servant of Christ, who is called John Eliot." The production and printing of Eliot''s translation were supported by the Society for the Propagation of the Gospel in New England, headed by the renowned scientist Robert Boyle.', 'historic', NULL, '98', 'eng', '1709', 'scan', 'GreatSite.com', NULL, NULL, 'ENGKJV_DBS_HS', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('107', 'French-Breton-1886-Testamant-Nevez-Diglot-Ostervald', 'FRAOST', 'French-Breton (1886) Testamant Nevez Diglot (Ostervald)', 'Testamant Nevez Diglot (1886, Ostervald)  ', 'French-Breton (1886) Testamant Nevez Diglot (Ostervald) presents a dual language edition of the New Testament, showcasing the collaborative efforts of Welsh-speaking missionaries and Breton writers to make the biblical texts accessible to Breton speakers. Initiated by John Jenkins in the 1830s, the translation process aimed to revise the scholarly language of the Le Gonidec version to a form more understandable to the general populace. Jenkins'' revision, influenced by Greek, Welsh, and English texts, was further refined with the assistance of Guillaume Ricou and later, Rev James Williams. Alfred Llewellyn Jenkins, continuing his father''s mission, collaborated with Monsieurs Rohan, Luzel, and V. E. Bouhon for the 1886 revision, which was published alongside the French language. This endeavor not only made the New Testament accessible in Breton but also initiated the translation of the Old Testament into Breton, culminating in the publication of Genesis in 1897 and several reprints of the New Testament in the early 20th century.', 'historic', NULL, '126', 'fra', '1886', 'scan', 'Rue De Clichy', NULL, NULL, 'FRAOST_DBS_HS/French-Breton-(1886)-Testamant-Nevez-Diglot-(Ostervald)', 'fra', 'stan1290', 'French', 'français', 'L', 'FR', '48', '2', '1', 'fr', '77200000', 'Andorra and France', 'Also in Algeria, Andorra, Austria, Belgium, Benin, Burkina Faso, Burundi, Cambodia, Cameroon, Canada, Central African Republic, Chad, Comoros, Congo, Côte d’Ivoire, Democratic Republic of the Congo, Djibouti, Equatorial Guinea, French Guiana, French Polynesia, Gabon, Guadeloupe, Guinea, Haiti, India, Israel, Italy, Lebanon, Libya, Luxembourg, Madagascar, Mali, Martinique, Mauritania, Mauritius, Mayotte, Monaco, Morocco, Mozambique, New Caledonia, Niger, Philippines, Puerto Rico, Réunion, Rwanda, Saint Pierre and Miquelon, Saudi Arabia, Senegal, Seychelles, South Africa, Switzerland, Togo, Tunisia, United Arab Emirates, United Kingdom, United States, U.S. Virgin Islands, Vanuatu, Wallis and Futuna.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('108', 'English-1869-Devotional-and-Practical-Polyglott-Bible-Study', 'ENGKJV', 'English (1869) Devotional and Practical Polyglott Bible (Study)', NULL, 'The Devotional and Practical Polyglott Family Bible, a significant mid-nineteenth-century publication, emerged from the prolific Glasgow-based publishing house of William Collins, Sons & Company. Recognized for their extensive Bible production, Collins catered not only to the Scottish and British markets but also to the rapidly growing overseas audience during the Victorian era. <br><br> This particular edition, comprising both the Old and New Testaments, stands out for its comprehensive approach and practical orientation, designed to resonate with families during a time when Bible reading was a central part of daily life and spiritual practice. The term ''Polyglott'' in the title suggests the inclusion of multiple languages or extensive annotations, indicative of the educational aspirations of the Victorian era, aiming to provide a more profound and insightful engagement with the scriptures. <br><br> William Collins, Sons & Company''s reputation for producing high-quality religious texts is well-documented. Their Bibles were known for their reliability, accessibility, and the elegance of their presentation, making them a preferred choice for family devotionals. The Devotional and Practical Polyglott Family Bible exemplifies the Victorian era''s commitment to religious education and the dissemination of biblical knowledge across diverse population segments. This Bible not only served as a spiritual guide but also as an educational tool, reflecting the era''s broader cultural and educational values.', 'historic', NULL, '359', 'eng', '1869', 'study', 'National Publishing Company', NULL, NULL, 'ENGKJV_DBS_HS/English-(1869)-Devotional-and-Practical-Polyglott-Bible-(Study)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('109', 'English-1823-Kneeland-New-Testament', 'ENGKNT', 'English (1823) Kneeland New Testament', NULL, 'English (1823) Kneeland New Testament: This rare translation was first published in Philadelphia in two volumes, the Gospels in 1822, and Acts-Revelation in 1823. This first two-volume edition contains both the Greek text and Kneeland’s own translation on each page. In his preface, he claims that he is the first to publish “a Greek and English testament.” The Greek text is that of Griesbach, which, according to Kneeland, was in his day “the most correct Greek text, as acknowledged by all.” A one-volume edition of the English translation alone appeared in 1823. Kneeland lived from 1774-1844.<br><br>Reflecting the scholarship of the time, frequent references are made throughout the notes to the translations of George Campbell, Wakefield, Scarlett, MacKnight, Charles Thomson, and the 1808 Improved Version. Parkhurst’s Greek lexicon is also referenced regularly.<br><br>Kneeland himself was a story of continually developing liberalism. In 1803 he became a Universalist after spending a few years as a Baptist preacher. He stayed a Universalist for 26 years. It was during this period that his friend, Hosea Ballou, helped allay his doubts about the inspiration of Scripture, leading to his producing this translation. In 1829, he left the Universalists, moved to Boston, and founded a group of freethinkers. Here he enjoyed the friendship of men such as William Ellery Channing, Ralph Walso Emerson, Theodore Parker, and William Lloyd Garrison. In 1834 he was tried and convicted for blashphemy. After 4 years of appeals and litigation, he served 60 days. Simms says his trial and conviction were “utter absurdities, growing out of the narrowness of the day.” In 1839, hoping to found a freethinker colony, he moved to Iowa where he died in 1844. Throughout his life, he was an avid writer and publisher.', 'historic', 'http://www.biblecollectors.org/biographies/abner_kneeland.htm', '10', 'eng', '1823', 'scan', 'Abner Kneeland, Minister of the First Independent Church of Christ', NULL, NULL, 'ENGKNT_DBS_HS/English-(1823)-Kneeland-New-Testament', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('110', 'English-1897-Emphasised-Study-Bible-Rotherham-Vol.-1-4', 'ENGEMP', 'English (1897) Emphasised Study Bible (Rotherham) Vol. 1-4', NULL, 'The Emphasised Bible by Joseph B. Rotherham, first published in 1897 in four volumes, marks a significant period in the history of Bible publishing in America. Despite the initial limitations in Bible printing in the United States during the seventeenth and early eighteenth centuries, largely due to reliance on British and European printers, the landscape of Bible publishing underwent a dramatic transformation by the late eighteenth and early nineteenth centuries. Cities like Boston, Philadelphia, and New York emerged as prominent hubs for Bible publishing, responding to an increasing demand fueled by technological advancements in printing machinery and techniques.<br><br>Paul Gutjahr, a renowned Bible historian, notes that during much of the eighteenth century, the Bible enjoyed immense popularity in North America, becoming the most printed, distributed, and read text. This was not just due to its religious significance; for many American families, the Bible served as a cherished link to their heritage, connecting them to distant relatives and commemorating ancestors. It was a symbol of spiritual commitment and a source of familial pride.<br><br>In response to this deep cultural and familial connection, publishers began producing Bibles with ornate and decorative designs, often featuring carved or embossed covers and elaborate illustrations, some even in color. These aesthetically appealing Bibles were not just religious texts but also treasured family heirlooms, displayed prominently in homes. The Emphasised Bible, with its emphasis on linguistic precision and theological depth, is a product of this rich tradition of Bible publishing in America, reflecting both the scholarly rigor and the artistic craftsmanship of its time.', 'historic', NULL, '101', 'eng', '1897', 'study', 'The Standard Publishing Company', NULL, NULL, 'ENGEMP_DBS_HS/English-(1897)-Emphasised-Study-Bible-(Rotherham)-Vol.-1-4', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('111', 'Aramaic-1514-Complutensian-Polyglot-Bible-Vol-4-of-5-Grk-Heb-Lat-Aramaic-StudyWDL-10636', 'AII1514', 'Aramaic (1514) Complutensian Polyglot Bible (Vol 4 of 5) Grk-Heb-Lat-Aramaic Study(WDL-10636)', 'Vetus testamentū multiplici lingua nūc primo impressum, Et imprimis Pentateuchus Hebraico Greco atq[ue] Chaldaico idiomate', 'The fourth volume of the Complutensian Polyglot Bible, completed in 1514 under the auspices of Cardinal Francisco Jiménez de Cisneros, is a landmark in biblical studies, featuring the New Testament in Greek and Latin. This work is part of a broader project to compile the first printed multilingual Bible, aiming to enhance scholarly access to scriptural texts in their original languages. The production, led by Arnaldo Guillén de Brocar, showcases exquisite typographical artistry, especially noted for the Greek characters, considered among the most beautiful ever produced. The Complutensian Polyglot''s meticulous parallel presentation of texts was revolutionary, fostering comparative scriptural studies and contributing significantly to the Renaissance humanist scholarship. Its publication, following papal approval in 1520, marked a significant advancement in biblical scholarship, offering an unprecedented tool for the study of the New Testament. The inclusion of comprehensive linguistic resources, such as dictionaries and grammars for Hebrew, Aramaic, and Greek within the final volumes, underscored the project''s academic rigor and its foundational role in biblical linguistics and exegesis.', 'historic', 'https://www.wdl.org/en/item/10636', '125', 'aii', '1514', 'study', 'Arnao Guillén de Brocar, Alcalá de Henares', NULL, 'World Digital Library', 'AII1514_DBS_HS/Aramaic-(1514)-Complutensian-Polyglot-Bible-(Vol-4-of-5)-Grk-Heb-Lat-Aramaic-Study(WDL-10636)', 'aii', 'assy1241', 'Assyrian Neo-Aramaic', 'Sūreṯ', 'L', 'IQ', '36.75', '43', '6b', NULL, '626000', 'Iraq', 'Northern Iraq, Baghdad, Basrah, Karkuk, Arbil. Also in Armenia, Australia, Austria, Azerbaijan, Belgium, Brazil, Canada, Cyprus, France, Georgia, Germany, Greece, Iran, Italy, Lebanon, Netherlands, New Zealand, Russian Federation (Europe), Sweden, Switzerland, Syria, Turkey (Asia), United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('112', 'English-1907-Naves-Study-Bible-KJV', 'ENGKJV', 'English (1907) Naves Study Bible (KJV)', NULL, 'Nave''s Study Bible, a product of Orville J. Nave''s extensive and meticulous study, stands as a comprehensive encyclopedic tool for exploring the Bible. Formulated over fourteen years, it organizes biblical content under well-defined headings and subjects, making it highly practical for diverse readers including professionals, theologians, and anyone interested in biblical teachings. This study Bible, grounded in the King James Version, enables focused thematic study and easy reference across the scriptures. Its unique organization and practical utility make it invaluable for applying biblical wisdom to various aspects of life and spirituality, marking it as a significant contribution to biblical scholarship and a facilitator for deeper scriptural understanding.', 'historic', NULL, '371', 'eng', '1907', 'study', NULL, NULL, NULL, 'ENGKJV_DBS_HS/English-(1907)-Naves-Study-Bible-(KJV)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('113', 'English-1862-Christian-Soldiers-Penny-Bible', 'ENGCSPB', 'English (1862) Christian Soldiers Penny Bible', NULL, 'The "Souldiers Pocket Bible," first issued in 1643, is a historically significant artifact from the English Civil War, particularly associated with the soldiers of Oliver Cromwell''s New Model Army. This pamphlet version of the Protestant Bible, notable for its absence of a possessive apostrophe in the title, was a compact and portable guide tailored for the spiritual needs of soldiers amidst the tumult of war.<br><br>The discovery of this unique version of the Bible is credited to George Livermore, an American book collector from Cambridgeport, Massachusetts, who stumbled upon it in 1854. Livermore''s find revealed that the Bible known to be carried by Cromwell''s soldiers was not the complete 66-book Protestant Bible, but a significantly condensed version in the form of an octavo booklet, roughly the size and thickness of a 20th-century international travel passport. This realization shed new light on the spiritual practices and resources available to soldiers during the 17th century.<br><br>The "Souldiers Pocket Bible" stands out not only for its physical attributes but also for the historical context it represents. Being part of the standard gear of Cromwell''s army, it signifies the integration of faith and military life in that era. Its distribution among soldiers reflects the emphasis on religious motivation and moral support during one of England''s most tumultuous historical periods, underscoring the significance of religion in shaping the events and ideologies of the English Civil War.', 'historic', NULL, '1', 'eng', '1862', 'scan', 'Willis and Sotheran', NULL, NULL, 'ENGCSPB_DBS_HS/English-(1862)-Christian-Soldiers-Penny-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('114', 'Greek-English-1897-Interlinear-Literal-Translation-Greek-New-Testament', 'GRCTISH', 'Greek-English (1897) Interlinear Literal Translation - Greek New Testament', 'Διαγλωσσική Κυριολεκτική Μετάφραση (1897, Ελληνική Καινή Διαθήκη)', 'The 1897 "Interlinear Literal Translation of the Greek New Testament" is a comprehensive work that offers a unique approach to studying the New Testament. This edition provides a literal interlinear translation of the Greek New Testament text, with the authorized version conveniently presented in the margins for quick and easy reference.<br><br>One of the key features of this publication is the inclusion of various readings from significant editions of the Greek New Testament, such as Elzever 1624, Griesbach, Lachmann, Tischendorf, Tregelles, Alford, and Wordsworth. This aspect allows readers to compare different textual interpretations and understand the nuances of the original Greek text.<br><br>Additionally, this work includes a new Greek-English New Testament lexicon, which is a valuable tool for those studying the Greek language and its application in the New Testament. The lexicon is supplemented by a chapter that elucidates the synonyms of the New Testament, providing deeper insight into the Greek vocabulary and its usage. The complete index to the synonyms further enhances the utility of this publication.<br><br>This interlinear translation, with its comprehensive approach to presenting the Greek New Testament text alongside its English translation and critical apparatus, is a valuable resource for scholars, theologians, and students of biblical languages and texts. It offers a detailed and accessible means to study the New Testament in its original language, alongside an English translation for reference.', 'historic', NULL, '72', 'grc', '1897', 'study', 'The University of Chicago Press', NULL, NULL, 'GRCTISH_DBS_HS/Greek-English-(1897)-Interlinear-Literal-Translation-Greek-New-Testament', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('115', 'English-1855-Translation-of-The-Gospels-Nortan-Bible-Vol.1-2-Gospels', 'ENGNOR', 'English (1855) Translation of The Gospels (Nortan) Bible - Vol.1-2 Gospels', NULL, 'A translation of the Gospels : with notes by Norton, Andrews, 1786-1853, tr; Metcalf and Company; Massachusetts Bible Society', 'historic', NULL, '86', 'eng', '1855', 'scan', 'Little, Brown, and Company', NULL, NULL, 'ENGNOR_DBS_HS/English-(1855)-Translation-of-The-Gospels-(Nortan)-Bible-Vol.1-2-Gospels', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('116', 'Coptic-1898-Psalter-dialect-of-Upper-Egypt-Psalms', 'COPPSA', 'Coptic (1898) Psalter (dialect of Upper Egypt) Psalms', 'Ⲙⲉⲧⲛⲓⲙ ⲛ̀ⲛⲉⲛⲧⲟⲥ (1898) Ⲡⲓⲯⲁⲗⲧⲉⲣ (ⲁⲣⲁⲃⲓⲕⲟⲛ)', 'The term ‘Coptic’ refers to the form of Egyptian in use after the establishment of Christianity in Egypt during the 3rd century. Sometimes called Neo-Egyptian, it is a development of Ancient Egyptian, in use until the 6th century B.C., and it''s later Hieratic and Demotic forms. These long succeeding periods made Coptic the living language with the longest recorded history. The few remaining Coptic speakers succumbed to the Arabic language in the 17th century.<br>Coptic was spoken in several dialects. Scriptures are extant in the Bohairic (Coastal, Lower Egypt); Fayumic or Bashmuric, Sub- Achmimic, and Middle Egyptian; and Sahidic and Achmimic (Upper Egyptian) dialects. Bohairic, earlier known as Memphitic, was the usage of Alexandria and hence survives as the ecclesiastical and liturgical language of the Coptic Church. However, it appears that Scriptures first appeared (3rd century) in Sahidic, because Lower Egypt had been Hellenized and the Greek Scriptures could be used there. Although considerable research remains to be done on the Coptic texts, these early versions cast light on the text used by the early Church.<br>The Coptic alphabet employs 24 Greek characters and 7 characters retained from Demotic script.', 'historic', NULL, '9', 'cop', '1898', 'scan', 'Clarendon Press', NULL, NULL, 'COPPSA_DBS_HS/Coptic-(1898)-Psalter-(dialect-of-Upper-Egypt)-Psalms', 'cop', 'copt1239', 'Coptic', 'ϯⲙⲉⲧⲣⲉⲙⲛ̀ⲭⲏⲙⲓ ~ ⲧⲙⲛ̄ⲧⲣⲙ̄ⲛ̄ⲕⲏⲙⲉ', 'E', 'EG', '29.47203', '31.2053', '9', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('117', 'English-1851-Oriental-Bible-Cobbin-Study', 'ENGKJV', 'English (1851) Oriental Bible (Cobbin) Study', NULL, 'English (1851) Oriental Bible (Cobbin) Study: The Oriental Bible, compiled by Rev. Ingram Cobbin, M.A., presents an in-depth study of the sacred Scriptures, enriched with marginal references derived from authoritative sources. This comprehensive work stands out for its extensive use of notes, wood engravings, and colored maps, which serve to illuminate the historical, geographical, and cultural contexts of the Bible. The edition is particularly notable for its exploration of the "Orientalisms" of the Bible, shedding light on the unique aspects of the regions and cultures where the biblical narratives took place.<br><br>Cobbin''s work is a significant contribution to biblical scholarship, particularly in its effort to bridge the gap between ancient biblical times and the contemporary reader. The inclusion of various readings and detailed annotations offers a multifaceted perspective of the biblical texts, providing a richer understanding of their meanings and implications. The wood engravings and maps add a visual dimension to the study, making the biblical world more accessible and comprehensible to readers. This edition is an invaluable resource for scholars, students, and anyone interested in a deeper, more contextual understanding of the Bible.', 'historic', NULL, '166', 'eng', '1851', 'study', 'Partridge and Oakey', NULL, NULL, 'ENGKJV_DBS_HS/English-(1851)-Oriental-Bible-(Cobbin)-Study', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('118', 'Hebrew-1898-Letteris-Old-Testament', 'HEBLET', 'Hebrew (1898) Letteris Old Testament', 'עברית - תנ"ך לטריס (1898, התנ"ך)', 'The 1866 Letteris edition of the Masoretic text, created by Max Letteris for the British and Foreign Bible Society, stands out as a significant contribution to the printing of the Hebrew Bible. Max Letteris, a noted poet and printer from Amsterdam, crafted an edition that gained immense popularity, widely reprinted across both Jewish and Christian communities. This edition is renowned for its accuracy and readability, making it a valuable resource in the study and dissemination of Hebrew scriptures during the late 19th century. The widespread acceptance and use of the Letteris edition in diverse religious circles highlight its impact and importance in the history of biblical publications, exemplifying its role in enhancing the accessibility and understanding of the Hebrew scriptures.', 'historic', NULL, '2', 'heb', '1898', 'scan', NULL, NULL, 'Internet Archive', 'HEBLET_DBS_HS/Hebrew-(1898)-Letteris-Old-Testament', 'heb', 'hebr1245', 'Hebrew', 'Israeli Hebrew', 'L', 'IL', '31.10565', '35.01788', '1', 'he', '5000000', NULL, 'Also in Australia, Canada, Germany, Palestinian West Bank and Gaza, Panama, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('119', 'English-1904-Worrell-New-Testament-Bible', 'ENGWORR', 'English (1904) Worrell New Testament Bible', NULL, 'Adolphus Spalding Worrell''s "The New Testament Revised and Translated," published in 1904 during the onset of the Russo-Japanese war, represents a distinctive contribution to biblical translation. Worrell, a figure known for his strong convictions and belief in divine healing, embarked on this translation project with a profound sense of divine mission. <br><br> Raised as a Landmark Baptist before converting to Pentecostalism, Worrell''s translation reflects these theological perspectives. His goal was to update the King James Version''s accuracy and grammar, infusing his personal study notes into the text. This translation is noted for its unique features, such as capitalizing pronouns referring to deity, restricting the solemn form of pronouns and verbs solely to Deity, and the precise use of quotation marks for direct quotations. <br><br> Worrell''s work is particularly notable for its fidelity to the original Greek, especially in the translation of critical words like ''baptidzo'' and ''ecclesia.'' He believed that accurate translation of these terms could have prevented many divisions within Christendom. The Greek text of Westcott and Hort, modified by Scrivener and others, served as the foundation for this work. <br><br> Beyond his translation, Worrell authored several volumes, including "Review of Corrective Church Discipline," "Principles of English Grammar," and "The First and Seventh Day Controversy," highlighting his diverse interests and contributions. His translation, though not claiming absolute perfection, aimed at pleasing the "Supreme Critic" and is seen as a significant effort in bringing forth a more accurate and comprehensible version of the New Testament.', 'historic', NULL, '14', 'eng', '1904', 'scan', NULL, NULL, NULL, 'ENGWORR_DBS_HS/English-(1904)-Worrell-New-Testament-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('120', 'Greek-1550-Stephanus-Greek-NT', 'GRCSTEP', 'Greek (1550) Stephanus Greek New Testament', 'Ελληνική Καινή Διαθήκη του Στεφάνου (1550)', 'The 1550 Stephanus Greek New Testament, printed by Robert Estienne (also known as Robert Stephani or Stephanus in Latin), marks a pivotal moment in the history of biblical scholarship. Born in Paris in 1503, Robert Estienne was the son of the renowned printer Henri Estienne. Taking over his father''s printing shop in 1526, Estienne established himself as a prominent figure in the world of publishing during the reign of King Francis I of France, earning the titles “Royal Typographer” and “Printer in Greek to the king.”<br><br>Robert Estienne is particularly celebrated for his religious texts, including the entire Hebrew Bible (1539-43) and his four editions of the Greek New Testament (1546, 1549, 1550, 1551). The 1550 edition, known as the “Editio Regia” or Royal Edition, is especially noteworthy. This edition was based on 15 other Greek Byzantine manuscripts, the Complutensian Polyglot, and two Alexandrian Codices, which harmonized remarkably well with Erasmus'' Greek text. This alignment effectively established the Erasmus Greek New Testament as the “Received Text” for the next several centuries, playing a crucial role in the Reformation.<br><br>The 1550 edition was not only a masterpiece in terms of its beautiful Greek font and large folio size, but it was also the first to include a textual apparatus listing the readings from the 15 Greek manuscripts used. This made it not only the most visually appealing but also the most important of Estienne''s texts.<br><br>Significantly, the third and fourth editions of Stephanus’ Greek New Testament solidified the Erasmus text as the foundation for all future Bibles until 1881. The work of Stephanus thus ensured the continued dominance of Erasmus'' text, which formed the basis for translations in the common languages of the Reformation era. His textual criticism efforts, particularly in the 1550 Greek Testament, affirmed the purity and authenticity of the Word of God, underscoring its divine authorship.', 'historic', NULL, '114', 'grc', '1550', 'scan', NULL, NULL, NULL, 'GRCSTEP_DBS_HS', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('121', 'English-1873-Cambridge-Paragraph-KJV-Study-Bible', 'ENGKJVPCE', 'English (1873) Cambridge Paragraph KJV Study Bible', NULL, 'The Pure Cambridge Edition of the King James Bible, also known as the Standard Text, represents a significant milestone in the evolution of biblical texts since the completion of the Authorized Version in 1611. First published around 1900 by the prestigious Cambridge University Press and Collins publishers, this edition is notable for its adherence to textual purity and fidelity to the original 1611 version. <br><br> The Pure Cambridge Edition stands in stark contrast to many modern versions of the Bible. It meticulously preserves the original formatting, including the standard Cambridge spelling, as well as the italics and punctuation used in the 1611 version. This scrupulous attention to detail ensures that the text remains accurate and faithful to the original scriptures. <br><br> Over the twentieth century, the Pure Cambridge Edition gained widespread acclaim and distribution, with millions of copies being issued by various Bible and missionary societies. Its popularity and usage underscored its status as a received text, regarded by many as an authoritative and reliable edition of the Bible. The edition''s commitment to maintaining the integrity and authenticity of the original King James Bible makes it a cherished version for those seeking a traditional and unaltered scriptural text. The Pure Cambridge Edition is more than just a religious text; it is a testament to the enduring legacy and influence of the King James Bible in the Christian world.', 'historic', NULL, '305', 'eng', '1873', 'study', 'Rev. F. H. Scrivener, M.A., L.L.D., University Press', NULL, 'Internet Archive', 'ENGKJVPCE_DBS_HS/English-(1873)-Cambridge-Paragraph-KJV-Study-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('122', 'English-1893-Book-of-Psalms-Metrical-Version-Bible-Psalms', 'ENGMVB', 'English (1893) Book of Psalms Metrical Version Bible - Psalms', NULL, 'The 1893 Metrical Version of the Book of Psalms represents a unique blend of religious devotion and poetic artistry, embodying a significant aspect of the Protestant Reformation, particularly its Calvinist stream. A metrical psalter, by its nature, is more than a mere translation; it''s a reimagining of the Psalms as vernacular poetry, crafted to be sung as hymns within the church. This approach to scripture highlights the Reformation''s emphasis on accessibility and communal worship.<br><br>Metrical psalters are a testament to the Reformation’s commitment to making biblical texts not only readable but also singable for the average churchgoer. By converting the Psalms into vernacular poetry, these works allowed congregations to engage with scripture in a deeply personal and communal way, embodying the spirit of the Psalms as both prayers and songs. The Psalms, originally Hebrew poetry often set to music, find a new expression in these metrical translations, bridging the gap between ancient Israelite worship and contemporary Christian practice.<br><br>The creation of metrical psalters was a substantial undertaking, reflecting the reformers'' dedication to liturgical renewal and scriptural engagement. Some psalters of this era went further, including musical notations and harmonizations, thus providing a complete resource for worship. This endeavor not only democratized access to scripture but also enriched the musical heritage of the Protestant tradition, leaving a lasting impact on Christian worship and hymnody. The 1893 Metrical Version of the Psalms, therefore, stands as a significant cultural and religious artifact, merging the ancient words of the Psalms with the rhythmic beauty of poetry and music.', 'historic', NULL, '19', 'eng', '1893', 'scan', 'J. W. Pratt and Son', NULL, NULL, 'ENGMVB_DBS_HS/English-(1893)-Book-of-Psalms-Metrical-Version-Bible-Psalms', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('123', 'English-1836-The-Prophets-Lowth-Bible-Vol.1-5-OT-Prophets', 'ENGLOW', 'English (1836) The Prophets (Lowth) Bible - Vol.1-5 OT Prophets', NULL, 'English (1836) The Prophets (Lowth) Bible - Vol.1-5 OT Prophets Robert Lowth (1710 – 1787) was a Bishop in the Church of England and an Oxford Professor of Poetry, renowned for his influential work on English grammar. He is particularly famous for his lectures between 1741 and 1750, in which he reimagined the Hebrew Bible as literature, focusing on its artistic and formal qualities. Lowth''s major contribution was the rediscovery of parallelism in ancient Hebrew poetry, which he theorized originated from the responsive singing of the seraphim. At a time when the divine authority of the Bible was declining, Lowth''s work on classifying large portions of prophecy as poetry helped elevate the human figure of the prophet as a literary genius. He portrayed the prophetic-poetic text as "strong," characterized by artfulness, control, order, and balance. His work responded to contemporary concerns about the Bible and biblical prophecy in eighteenth-century English society, simultaneously introducing more passion, enthusiasm, and subjectivity into neoclassical English poetry. Despite his efforts to minimize the irregularities and complexities in prophecy, Lowth''s scholarship inadvertently transmitted these elements into English literature, influencing Romantic poets like William Blake to adopt similar complex prophetic stances in their work.', 'historic', NULL, '221', 'eng', '1836', 'scan', 'Robert Lowth, D.D., F.R.S., Bishop of London', NULL, NULL, 'ENGLOW_DBS_HS/English-(1836)-The-Prophets-(Lowth)-Bible-Vol.1-5-OT-Prophets', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('124', 'English-1824-A-New-Family-Bible-Vol.-3-of-3-Boothroyd-Study', 'ENGNFB', 'English (1824) A New Family Bible (Vol. 3 of 3) Boothroyd (Study)', NULL, 'English (1824) A New Family Bible (Vol. 3 of 3) Boothroyd (Study) Bible. English. Boothroyd. 1824. New family Bible, and improved version, from corrected texts of the originals. Huddersfield : William Moore, 1824<br><br>“Boothroyd, Benjamin A New Family Bible, and improved version, from corrected texts of the originals; with notes critical and explanatory, and short practical reflections...with a general introduction...By the Rev. B. Boothroyd... 3 Vols. Huddersfield: Printed for the Author, and others, by William Moore, 1817 and again in 1824. New edition, revised, 1835. An Abridged Edition; London: James Duncan, 1836. Another edition; Translated from Corrected Texts. London: Partridge & Oakey, 1853.”<br><br>(From: William J. Chamberlin. “Catalogue of English Bible Translations”.<br><br>Benjamin Boothroyd (1768 – 8 September 1836) was an English Independent minister and Hebrew scholar. He had the degrees of D.D. and L.L.D. In 1818 Boothroyd (who had accepted the degree of LL.D.) became co-pastor at Highfield Chapel, Huddersfield, with the Rev. William Moorhouse. In 1818 Booth completed his New Family Bible and Improved Version in three vols. 4to, which had been suggested to him on a visit to York by Henry Tuke, a Quaker. He printed many copies of it at his own press. It contained notes, and in recognition of his achievement the university of Glasgow conferred on Boothroyd the degree of D.D. in 1824. In 1835 he completed an octavo edition of the Family Bible. On 10 January 1836 he went down with a violent illness; he died on 8 September and was buried at Huddersfield.', 'historic', 'https://en.wikipedia.org/wiki/Benjamin_Boothroyd', '198', 'eng', '1824', 'study', 'Rev. B. Boothroyd, L. L. D.', NULL, NULL, 'ENGNFB_DBS_HS/English-(1824)-A-New-Family-Bible-(Vol.-3-of-3)-Boothroyd-(Study)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('125', 'English-1615-Geneva-Bible', 'ENGGNV', 'English (1615) Geneva Bible', NULL, 'The Geneva Bible, printed in 1615, is a historically significant English translation of the Bible, predating the King James Version by 51 years. It was the primary Bible for 16th-century English Protestantism and was utilized by notable figures such as William Shakespeare, Oliver Cromwell, John Knox, John Donne, and John Bunyan, author of "The Pilgrim''s Progress" (1678). This Bible was also among those brought to America on the Mayflower, as evidenced by collections at the Pilgrim Hall Museum.<br><br>The Geneva Bible was significant for being the first mechanically printed, mass-produced Bible accessible to the general public. It included a comprehensive set of study aids, such as verse citations, book introductions, maps, tables, woodcut illustrations, and indices. Its forceful and vigorous language made it more popular than the Great Bible, with Cleland Boyd McAfee noting that it "drove the Great Bible off the field by sheer power of excellence."<br><br>Produced during Queen Mary I''s reign (1553–58), the Geneva Bible was translated by Protestant scholars in Geneva, Switzerland. William Whittingham supervised the translation, working with Myles Coverdale, Christopher Goodman, Anthony Gilby, Thomas Sampson, and William Cole. Whittingham was responsible for the New Testament (published in 1557), while Gilby oversaw the Old Testament.<br><br>The first full edition of the Geneva Bible appeared in 1560, but it wasn''t printed in England until 1575 (New Testament) and 1576 (complete Bible). Over 150 editions were issued, the last probably in 1644. The first Bible printed in Scotland was the Geneva Bible, issued in 1579. This Bible remained popular among Puritans and in use until after the English Civil War. Some editions from 1576 onwards included Laurence Tomson''s revisions of the New Testament, and editions from 1599 onwards used Franciscus Junius'' new version of the Book of Revelation.<br><br>The Calvinist and Puritan annotations in the Geneva Bible were disliked by Anglicans and King James I, who commissioned the King James Bible as a replacement. The Geneva Bible influenced the earlier production of the Bishops'' Bible and the later Rheims-Douai edition. Its notes were even included in a few editions of the King James version as late as 1715.', 'historic', 'https://en.wikipedia.org/wiki/Geneva_Bible', '398', 'eng', '1640', 'scan', NULL, NULL, NULL, 'ENGGNV_DBS_HS/English-(1615)-Geneva-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('126', 'English-1858-Imperial-Family-Bible-Study', 'ENGKJV', 'English (1858) Imperial Family Bible (Study)', NULL, 'The Imperial Family Bible, a comprehensive work containing both the Old and New Testaments, is distinguished by its adherence to the most approved copies of the Authorized Version. This edition is remarkable for its extensive array of critical, explanatory, and practical notes, alongside references, readings, chronological tables, and indexes. The text is further enhanced by a curated series of historical designs and authentic depictions of significant biblical locations. This unique blend of scholarly rigor and visual appeal was crafted to cater to a wide audience, aiming to be accessible for the general populace while maintaining the depth needed for scholarly pursuits.<br><br>Published by Blackie, a renowned name in theological and biblical publications, the Imperial Family Bible was celebrated as one of their most grandiose and significant works. Its appeal transcended social strata, finding favor in both academic circles and among the general public. Notably, the edition garnered royal attention and approval. Her Majesty Queen Victoria and His Royal Highness Prince Albert, the Prince Consort, each procured a copy upon its initial release, underscoring its esteemed status. Furthermore, it received patronage from numerous members of the Royal Household, several bishops, and a broad spectrum of the nobility, clergy, and landed gentry. This widespread endorsement and popularity underscore the Imperial Family Bible''s significant impact and its enduring legacy in the realm of religious literature.', 'historic', NULL, '299', 'eng', '1858', 'study', 'Blackie and Son', NULL, NULL, 'ENGKJV_DBS_HS/English-(1858)-Imperial-Family-Bible-(Study)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('127', 'French-1904-Jefferson-Gospels-Latin-Greek-Engilsh-Gospels', 'FRAOST', 'French (1904) Jefferson Gospels (Latin Greek Engilsh) - Gospels', 'Évangiles de Jefferson (1904, Latin-Grec-Anglais)', 'French (1904) Jefferson Gospels (Latin Greek English) - Gospels, also known as The Life and Morals of Jesus of Nazareth or the Jefferson Bible, showcases Thomas Jefferson''s effort to distill Jesus'' teachings by excluding the supernatural aspects and miracles from the New Testament. Jefferson, who created this work by cutting and pasting sections from the New Testament, aimed to highlight Jesus'' moral teachings without the doctrinal overlay of divinity and miracles. This unique compilation, completed in 1820 but not published during Jefferson''s lifetime, focuses solely on Jesus'' ethical instructions. The Smithsonian Institution acquired the original manuscript in 1895, and following conservation efforts, it was displayed in an exhibit at the National Museum of American History from November 2011 to May 2012. The exhibit, which also featured the source books Jefferson used and a 1904 congressional edition of the Jefferson Bible, was complemented by a documentary titled Jefferson''s Secret Bible, aired by the Smithsonian Channel in February 2012.', 'historic', NULL, '19', 'fra', '1904', 'study', 'Thomas Jefferson, Government Printing Office', NULL, NULL, 'FRAOST_DBS_HS/French-(1904)-Jefferson-Gospels-(Latin-Greek-Engilsh)-Gospels', 'fra', 'stan1290', 'French', 'français', 'L', 'FR', '48', '2', '1', 'fr', '77200000', 'Andorra and France', 'Also in Algeria, Andorra, Austria, Belgium, Benin, Burkina Faso, Burundi, Cambodia, Cameroon, Canada, Central African Republic, Chad, Comoros, Congo, Côte d’Ivoire, Democratic Republic of the Congo, Djibouti, Equatorial Guinea, French Guiana, French Polynesia, Gabon, Guadeloupe, Guinea, Haiti, India, Israel, Italy, Lebanon, Libya, Luxembourg, Madagascar, Mali, Martinique, Mauritania, Mauritius, Mayotte, Monaco, Morocco, Mozambique, New Caledonia, Niger, Philippines, Puerto Rico, Réunion, Rwanda, Saint Pierre and Miquelon, Saudi Arabia, Senegal, Seychelles, South Africa, Switzerland, Togo, Tunisia, United Arab Emirates, United Kingdom, United States, U.S. Virgin Islands, Vanuatu, Wallis and Futuna.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('128', 'Greek-English-1864-New-Testament-Emphatic-Diaglot', 'GRCTISH', 'Greek-English (1864) New Testament Emphatic Diaglot', 'Έμφατικός Διαγλωσσικός Καινή Διαθήκη (1864)', 'The 1864 "Emphatic Diaglott," a Greek-English edition of the New Testament, is a notable work in biblical scholarship. This publication contains the original Greek text based on the recension of J.J. Griesbach, along with an interlinear word-for-word English translation. Additionally, it features a new emphatic version derived from the interlinear translation, the renderings of eminent critics, and the various readings of the Vatican manuscript no. 1209 housed in the Vatican Library.<br><br>Published by Fowler & Wells, the Emphatic Diaglott is distinguished by its comprehensive approach, which includes illustrative and explanatory footnotes, as well as a copious selection of references. This work also contains a valuable alphabetical appendix, adding to its utility as a study tool.<br><br>The Emphatic Diaglott is significant for its contribution to the understanding of the New Testament, offering a detailed examination of the Greek text alongside a precise English translation. Its integration of critical insights, various readings, and academic commentary makes it a valuable resource for scholars, theologians, and students of biblical languages and texts. The meticulous attention to detail in translation and interpretation has made this publication a noteworthy addition to the study of New Testament scriptures.', 'historic', NULL, '63', 'grc', '1864', 'study', 'Samuel Bagster and Sons', NULL, NULL, 'GRCTISH_DBS_HS/Greek-English-(1864)-New-Testament-Emphatic-Diaglot', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('129', 'Aramaic-1885-Old-Testament-Talgum-with-Commentaries-vol-6-9-Old-Testmant', NULL, NULL, NULL, 'In the Syriac (Eastern Aramaic) language the Peshitta (Syriac: "common version") is the standard version of the Christian Bible. It continues to serve as the Bible of churches in the Syriac tradition (Church of the East, Chaldean Catholic, and Syriac Orthodox) to this day. The history of Christian Translations of the Bible into Syriac language includes the Diatessaron, the Old Syriac versions (Curetonian and Sinaitic), the Peshitto, the Philoxenian version, the Harklean Version and the recent United Bible Societies'' modern Aramaic New Testament.<br><br>About AD 500 a Christian Palestinian Aramaic version was made. It contains 2 Peter, 2-3 John, Jude, and Apocalypse. It is representative of the Caesarean text type and is a unique translation different from any other which was made into Syriac. These are among the manuscripts used by John Gwynn in 1893 to complete his edition of the Catholic Epistles. In 1892 Agnes Smith Lewis discovered the manuscript of the Palestinian Syriac lectionary in the library of Saint Catherine''s Monastery on Mount Sinai. It is designated by Syr.<br><br>The first revision of the New Testament from the Syriac into Turoyo language (Western Aramaic in Syriac and Latin script) was made by Malphono Yuhanun Üzel (Bar Shabo), Benjamin Bar Shabo, and Yahkup Bilgic in 2009 with notes from Harclean and Philoxenios. This commission "Sihto du Kthovo Qadisho Suryoyo" works especially to preach the Gospel in Aramaic all over the world.', NULL, NULL, NULL, 'aii', NULL, NULL, NULL, NULL, NULL, NULL, 'aii', 'assy1241', 'Assyrian Neo-Aramaic', 'Sūreṯ', 'L', 'IQ', '36.75', '43', '6b', NULL, '626000', 'Iraq', 'Northern Iraq, Baghdad, Basrah, Karkuk, Arbil. Also in Armenia, Australia, Austria, Azerbaijan, Belgium, Brazil, Canada, Cyprus, France, Georgia, Germany, Greece, Iran, Italy, Lebanon, Netherlands, New Zealand, Russian Federation (Europe), Sweden, Switzerland, Syria, Turkey (Asia), United Kingdom, United States.', 'AII1885', 'Aramaic (1885) Old Testament (Talgum) with Commentaries vol 1-9 - Old Testmant', 'Aramaic-1885-Old-Testament-Talgum-With-Commentaries-Vol-1-9-Old-Testmant.jpg', '1885', 'study', NULL, NULL, 'AII1885_DBS_HS/Aramaic-(1885)-Old-Testament-(Talgum)-with-Commentaries-vol-1-9-Old-Testmant', NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('130', 'English-1888-JW-Hanson-New-Testament-Vol-1-2', 'ENGJWH', 'English (1888) JW Hanson New Testament (Vol 1-2)', NULL, 'John Wesley Hanson D.D. (1823–1901) was an influential figure in American religious history, notably as a Universalist minister and historian. Born in Boston, Hanson is recognized for his contributions to the Universalist movement and his unique perspectives on early Christian beliefs. His commitment to Universalism, the belief in universal salvation, shaped much of his work and theological stance.<br><br>Hanson''s journey in ministry began in 1845 when he became a Universalist minister in Wentworth, New Hampshire. His active involvement in the American Civil War as a chaplain to the Sixth regiment of Massachusetts volunteers marked a significant period in his life, providing him with experiences and insights that influenced his later works. In the 1870s, his missionary work led him to Britain, where he served as the pastor of St. Paul''s Universalist Church in Glasgow, Scotland.<br><br>However, Hanson is perhaps best known for his work on the New Testament, titled "Hanson''s edited New Testament" (1885). This work was a meticulous revision of the English Revised Version, notable for its substitution of "baptism" with "immersion," among other changes, reflecting his Universalist interpretations.<br><br>Additionally, Hanson''s historical writings, particularly "Universalism: The Prevailing Doctrine of the Christian Church" (1899), have been significant in the discourse on early Christian theology. In this work, he argued that Universalism was the dominant doctrine in early Christianity before Augustine, a perspective that challenged traditional interpretations and continued the arguments presented by earlier Universalist scholars like Hosea Ballou.<br><br>Hanson''s views on church history, while contested, have been influential in religious studies. He is cited in prominent resources like the 1911 edition of the Encyclopædia Britannica and the New Schaff-Herzog Encyclopedia of Religious Knowledge. His interpretations, along with those of contemporaries like George T. Knight and later scholars like Ilaria Ramelli, have contributed to a diverse understanding of early Christian beliefs and Universalism''s role in them.', 'historic', NULL, '97', 'eng', '1888', 'scan', NULL, NULL, NULL, 'ENGJWH_DBS_HS/English-(1888)-JW-Hanson-New-Testament-(Vol-1-2)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('131', 'English-1846-Adam-Clarke-KJV-Old-Testament-Study-Bible-Vol-1-4-OT', 'ENGKJV', 'English (1846) Adam Clarke KJV Old Testament Study Bible (Vol 1-4) OT', NULL, 'English (1846) Adam Clarke KJV Old Testament Study Bible (Vol 1-4) OT: Adam Clarke, born in 1760 or 1762 and passing in 1832, was a distinguished British Methodist theologian and Biblical scholar. He is best remembered for his extensive commentary on the Bible, a monumental work that took him four decades to complete. This commentary has been a cornerstone of Methodist theological resources for over two centuries. Clarke, a devout theologian, upheld and expanded upon the teachings of John Wesley, the founder of Methodism. He believed fervently in the Bible as the ultimate guide to understanding God''s nature and intentions. Clarke viewed the Scriptures as a divine grace, capable of dispelling the darkness of ignorance. His approach to theology was fundamentally rooted in the Bible, and he often expressed reservations about purely systematic theological methods, preferring instead the direct interpretation of the biblical texts.', 'historic', NULL, '457', 'eng', '1846', 'study', 'G. Lane & C. B. Tippett', NULL, NULL, 'ENGKJV_DBS_HS/English-(1846)-Adam-Clarke-KJV-Old-Testament-Study-Bible-(Vol-1-4)-OT', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('132', 'English-1541-The-Great-Bible', 'ENGGRB', 'English (1541) The Great Bible', NULL, 'The Great Bible of 1539, known as the first authorized edition of the Bible in English, was a significant milestone in religious history, sanctioned by King Henry VIII for use in Church of England services. This authorization marked a crucial shift in religious practice, making scripture accessible in the vernacular to English congregants. Myles Coverdale, under the commission of Thomas Cromwell, King Henry VIII''s Secretary and Vicar General, was responsible for its preparation.<br><br>In 1538, Cromwell issued a directive to the clergy to provide a "one book of the Bible of the largest volume in English" in churches for parishioners to read. This Bible incorporated much from William Tyndale''s translation, revising parts deemed objectionable. Coverdale completed the Tyndale Bible by translating the remaining books of the Old Testament and Apocrypha from the Latin Vulgate and German translations, as Tyndale''s work was incomplete and not entirely derived from the original Greek, Hebrew, and Aramaic texts.<br><br>The Great Bible is known by several names: the Cromwell Bible, in honor of Thomas Cromwell''s role in its publication; Whitchurch''s Bible, after its first English printer; and the Chained Bible, as it was often chained in churches to prevent theft. It is sometimes inaccurately referred to as Cranmer''s Bible because, although Thomas Cranmer was not responsible for the translation, his preface appeared in the second edition. The Great Bible''s title page read: "The Byble in Englyſhe, that is to ſaye the content of all the holy ſcrypture, bothe of yͤ olde and newe teſtament, truly tranſlated after the veryte of the Hebrue and Greke textes, by yͤ Dylygent ſtudye of dyuerſe excellent learned men, expert in the forſayde tonges."', 'historic', NULL, '496', 'eng', '1541', 'scan', 'GreatSite.com', NULL, NULL, 'ENGGRB_DBS_HS', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('133', 'English-1912-Self-Interpreting-Study-Bible-Vol.-1-4', 'ENGKJV', 'English (1912) Self Interpreting Study Bible (Vol. 1-4)', NULL, 'The 1912 edition of John Brown of Haddington''s ''Self-interpreting Bible,'' first published in 1778, is a remarkable work designed to make the scriptures accessible to the ''poorer and labouring part of mankind.'' Brown''s intent was to encapsulate the insights of esteemed biblical commentators in a format that resonates with the common reader, effectively making the Bible its own best interpreter. This comprehensive compilation includes historical context, chronological timelines, geographical references, concise summaries, and explanatory notes, all aimed at demystifying the Bible''s content.<br><br>Brown''s approach is characterized by his readiness to offer definitive explanations for each verse and to draw practical lessons applicable to everyday life. His writing style is noted for its clarity and vigor, making complex theological concepts accessible to a broad audience. The ''Self-interpreting Bible'' quickly gained widespread popularity, becoming a staple in many English-speaking households, including those in Wales and the Scottish Highlands.<br><br>This work stands as a testament to Brown''s dedication to biblical scholarship and his commitment to making biblical knowledge available to all, regardless of their educational background or social status. It serves not only as a religious guide but also as a comprehensive resource, offering a deep and practical understanding of the Bible''s teachings. The ''Self-interpreting Bible'' remains a significant contribution to the field of biblical studies and continues to be valued for its insightful and approachable commentary on the scriptures.', 'historic', NULL, '1', 'eng', '1912', 'study', NULL, NULL, NULL, 'ENGKJV_DBS_HS/English-(1912)-Self-Interpreting-Study-Bible-(Vol.-1-4)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('134', 'Coptic-1916-Psalter-Freer-Collection-Psalms', 'COPPSA', 'Coptic (1916) Psalter (Freer Collection) - Psalms', 'Ⲙⲉⲧⲛⲓⲙ ⲛ̀ⲛⲉⲛⲧⲟⲥ (1916) Ⲡⲓⲯⲁⲗⲧⲉⲣ (Freer Collection)', 'The term ‘Coptic’ refers to the form of Egyptian in use after the establishment of Christianity in Egypt during the 3rd century. Sometimes called Neo-Egyptian, it is a development of Ancient Egyptian, in use until the 6th century B.C., and it''s later Hieratic and Demotic forms. These long succeeding periods made Coptic the living language with the longest recorded history. The few remaining Coptic speakers succumbed to the Arabic language in the 17th century.<br>Coptic was spoken in several dialects. Scriptures are extant in the Bohairic (Coastal, Lower Egypt); Fayumic or Bashmuric, Sub- Achmimic, and Middle Egyptian; and Sahidic and Achmimic (Upper Egyptian) dialects. Bohairic, earlier known as Memphitic, was the usage of Alexandria and hence survives as the ecclesiastical and liturgical language of the Coptic Church. However, it appears that Scriptures first appeared (3rd century) in Sahidic, because Lower Egypt had been Hellenized and the Greek Scriptures could be used there. Although considerable research remains to be done on the Coptic texts, these early versions cast light on the text used by the early Church.<br>The Coptic alphabet employs 24 Greek characters and 7 characters retained from Demotic script.', 'historic', NULL, '6', 'cop', '1916', 'scan', 'Kegan Paul, Trench, Trubner & Co. LTD', NULL, NULL, 'COPPSA_DBS_HS/Coptic-(1916)-Psalter-(Freer-Collection)-Psalms', 'cop', 'copt1239', 'Coptic', 'ϯⲙⲉⲧⲣⲉⲙⲛ̀ⲭⲏⲙⲓ ~ ⲧⲙⲛ̄ⲧⲣⲙ̄ⲛ̄ⲕⲏⲙⲉ', 'E', 'EG', '29.47203', '31.2053', '9', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('135', 'English-1860-Cassell''s-Illustrated-Family-Bible-Vol.-1-2-Study', 'ENGKJV', 'English (1860) Cassell''s Illustrated Family Bible (Vol. 1-2) Study', NULL, 'The "Holy Bible: Containing the Old and New Testaments, with Explanatory Notes, References, and a Condensed Concordance," published by Cassell, Petter & Galpin, is a testament to the ingenuity and vision of John Cassell, a towering figure in the world of English publishing. Born on January 23, 1817, and passing away on April 2, 1865, Cassell was not just a publisher and printer; he was a writer, editor, and a profound influence in the realms of educational literature and novel serial publication. His firm, Cassell & Co., is celebrated for its role in transforming and democratizing the field of educational books and periodicals.<br><br>More than just a successful entrepreneur, Cassell was deeply involved in the temperance movement in Britain and fervently advocated for the reduction of taxes on publishing. His efforts were not limited to the publishing world; he was a passionate social reformer who understood the critical role of education in uplifting the working class. Cassell’s commitment to social improvement is evident in his work as a tea and coffee merchant and his numerous publications, both in magazine and book formats, which made learning and culture accessible to a broader audience.<br><br>The illustrated family Bible is a crowning achievement in this regard, featuring over nine hundred meticulously crafted engravings. It stands as a symbol of Cassell’s dedication to spreading knowledge and cultural enrichment. This Bible, through its detailed illustrations and comprehensive notes, reflects Cassell’s lifelong mission to educate and inspire the masses, making it a significant contribution to the world of religious and educational literature.', 'historic', NULL, '158', 'eng', '1860', 'study', 'The British and Foreign Bible Society', 'british-and-foreign-bible-society', NULL, 'ENGKJV_DBS_HS/English-(1860)-Cassell''s-Illustrated-Family-Bible-(Vol.-1-2)-Study', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('136', 'Greek-Latin-1598-Beza-Bible-NT', 'GRCBEZA', 'Greek - Latin (1598) Beza Bible (NT)', 'Βίβλος του Beza (1598, Καινή Διαθήκη)', 'The Beza Bible, named after Theodore Beza, a prominent French Calvinist Protestant theologian and a disciple of John Calvin, is a noteworthy contribution to Biblical scholarship. Beza, who succeeded Calvin as the spiritual leader of the Republic of Geneva, first issued an edition of the Greek New Testament in 1565. This edition was unique as it featured the Greek text alongside the Latin Vulgate and Beza’s own translation, initially published in 1556, with the earliest extant edition dating to 1559.<br><br>Beza significantly enhanced this work with enriched and expanded annotations. For the preparation of this edition, and more so for his second edition in 1582, Beza may have utilized two valuable manuscripts: the Codex Bezae or Cantabrigensis, which he later donated to the University of Cambridge, and the Codex Claromontanus, found in Clermont and now housed in the Bibliothèque Nationale de France in Paris.<br><br>However, Beza''s primary reference was the 1550 edition by Robert Estienne, itself largely based on Erasmus''s later editions. Beza''s efforts in textual scholarship were instrumental for future Biblical studies. His Latin translation and the comprehensive notes accompanying it, which were published over a hundred times, significantly aided in the understanding of the New Testament. Despite some criticism of Beza''s interpretation being overly influenced by his views on predestination, his work undeniably contributed to a clearer understanding of the New Testament texts.', 'historic', NULL, '184', 'grc', '1598', 'study', NULL, NULL, NULL, 'GRCBEZA_DBS_HS', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('137', 'Greek-English-1864-TwoFold-Parallel-New-Testament-Green', 'GRCTFP', 'Greek-English (1864) TwoFold Parallel New Testament (Green)', 'Διπλή Παράλληλη Καινή Διαθήκη (1864, Green)', 'The 1864 "Twofold New Testament" by Rev. Thomas Sheldon Green, M.A., is a notable contribution to the field of New Testament studies. Published in London by Samuel Bagster and Sons, this work presents a unique parallel-column format featuring both a new translation and a newly formed text of the Greek New Testament.<br><br>Rev. Thomas Sheldon Green, a late Fellow of Christ''s College, Cambridge, was already known for his "Treatise on the Grammar of the New Testament." In this publication, he offered a new translation of the Greek Testament, accompanied by a critical edition of the original text. The title "The Twofold New Testament" aptly reflects the dual nature of this work.<br><br>Green''s work is significant for providing readers with an accessible English translation alongside the Greek text, allowing for a direct comparison between the original language and its English rendition. This parallel presentation is especially valuable for students of biblical languages and scholars interested in textual criticism and the translation process of the New Testament. Green''s translation and critical text offer insights into the linguistic and contextual nuances of the New Testament, contributing to a deeper understanding of its teachings and historical background.', 'historic', NULL, '37', 'grc', '1864', 'study', 'Samuel Bagster and Sons', NULL, NULL, 'GRCTFP_DBS_HS/Greek-English-(1864)-TwoFold-Parallel-New-Testament-(Green)', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('138', 'Hebrew-1008-The-Leningrad-Codex-Codex-Leningradensis-OT', 'HBOLENI', 'Hebrew (1008) The Leningrad Codex (Codex Leningradensis) - OT', 'עברית - כתר לנינגרד (1008, התנ"ך)', 'The Leningrad Codex, known in Latin as Codex Leningradensis, holds the distinction of being the oldest complete manuscript of the Hebrew Bible in Hebrew, utilizing the Masoretic Text and Tiberian vocalization. According to its colophon, the codex was created in Cairo in 1008 CE, or possibly 1009. This manuscript is central to the study and understanding of the Hebrew scriptures.<br><br>There is a theory suggesting that the Leningrad Codex may have been corrected against the Aleppo Codex, a slightly earlier manuscript that was partially lost in the mid-20th century. However, Paul E. Kahle posited that the Leningrad manuscript likely relied on other, now-lost manuscripts from the ben Asher family. Despite the Aleppo Codex being several decades older, it has been missing significant parts since the anti-Jewish riots in Aleppo in 1947. Consequently, the Leningrad Codex is the oldest complete codex of the Tiberian mesorah that has survived intact to this day.<br><br>In modern biblical scholarship, the Leningrad Codex is of immense importance. It is the Hebrew text reproduced in major editions of the Hebrew Bible, including Biblia Hebraica (1937), Biblia Hebraica Stuttgartensia (1977), and Biblia Hebraica Quinta (2004–present). Additionally, it serves as a crucial source for reconstructing the missing parts of the Aleppo Codex, thereby aiding in the preservation and understanding of the ancient textual tradition of the Hebrew Bible.', 'historic', NULL, '182', 'hbo', '1008', 'manuscript', NULL, NULL, NULL, 'HBOLENI_DBS_HS/Hebrew-(1008)-The-Leningrad-Codex-(Codex-Leningradensis)-OT', 'hbo', 'anci1244', 'Ancient Hebrew', 'עִבְרִית מִקְרָאִית', 'H', 'IL', '31.77607', '35.17248', '9', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('139', 'English-1826-Living-Oracles-New-Testament-Alexander-Campbell', 'ENGTLO', 'English (1826) Living Oracles New Testament (Alexander Campbell)', NULL, 'The Living Oracles is a translation of the New Testament compiled and edited by the early Restoration Movement leader Alexander Campbell. Published in 1826, it was based on an 1818 combined edition of translations by George Campbell, James MacKnight and Philip Doddridge, and included edits and extensive notes by Campbell.', 'historic', NULL, '72', 'eng', '1826', 'scan', NULL, NULL, NULL, 'ENGTLO_DBS_HS/English-(1826)-Living-Oracles-New-Testament-(Alexander-Campbell)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('140', 'Greek-1896-Tischendorf-Novem-Testamentum-Vol.-1-9-7th-and-8th-Study-Bible-NT', 'GRCTISH', 'Greek (1896) Tischendorf Novem Testamentum (Vol. 1-9) 7th and 8th (Study Bible) NT', 'Novum Testamentum του Tischendorf (1896, Τόμος 1-9, 7η και 8η Έκδοση, Μελέτη Καινής Διαθήκης)', 'The 1896 Tischendorf Novum Testamentum, encompassing volumes 1-9 and including the 7th and 8th editions, stands as a monumental work in the study of the Greek New Testament. Constantine Tischendorf, an eminent biblical scholar, is renowned for his Critical Greek New Testament, highly valued for its extensive detail in textual readings and witness to the text.<br><br>Tischendorf''s contributions to biblical scholarship, especially his work on the Codex Sinaiticus, one of the oldest and most complete manuscripts of the Greek Bible, are widely recognized and celebrated. Over his lifetime, he published eight major editions of the Greek New Testament, along with various abridged editions, collations, and facsimiles.<br><br>His magnum opus, the Editio octava critica maior (1869-1872), remains a seminal work in New Testament studies. This edition is particularly significant for its comprehensiveness and remains unsurpassed as a complete edition of the New Testament text. Tischendorf''s meticulous scholarship and dedication to the study of biblical texts have made his editions essential resources for scholars and theologians, continuing to influence the field of New Testament textual criticism.', 'historic', NULL, '287', 'grc', '1896', 'study', 'Lipsiae, Sumptibus Adolphi Winter', NULL, NULL, 'GRCTISH_DBS_HS/Greek-(1896)-Tischendorf-Novem-Testamentum-(Vol.-1-9)-7th-and-8th-(Study-Bible)-NT', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('141', 'English-1851-Portable-Folio-Family-Bible', 'ENGKJV', 'English (1851) Portable Folio Family Bible', NULL, 'English (1851) Portable Folio Family Bible: The Portable Folio Family Bible, expertly compiled by Rev. Walter McGilvray, D.D., is a remarkable edition that blends the revered Holy Bible with the insightful commentaries of Scott and Henry. This version stands out for encompassing over four thousand notes, meticulously chosen from the esteemed standard authors of Europe and America. These notes are critical and explanatory in nature, offering a deeper and more nuanced understanding of the biblical texts.<br><br>Rev. McGilvray''s edition is designed to cater to families seeking a comprehensive and accessible study of the Bible. The integration of Scott and Henry''s commentaries with the scriptural texts provides a rich tapestry of theological insights and interpretations. The extensive collection of notes, drawn from a wide range of authoritative sources, ensures that readers are exposed to diverse perspectives and interpretations, enhancing their engagement with the Bible. This edition is an invaluable asset for families and individuals who wish to delve into a profound and enriching exploration of their faith.', 'historic', NULL, '558', 'eng', '1851', 'scan', 'Rev. Walter M''Gilvray, D. D.', NULL, NULL, 'ENGKJV_DBS_HS/English-(1851)-Portable-Folio-Family-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('142', 'English-1572-Bishops-Bible', 'ENGBSB', 'English (1572) Bishops Bible', NULL, 'The Bishops'' Bible, an English translation of the Bible produced under the Church of England''s authority, was first published in 1568. It underwent a substantial revision in 1572, and its 1602 edition was designated as the base text for the King James Bible, completed in 1611. This Bible followed the Great Bible of 1539, the first authorized English Bible, and the Geneva Bible of 1557–1560.<br><br>The Geneva Bible''s Calvinist tones, particularly in its marginal notes, clashed with the beliefs of the Church of England''s high-church faction, leading to the creation of the Bishops'' Bible. Archbishop of Canterbury Matthew Parker spearheaded this project, and the early editions featured the initials of the translating bishops, a method Parker believed would ensure diligence and accountability. However, the absence of a supervisory editor resulted in inconsistent translation practices.<br><br>Queen Elizabeth I is portrayed in this edition, flanked by allegorical figures of Faith and Charity, symbolizing Hope, with a Latin excerpt from Romans 1:16 beneath her portrait. The Apocrypha revision in the Bishops'' Bible was minimal, largely mirroring the Great Bible''s text, which was based on the Latin Vulgate, suggesting it wasn''t entirely translated from the original languages.<br><br>First published in 1568, the Bishops'' Bible was reissued in a revised form in 1572. This revision aimed to align more closely with the Geneva Bible and introduced more ecclesiastical language. However, it did not replace the Geneva Bible as a household Bible, instead serving as a "pulpit Bible" for church use. The first edition was notably large with 124 full-page illustrations, while later editions were smaller and mostly lacked illustrations. The Bishops'' Bible or its New Testament was printed in over 50 editions, compared to the Geneva Bible''s 150 reprints. The last complete Bible edition was in 1602, with the New Testament reissued until at least 1617. William Fulke published several parallel editions contrasting it with the Rheims New Testament until 1633.', 'historic', 'https://en.wikipedia.org/wiki/Bishops%27_Bible#References', '149', 'eng', '1580', 'reprint', NULL, NULL, NULL, 'ENGBSB_DBS_HS/English-(1572)-Bishops-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('143', 'English-1858-Pictorial-Expository-Family-Bible-Vol.-1-of-3-Study', 'ENGKJV', 'English (1858) Pictorial Expository Family Bible (Vol. 1 of 3) Study', NULL, '"The Pictorial Bible: Being the Old and New Testaments According to the Authorized Version," published in 1858, stands out as a monumental work in the realm of biblical literature. This edition, the first of a three-volume series, distinguishes itself through the integration of over a thousand engravings, offering readers a visually rich journey through the Scriptures. These engravings, inspired by renowned artworks of the era, beautifully illustrate various historical events, bringing the biblical stories to life with remarkable clarity and detail.<br><br>What sets this edition apart is its in-depth portrayal of landscape scenes, meticulously compiled from original drawings or authentic engravings. This visual feast not only enhances the reader''s experience but also provides an immersive understanding of the geographical context of the biblical world. Additionally, the edition delves into the diverse aspects of natural history, costumes, and antiquities, each illustration carefully chosen from the finest sources available. This approach ensures both the historical accuracy and the educational merit of the visuals.<br><br>This unique blend of academic rigor and artistic splendor positions "The Pictorial Bible" as a significant contribution to religious studies. It caters to a broad spectrum of readers, from those seeking a deeper theological understanding of the Scriptures to those intrigued by the historical and cultural dimensions of the biblical era. The 1858 edition, therefore, not only serves as a source of spiritual enlightenment but also as a gateway to the rich historical and cultural heritage encapsulated in the Bible.', 'historic', NULL, '396', 'eng', '1858', 'study', 'Glasgow & London-W.R. M''Phun', NULL, NULL, 'ENGKJV_DBS_HS/English-(1858)-Pictorial-Expository-Family-Bible-(Vol.-1-of-3)-Study', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('144', 'English-1611-First-Edition-King-James', 'ENGKJV', 'English (1611) First Edition King James', NULL, 'The King James Version (KJV), also known as the King James Bible (KJB) and the Authorized Version, is a notable English translation of the Christian Bible. Commissioned for the Church of England in 1604 and published in 1611 under the sponsorship of King James VI and I, the KJV is celebrated for its "majesty of style" and profound cultural impact. It includes 39 books of the Old Testament, 14 books of the Apocrypha (as considered by Protestants), and 27 books of the New Testament, totaling 80 books.<br><br>The KJV was the third English translation authorized by the English Church, following the Great Bible (commissioned by King Henry VIII in 1535) and the Bishops'' Bible (commissioned by Queen Elizabeth I in 1568). The Geneva Bible of 1560, produced by Protestant Reformers in Geneva, significantly influenced the writing of the KJV.<br><br>The translation was initiated at the Hampton Court Conference in January 1604, convened by King James in response to the Puritans'' concerns with earlier translations. James set guidelines to align the translation with the ecclesiology and episcopal structure of the Church of England. The translation was undertaken by 47 scholars in six panels, dividing the work of translating the Old Testament, New Testament, and Apocrypha.<br><br>The translators used Hebrew and Aramaic texts for the Old Testament and Greek texts for the New Testament and Apocrypha. The KJV replaced the Great Bible in the 1662 Book of Common Prayer for Epistle and Gospel readings, authorized by Act of Parliament.<br><br>By the 18th century, the KJV became the predominant English translation among Anglican and other English Protestant churches. It also replaced the Latin Vulgate as the standard scripture version for English-speaking scholars. The standard text of the KJV, extensively re-edited by Benjamin Blayney in 1769, became the most widely printed book in history due to stereotype printing in the early 19th century. This version, usually omitting the Apocrypha, is commonly known today as the Oxford standard text of the King James Version.', 'historic', NULL, '350', 'eng', '1611', 'scan', 'GreatSite.com', NULL, NULL, 'ENGKJV_DBS_HS', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('145', 'English-1611-KJV-Old-Testament-with-Translators-Notes-OT', 'ENGKJV', 'English (1611) KJV Old Testament (with Translators Notes) OT', NULL, 'The King James Version (KJV), also known as the King James Bible (KJB) and the Authorized Version, is an English translation of the Christian Bible commissioned for the Church of England. Sponsored by King James VI and I, it was first published in 1611. The KJV includes 39 books of the Old Testament, 14 books of the Apocrypha (as recognized by Protestants), and 27 books of the New Testament, totaling 80 books. Renowned for its majestic style, the King James Version is celebrated as a pivotal work in English culture and a significant influence on the English-speaking world.<br><br>Printed by John Norton and Robert Barker, the King''s Printers, the KJV was the third authorized English translation, following the Great Bible (commissioned in 1535 by King Henry VIII) and the Bishops'' Bible (commissioned in 1568 by Queen Elizabeth I). The Geneva Bible of 1560, produced in Geneva by Protestant Reformers from the original Hebrew and Greek scriptures, greatly influenced the writing of the KJV.<br><br>The Hampton Court Conference, convened by King James in January 1604, led to the creation of the KJV in response to the Puritans'' issues with previous translations. The translation, adhering to the ecclesiology and episcopal structure of the Church of England, involved 47 scholars working in six panels, with the Old Testament, New Testament, and Apocrypha assigned to different groups. The Old Testament was translated from Hebrew and Aramaic, the New Testament from Greek, and the Apocrypha from Greek and Latin.<br><br>In the 1662 Book of Common Prayer, the KJV text replaced the Great Bible for Epistle and Gospel readings. By the early 18th century, the KJV became the primary English translation used in Anglican and other English Protestant churches. The 1769 Oxford standard text, extensively re-edited by Benjamin Blayney and typically omitting the Apocrypha, became the most widely printed book in history due to stereotype printing in the 19th century. Today, "King James Version" usually refers to this Oxford standard text.', 'historic', 'https://en.wikipedia.org/wiki/King_James_Version', '100', 'eng', '1615', 'scan', NULL, NULL, NULL, 'ENGKJV_DBS_HS/English-(1611)-KJV-Old-Testament-(with-Translators-Notes)-OT', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('146', 'Aramaic-1514-Complutensian-Polyglot-Bible-Vol-1-of-5-Grk-Heb-Lat-Aramaic-StudyWDL-10636', 'AII1514', 'Aramaic (1514) Complutensian Polyglot Bible (Vol 1 of 5) Grk-Heb-Lat-Aramaic Study(WDL-10636)', 'Vetus testamentū multiplici lingua nūc primo impressum, Et imprimis Pentateuchus Hebraico Greco atq[ue] Chaldaico idiomate', 'The Complutensian Polyglot Bible, completed between 1514 and 1517, stands as a monumental achievement in the history of biblical scholarship and printing. Initiated by Cardinal Francisco Jiménez de Cisneros to foster advanced biblical studies at the University of Alcalá de Henares, Spain, this work is notable for being the first multilingual printed Bible, encompassing Hebrew, Greek, Latin, and Aramaic texts. Printed by Arnaldo Guillén de Brocar, the Bible features highly perfected characters for each language, particularly celebrated for the beauty of its Greek typeface. The project, reflecting the zenith of Spanish typographic art in the 16th century, was a complex endeavor involving numerous scholars and taking over a decade to complete. The first volume of this five-volume work contains the Pentateuch, presented in Greek, Latin, and Hebrew, with the Targum Onkelos and its Latin translation in the lower section of each page. Distribution began in 1520 after receiving papal approval. This pioneering publication significantly influenced the study and accessibility of biblical texts, marking a key moment in the Renaissance''s merging of humanist scholarship with technological innovation in printing.', 'historic', 'https://www.wdl.org/en/item/10636', '148', 'aii', '1514', 'study', 'Arnao Guillén de Brocar, Alcalá de Henares', NULL, 'World Digital Library', 'AII1514_DBS_HS/Aramaic-(1514)-Complutensian-Polyglot-Bible-(Vol-1-of-5)-Grk-Heb-Lat-Aramaic-Study(WDL-10636)', 'aii', 'assy1241', 'Assyrian Neo-Aramaic', 'Sūreṯ', 'L', 'IQ', '36.75', '43', '6b', NULL, '626000', 'Iraq', 'Northern Iraq, Baghdad, Basrah, Karkuk, Arbil. Also in Armenia, Australia, Austria, Azerbaijan, Belgium, Brazil, Canada, Cyprus, France, Georgia, Germany, Greece, Iran, Italy, Lebanon, Netherlands, New Zealand, Russian Federation (Europe), Sweden, Switzerland, Syria, Turkey (Asia), United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('147', 'Greek-1517-Complutensian-Polyglot-Bible-Latin-Hebrew', 'GRCNA28', 'Greek (1517) Complutensian Polyglot Bible (Latin Hebrew)', 'Πολύγλωσση Βίβλος Complutensian (1517, Λατινικά-Εβραϊκά)', 'The Complutensian Polyglot Bible is the first multilingual printed edition of the entire Bible. The project to produce the Bible was conceived, led, and financed by Cardinal Francisco Jiménez de Cisneros (circa 1436−1517), who early in the 16th century spearheaded the revitalization of the old University of Alcalá de Henares (founded in 1293) with the establishment of a new university, the Universidad Complutense, in 1508. (Complutense refers to Complutum, the ancient Roman settlement at the site of Alcalá de Henares). With the aid of important figures, such as Antonio de Nebrija, Cardinal Cisneros instituted a new curriculum with a more modern pedagogical orientation. Production of the Complutensian Polyglot Bible was a part of the cardinal’s effort to revive learning and encourage the study of the Holy Scriptures. The book represents the height of Spanish typographic achievement in the 16th century. Although precise information regarding who produced which section is lacking, it is known that around 1503, Cardinal Cisneros, who was surrounded by experts and scholars specializing in a wide array of languages, took on the great task of producing the work. It was a difficult and arduous process that required more than ten years. The printing was done by Arnaldo Guillén de Brocar, a Frenchman who had worked in Pamplona and who opened his main press in Alcalá in 1510. In order to print the book, Brocar had to create new and highly perfected characters for Latin, Greek, and Hebrew. His Greek characters are considered the most beautiful ever carved. The printing was done between 1514 and 1517, but it was not until 1520—after receiving authorization from Rome—that the book was distributed. The Bible consists of separately-bound volumes adding up to 1,500 pages; 600 copies were printed on paper, and six on vellum. Volume one contains the text of the Pentateuch, the first five books of the Hebrew Bible. The upper three-quarters of the pages are divided in three columns that contain the Greek text in the left column; the text of the Latin Vulgate in the middle column; and the Hebrew text in the right column. The lower section of the page is divided into two columns: the left contains the Aramaic translation of the Pentateuch known as the Targum Onkelos, the right the Latin translation of this text. Each page includes an epigraph and apostilles on the right margin. Volumes two and three contain the remainder of the Old Testament, in Greek, Latin, and Hebrew. Volume four contains the New Testament, in Greek and Latin. The last part of volume four and volume five consist of a Hebrew and Aramaic dictionary, a Hebrew grammar, and a Greek dictionary. (World Digital Library)', 'historic', NULL, '489', 'grc', '1517', 'scan', NULL, NULL, NULL, 'GRCNA28_DBS_HS/Greek-(1517)-Complutensian-Polyglot-Bible-(Latin-Hebrew)', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('148', 'English-1897-Weekes-New-Dispensation-Testament', 'ENGWEEK', 'English (1897) Weekes New Dispensation Testament', NULL, '"The New Dispensation. The New Testament Translated from the Greek by Robert D. Weekes," published in 1897 by Funk & Wagnalls Co., New York & London, is a significant work in the realm of English Bible translations. Robert D. Weekes’ translation effort marked a unique attempt to render the New Testament from its original Greek into a version that was not only accessible to the contemporary audience but also faithful to the original texts. The choice of the title, "The New Dispensation," possibly indicates an intention to present the Christian scriptures under a fresh perspective, highlighting the transformative teachings of the New Testament.<br><br>Published by Funk & Wagnalls, renowned for their educational and reference materials, including the esteemed Funk & Wagnalls Standard Dictionary, this translation was set to reach a widespread audience across the United States and the United Kingdom. Weekes’ translation forms an integral part of the late 19th-century efforts in Bible translation, characterized by a desire to bridge the gap between ancient scriptural texts and the modern reader’s understanding. It contributes to the diverse and evolving field of biblical scholarship, reflecting a period marked by an increased interest in making the biblical texts more relatable and understandable to contemporary society.', 'historic', NULL, '57', 'eng', '1897', 'scan', NULL, NULL, NULL, 'ENGWEEK_DBS_HS/English-(1897)-Weekes-New-Dispensation-Testament', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('149', 'Greek-English-1879-Septuagint-Old-Testament', 'GRCSEPT', 'Greek-English (1879) Septuagint Old Testament', 'Σεπτουαγίντα Παλαιά Διαθήκη (1879)', 'The 1879 Greek-English edition of the Septuagint Old Testament, translated by Lancelot Charles Lee Brenton, is a significant work in biblical studies. Brenton''s translation of the Septuagint, which was first released in 1844, stands as the second English translation of this crucial ancient Greek version of the Old Testament.<br><br>This edition is noteworthy for pairing the Greek text of the Septuagint with its English translation, offering valuable insights for comparative study and understanding of the texts. Additionally, Brenton''s work includes various readings and critical notes, providing a deeper scholarly context for the translation. Over the century and a half since its first release, Brenton''s translation of the Septuagint has seen several reprints and formats, attesting to its enduring importance and utility in biblical scholarship.<br><br>The Septuagint, a translation of the Hebrew Bible into Greek, is particularly significant as it was widely used in the Hellenistic Jewish community and by early Christians, influencing the development of Christian theology. Brenton''s translation has played a crucial role in making this seminal text accessible to English-speaking audiences, thereby contributing significantly to the study of biblical history and interpretation.', 'historic', NULL, '126', 'grc', '1879', 'study', 'C. J. Clay, M. A. and Son-The University Press', NULL, NULL, 'GRCSEPT_DBS_HS/Greek-English-(1879)-Septuagint-Old-Testament', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('150', 'English-1902-Amercian-Bible-Ballentine-NT-Portions', 'ENGAME', 'English (1902) Amercian Bible (Ballentine) NT Portions', NULL, 'The 1902 publication "The American Bible - The Books of the Bible in Modern English for American Readers" by Frank Schell Ballentine represents a significant endeavor in making the Bible more accessible to American audiences. Published by the Good News Publishing Company in Scranton, PA, this edition sought to bridge the linguistic and cultural gap between the traditional Biblical texts and the contemporary American reader.<br><br>Ballentine''s work is notable for its commitment to presenting the Bible in a language and style that resonates with the modern American vernacular. This adaptation was not merely a simplification of the text but a thoughtful translation that aimed to maintain the essence and integrity of the original scriptures while making them more understandable and relatable to a 20th-century American audience. The focus was on clarity and relevance, ensuring that the timeless messages of the Bible could be comprehended and appreciated by readers unfamiliar with the archaic languages and contexts of the original texts.<br><br>"The American Bible" is a testament to the evolving nature of Biblical translations and their role in making sacred texts accessible to broader audiences. By adapting the language to fit the contemporary dialect of the time, Ballentine''s translation played a crucial role in democratizing the Bible, allowing more people to engage with its teachings in a meaningful way. This edition remains an important part of the history of Bible translations, reflecting the dynamic interplay between religious texts and the linguistic and cultural contexts of their readers.', 'historic', NULL, '124', 'eng', '1902', 'scan', 'Frank Schell Ballentine, Good News Publishing Company', NULL, NULL, 'ENGAME_DBS_HS/English-(1902)-Amercian-Bible-(Ballentine)-NT-Portions', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('151', 'Hebrew-1300-ca.-Hebrew-Bible-National-Library-of-Israel-WDL-11363', 'HEBMASP', 'Hebrew (1300 ca.) Hebrew Bible - National Library of Israel (WDL-11363)', 'עברית - תנ"ך עברי (1300 בקירוב, הספרייה הלאומית של ישראל) (WDL-11363)', 'The Hebrew Bible manuscript from around 1300, housed in the National Library of Israel, is a remarkable artifact of medieval Hebrew scholarship. Originating from Spain, this manuscript is distinguished by its full vocalization, accentuation, and detailed Masorah annotation, reflecting the extensive work of the Masoretes from the 7th to the 10th centuries. These annotations are critical for the accurate transmission of the Hebrew Bible, especially regarding spelling, vocalization, and accentuation.<br><br>The manuscript is beautifully illustrated and decorated with color, silver, and gold. The text is written in Sephardi square script on parchment, laid out in three columns per page, with 35 lines per column. The arrangement of the biblical books follows the conventional order typically seen in Hebrew printed editions, with the notable exception of Ecclesiastes preceding Lamentations.<br><br>An important feature of this manuscript is the Masorah Magna notes, executed in micrography, a technique where small script is used to create intricate decorative designs. The Masorah Magna, consisting of extensive notes on the upper and lower margins of the pages, is distinct from the Initial Masorah around the first letter of each book and the Masorah Parva found in the side margins or between columns.<br><br>Acquired by the Jewish National and University Library (now the National Library of Israel) in 1969, this manuscript serves as a crucial link to the medieval Jewish scholarly tradition and the history of Hebrew biblical manuscripts. Its preservation and accessibility in the National Library of Israel provide invaluable insights for scholars studying Hebrew scriptures and the development of religious texts over centuries.', 'historic', 'https://www.wdl.org/en/item/11363', '225', 'heb', '1300', 'scan', 'World Digital Library', NULL, 'World Digital Library', 'HEBMASP_DBS_HS/Hebrew-(1300-ca.)-Hebrew-Bible-National-Library-of-Israel-(WDL-11363)', 'heb', 'hebr1245', 'Hebrew', 'Israeli Hebrew', 'L', 'IL', '31.10565', '35.01788', '1', 'he', '5000000', NULL, 'Also in Australia, Canada, Germany, Palestinian West Bank and Gaza, Panama, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('152', 'English -1861-Codex-Sinaiticus-Snyder-Miller-1861-2004', 'ENGSINT', 'English  (1861) Codex Sinaiticus Snyder Miller (1861) 2004 Remake', NULL, 'The Codex Sinaiticus, a 4th-century manuscript, is among the oldest known complete copies of the Christian New Testament. Discovered by Constantin von Tischendorf in the mid-19th century at the Monastery of Saint Catherine on Mount Sinai, this manuscript has been pivotal in biblical scholarship.<br><br>In 1861, Henry Tompkins Anderson, an American scholar, embarked on translating the New Testament from its original Greek. His dedication culminated in a publication in 1864. Subsequently, Anderson revised his translation to incorporate readings from the Codex Sinaiticus, leading to the 1918 release titled "The New Testament Translated from the Sinaitic Manuscript Discovered by Constantine Tischendorf at Mt. Sinai." However, it''s important to note that this work was not a direct translation of the Codex but rather a revision of Anderson''s earlier translation, adjusted to align with some readings from the Sinaitic manuscript.<br><br>In 2004, Jackson Snyder undertook a project to make Anderson''s translation more accessible to contemporary readers. This endeavor involved modernizing the language and formatting while striving to maintain the integrity of Anderson''s original work. Snyder''s version, titled "The New Testament: The H.T. Anderson Translation," offers readers a rendition of the New Testament that reflects the textual nuances of the Codex Sinaiticus, presented in a style attuned to modern sensibilities.<br><br>These translations underscore the enduring significance of the Codex Sinaiticus in biblical studies, providing insights into early Christian texts and informing contemporary interpretations of the New Testament.', 'historic', NULL, '2', 'eng', '1861', 'scan', NULL, NULL, NULL, NULL, 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('153', 'Greek-1521-Erasmus-Greek-NT', 'GRCERAS', 'Greek (1521) Erasmus Greek New Testament', 'Ελληνική Καινή Διαθήκη του Έρασμου (1521)', 'The 1521 Erasmus Greek New Testament reflects the influential work of Erasmus of Rotterdam, a major figure of the Renaissance and a renowned scholar in Europe. Committed to the revitalization of the Church through what he termed the "philosophy of Christ," Erasmus dedicated himself to studying and publishing the Bible and early Church writings.<br><br>Erasmus had been engaged for years in two key projects: compiling Greek texts and producing a fresh Latin New Testament. Starting in 1512, his efforts to create a critical edition of the Latin New Testament involved collecting Vulgate manuscripts and refining the language. He aimed for a more polished Latin translation, asserting, "It is only fair that Paul should address the Romans in somewhat better Latin."<br><br>The inclusion of the Greek text in his work, while clearly intentional, was initially less apparent in purpose. Speculation about his motives includes producing a critical Greek text or preempting the Complutensian Polyglot, but there is no definitive evidence for these theories. Erasmus wrote, "There remains the New Testament translated by me, with the Greek facing, and notes on it by me." He included the Greek text to allow readers to assess the accuracy of his Latin version and to address translation errors and corruptions in the Greek text, often a result of translators'' clumsiness or scribes'' alterations.<br><br>By naming the final product "Novum Instrumentum omne" ("All of the New Teaching") and later "Novum Testamentum omne" ("All of the New Testament"), Erasmus indicated his belief in the critical importance of a text where Greek and Latin versions were consistently comparable, forming the core of the church''s New Testament tradition. His work not only contributed to the study and understanding of biblical texts but also set a precedent for future biblical scholarship and translations.', 'historic', NULL, '212', 'grc', '1521', 'scan', NULL, NULL, NULL, 'GRCERAS_DBS_HS', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('154', 'English-1640-Bay-Psalter-Bible-Psalms-Facsimile', 'ENGBAY', 'English (1640) Bay Psalter Bible - Psalms Facsimile', NULL, 'The Bay Psalm Book, printed in 1640 in Cambridge, Massachusetts, holds the distinction of being the first book printed in British North America. It is a metrical Psalter with English translations of the Psalms that, while not noted for their literary polish, mark a significant achievement in early American printing. The book''s translations did not endure in popularity, although some of the tunes for these Psalms, like "Old 100th," have survived.<br><br>In November 2013, a first edition copy of the Bay Psalm Book sold at auction for a record $14.2 million, underscoring its historical value. Early Massachusetts Bay Colony settlers brought with them several psalm books, including the Ainsworth Psalter, the Ravenscroft Psalter, and the Sternhold and Hopkins Psalter. Dissatisfied with these translations, they commissioned "thirty pious and learned Ministers" for a new translation closer to the Hebrew original. This group included Richard Mather, Thomas Mayhew, and John Eliot.<br><br>The Bay Psalm Book was the third product of the Stephen Day press and included a preface, an admonition to the reader, and an extensive list of errata. About 1,700 copies of the first edition were printed.<br><br>Subsequent editions, notably the third edition in 1651 revised by Henry Dunster and Richard Lyon, were popularly known as the New England Psalter or New England Version. This version formed the basis for all later editions, with the ninth edition in 1698 being the first to include music, featuring tunes from John Playford''s work.<br><br>Neoclassical influences in England led to an evolution in psalm singing, affecting American practices. In the 18th century, new psalm versions by Tate and Brady, and Isaac Watts, gained popularity, eventually replacing the Bay Psalm Book in many New England congregations.<br><br>Cotton Mather''s 1718 revision of the original Bay Psalm Book, followed by revisions in 1752 by John Barnard and in 1758 by Thomas Prince, reflected ongoing efforts to update the text. However, Prince''s version did not gain widespread acceptance, leading the Old South Church in Boston to revert to Isaac Watts''s earlier edition in 1789.', 'historic', 'https://en.wikipedia.org/wiki/Bay_Psalm_Book', '16', 'eng', '1640', 'reprint', 'Dodd, Mead & Company', NULL, NULL, 'ENGBAY_DBS_HS/English-(1640)-Bay-Psalter-Bible-Psalms-Facsimile', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('155', 'English-1966-Fenton-Holy-Bible', 'ENGFFB', 'English (1966) Fenton Holy Bible', NULL, 'The Ferrar Fenton Bible, also known as The Holy Bible in Modern English, is a landmark translation by Ferrar Fenton (1832–1920), a London businessman with a passion for biblical languages and texts. Initiated in 1853, Fenton embarked on a journey to translate the Bible into contemporary English, a task that spanned almost five decades. His primary aim was to preserve the Christian faith by making the Bible accessible and understandable in the vernacular of the 19th and early 20th centuries.<br><br>Fenton''s scholarly approach involved studying the original languages of the Bible - Sanskrit, Greek, Hebrew, and Latin. A distinguished member of the Royal Asiatic Society, he leveraged his expertise and access to ancient Septuagint and Masoretic manuscripts. Additionally, he referred to Brian Walton''s Polyglot Bible for minimal cross-referencing. His translation of Paul''s epistles appeared in 1883, followed by other parts, culminating in the complete Bible''s first publication in 1903, with revisions until 1910.<br><br>Notably, Fenton''s version reorganizes the books of the Bible into what he believed was their correct chronological order, particularly in the Old Testament, following the sequence of the Hebrew Bible. His unique interpretation of God''s name as "The EVER-LIVING" in the Old Testament, and occasionally as "LORD" and "JEHOVAH", reflects his commitment to a faithful yet modern rendering. For the Book of Job, he collaborated with Henrik Borgström, translating it into the same meter as the original Hebrew. His New Testament translation, based on the Greek text of Westcott and Hort, received approval from numerous theologians and academics. Fenton''s half-century endeavor in creating the Ferrar Fenton Bible stands as a testament to his dedication to making the biblical texts accessible and relevant to modern readers.', 'modern', NULL, '104', 'eng', '1966', 'book', 'Destiny Publishers', NULL, NULL, 'ENGFFB_DBS_HS/English-(1966)-Fenton-Holy-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('156', 'English-1904-The-Gospels-in-Art-Shaw', 'ENGSHAW', 'English (1904) The Gospels in Art (Shaw)', NULL, '"The Gospels in Art," edited by W. Shaw Sparrow, is a distinguished work that masterfully intertwines the life of Christ with the artistic expressions of renowned painters ranging from Fra Angelico to Holman Hunt. This book is part of the esteemed "Art & Life Library" series, specifically volumes 2 and 7, and offers a vivid portrayal of the Apostles both in art and symbolism. <br><br> This remarkable collection is notable for its combination of textual insights and visual artistry. The text contributions come from eminent figures like Leonce Benedite, Henry Van Dyke, R. F. Horton, and the Bishop of Derry & Raphoe, as stated on the title page. These scholarly perspectives provide a rich context to the artworks presented. <br><br> The volumes are notable for their decorated title pages, which are accompanied by photogravure and monochrome plates, offering readers a visually captivating experience. Each piece of art included in these volumes is not just a representation of a biblical scene but also a reflection of the artist''s interpretation of the Gospels, making this work a unique blend of religious narrative and artistic genius. <br><br> "The Gospels in Art" stands as a testament to the profound impact of the life of Christ on the world of art, capturing the essence of these biblical stories through the lens of some of the greatest painters in history. The combination of scholarly text and artistic representation makes this work an invaluable resource for both art enthusiasts and those interested in religious studies.', 'historic', NULL, '65', 'eng', '1904', 'scan', 'Hodder & Stoughton', NULL, NULL, 'ENGSHAW_DBS_HS/English-(1904)-The-Gospels-in-Art-(Shaw)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('157', 'English-1904-Jefferson-Gospels-Latin-Greek-French-Gospels', 'ENGJEFF', 'English (1904) Jefferson Gospels (Latin Greek French) - Gospels', NULL, '"The Life and Morals of Jesus of Nazareth," commonly known as the Jefferson Bible, stands as a unique religious work compiled by Thomas Jefferson, the third President of the United States. This work, completed in 1820, represents Jefferson''s efforts to distill the teachings of Jesus, as he painstakingly cut and pasted sections from the New Testament to craft a narrative that focused solely on Jesus'' moral teachings, excluding all supernatural aspects, including miracles and the concept of Jesus'' divinity. <br><br> The Jefferson Bible is a testament to Jefferson''s complex relationship with religion and his pursuit of a rational approach to faith. His version of the Bible omits the Resurrection, miracles, and any portrayal of Jesus as divine, reflecting his Enlightenment-influenced views. <br><br> The original manuscript, which never saw publication during Jefferson''s lifetime, was acquired by the Smithsonian Institution in 1895 from Jefferson''s great-granddaughter, Carolina Randolph, for $400. This acquisition marked a significant moment in preserving a piece of America''s religious and political history. <br><br> The Smithsonian''s conservation efforts, spearheaded by Senior Paper Conservator Janice Stagnitto Ellis, culminated in a public exhibit from November 11, 2011, to May 28, 2012, at the National Museum of American History. This exhibit not only showcased the Jefferson Bible but also the source books from which Jefferson derived his passages, and the 1904 edition distributed by the United States Congress. The exhibit was further enhanced by an interactive digital facsimile and the Smithsonian Channel''s documentary "Jefferson''s Secret Bible," premiered on February 20, 2012, offering a deeper insight into this intriguing piece of history.', 'historic', NULL, '17', 'eng', '1904', 'study', 'Thomas Jefferson, Government Printing Office', NULL, NULL, 'ENGJEFF_DBS_HS/English-(1904)-Jefferson-Gospels-(Latin-Greek-French)-Gospels-copy', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('158', 'French-1801-Ostervald-Bible-La-Sainte-Bible-ou-L''Ancien-et-le-Nouveau-Testament', 'FRAOST', 'French (1801) Ostervald Bible', 'Bible Ostervald (1801)', 'French (1801) Ostervald Bible The 1801 Ostervald Bible, an outcome of efforts to refine Olivetan''s earlier version, was intended to better meet contemporary needs with contributions from Beza, Goulart, Fay, and others, under Cornelius Bertram''s editorial direction. First revised in 1588 by the Venerable Company of Pastors at Geneva, this edition notably uses "L''Eternel" to translate יהוָֹה, diverging from the common Protestant practice of using a term equivalent to "Lord." Further revisions were made in 1693, 1712, 1726, 1805, and for the New Testament in 1803, with the latter versions significantly modernized in style. Despite aiming for elegance, this translation has been critiqued for not fully capturing the essence of the original texts. The Ostervald Bible marks a significant moment in the history of French biblical translations, reflecting the evolving language and theological considerations of its time.', 'historic', NULL, '86', 'fra', '1801', 'scan', NULL, NULL, NULL, 'FRAOST_DBS_HS/French-(1801)-Ostervald-Bible-(La-Sainte-Bible-ou-L''Ancien-et-le-Nouveau-Testament)', 'fra', 'stan1290', 'French', 'français', 'L', 'FR', '48', '2', '1', 'fr', '77200000', 'Andorra and France', 'Also in Algeria, Andorra, Austria, Belgium, Benin, Burkina Faso, Burundi, Cambodia, Cameroon, Canada, Central African Republic, Chad, Comoros, Congo, Côte d’Ivoire, Democratic Republic of the Congo, Djibouti, Equatorial Guinea, French Guiana, French Polynesia, Gabon, Guadeloupe, Guinea, Haiti, India, Israel, Italy, Lebanon, Libya, Luxembourg, Madagascar, Mali, Martinique, Mauritania, Mauritius, Mayotte, Monaco, Morocco, Mozambique, New Caledonia, Niger, Philippines, Puerto Rico, Réunion, Rwanda, Saint Pierre and Miquelon, Saudi Arabia, Senegal, Seychelles, South Africa, Switzerland, Togo, Tunisia, United Arab Emirates, United Kingdom, United States, U.S. Virgin Islands, Vanuatu, Wallis and Futuna.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('159', 'English-1822-Critical-Commentary-Study-Bible-Patrick-Full-6-Voll', 'ENGCCS', 'English (1822) Critical Commentary Study Bible (Patrick) 6 Vol', NULL, 'The 1822 publication titled "The Holy Bible. A Critical Commentary and Paraphrase on the Old and New Testament, and the Apocrypha" is a significant scholarly work in the field of biblical studies. This comprehensive commentary, contributed to by Patrick, Lowth, Arnold, Whitby, and Lowman, represents a concerted effort by a group of esteemed divines to provide a critical and interpretive companion to the biblical text. The work was intended to be completed in sixty numbers, each priced at twenty-five cents, culminating in four imperial octavo volumes totaling over 4300 pages.<br><br>Published in Philadelphia by Cary and Hart, this edition also had a variant published in London, printed by J. F. Dove for Richard Priestley in 1822. The London edition, corrected by the Reverend J. R. Pitman, was presented in six volumes.<br><br>Thomas Horne, in his 1827 "Introduction to the Study of the Bible," highlights the significance of Dr. Whitby''s commentary on the New Testament. Whitby''s work, first appearing in 1703, has been widely recognized and frequently reprinted, often alongside Bishop Patrick''s Paraphrase and Commentary on the Historical and Poetical Books, and Mr. Lowth''s Paraphrase on the Prophetical Books of the Old Testament. Horne notes that while the most valuable annotations from the latter two works were included in Dr. D''Oyly''s and Bishop Mant''s Commentary, Whitby''s contributions remain distinct for their valuable dissertations on various subjects, making it a highly recommended resource for students and modern commentators.<br><br>This collection of commentaries and paraphrases reflects the rich diversity of theological and biblical scholarship of the early 19th century, offering critical insights and interpretations that have been influential in shaping subsequent biblical studies.', 'historic', NULL, '1', 'eng', '1822', 'study', 'Patrick, Lowth, Arnald, Whitby, and Lowman', NULL, NULL, 'ENGCCS_DBS_HS/English-(1822)-Critical-Commentary-Study-Bible-(Patrick)-6-Vol-(Vol.-1-3)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('160', 'Hebrew-1524-The-Second-Rabbinic-Bible-Mikraot-Gedolot-Volume-2', 'HEBRABB', 'Hebrew (1524) The Second Rabbinic Bible (Mikraot Gedolot) (מקראות גדולות) Volume 2', 'עברית - המקראות הגדולות (1524, התנ"ך הרבני השני, כרך 2)', 'The second volume of the Mikraot Gedolot, also known as the Second Rabbinic Bible, is an integral part of this landmark publication in the history of Hebrew biblical texts. Produced and edited by Jacob ben Haim (Yaakov ben Hayyim ibn Adonijah), this work was published by Daniel Bomberg in Venice between 1524 and 1525. The Mikraot Gedolot is a seminal printing of the Hebrew Bible, specifically the Hebrew Masoretic text.<br><br>This edition is historically significant as it is believed to have been the source text (Textus Receptus) for the Hebrew Old Testament used by the translators of the King James Version of the Bible in 1611. Jacob ben Haim, a Jewish Masoretic scholar who later converted to Christianity, played a crucial role in its production and editing.<br><br>The creation of the Mikraot Gedolot or Second Rabbinic Bible was a monumental achievement in typesetting, especially considering the technological limitations of the early printing press. The meticulous assembly of Hebrew letters, vowels, and accents for this edition was an arduous and innovative process.<br><br>Ben Hayyim used the best Hebrew manuscripts available to him at the time. While there has been some debate over the quality of the manuscripts he had access to, Masoretic scholar Ginsburg has supported the notion that this edition was a good representation of the Ben Asher text. Ginsburg''s own highly-regarded editions of the Hebrew Bible, printed by the British and Foreign Bible Society, were indeed based on ben Hayyim''s Second Rabbinic Bible or Mikraot Gedolot, further emphasizing its importance and influence in the field of Hebrew biblical scholarship.', 'historic', NULL, '1', 'heb', '1524', 'scan', NULL, NULL, NULL, 'HEBRABB_DBS_HS/Hebrew-(1524)-The-Second-Rabbinic-Bible-(Mikraot-Gedolot)-Volume-2', 'heb', 'hebr1245', 'Hebrew', 'Israeli Hebrew', 'L', 'IL', '31.10565', '35.01788', '1', 'he', '5000000', NULL, 'Also in Australia, Canada, Germany, Palestinian West Bank and Gaza, Panama, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('161', 'Latin-1890-Triglot-Bible-Heb-Greek-Latin', 'LATCLV', 'Latin (1890) Triglot Bible (Heb Greek Latin)', 'Biblia Triglotta (1890, Heb-Greek-Latin)', 'Latin (1890) Triglot Bible (Heb Greek Latin)<br><br>The Triglot Bible, published in 1890 by R.D. Dickinson, is a comprehensive compilation of the Holy Scriptures of the Old and New Testaments. This edition uniquely presents the texts in their original languages—Hebrew for the Old Testament, Greek for the New Testament—alongside the Septuagint (Greek translation of the Old Testament), the Syriac version of the New Testament, and the Latin Vulgate. These texts are arranged in parallel columns, offering a comparative study of the scriptures across different linguistic and cultural interpretations. The publication includes a complete prolegomenon, providing valuable insights and scholarly context. This Triglot Bible is an important resource for biblical scholars, linguists, and those interested in the textual analysis and historical study of the Bible.', 'historic', NULL, '715', 'lat', '1890', 'study', 'Richard D. Dickinson', NULL, NULL, 'LATHEX_DBS_HS/Latin-(1890)-Triglot-Bible-(Heb-Greek-Latin)', 'lat', 'lati1261', 'Latin', 'lingua latīna', 'A', 'VA', '41.90264', '12.45021', '3', 'la', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('162', 'French-1540-Sword-Bible-Middle-French', 'FRAOLI', 'French (1540) Sword Bible (Middle French)', 'Bible de l''Épée (1540, Moyen Français)', 'French (1540) "Sword Bible" (Middle French) Pierre Robert, also known as Olivétan (1506-1538), a native of Picardy, is known for his translation of the Bible into French, called the Olivetan Bible. The Waldensians commissioned and financed this translation – they were Waldo’s disciples who joined the Reform Movement at the Synod of Chanforan in 1532.<br><br>Some historians think that it was the French-speaking Swiss who encouraged this undertaking and William Farel in particular. It is thought that he persuaded the Waldensians to finance the project. The Reformers in Geneva and Lausanne were keen to have a translation of the Bible into French which was not based on the Vulgate, but on the original Greek and Hebrew texts. They were looking for a good translator and chose Olivétan because he had studied Hebrew with Bucer in Strasbourg. It was an incredible achievement for one man to have translated the entire Bible in two years. Indeed, he was a precursor of future translators, as his translation was the first to be based on the original Greek and Hebrew texts, although he did consult Lefèvre d’Etaples’ translation of the New Testament as well.<br><br>Unfortunately, his translation of the Bible, published by Pierre de Vingle in Neuchâtel in 1535, was not a commercial success. This was partly because of the Gothic script and the fact that it was a large book, so difficult to handle or take around. The 1540 version, also known as "The Sword Bible" was a printing success. The printer Jean Girard brought out an edition which was easier to handle and also to read because it was in Roman script and included punctuation marks.', 'historic', NULL, '353', 'fra', '1540', 'scan', NULL, NULL, NULL, 'FRASWOR_DBS_HS', 'fra', 'stan1290', 'French', 'français', 'L', 'FR', '48', '2', '1', 'fr', '77200000', 'Andorra and France', 'Also in Algeria, Andorra, Austria, Belgium, Benin, Burkina Faso, Burundi, Cambodia, Cameroon, Canada, Central African Republic, Chad, Comoros, Congo, Côte d’Ivoire, Democratic Republic of the Congo, Djibouti, Equatorial Guinea, French Guiana, French Polynesia, Gabon, Guadeloupe, Guinea, Haiti, India, Israel, Italy, Lebanon, Libya, Luxembourg, Madagascar, Mali, Martinique, Mauritania, Mauritius, Mayotte, Monaco, Morocco, Mozambique, New Caledonia, Niger, Philippines, Puerto Rico, Réunion, Rwanda, Saint Pierre and Miquelon, Saudi Arabia, Senegal, Seychelles, South Africa, Switzerland, Togo, Tunisia, United Arab Emirates, United Kingdom, United States, U.S. Virgin Islands, Vanuatu, Wallis and Futuna.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('163', 'English-1825-Family-Expositer-New-Testament-Doddridge', 'ENGFAM', 'English (1825) Family Expositer New Testament (Doddridge)', NULL, 'Doddridge, Philip The New Testament with Paraphrase and Notes. 6 Vols. London: J. Wilson, 1739-1756. First published 1739. Another Edition; 6 Vols. London: Printed by Assignment from the Author''s window..., 1761. <br><br>Also; A new translation of the New Testament... extracted from the paraphrase of the late Philip Doddridge, D.D., and carefully revised. With an introduction and notes [by Samuel Palmer). London: For J. Rivington, W. Johnston, R. Baldwin and C. Rivington, 1765. <br><br>Another edition; The Family Expositor; or a Paraphrase and Version of the New Testament; With Critical Notes, and a Practical Improvement of each Section. In six Volumes... by P. Doddridge, D.D. To which is prefixed, A Life of the Author, by Andrew Kippis... Etheridge''s Edition, from the Eighth London Edition. Charlestown, Massachusetts: S. Etheridge, Printer; Sold by him at Washington Head Bookstore. Sold also by said Etheridge and Company, in Boston. 1807. [This harmonized the Gospels. The New Testament paraphrase, separate from the commentary and notes, was published. In 1833, a 1 Vol. Edition of this work, along with a memoir of the Author was Published at Amherst. This was a very popular work and was reprinted many times in various forms.] First American Edition; Abridged. 2 Vols. Edited by S.Palmer. Hartford: Printed by Lincoln & Gleason, 1807. Also; 1 Vol. Edition. New York: Robert Carter & Bros., 1857.<br><br>Chamberlin, W. J. (1991). Catalogue of English Bible Translations: A Classified Bibliography of Versions and Editions Including Books, Parts, and Old and New Testament Apocrypha and Apocryphal Books. New York: Greenwood Press.<br><br>Philip Doddridge was an early 18th century non-conformist pastor, and like Matthew Henry, he spent much of his free time writing his commentary. Doddridge notes in the preface that he intended this commentary to be used by families at the dinner table. The forgotten practice of family worship is a great way to use this commentary; the expanded translation, and the devotions at the end of each section (see below) work together seamlessly as a perfect tool for family devotional reading and discussion. This may well be the book that Jonathan Edwards used for his family devotions.<br><br>The Family Expositor is an extraordinary work. Doddridge deems it “a paraphrase,” but it is much more than that. Really it’s three works in one. It is a puritan translation and expansion on the text, a puritan commentary on the text, and a puritan devotional work on the text. Doddridge combines these three to make a truly great puritan companion to the New Testament.', 'historic', 'https://en.wikipedia.org/wiki/Philip_Doddridge', '644', 'eng', '1825', 'scan', NULL, NULL, NULL, 'ENGFAM_DBS_HS/English-(1825)-Family-Expositer-New-Testament-(Doddridge)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('164', 'English-1886-Bartlett-Bible-Vol.1-2', 'ENGBAR', 'English (1886) Bartlett Bible - Vol.1-2', NULL, 'John Bartlett, a man whose lineage traced back to significant historical figures such as the Mayflower Pilgrims and survivors of the infamous 1635 shipwreck off Cape Ann, was a prodigious intellect from a young age. Born in Plymouth, Massachusetts, to William Bartlett and Susan Thacher, he showcased an extraordinary aptitude for reading, having read the entire Bible by the tender age of nine. His educational journey culminated at the age of sixteen, after which he ventured to Cambridge, Massachusetts. Here, he initially worked for the University Bookstore, a hub for Harvard students, and by twenty-nine, he had risen to own the store.<br><br>Bartlett''s remarkable memory for quotations and trivia soon made him a local oracle of knowledge, with "Ask John Bartlett" becoming a popular phrase for those seeking answers. His passion for quotations led him to compile a commonplace book to assist with queries, which eventually evolved into the first edition of his seminal work, "Familiar Quotations," published privately in 1855. This initial 258-page edition included quotations from 169 authors, with a significant portion devoted to the Bible and William Shakespeare, alongside other eminent English poets.<br><br>Bartlett''s dedication to this work was further exemplified by the meticulous concordance he created with his wife, Hannah, the daughter of Sidney Willard, a Harvard professor of Hebrew. This effort, he estimated, took about 16,000 hours. Bartlett''s life journey concluded in Cambridge, Massachusetts, where he passed away at 85, leaving behind a legacy etched in his contributions to literature and historical memory. He lies buried at Mount Auburn Cemetery in Cambridge, Middlesex County, Massachusetts.', 'historic', NULL, '110', 'eng', '1886', 'scan', 'G. P. Putnam''s Sons', NULL, NULL, 'ENGBAR_DBS_HS/English-(1886)-Bartlett-Bible-Vol.1-2', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('165', 'Hebrew-1299-The-Cervera-Bible-Illuminated-WDL-14158', 'HEBCERV', 'Hebrew (1299) The Cervera Bible - Illuminated (WDL-14158)', 'עברית - תנ"ך סרוורה (1299, מואר) (WDL-14158)', 'The Cervera Bible, completed in 1300 and originating from Cervera, Catalonia, Spain, is a highly significant Sephardi Bible, notable for its survival through periods of significant turmoil for Jewish communities in Spain and Portugal. This manuscript, a rare example of Iberian Hebrew paleography from that era, consists of 451 parchment folios, each containing two columns with 31 lines.<br><br>Richly illuminated with gold, color, Mozarabic, and Jewish motifs, the Cervera Bible includes the Old Testament, the Masorah, and "Sefer Ha-Nikud" (Et Sofer), a grammatical treatise by Rabbi David Kimhi. The main text''s scribe, Samuel Ben Abraham ibn Nathan, is credited in the colophon on folio 434 recto. The colophon reveals the manuscript''s execution dates, starting on July 30, 1299, and completing on May 19, 1300, while also noting the initial patron''s name, later erased due to ownership changes.<br><br>Josef Asarfati, identified in the last folio''s colophon, was responsible for the manuscript''s illumination. The Masorah scribe, Josue ben Abraham ibn Gaon, is named in 20 places within the Masoretic text. The illuminations, varying in color and form, include ornamental page borders, full-page illustrations of Jewish iconography, and depictions of Old Testament scenes and Tabernacle worship objects. The Masoretic text features micrographic script, forming intricate geometric and stylized motifs.<br><br>An 18th-century binding encases the manuscript, with red leather and gold-engraved cardboard folders and marbled flyleaves. The Cervera Bible was acquired in 1804 by António Ribeiro dos Santos, head librarian of the Royal Public Library of the Court in Lisbon, for 240,000 reis. This acquisition in The Hague highlights the manuscript''s historical journey and enduring significance.', 'historic', 'https://www.wdl.org/en/item/14158', '261', 'heb', '1299', 'illuminated', 'World Digital Library', NULL, 'World Digital Library', 'HEBCERV_DBS_HS/Hebrew-(1299)-The-Cervera-Bible-Illuminated-(WDL-14158)', 'heb', 'hebr1245', 'Hebrew', 'Israeli Hebrew', 'L', 'IL', '31.10565', '35.01788', '1', 'he', '5000000', NULL, 'Also in Australia, Canada, Germany, Palestinian West Bank and Gaza, Panama, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('166', 'English-1790-Christian-Complete-Family-Bible', 'ENGKJV', 'English (1790) Christian Complete Family Bible', NULL, 'The "Christian''s New and Complete British Family Bible," published by Hogg & Co. in London around the 1790s, is a significant edition in the realm of biblical literature. Presented as a hardback folio, this Bible measures approximately 39 cm in height and 25 cm in width. It is an example of a comprehensive family Bible, a format popular during that time, intended for use in daily devotions and as a reference for religious education within the family.<br><br>The Bible is bound in full paneled calf leather, featuring gilt tooling on its boards, indicative of the craftsmanship and aesthetic considerations of bookbinding in the late 18th century. The inclusion of the Psalms of David at the end of the Bible is a notable feature, as the Psalms were often used for personal devotion and in liturgical settings. <br><br>Illustrated with numerous plates and maps, including a frontispiece and title page, this Bible stands out for its visual appeal. These illustrations not only served to enhance the reader''s understanding of the biblical narratives but also added an artistic quality to the book, making it a valuable and cherished family possession.<br><br>This edition of the Bible reflects the era''s emphasis on religious education and the role of the Bible in everyday Christian life, particularly within the family context. It represents a blend of religious significance, educational utility, and artistic expression, characteristic of family Bibles produced in the late 18th and early 19th centuries.', 'historic', NULL, '458', 'eng', '1790', 'scan', 'B. Jackson', NULL, NULL, 'ENGKJV_DBS_HS/English-(1790)-Christian-Complete-Family-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('167', 'Greek-English-1882-Scrivener-Parallel-New-Testament', 'GRCSCRI', 'Greek-English (1882) Scrivener Parallel New Testament', 'Παράλληλη Καινή Διαθήκη του Scrivener (1882)', 'The 1882 Scrivener Parallel New Testament features the Greek New Testament as edited by Frederick H. A. Scrivener in 1881. Scrivener, a respected scholar of the late nineteenth century, worked on the Textus Receptus (TR), also known as the Received Text. This edition of the Greek New Testament is significant for its basis on the Traditional or Byzantine Text, which itself is grounded in a vast collection of ancient handwritten New Testament manuscripts.<br><br>The Textus Receptus has been a cornerstone in the history of biblical translations, particularly noted for its role in the translation of the King James Version (KJV) New Testament. The parallel nature of Scrivener''s edition, juxtaposing the Greek text of the Textus Receptus with the English text of the KJV, offers a valuable resource for comparative study and analysis. This parallel format allows scholars, theologians, and students to closely examine the translation choices made in the KJV and to understand the textual basis of this influential English translation of the New Testament. Scrivener''s work in editing and presenting the Textus Receptus thus continues to be an important contribution to biblical scholarship and the study of New Testament texts.', 'historic', NULL, '53', 'grc', '1882', 'study', 'Arthur Hinds and Company', NULL, NULL, 'GRCSCRI_DBS_HS/Greek-English-(1882)-Scrivener-Parallel-New-Testament', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('168', 'Hebrew-1137-Mishneh-Torah-Manuscript', NULL, 'Hebrew (1137) Mishneh Torah Manuscript', 'עברית - משנה תורה (1137, כתב יד)', NULL, 'historic', NULL, '130', 'hbo', '1137', 'manuscript', NULL, NULL, NULL, NULL, 'hbo', 'anci1244', 'Ancient Hebrew', 'עִבְרִית מִקְרָאִית', 'H', 'IL', '31.77607', '35.17248', '9', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('169', 'Greek-0867-ca.-Codex-Aureus-Anthimi-Gospels-WDL-21767', 'GRCAURE', 'Greek (0867 ca.) Codex Aureus Anthimi Gospels (WDL-21767)', 'Κώδικας Χρυσούς των Ευαγγελίων του Άνθιμου (0867 περ.) (WDL-21767)', 'The Codex Aureus Anthimi, also known as Codex of Berat number 2 (Gregory-Aland no. 1143), is a Byzantine manuscript from around 867 AD, renowned for its artistic and historical significance. This ninth-century manuscript contains the four Gospels, written in Greek minuscule letters with golden ink on purple parchment, which has since faded to a yellowish-green hue. It is notable for its one-column format, featuring 17 lines per page.<br><br>What sets this manuscript apart are its four gold miniatures of the Evangelists, making it an exceptional surviving artifact from its era. It is believed to have been copied in an imperial scriptorium either in Constantinople or along the shores of Asia Minor during the Macedonian Renaissance. The manuscript''s journey to Berat, south-central Albania, where it was present since 1356, remains undocumented. It endured through significant historical upheavals, including being hidden during the Communist regime''s anti-religious campaigns in Albania after World War II. Rediscovered in 1968, it was severely threatened by humidity before being restored in Beijing in 1971, under an agreement with the Academy of Sciences of China.<br><br>Since its return to Albania in January 1972, the Codex Aureus Anthimi has been preserved at the Central State Archive of Albania in Tirana. The manuscript, alongside the sixth-century Codex Beratinus Purpureus Phi, was recognized as a unique treasure for humanity and inscribed on the UNESCO Memory of the World register in 2005. Its embossed metal plate covers, produced in 1805, were likely added during a restoration in that period, adding to its historical and aesthetic value.', 'historic', 'https://www.wdl.org/en/item/21766', '115', 'grc', '867', 'manuscript', 'World Digital Library', NULL, 'World Digital Library', 'GRCAURE_DBS_HS/Greek-(0867-ca.)-Codex-Aureus-Anthimi-Gospels-(WDL-21767)', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('170', 'French-1744-La-Sainte-Bible-Martin-Version-Book', 'FRAM44', 'French (1744) La Sainte Bible (Martin Version) Book', 'La Sainte Bible (1744, Version Martin)', 'French (1744) La Sainte Bible (Martin Version) Book David Martin (1639-1721), was a learned French Protestant theologian educated at Montauban, and at the academy of the reformed at Nîmes. He afterward studied divinity at Puy-Laurent, whither the academy of Montauban had been removed. Having been admitted to the ministry in 1663, he settled as a pastor with the church of Esperance, in the diocese of Castres. In 1670 he accepted an invitation to the church of La Caune, in the same diocese, where he officiated till the revocation of the Edict of Nantes, in 1685. In 1686, the magistrates of Deventer invited him to become a professor of divinity and pastor of the Walloon church in that city; but the regency of Utrecht, where he had taken up his residence, fully apprised of his merit, prevailed upon him to accept the office of pastor in their city.<br><br>Martin published an edition of the New Testament, according to the Geneva version, with corrections, notes, new prefaces to each book, etc., printed at Utrecht in 1696, with a History of the Old and New Testament, at Amsterdam, in 1707, in two volumes, folio, embellished with upwards of 420 beautiful engravings, which is commonly called Mortier''s Bible, after the name of the printer. He also published an edition of The Holy Bible, with corrections, notes, and prefaces, at Amsterdam, 1702, in 2 vols, fol., which was afterward reprinted in 1712 with parallel passages, and short notes in the margin.', 'modern', NULL, '7', 'fra', '1744', 'book', NULL, NULL, NULL, 'FRAM44_DBS_HS/French-(1744)-La-Sainte-Bible-(Martin-Version)-Book', 'fra', 'stan1290', 'French', 'français', 'L', 'FR', '48', '2', '1', 'fr', '77200000', 'Andorra and France', 'Also in Algeria, Andorra, Austria, Belgium, Benin, Burkina Faso, Burundi, Cambodia, Cameroon, Canada, Central African Republic, Chad, Comoros, Congo, Côte d’Ivoire, Democratic Republic of the Congo, Djibouti, Equatorial Guinea, French Guiana, French Polynesia, Gabon, Guadeloupe, Guinea, Haiti, India, Israel, Italy, Lebanon, Libya, Luxembourg, Madagascar, Mali, Martinique, Mauritania, Mauritius, Mayotte, Monaco, Morocco, Mozambique, New Caledonia, Niger, Philippines, Puerto Rico, Réunion, Rwanda, Saint Pierre and Miquelon, Saudi Arabia, Senegal, Seychelles, South Africa, Switzerland, Togo, Tunisia, United Arab Emirates, United Kingdom, United States, U.S. Virgin Islands, Vanuatu, Wallis and Futuna.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('171', 'English-1808-The-Septuagint-Old-Testamant-Translation-Charles-Thomson', 'ENGSOT', 'English (1808) The Septuagint Old Testamant Translation (Charles Thomson)', NULL, 'Charles Thomson''s translation of the Septuagint, the Greek version of the Old Testament, into English is a notable work in biblical scholarship. Completed over 19 years and published in 1808, Thomson’s work stands out for being a direct translation from the Greek Septuagint, a rarity at the time. Thomson, a Greek scholar who had been a teacher at several prominent schools before the American Revolution, accomplished this monumental task largely independently, without significant assistance from other scholars.<br><br>His translation of the entire Greek Bible, excluding the Apocrypha, was published in a thousand sets of four volumes, with the fourth volume dedicated to Thomson’s translation of the New Testament. The project was printed by Jane Aitken in Philadelphia. Thomson''s translation was the first English version of the Septuagint to be published and was highly regarded by British biblical scholars, who viewed it as representative of the best in American scholarship.<br><br>David Daniell, in his comprehensive work "The Bible in English" (2003), noted that the scholars working on the Revised Version in England in 1881 referred to Thomson''s translations among other sources. Furthermore, Thomson''s version of the New Covenant/Testament is recognized as the first American translation of these texts.<br><br>Thomson''s personal copy of the translation, which contains his final corrections to the manuscript, is housed in the Philadelphia library. In addition to this translation, Thomson also published "A Synopsis of the Four Evangelists" in 1815, a work that originated from his notes for the translation project.<br><br>Charles Thomson (1729–1824) is also historically significant as the secretary of the Continental Congress from 1774 to 1789, playing a vital role in the early history of the United States. His translation of the Septuagint is a testament to his scholarly contributions beyond his political involvement.', 'historic', 'https://en.wikipedia.org/wiki/Thomson%27s_Translation', '65', 'eng', '1808', 'scan', NULL, NULL, NULL, 'ENGSOT_DBS_HS/English-(1808)-The-Septuagint-Old-Testamant-Translation-(Charles-Thomson)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('172', 'English-1610-Douay-Bible', 'ENGDRB', 'English (1610) Douay Bible', NULL, 'The Douay–Rheims Bible, also known as the Rheims–Douai Bible or Douai Bible, and abbreviated as D–R and DRB, is a significant English translation of the Bible. It was translated from the Latin Vulgate by members of the English College, Douai, in service to the Catholic Church. The New Testament was first published in Reims, France, in 1582 with extensive commentary and notes. The Old Testament followed in two volumes, published in 1609 and 1610 by the University of Douai. The first volume covered Genesis through Job, and the second included Psalms to 2 Machabees along with the deuterocanonical books of the Vulgate. The extensive marginal notes were polemical and patristic in nature, providing insights on translation issues and the Hebrew and Greek source texts.<br><br>The Douay–Rheims Bible was intended to support Catholic tradition against the Protestant Reformation, which had been influential in Elizabethan religion and academia. As part of the Counter-Reformation, this translation aimed to uphold Catholic perspectives. The New Testament was reprinted in 1600, 1621, and 1633, while the Old Testament volumes were reprinted in 1635.<br><br>William Fulke''s 1589 collation of the Rheims text with the Bishops'' Bible helped disseminate the Rheims New Testament in England, influencing 17th-century English. The original 1582/1610 text, characterized by dense Latinate vocabulary, was difficult to read. It was replaced by a revision by Bishop Richard Challoner, with the New Testament in editions from 1749 to 1752 and the Old Testament in 1750, minus the Apocrypha. This revision, while retaining the Douay–Rheims title, was essentially a new version, based largely on the King James Version and adjusted for readability and consistency with the Clementine Vulgate.<br><br>Subsequent editions of the Challoner Bible varied, with those printed in England often following his earlier New Testament texts. The Dublin editions revised by Bernard MacMahon from 1783 to 1810 influenced some American printings in the 19th century.<br><br>While the Jerusalem Bible, New American Bible Revised Edition, Revised Standard Version Catholic Edition, and New Revised Standard Version Catholic Edition are commonly used in English-speaking Catholic churches, the Challoner revision of the Douay–Rheims remains popular among more traditional Catholics. The original translation employed Early Modern (Renaissance) English, while later editions used Modern English. This translation, derived from the Vulgate, was a formal equivalence translation, compared with Hebrew and Greek sources for accuracy. Subsequent editions used the Sixto-Clementine Vulgate, often in diglot editions with the respective Vulgate versions.', 'historic', 'https://en.wikipedia.org/wiki/Douay%E2%80%93Rheims_Bible', '5', 'eng', '1611', 'scan', NULL, NULL, NULL, 'ENGDRB_DBS_HS/English-(1610)-Douay-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('173', 'English-1754-Wesleys-New-Testament-with-Notes', 'ENGWES', 'English (1754) Wesleys New Testament (with Notes)', NULL, 'John Wesley''s translation of the New Testament, published in 1755, represents a significant effort to correct perceived errors in the King James Version (AV). His translation of the Old Testament followed in 1764. Wesley, directly consulting Greek texts, aimed to improve the clarity, strength, and consistency of the biblical text. His approach to translation was meticulous, as he states in the Preface, altering the text only where it enhanced the sense or brought it closer to the original.<br><br>Wesley''s New Testament features many modifications from the AV, with approximately 12,000 single-word changes. The text is presented in paragraphs rather than verses, and Wesley''s notes are included below the text on each page. The Bible also contains a portrait of Wesley preaching.<br><br>The work saw several reprints and editions, including a 1757 reprint, a standard edition in 1760, and subsequent editions in 1765 (Bristol: William Pine), 1768, 1790 (abridged edition, City Road, London), 1839, and modern editions by Lutterworth Press (1938, 1953) and Epworth Press (1954, 1976). The first American edition was published in Philadelphia in 1791, with other American editions following in New York (1806, 1812, 1818, 1839, 1844), Chicago, Philadelphia, and Toronto (1938), and Grand Rapids (1986), among others.<br><br>John Wesley''s New Testament is not just a translation but also a testament to his theological perspectives and commitment to making the Bible accessible and understandable to a wider audience.', 'historic', 'https://library.garrett.edu/collections/special-collections/rare-bible-digital-exhibit/post-1600/john-wesley-new-testament-1755', '40', 'eng', '1754', 'scan', 'Carlton & Porter', NULL, NULL, 'ENGWES_DBS_HS/English-(1754)-Wesleys-New-Testament-(with-Notes)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('174', 'English-1922-Moffatt-New-Testament', 'ENGMOFF', 'English (1922) Moffatt New Testament', NULL, 'James Moffatt, born on July 4, 1870, in Glasgow, was a distinguished Scottish theologian and a proud alumnus of the University of Glasgow. His theological journey was deeply rooted in his early experiences as a minister at the United Free Church in Dundonald. Moffatt''s academic prowess led him to receive a Doctor of Divinity degree from the prestigious University of St Andrews in April 1902, a testament to his scholarly dedication and expertise. <br><br> In 1911, Moffatt''s career took a significant turn when he was appointed as Professor of Greek and New Testament Exegesis at Mansfield College, Oxford. However, his connection to Glasgow remained strong, and he returned in 1915 to serve as Professor of Church History at the United Free Church College. Moffatt''s academic journey eventually led him across the Atlantic to the Union Theological Seminary in New York, where from 1927 to 1939, he was the esteemed Washburn Professor of Church History. <br><br> Among his many scholarly accomplishments, Moffatt is renowned for his translation of the Bible into Modern English, known as the Moffatt, New Translation (MNT). This groundbreaking work first saw the light of day in 1913 with the publication of his New Translation of the New Testament. Moffatt''s translation was acclaimed for its fresh approach and accessibility, offering a contemporary interpretation of the scriptures that resonated with a modern audience. His work in translating the New Testament not only showcased his linguistic skill but also his deep understanding of biblical texts, making the Moffatt New Translation a significant contribution to biblical scholarship and study.', 'historic', NULL, '87', 'eng', '1922', 'scan', 'George H. Doran Company', NULL, NULL, 'ENGMOFF_DBS_HS/English-(1922)-Moffatt-New-Testament', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('175', 'Hebrew-1280-ca.-Old-Testament-Portions-Natoinal-Library-of-Israel-WDL-11366', 'HEBPOR', 'Hebrew (1280 ca.) Old Testament Portions - National Library of Israel (WDL-11366)', 'עברית - קטעי תנ"ך (1280 בקירוב, הספרייה הלאומית של ישראל) (WDL-11366)', 'This manuscript from around 1280, housed in the National Library of Israel, is a valuable fragment of what could have been a complete Hebrew Bible. It contains books from the Nevi''im (Prophets) and selections from the Ketuvim (Hagiographa or Writings), specifically the books of Chronicles and Psalms. This composition reflects the tripartite division of the Hebrew Bible, which includes the Torah, the Prophets, and the Hagiographa.<br><br>The manuscript features full vocalization and accentuation, essential for the correct reading and interpretation of the text. It also includes Masorah Parva notes, which are brief annotations found on the side margins or between columns. These notes are part of the Masorah, a critical collection compiled by Jewish scribes and scholars known as the Masoretes between the 7th and 10th centuries. The Masorah is recognized as the authoritative regulator of the written and vocalized transmission of the Hebrew Bible.<br><br>Written on parchment in Ashkenazi square script, the manuscript is arranged in two columns per page, with 28–30 lines per column. Interestingly, the leather binding was added by a Christian owner in France in the early 18th century, indicating the manuscript''s journey and the diverse interest in Hebrew scriptures across different cultures and time periods.', 'historic', 'https://www.wdl.org/en/item/11366', '251', 'heb', '1280', 'scan', 'World Digital Library', NULL, 'World Digital Library', 'HEBPOR_DBS_HS/Hebrew-(1280-ca.)-Old-Testament-Portions-Natoinal-Library-of-Israel-(WDL-11366)', 'heb', 'hebr1245', 'Hebrew', 'Israeli Hebrew', 'L', 'IL', '31.10565', '35.01788', '1', 'he', '5000000', NULL, 'Also in Australia, Canada, Germany, Palestinian West Bank and Gaza, Panama, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('176', 'English-1918-New-Testament-from-Sinaitic-Manuscripts-Anderson', 'ENGSINA', 'English (1918) New Testament from Sinaitic Manuscripts (Anderson)', NULL, 'The 1918 publication of Henry T. Anderson''s "The New Testament Translated from the Sinaitic Manuscript" represents a unique chapter in the history of biblical translations. Anderson''s work claims to be an English translation of the Codex Sinaiticus, a crucial and ancient biblical manuscript discovered by Constantine Tischendorf at Mount Sinai. However, the translation is actually a revision of Anderson''s earlier New Testament translation, incorporating some readings from the Codex Sinaiticus.<br><br>The preface of this edition does not detail the specific sources Anderson used, leaving a veil over the precise methodology of his translation work. Intriguingly, it is believed that Anderson prepared this version shortly before his death in 1872, indicating that the 1918 publication was a posthumous one.<br><br>Anderson''s translation efforts align with the broader movement of biblical scholarship in the 19th century, which saw a surge in interest in ancient manuscripts and their implications for understanding the original texts of the Bible. The Codex Sinaiticus, dating back to the 4th century, is one of the earliest complete manuscripts of the Greek Bible (Old and New Testament) and has been pivotal in biblical textual criticism. Anderson''s translation, though not a direct translation from the Sinaitic manuscript as claimed, contributed to the dynamic field of biblical studies by integrating elements from one of the most significant textual discoveries of the era.', 'historic', NULL, '44', 'eng', '1918', 'scan', 'The Standard Publishing Company', NULL, NULL, 'ENGSINA_DBS_HS/English-(1918)-New-Testament-from-Sinaitic-Manuscripts-(Anderson)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('177', 'English-1890-English-Shorthand-Bible', 'ENGPED', 'English (1890) English Shorthand Bible', NULL, 'The 1890 Holy Bible in Pitman''s Shorthand represents a unique fusion of religious scripture with a revolutionary form of writing. Pitman''s shorthand, developed by Sir Isaac Pitman, was a popular system of shorthand in the 19th century, known for its efficiency and ease of learning. This specific edition lithographed the entire Bible in the "Easy Reporting Style" of Pitman''s shorthand, a variant designed for quick transcription of speech.<br><br>Shorthand, a method of rapid writing by means of abbreviations and symbols, was widely used in business, journalism, and legal fields during that era. The publication of the Bible in this format was a testament to the widespread prevalence and acceptance of shorthand as a practical skill. This adaptation of the Bible was not just a novelty but served practical purposes, particularly for those proficient in shorthand, offering a unique way to engage with the scriptures.<br><br>The choice of the Authorized Version, commonly known as the King James Version, for this shorthand edition, reflects the version''s prominence and wide acceptance within English-speaking Christian communities. This version of the Bible in shorthand was more than a religious text; it was a cultural artifact of the period, showcasing the intersection of technological advancement in communication (shorthand writing) with enduring religious traditions. The 1890 Holy Bible in Pitman''s Shorthand is a remarkable example of how religious texts can be adapted to reflect and utilize contemporary advancements in communication and education.', 'historic', NULL, '87', 'eng', '1890', 'scan', 'Isaac Pitman & Sons', NULL, NULL, 'ENGPED_DBS_HS/English-Shorthand-(1890)-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('178', 'Hebrew-1524-The-Second-Rabbinic-Bible-Mikraot-Gedolot-Volume-1', 'HEBRABB', 'Hebrew (1524) The Second Rabbinic Bible (Mikraot Gedolot) (מקראות גדולות) Volume 1', 'עברית - המקראות הגדולות (1524, התנ"ך הרבני השני, כרך 1)', 'The Mikraot Gedolot, also known as the Second Rabbinic Bible, is a significant work in the history of Hebrew biblical texts. Published in Venice in 1524-1525 by Daniel Bomberg, this work was produced and edited by Jacob ben Haim (Yaakov ben Hayyim ibn Adonijah), a Jewish Masoretic scholar who later converted to Christianity. The Mikraot Gedolot is a classic printing of the Hebrew Bible, specifically the Hebrew Masoretic text, and it played a pivotal role in the development of later biblical translations.<br><br>This edition of the Mikraot Gedolot is believed to have been used by the translators of the King James Version of the Bible in 1611 as the source text (Textus Receptus) for the Hebrew Old Testament. The production of the Mikraot Gedolot was a monumental achievement in typesetting, especially considering the nascent state of the printing press at the time. It required meticulous and individual assembly of Hebrew letters, vowels, and accents.<br><br>Jacob ben Haim, in compiling this work, used the best Hebrew manuscripts available to him. While some have debated the quality of the manuscripts he had access to, the renowned Masoretic scholar Ginsburg argued that ben Hayyim''s edition was a good representation of the Ben Asher text. In fact, Ginsburg''s own highly-regarded editions of the Hebrew Bible, printed by the British and Foreign Bible Society, were based on ben Hayyim''s Second Rabbinic Bible or Mikraot Gedolot, underscoring its significant impact on Hebrew biblical scholarship.', 'historic', NULL, '585', 'heb', '1524', 'scan', NULL, NULL, NULL, 'HEBRABB_DBS_HS/Hebrew-(1524)-The-Second-Rabbinic-Bible-(Mikraot-Gedolot)-Volume-1', 'heb', 'hebr1245', 'Hebrew', 'Israeli Hebrew', 'L', 'IL', '31.10565', '35.01788', '1', 'he', '5000000', NULL, 'Also in Australia, Canada, Germany, Palestinian West Bank and Gaza, Panama, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('179', 'Greek-1150-ca.-Trebizond-Gospels-WDL-13009', 'GRCTREB', 'Greek (1150 ca.) Trebizond Gospels (WDL-13009)', 'Ευαγγέλια Τραπεζούντας (1150 περ.) (WDL-13009)', 'The Trebizond Gospels, likely created in Constantinople around the mid-12th century, is an exquisite example of Byzantine manuscript art. Its most striking feature is the full-page miniatures, demonstrating fine execution and a monumental quality. While the opening for the Gospel of Matthew is missing, the other three Gospels each begin with a pair of miniatures: one of the respective Evangelist and the other depicting a scene from their Gospel. Notably, the combination of Saint John with the Raising of Lazarus is unique to this manuscript.<br><br>The text was penned by two scribes with distinctly different handwriting styles. An ornament on folio 175 recto, showing two falcons, a partridge, and a hare, reflects the Byzantine nobility''s fondness for falconry. Folio 59 verso features a full-page miniature of "The Baptism," depicting the Holy Spirit as a dove descending over Christ, with two angels and a personification of the River Jordan. Saint Mark is portrayed on folio 60 recto, holding an open book at the beginning of his Gospel, with a writing desk in front.<br><br>The Annunciation is beautifully rendered on folio 102 verso, showing Mary spinning purple thread for the Temple''s curtain. The Evangelist Luke appears in a half-page miniature on folio 103 recto. A full-page miniature on folio 173 verso illustrates the Raising of Lazarus, with Lazarus''s sisters, Martha and Mary, depicted much smaller than Jesus. A man beside Lazarus holds his nose, indicating the body''s decomposition.<br><br>Saint John the Theologian, typically shown as an elderly man in Byzantine art, is featured in a full-page miniature on folio 174 recto, sitting at a writing desk with an oil lamp above. This manuscript, with its detailed and symbolic artwork, is a remarkable representation of Byzantine artistic and religious culture, offering valuable insights into the period''s manuscript production and iconography.', 'historic', 'https://www.wdl.org/en/item/21767', '139', 'grc', '1150', 'scan', 'World Digital Library', NULL, 'World Digital Library', 'GRCTREB_DBS_HS/Greek-(1150-ca.)-Trebizond-Gospels-(WDL-13009)', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('180', 'Hebrew-0895-Cairo-Codex-facsimilie', 'HBOCAIR', 'Hebrew (0895) Cairo Codex (facsimilie)', 'עברית - כתב יד קהיר (0895, פקסימיליה)', 'The Codex Cairensis, also known as the Codex Prophetarum Cairensis or Cairo Codex of the Prophets, is a significant Hebrew manuscript containing the complete text of the Nevi''im (Prophets) section of the Hebrew Bible. Traditionally believed to be the oldest dated Hebrew Codex of the Bible in existence, recent research suggests it may actually date from the 11th century, rather than the year 895 CE as indicated in its colophon. The codex includes the books of the Former Prophets (Joshua, Judges, Samuel, and Kings) and Latter Prophets (Isaiah, Jeremiah, Ezekiel, and the Twelve Minor Prophets), totaling 575 pages, which include 13 carpet pages.<br><br>According to its colophon, the codex was written with punctuation by Moses ben Asher in Tiberias, at the end of the year 827 after the destruction of the Second Temple. This corresponds to the year 895 CE, during the reign of Al-Mu''tadid. Originally a gift to the Karaite community in Jerusalem, the codex was taken as booty by Crusaders in 1099. It was later redeemed and came into the possession of the Karaite community in Cairo. In 1983, as the Karaite Jews departed Egypt, they entrusted the Codex Cairensis to the Hebrew University of Jerusalem. It is currently securely stored in a special room beneath the Hebrew Manuscript collection. The Codex''s journey back to Jerusalem was undertaken by a committee of six individuals, marking its return to the city after centuries.<br><br>The Codex Cairensis is of immense historical and textual significance, offering insights into the medieval Hebrew text of the Prophets. Its journey through time, from Tiberias to Jerusalem, then to Cairo, and back to Jerusalem, reflects the turbulent history of the Hebrew manuscripts and the communities that preserved them. This codex remains a crucial artifact for biblical scholars, particularly those interested in the textual traditions of the Hebrew Bible.', 'historic', NULL, '23', 'hbo', '895', 'manuscript', 'Makor Publishing LTD.', NULL, NULL, 'HBOCAIR_DBS_HS/Hebrew-(0895)-Cairo-Codex-(facsimilie)', 'hbo', 'anci1244', 'Ancient Hebrew', 'עִבְרִית מִקְרָאִית', 'H', 'IL', '31.77607', '35.17248', '9', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('181', 'English-1911-Hexaplar-Psalter-Psalms', 'ENGKJV', 'English (1911) Hexaplar Psalter Psalms', NULL, 'The Hexaplar Psalter, published in 1911, is a distinctive compilation that presents the Book of Psalms in six parallel English translations. Edited by William Aldis Wright, a renowned nonconformist writer and critic, this work offers readers a comprehensive view of the evolution of English biblical translation over several centuries. <br><br>The six versions included are:<br><br>Coverdale Bible (1535)<br>Great Bible (1539)<br>Geneva Bible (1560)<br>Bishops'' Bible (1568)<br>Authorized King James Version (1611)<br>Revised Version (1885)<br>By aligning these translations side by side, the Hexaplar Psalter enables readers to observe the linguistic and interpretative shifts that have occurred in the rendering of the Psalms. This format not only highlights the textual variations but also provides insights into the historical and theological contexts that influenced each translation.<br><br>The term "Hexaplar" is derived from Origen''s "Hexapla," a third-century work that presented the Old Testament in six versions. Similarly, the Hexaplar Psalter serves as a valuable resource for scholars, theologians, and lay readers interested in comparative biblical studies, textual analysis, and the history of English Bible translations.', 'historic', NULL, '33', 'eng', '1911', 'scan', NULL, NULL, NULL, NULL, 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('182', 'Aramaic-1885-Old-Testament-Talgum-with-Commentaries-vol-1-5-Old-Testmant', NULL, NULL, NULL, 'In the Syriac (Eastern Aramaic) language the Peshitta (Syriac: "common version") is the standard version of the Christian Bible. It continues to serve as the Bible of churches in the Syriac tradition (Church of the East, Chaldean Catholic, and Syriac Orthodox) to this day. The history of Christian Translations of the Bible into Syriac language includes the Diatessaron, the Old Syriac versions (Curetonian and Sinaitic), the Peshitto, the Philoxenian version, the Harklean Version and the recent United Bible Societies'' modern Aramaic New Testament.<br><br>About AD 500 a Christian Palestinian Aramaic version was made. It contains 2 Peter, 2-3 John, Jude, and Apocalypse. It is representative of the Caesarean text type and is a unique translation different from any other which was made into Syriac. These are among the manuscripts used by John Gwynn in 1893 to complete his edition of the Catholic Epistles. In 1892 Agnes Smith Lewis discovered the manuscript of the Palestinian Syriac lectionary in the library of Saint Catherine''s Monastery on Mount Sinai. It is designated by Syr.<br><br>The first revision of the New Testament from the Syriac into Turoyo language (Western Aramaic in Syriac and Latin script) was made by Malphono Yuhanun Üzel (Bar Shabo), Benjamin Bar Shabo, and Yahkup Bilgic in 2009 with notes from Harclean and Philoxenios. This commission "Sihto du Kthovo Qadisho Suryoyo" works especially to preach the Gospel in Aramaic all over the world.', NULL, NULL, NULL, 'aii', NULL, NULL, NULL, NULL, NULL, NULL, 'aii', 'assy1241', 'Assyrian Neo-Aramaic', 'Sūreṯ', 'L', 'IQ', '36.75', '43', '6b', NULL, '626000', 'Iraq', 'Northern Iraq, Baghdad, Basrah, Karkuk, Arbil. Also in Armenia, Australia, Austria, Azerbaijan, Belgium, Brazil, Canada, Cyprus, France, Georgia, Germany, Greece, Iran, Italy, Lebanon, Netherlands, New Zealand, Russian Federation (Europe), Sweden, Switzerland, Syria, Turkey (Asia), United Kingdom, United States.', 'AII1885', 'Aramaic (1885) Old Testament (Talgum) with Commentaries vol 1-5 - Old Testmant', 'Aramaic-1885-Old-Testament-Talgum-With-Commentaries-Vol-1-9-Old-Testmant.jpg', '1885', 'study', NULL, NULL, 'AII1885_DBS_HS/Aramaic-(1885)-Old-Testament-(Talgum)-with-Commentaries-vol-1-9-Old-Testmant', NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('183', 'French-1831-Sacy-New-Testament-Le-Nouveau-Testament', 'FRASAC', 'French (1831) Sacy New Testament', 'Nouveau Testament (1831, Sacy)', 'French (1831) "Sacy New Testament" refers to a significant translation of the New Testament into French, rooted in the Jansenist tradition and closely associated with the work of Isaac-Louis Le Maistre de Sacy. This version, often linked with the scholarly environment of Port-Royal des Champs, was part of a broader effort to provide a French translation of the Bible directly from the Latin Vulgate. The initial New Testament was published in 1667, with the complete Bible appearing under the guise of being from Mons but actually produced in Amsterdam due to the controversial nature of Jansenism and its conflict with official Catholic positions. De Sacy''s translation is renowned for its literary quality and its influence on French biblical scholarship and piety. Over the years, it saw many editions, both with and without extensive notes, reflecting its enduring value for French-speaking Christians. The version became widely known as the Version de Sacy and is considered one of the most important contributions to French biblical literature, bridging scholarly work and devotional reading.', 'historic', NULL, '551', 'fra', '1831', 'scan', 'Imprimerie De Firmin Didot Freres', NULL, NULL, 'FRASAC_DBS_HS/French-(1831)-Sacy-New-Testament-(Le-Nouveau-Testament)', 'fra', 'stan1290', 'French', 'français', 'L', 'FR', '48', '2', '1', 'fr', '77200000', 'Andorra and France', 'Also in Algeria, Andorra, Austria, Belgium, Benin, Burkina Faso, Burundi, Cambodia, Cameroon, Canada, Central African Republic, Chad, Comoros, Congo, Côte d’Ivoire, Democratic Republic of the Congo, Djibouti, Equatorial Guinea, French Guiana, French Polynesia, Gabon, Guadeloupe, Guinea, Haiti, India, Israel, Italy, Lebanon, Libya, Luxembourg, Madagascar, Mali, Martinique, Mauritania, Mauritius, Mayotte, Monaco, Morocco, Mozambique, New Caledonia, Niger, Philippines, Puerto Rico, Réunion, Rwanda, Saint Pierre and Miquelon, Saudi Arabia, Senegal, Seychelles, South Africa, Switzerland, Togo, Tunisia, United Arab Emirates, United Kingdom, United States, U.S. Virgin Islands, Vanuatu, Wallis and Futuna.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('184', 'Coptic-Southen-1910-New-Testament-Sahidic-and-Thebaic-Vol-1-4', 'COPSNT', 'Coptic Southen (1910) New Testament Vol 1-4)', 'Ⲙⲉⲧⲛⲓⲙ ⲛ̀ⲛⲉⲛⲧⲟⲥ (1910) Ⲛⲁⲩ 1-4', 'Sahidic Coptic, the Upper Egyptian dialect of Coptic, was spoken in the Theban (now Luxor) area of Egypt. The first Coptic dialect into which Scriptures are thought to have been translated, the language was extinct by the 10th century', 'historic', NULL, '198', 'cop', '1910', 'scan', 'Henry Frowde-University of Oxford', NULL, NULL, 'COPSNT_DBS_HS/Coptic-Southen-(1910)-New-Testament-(Sahidic-and-Thebaic)-Vol-1-6)', 'cop', 'copt1239', 'Coptic', 'ϯⲙⲉⲧⲣⲉⲙⲛ̀ⲭⲏⲙⲓ ~ ⲧⲙⲛ̄ⲧⲣⲙ̄ⲛ̄ⲕⲏⲙⲉ', 'E', 'EG', '29.47203', '31.2053', '9', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('185', 'Hebrew-1483-Lisbon-Bible-Pentateuch-Vol.-1-6-Manuscript', 'HEBLISB', 'Hebrew (1483) Lisbon Bible (Pentateuch) Vol. 1-6 Manuscript', 'עברית - תנ"ך ליסבון (1483, חמשה חומשי תורה, כרכים 1-6, כתב יד)', 'The Lisbon Bible, a manuscript dating back to 1483, is a distinguished example of the Portuguese school of medieval Hebrew illumination. As a codex, it stands out from traditional scroll forms of Hebrew manuscripts. This particular Bible is comprised of three volumes, collectively containing all 24 books of the Hebrew Bible. Volume One is dedicated to the Torah, or the Five Books of Moses, also known as the Pentateuch. The subsequent volumes cover the Prophets and the Hagiographa (Holy Writings), respectively.<br><br>Additionally, this manuscript includes lists of the Commandments found in the Torah and Masoretic material, providing critical information on the correct spelling, reading, and pronunciation of the biblical text. This inclusion enhances its value as a resource for biblical study and understanding. The Lisbon Bible was acquired by the British Museum (now part of the British Library) in 1882. Its current binding, which was crafted in 1954, replaced the original 16th-century leather covers, signifying the manuscript''s historical significance and the care taken to preserve it over the centuries.', 'historic', NULL, '187', 'heb', '1483', 'manuscript', NULL, NULL, NULL, 'HEBLISB_DBS_HS/Hebrew-(1483)-Lisbon-Bible-(Pentateuch)-Vol.-1-6-Manuscript', 'heb', 'hebr1245', 'Hebrew', 'Israeli Hebrew', 'L', 'IL', '31.10565', '35.01788', '1', 'he', '5000000', NULL, 'Also in Australia, Canada, Germany, Palestinian West Bank and Gaza, Panama, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('186', 'English-1869-Readers-New-Testament-Alford-Vol.-1-4', 'ENGRNT', 'English (1869) Readers New Testament (Alford) Vol. 1-4', NULL, 'Henry Alford''s 1869 publication, "The New Testament for English Readers" (4 volumes, Rivingtons), is a remarkable achievement in biblical scholarship, reflecting his profound expertise as an English churchman, theologian, textual critic, scholar, poet, hymnodist, and writer. Born in 1810, Alford''s most significant contribution to theology and biblical studies is his monumental edition of the New Testament in Greek, a task that engaged him from 1841 to 1861. <br><br> Alford''s Greek New Testament is distinguished for its rigorous collation of the chief manuscripts and incorporation of the most advanced continental scholarship of his era. This philologically focused work heralded a shift from traditional homiletic commentary, paving the way for modern New Testament exegesis, despite the evolution of research methods involving patristic studies and papyrology. His work remains a valuable resource for contemporary students of the Bible, offering insights and scholarly rigor. <br><br> Post completion of his Greek New Testament, Alford undertook the task of making this scholarship accessible to a broader audience through "The New Testament for English Readers." This work, published just a few years before his death in 1871, demonstrates his commitment to bringing deeper biblical understanding to the English-speaking laity. His legacy is further illuminated in the biography penned by his widow, which was released in 1873, offering a personal glimpse into the life of a man whose work significantly influenced the course of biblical studies.', 'historic', NULL, '361', 'eng', '1869', 'study', 'Deighton, Bell, and Co.', NULL, NULL, 'ENGRNT_DBS_HS/English-(1869)-Readers-New-Testament-(Alford)-Vol.-1-4', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('187', 'English-1808-Newcomes-Corrected-New-Testament', 'ENGNCN', 'English (1808) Newcomes Corrected New Testament', NULL, 'The "New Testament, in an Improved Version, upon the Basis of Archbishop Newcome’s New Translation: with a Corrected Text, and Notes Critical and Explanatory," published in 1808 in London by Richard Taylor & Co., and distributed in America by William Wells of Boston in 1809, represents a significant revision in the history of biblical translations. This version, also published in a fourth edition with corrections and additions in 1817, is a revision of Newcome’s version from 1796.<br><br>This "Improved" New Testament was published anonymously by a group identified on the title page as “A Society for Promoting Christian Knowledge and the Practice of Virtue by the Distribution of Books.” This phrasing seems to have been chosen to suggest affiliation with the well-established Anglican organization founded in 1698 by Thomas Bray, which focused on distributing orthodox Christian literature to poor churches abroad. However, the introduction omits a crucial detail: the "Society" in question was actually the Unitarian Society, and the version''s main goal was to promote Unitarian ideas.<br><br>The decision to conceal its Unitarian origins was intentional, as the principal editor later revealed. They avoided using the word "Unitarian" on the title page to prevent deterring people who might otherwise benefit from the work but would be put off by its Unitarian association. Despite these precautions, it eventually became common knowledge that the version was financed by Unitarians and mainly edited by Thomas Belsham, a well-known Unitarian controversialist. This version of the New Testament thus stands as an example of how religious texts can be used to advance specific theological perspectives while navigating the sensitivities and biases of the broader religious community.', 'historic', 'http://www.bible-researcher.com/belsham.html', '94', 'eng', '1808', 'scan', 'Society for Promoting Christian Knowledge', NULL, NULL, 'ENGNCN_DBS_HS/English-(1808)-Newcomes-Corrected-New-Testament', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('188', 'English-1917-Masoretic-Bible-OT', 'ENGMASO', 'English (1917) Masoretic Bible - OT', NULL, 'The Jewish Publication Society of America Version (JPS) of the Tanakh, published in 1917, marked a significant milestone in the translation of the Hebrew Bible. It was the first such translation undertaken by a committee of Jewish scholars and published by the Jewish Publication Society of America, building on previous solo endeavors like Isaac Leeser''s translation. Officially titled "The Holy Scriptures According to the Masoretic Text: A New Translation with the Aid of Previous Versions and with Constant Consultation of Jewish Authorities," this translation is a critical landmark in Jewish biblical scholarship.<br><br>Rooted in the Masoretic Text, the JPS version drew considerable influence from the Revised Version and American Standard Version, yet it diverged notably in various passages to reflect Jewish interpretations. A prime example is in Isaiah 7:14, where it uses "young woman" instead of "virgin," a significant departure from most Christian Bible translations.<br><br>Originally initiated in 1892 by the Central Conference of American Rabbis, the project aimed to assign different books of the Bible to individual rabbis and scholars, with a committee of editors ensuring quality and consistency. However, this approach proved challenging, and by 1908, only the Book of Psalms had been completed. The Jewish Publication Society then took over the project, leading to the successful completion and publication of this landmark translation. This version holds a special place in Jewish history and continues to be a significant resource for understanding the Hebrew scriptures.', 'historic', NULL, '28', 'eng', '1917', 'scan', 'The Jewish Publication Society of America', 'jewish-publication-society', NULL, 'ENGMASO_DBS_HS/English-(1917)-Masoretic-Bible-OT', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('189', 'English-1933-The-Four-Gospels-Torrey', 'ENGTORR', 'English (1933) The Four Gospels (Torrey)', NULL, '"English (1933) The Four Gospels (Torrey)" reflects the significant work of Charles Cutler Torrey, an American historian, archaeologist, and scholar, in the realm of biblical translations. Born in 1863, Torrey''s multifaceted expertise in history and archaeology, coupled with his deep understanding of Semitic languages, led to innovative perspectives on the origins of Christian and Islamic religious texts.<br><br>As the founder of the American School of Archaeology in Jerusalem in 1901 and a professor at Andover Theological Seminary and Yale University, Torrey''s academic pursuits were broad and influential. His translation of "The Four Gospels" in 1933 stands as a testament to his linguistic prowess and unique approach to biblical texts, offering fresh insights into these central Christian narratives.<br><br>Torrey''s scholarly work also extends to Islamic studies, with his contributions included in "The Origins of The Koran: Classic Essays on Islam’s Holy Book," edited by Ibn Warraq. This inclusion highlights the wide-ranging impact of his studies, particularly in the understanding of religious texts and their historical contexts, contributing significantly to discussions on the development of major religious traditions.', 'historic', NULL, '3', 'eng', '1933', 'study', 'Harper & Brothers Publishers', NULL, NULL, 'ENGTORR_DBS_HS/English-(1933)-The-Four-Gospels-(Torrey)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('190', 'English-1860-Cassell''s-Illustrated-Family-Bible-Vol.-2-2-Study', 'ENGKJV', 'English (1860) Cassell''s Illustrated Family Bible (Vol. 2-2) Study', NULL, 'The second volume of "The Holy Bible: Containing the Old and New Testaments, with Explanatory Notes, References, and a Condensed Concordance," published by Cassell, Petter & Galpin, is a continuation of the remarkable work initiated by John Cassell. Born on January 23, 1817, and passing on April 2, 1865, Cassell''s legacy as an English publisher, printer, writer, and editor is deeply ingrained in the annals of educational and cultural literature. His founding of Cassell & Co marked a pivotal moment in the publishing world, particularly noted for its contribution to educational books, periodicals, and the pioneering of novel serial publication.<br><br>John Cassell was more than a publisher; he was a visionary and a social reformer. His fervent Christian faith drove him to actively participate in the temperance movement within Britain and advocate for the reduction of taxes on publishing. Understanding the transformative power of education, Cassell dedicated his life to enhancing the lives of the working class through his publications. His efforts extended beyond the realm of publishing, as he was also a renowned tea and coffee merchant and a versatile business entrepreneur.<br><br>The second volume of this illustrated Bible, embellished with over nine hundred detailed engravings, is a testament to Cassell''s commitment to making learning and culture accessible. His publications, spanning magazines and books, were not merely informative but were vehicles of cultural enrichment, bringing a wealth of knowledge and enlightenment to a wide audience. This volume, therefore, stands as a fitting tribute to Cassell''s enduring impact on education and social reform.', 'historic', NULL, '151', 'eng', '1860', 'study', 'The British and Foreign Bible Society', 'british-and-foreign-bible-society', NULL, 'ENGKJV_DBS_HS/English-(1860)-Cassell''s-Illustrated-Family-Bible-(Vol.-2-2)-Study', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('191', 'Syriac-1555-Gospels-Kaspar-Kraft-WDL-9917', 'SYRGOSP', 'Syriac (1555) Gospels - Kaspar Kraft (WDL-9917)', 'ܟܬܒܐ ܕܐܘܢܓܠܝܘܢ ܩܕܝܫܐ ܕܡܪܢ ܘܐܠܗܢ ܝܫܘܥ ܡܫܝܚܐ', 'The first printed edition of the Syriac New Testament was produced in 1555 under the patronage of Ferdinand I, a significant milestone in the history of biblical texts. Key contributors to this edition included Johann Albrecht Widmanstetter, a pivotal figure in the study of Eastern languages in Europe, and Moses of Mardin, whose handwriting influenced the Syriac typeface created for this publication by Kaspar Kraft under the guidance of French Orientalist Guillaume Postel.<br><br>This edition is distinguished by its content, including the books of James, 1 Peter, and 1 John, but notably excluding the other General Epistles and the Book of Revelation. The book is also remarkable for its artistic elements, featuring woodcuts with Hapsburg motifs, Syriac and Latin inscriptions, and a unique illustration of the crucifixion paired with the Kabbalistic Sephirot at the beginning of the Gospel of John. These artistic additions highlight the cultural and religious significance of the work.<br><br>Designed for liturgical use, this edition concludes with a Syriac and Latin table of lectionary readings, underscoring its practical application in Christian worship. The 1555 Syriac New Testament thus stands as a key artifact in the history of biblical scholarship, showcasing a fusion of religious, linguistic, and cultural elements of its time.', 'historic', 'https://www.wdl.org/en/item/9917', '289', 'syr', '1555', 'scan', 'Michael Zimmermann', NULL, 'World Digital Library', 'SYRGOSP_DBS_HS/Syriac-(1555)-Gospels-Kaspar-Kraft-(WDL-9917)', 'syr', 'syr', 'Syriac', NULL, 'L', 'IQ', NULL, NULL, NULL, NULL, '858080', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('192', 'English-1907-The-Modern-Readers-Bible-Moulton', 'ENGMRB', 'English (1907) The Modern Readers Bible (Moulton)', NULL, '"The Modern Readers Bible," edited by Richard G. Moulton, is a unique presentation of the biblical text tailored for contemporary readers. Published in October 1907 by The Macmillan Company, this edition has undergone several reprints, signifying its popularity and utility. The compilation relies on The English Revised Version (1885) as its base text, offering readers a choice between the original readings and marginal notes, with minimal modifications for modern literary appeal.<br><br>Moulton''s approach involves structuring the text to resonate with modern literary sensibilities while retaining the essence of the sacred writings. The layout varies between single and double columns, reflecting the importance Moulton assigns to different texts. Poetical books, in particular, are presented in a chromatic text form, enhancing their literary and aesthetic quality. In his six-page preface, dated June 1907, Moulton elaborates on his vision of making the Scriptures more accessible and relatable to the modern reader. This edition stands as a bridge between the time-honored reverence of the biblical text and the evolving literary tastes of contemporary society, offering a fresh perspective on the enduring words of the Bible.', 'historic', NULL, '313', 'eng', '1907', 'scan', 'The MacMillan Company', NULL, NULL, 'ENGMRB_DBS_HS/English-(1907)-The-Modern-Readers-Bible-(Moulton)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('193', 'Greek-1881-Westcott-Hort-New-Testament', 'GRCWHT', 'Greek (1881) Westcott-Hort New Testament', 'Καινή Διαθήκη του Westcott-Hort (1881)', 'The 1881 Westcott-Hort New Testament, titled "The New Testament in the Original Greek," is a significant work in the field of biblical textual criticism. Authored primarily by Hort (with an introduction and appendix appearing in 1882, and a revised edition by F. C. Burkitt in 1892), this text is known for its strong Alexandrian leanings.<br><br>The Westcott-Hort (WH) text is often characterized by its alignment with the Codex Vaticanus (B), one of the oldest and most valued manuscripts of the Greek Bible. Although Hort, the principal architect of the edition''s textual theory, would consider other witnesses if internal evidence was compelling, the WH text generally skews closer to the Codex Vaticanus than other critical editions. This approach is somewhat akin to non-Biblical critical methods that rely on editing from a proof text.<br><br>One notable aspect of the WH edition is its handling of the so-called Western Non-Interpolations, demonstrating the editors'' willingness to diverge from the Codex Vaticanus where they deemed the evidence strong enough. Despite this, the edition is still very much anchored in the Alexandrian text-type.<br><br>The WH edition is unique in that it does not have a traditional critical apparatus; no manuscripts are cited in the main body of the text. The margin contains a few variant readings, primarily those where the editors either disagreed with the text or were uncertain of the original readings. They also compiled a list of "interesting" variants, but did not provide a comprehensive list of witnesses for these. The only textual evidence provided is in the introduction and appendix, where manuscripts are referenced using Tischendorf numbers, making them somewhat challenging to use.<br><br>This approach to textual criticism and the lack of a detailed critical apparatus make the Westcott-Hort New Testament a unique, albeit sometimes controversial, contribution to New Testament studies. Its influence on subsequent biblical scholarship and textual criticism has been significant, particularly in discussions regarding the Alexandrian text-type and the methodology of New Testament textual criticism.', 'historic', NULL, '686', 'grc', '1881', 'scan', 'Harper & Brothers', NULL, NULL, 'GRCWHT_DBS_HS/Greek-(1881)-Westcott-Hort-New-Testament', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('194', 'English-1875-Davidsons-New-Testament', 'ENGDNT', 'English (1875) Davidsons New Testament', NULL, 'The 1875 edition of "The New Testament," translated by Samuel Davidson, is a significant work in the field of biblical scholarship. Davidson, a respected biblical scholar of his time, embarked on this ambitious project to translate the New Testament from the critical text of Constantin von Tischendorf. This edition is particularly noteworthy for its use of Tischendorf''s eighth edition of the Greek text, a text that was groundbreaking in its reliance on earlier manuscripts and a more rigorous approach to textual criticism. <br><br> Samuel Davidson''s translation is accompanied by an insightful introduction on the criticism, translation, and interpretation of the New Testament. This introduction offers readers a comprehensive overview of the challenges and methodologies involved in translating the New Testament, as well as the various approaches to its interpretation. Davidson''s work stands out for its scholarly rigor and commitment to accuracy, reflecting the advancements in biblical scholarship of the 19th century. <br><br> The significance of this translation lies in its contribution to the understanding of the New Testament through the lens of critical textual analysis. By leveraging Tischendorf''s critical Greek text, Davidson provided an English translation that brought readers closer to what was then believed to be the original wording of the New Testament writings. His work remains an important reference for scholars and students of biblical studies, offering a window into the evolving landscape of New Testament scholarship in the late 19th century.', 'historic', NULL, '50', 'eng', '1875', 'scan', NULL, NULL, NULL, 'ENGDNT_DBS_HS/English-(1875)-Davidsons-New-Testament', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('195', 'English-1885-The-Companion-Study-Bible', 'ENGKJV', 'English (1885) The Companion Study Bible (Study)', NULL, '"The Companion Study Bible" stands as a testament to America''s rich history of Bible printing, which evolved significantly from its limited beginnings in the seventeenth and early eighteenth centuries. During this early period, most Bibles were supplied by European printers or brought by immigrants, a testament to the cultural and technological constraints of the time. However, as advancements in printing techniques and machinery merged with increasing demand, a notable shift occurred by the late eighteenth and early nineteenth centuries. This era marked a significant surge in Bible publishing, with cities like Boston, Philadelphia, and New York emerging as primary publishing centers.<br><br>Bible historian Paul Gutjahr''s insights reveal the Bible''s immense popularity in eighteenth-century North America, dubbing it the “most printed, most distributed, and most read written text.” This popularity extended beyond its religious significance, as the Bible also symbolized familial heritage and cultural pride. It connected families to their ancestral past and served as a cherished possession. Recognizing this profound connection, publishers began producing Bibles with ornate features, such as elaborately carved or embossed covers and intricate illustrations. These aesthetic enhancements transformed the Bible into a symbol of both spiritual and cultural value, often displayed prominently in homes. "The Companion Study Bible" fits within this historical narrative, reflecting the evolution of Bible printing in America and its deep-seated importance in both the religious and domestic realms.', 'historic', NULL, '111', 'eng', '1885', 'study', 'Humphrey Milford, University Press', NULL, NULL, 'ENGKJV_DBS_HS/English-(1885)-The-Companion-Study-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('196', 'English-1902-Twentieth-Century-Bible', 'ENGTWE', 'English (1902) Twentieth Century Bible', NULL, 'The "Twentieth Century New Testament," a modern English translation from the original Greek, represents a significant effort in biblical translation, particularly for its time. This translation, based on Westcott and Hort''s text, was one of the early attempts to render the New Testament into contemporary language, making it more accessible and understandable to the modern reader. <br><br> The publication history of this translation is marked by several variations, reflecting its evolving nature and the demand for its copies. Some editions of the volume bear the title "20th Century," while others are labeled "Twentieth Century." The variations extend to the title pages, with some editions announcing the completion of the New Testament in "Two Parts," and others in "Three Parts." Additionally, while some title pages are dated 1900, others do not carry a date. The presence of a "Fifth Edition" suggests the translation’s ongoing popularity and the necessity for multiple reprints to meet the demand.<br><br> This translation project underscores the shifting trends in biblical studies and translations at the turn of the 20th century. The move towards modern English translations was driven by a desire to make biblical texts more relatable and comprehensible to a broader audience, breaking away from the archaic language that characterized earlier translations. The "Twentieth Century New Testament" thus stands as an important milestone in the history of Bible translation, reflecting both the changing linguistic preferences and the evolving nature of biblical scholarship.', 'historic', NULL, '53', 'eng', '1902', 'scan', 'Fleming H. Revell Company', NULL, NULL, 'ENGTWE_DBS_HS/English-(1902)-Twentieth-Century-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('197', 'Hebrew-1725-Haggadah-Yiddish-Instructions-illuminated', 'HEBHAGT', 'Hebrew (1725) Haggadah Yiddish Instructions illuminated', 'עברית - ההגדה של פסח (1725, עם הוראות ביידיש, מוארת)', 'The 1725 Haggadah, featuring Yiddish instructions and illuminated illustrations, is a beautifully crafted Jewish manuscript designed to guide families through the Passover Seder. The Haggadah is the traditional text that recounts the Exodus from Egypt, forming the core of the Passover ritual meal. This particular edition, produced in 1725, is notable for its inclusion of Yiddish-language instructions, making it more accessible to Ashkenazi Jewish communities who spoke Yiddish as their primary language.<br><br>Unlike earlier Hebrew-only Haggadot, this edition provided practical guidance in Yiddish, ensuring that readers could understand and correctly perform the Seder rituals, blessings, and prayers. The use of Yiddish alongside Hebrew reflects the cultural and linguistic needs of Jewish communities in Central and Eastern Europe, where this edition was likely produced.<br><br>The illuminations in this 1725 Haggadah are particularly striking. The manuscript features hand-colored woodcuts or engraved illustrations, depicting key moments from the Passover story, such as the Ten Plagues, the Crossing of the Red Sea, and the Seder table. These artistic elements not only enhanced the beauty of the Haggadah but also served as a visual aid for those who might have had limited literacy. The artistic style is influenced by Baroque and Jewish folk art traditions, often featuring rich decorative borders, ornate lettering, and lively depictions of biblical scenes.<br><br>This illuminated Haggadah would have been used in Jewish households during the Seder night, allowing families to engage more deeply with the rituals, prayers, and songs of Passover. The inclusion of Yiddish instructions demonstrates the evolving accessibility of Jewish texts, catering to the vernacular language of the Jewish diaspora while preserving the sacred Hebrew prayers.', 'historic', NULL, '48', 'heb', '1725', 'illuminated', NULL, NULL, NULL, NULL, 'heb', 'hebr1245', 'Hebrew', 'Israeli Hebrew', 'L', 'IL', '31.10565', '35.01788', '1', 'he', '5000000', NULL, 'Also in Australia, Canada, Germany, Palestinian West Bank and Gaza, Panama, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('198', 'English-1539-Taverner-Bible', 'ENGTVB', 'English (1539) Taverner Bible', NULL, 'Taverner''s Bible, officially titled "The Most Sacred Bible which is the holy scripture, containing the old and new testament, translated into English, and newly recognized with great diligence after most faithful exemplars by Richard Taverner," is a significant yet relatively minor revision of Matthew''s Bible. Edited by Richard Taverner and first published in 1539, this version of the Bible is noted for its rarity, particularly in its first editions.<br><br>The creation of Taverner''s Bible was somewhat contentious, stemming from a rivalry in the publication of religious texts. The printers Grafton and Whitchurch, who had successfully sold Matthew''s Bible, faced competition from a rival edition published by John Byddell for Thomas Bartlet in 1539, with Taverner as the editor. This edition was effectively a "pirated" version, being a revision of Grafton''s Matthew Bible by Taverner, who was a learned member of the Inner Temple and a noted Greek scholar. Taverner''s alterations in the Matthew Bible were characterized by critical insight and the use of strong, idiomatic expressions.<br><br>Despite these revisions, Taverner''s Bible had limited impact on future translations, with only a few phrases finding their way into the King James Bible. Its influence is summarized by Daniell as being minimal, and it was not reprinted in its entirety. However, quarto and octavo editions of the New Testament alone were published in the same year as the original edition, and the Old Testament was reprinted as part of a Bible in 1551. The Old Testament and Apocrypha were also issued by Day and Seres in five sections between 1549 and 1551.', 'historic', 'https://en.wikipedia.org/wiki/Taverner%27s_Bible', '318', 'eng', '1540', 'scan', NULL, NULL, NULL, 'ENGTVB_DBS_HS/English-(1539)-Taverner-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('199', 'French-1525-Olivetan-Bible', 'FRAOLI', 'French (1525) Olivetan Bible', 'Bible d''Olivétan (1525)', 'French (1525) Olivetan Bible In the year 1523 appeared at Paris, from the press of Simon de Colines, an anonymous translation of the N.T., which was often reprinted, and to which, in 1525, was added the Psalter, and in 1528 the rest of the O.T. (together 7 volumes, 8vo), the last portion being issued at Antwerp, in consequence of attempts on the part of the French clergy to prevent its appearance. Tradition ascribes this version to Jacqimes le Fevre d''Etaples, who had before this distinguished himself by a Latin translation, of Paul''s epistles, and by exegetical works on the Gospels and Epistles; and there is no reason to question the justice of the ascription. This version is made from the Vulgate, with slight variations in the N.T., where the author follows the Greek. The complete work appeared in one volume fol., at Antwerp, in 1530, and again from the same types in 1532. It was placed in the papal Index in 1546; but in 1550 it was reissued at Louvain in fol., edited by two priests, Nicolas de Leuze, and Franz van Larben, who corrected the style, and struck out all that savored of what they deemed heresy. Of this corrected version many editions have been issued.', 'historic', NULL, '720', 'fra', '1525', 'scan', NULL, NULL, NULL, 'FRAOLI_DBS_HS/French-(1525)-Olivetan-Bible', 'fra', 'stan1290', 'French', 'français', 'L', 'FR', '48', '2', '1', 'fr', '77200000', 'Andorra and France', 'Also in Algeria, Andorra, Austria, Belgium, Benin, Burkina Faso, Burundi, Cambodia, Cameroon, Canada, Central African Republic, Chad, Comoros, Congo, Côte d’Ivoire, Democratic Republic of the Congo, Djibouti, Equatorial Guinea, French Guiana, French Polynesia, Gabon, Guadeloupe, Guinea, Haiti, India, Israel, Italy, Lebanon, Libya, Luxembourg, Madagascar, Mali, Martinique, Mauritania, Mauritius, Mayotte, Monaco, Morocco, Mozambique, New Caledonia, Niger, Philippines, Puerto Rico, Réunion, Rwanda, Saint Pierre and Miquelon, Saudi Arabia, Senegal, Seychelles, South Africa, Switzerland, Togo, Tunisia, United Arab Emirates, United Kingdom, United States, U.S. Virgin Islands, Vanuatu, Wallis and Futuna.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('200', 'English-1703-Whitbys-Paraphrase-and-Commentary-New-Testament-Vol.-1-2', 'ENGWHI', 'English (1703) Whitbys Paraphrase and Commentary New Testament (Vol. 1-2)', NULL, 'Daniel Whitby''s work, titled "A Paraphrase and Commentary upon all the epistles of the New Testament," is a noteworthy contribution to biblical scholarship. Whitby (1638–1726), a controversial English theologian and Arminian priest in the Church of England, was known for his strong anti-Calvinistic views and later indications of Unitarian tendencies. His major work, this paraphrase and commentary, began in 1688 and was first published in 1700, with the final edition released in 1822.<br><br>Whitby''s commentary, printed in London in 1703 by W. Bowyer for Awnsham and John Churchill, was held in high regard; Philip Doddridge, another respected theologian, considered it superior to other contemporaneous commentaries. Whitby''s approach in this work included opposing John Tillotson''s views on hell torments and defining faith as mere assent to the facts of the Gospel.<br><br>In 1710, Whitby engaged in a critical defense of the Textus Receptus, challenging John Mill''s work, which presented thirty thousand textual variants in the New Testament. Whitby''s critique, "Examen variantium Lectionum Johannis Milli," was used by Anthony Collins and was reprinted in 1724 by Sigebert Haverkamp in Leyden. Whitby''s work not only reflects the theological and interpretive debates of his time but also contributes to the historical understanding of New Testament scholarship.', 'historic', NULL, '279', 'eng', '1703', 'study', NULL, NULL, NULL, 'ENGWHI_DBS_HS/English-(1703)-Whitbys-Paraphrase-and-Commentary-New-Testament-(Vol.-1-2)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('201', 'Syriac-1910-Gospels-Evangelion-da-Mepharreshe-Sinai-or-Syro-Antiochene-Palimpsest-Gospels', 'SYROLD', 'Syriac (1910) Gospels Sinai or Syro-Antiochene Palimpsest - Gospels', 'ܣܘܪܝܝܐ (1910) ܐܘܢܓܠܝܘܢ ܕܣܝܢܝ (Gospels Sinai or Syro-Antiochene Palimpsest)', 'Syriac (1910) Gospels Sinai or Syro-Antiochene Palimpsest - Gospels The Syriac language, known as Syriac Aramaic, Syro-Aramaic, or Classical Syriac ܠܫܢܐ ܥܬܝܩܐ, is an Aramaic dialect from the ancient Aramean kingdom of Osroene, with Edessa as its center. It became the literary language of Aramaic-speaking Christian communities in Ancient Syria and the Near East during the Early Christian period. As a liturgical language, it was prominent among Eastern Christian communities using both Eastern and Western Syriac rites and spread to Christian communities in India and China. Flourishing from the 4th to the 8th century, it remained significant in subsequent centuries but was eventually limited to liturgical use due to the rise of Neo-Aramaic dialects.<br><br>Scripts include Estrangelo (E), Jacobite (J), Hebrew (H), and Nestorian (N). Key publications: 1555 New Testament (J) in Vienna, edited by Johann A. Widmanstadt; 1569 New Testament (H) in Geneva, edited by Immanuel Tremcllius; 1625 Psalms (J) in Paris, edited by Gabriel Sionita; 1630 publications of 2 Peter, 2-3 John, Jude (J & H) in Leiden, edited by E. Pococke; 1629-1645 Paris Polyglot containing the first complete Syriac printed Bible (J), edited by G. Sionita; 1655-1657 Bible (J) in London Polyglot; 1708 New Testament (J) in Leiden; 1778 Gospels (J); 1799-1803 Acts Epistles (J) in Oxford; 1823 Old Testament (J) for BFBS in London; 1820 Psalms (J) in Milan; 1828 New Testament (J) in London; 1835 Syro-Hexaplar (J) in Berlin; 1836 New Testament (H) in London; 1841 Bible (N) for the Nestorian Christian communities; 1858 Gospels (E) in London; 1861-1874 Old Testament (J) in Milan; 1874 Bible (N) in New York; 1886 Psalms (J) in Paris; 1891 Bible (J) for Nestorian Christians in Mosul; 1894 Gospels (E) in Cambridge; 1901 Gospels (J) in Oxford; 1904 Psalms (E) and Gospels (J) in Cambridge; 1905-1920 New Testament (J) for BFBS in London. Notable publications also include the 1861-1864 Gospels in Verona and the 1899 Gospels (E) in London.', 'historic', NULL, '28', 'syr', '1910', 'scan', 'Williams and Norgate', NULL, NULL, 'SYROLD_DBS_HS/Syriac-(1910)-Gospels-(Evangelion-da-Mepharreshe)-Sinai-or-Syro-Antiochene-Palimpsest-Gospels', 'syr', 'syr', 'Syriac', NULL, 'L', 'IQ', NULL, NULL, NULL, NULL, '858080', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('202', 'Syriac-1826-Old-Testament-Ketabe-Qaddise-Vol.-1-2', 'SYROLD', 'Syriac (1826) Old Testament (Ketabe Qaddise) Vol. 1-2', 'ܣܘܪܝܝܐ (1826) ܩܬܒܐ ܩܕܝܫܐ', 'Syriac (1826) Old Testament (Ketabe Qaddise) Vol. 1-2 The Syriac language, also known as Syriac Aramaic (Syrian Aramaic, Syro-Aramaic) and Classical Syriac ܠܫܢܐ ܥܬܝܩܐ (in its literary and liturgical form), is an Aramaic dialect that emerged during the first century AD from a local Aramaic dialect that was spoken by Arameans in the ancient Aramean kingdom of Osroene, centered in the city of Edessa. During the Early Christian period, it became the main literary language of various Aramaic-speaking Christian communities in the historical region of Ancient Syria and throughout the Near East. As a liturgical language of Syriac Christianity, it gained a prominent role among Eastern Christian communities that used both Eastern Syriac and Western Syriac rites. Following the spread of Syriac Christianity, it also became a liturgical language of eastern Christian communities as far as India and China. It flourished from the 4th to the 8th century and continued to have an important role during the next centuries, but by the end of the Middle Ages it was gradually reduced to liturgical use since the role of vernacular language among its native speakers was overtaken by several emerging Neo-Aramaic dialects.<br><br>Script is indicated as follows: (E) Estrangelo;(J) Jacobite;(H) Hebrew; (N) Nestorian;  1555 New Testament (J) Zimmermann, ViennaEditedfrom Ms. Peshitta texts by Johann A. Widmanstadt;  1569 New Testament (H) Stephanus, GenevaEdited by Immanuel Tremcllius and published with Greek and Latin texts. Syriac versions appeared in other Polyglots: 1575, Antwerp; H99, Niirnherg; also the Paris and London Polyglots (see below);  1625 Psalms(J) ParisEdited by Gabriel Sionita, a Maronite. In the same year a SyriacPsalter was published in Leiden, edited by T. Erpenius;  1627 Revelation (J & H);  1630 2 Peter 2-3JohnJude (J & H) LeidenThefirst publication of these Books which are omitted from the Syriaccanon; edited by E. Pococke;  1629-1645 Bible (J) Paris: The Paris Polyglot contained the first complete Syriac printed Bible, edited by G. Sionita;  1655-1657 Bible(J) LondonThe London Polyglot, edited by Brian Walton and others. Numerous editions appeared during the 17th and centuries, based on the texts of these prestigious polyglot Bibles;  1708 New Testament(J) LeidenAn early critical edition, prepared by J. Leusden and C. Schaaf. The Gospels were reprinted by the BFBS in 1815;  1778 Gospels(J);  1799-1803 Acts Epistles(J) OxfordThe Philoxenian and/or Harkleian recension, edited byJoseph White;  1816 NewTestament(J);  1822 Psalms (J);  1823 Old Testament(J) BFBS, LondonEditedfor the BFBS by S. Lee, and based on the London Polyglot;  1820 Psalms (J) MilanThe Syro-Hcxaplar text, edited by C. Bugatus. This version, prepared by Paul of Telia (617 A.D.), is a translation of the Septuagint into Syriac. Other portions of the Syro-Hcxaplar had appeared earlier;  1828 New Testament(J) Bagster, London Edited by William Greenfield;  1835 2 Kings Job Proverbs-Isaiah Lamentations Hosea—Malachi(J) BerlinThe Syro-Hcxaplar, edited by Heinrich Middeldorpf In 1858-1860 Judges and Ruth from the Syro-Hexaplar, edited by T. Skat Rordatn, were published in Copenhagen;  1836 New Testament (H) London Jews Society, London Edited for the LJS in the hope that similarity of usage with that of the Zohar would encourage interest in Jewish readers;  1841 Bible (N) American Board of Commissioners for Foreign Missions, UrumiaThe first edition of the Scriptures prepared for the use of the Nestorian Christian communities. In 1846 a N. T. with Modern Syriac text was also published by the ABCFM; O.T., 1852. A Liturgical Psalter was published in Mosul, in 186', 'historic', NULL, '134', 'syr', '1826', 'scan', NULL, NULL, NULL, 'SYROLD_DBS_HS/Syriac-(1826)-Old-Testament-(Ketabe-Qaddise)-Vol.-1-2', 'syr', 'syr', 'Syriac', NULL, 'L', 'IQ', NULL, NULL, NULL, NULL, '858080', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('203', 'Aramaic-1885-Old-Testament-Talgum-with-Commentaries-vol-1-5-Old-Testament', 'AII1885', 'Aramaic (1885) Old Testament (Talgum) with Commentaries vol 1-5 - Old Testament', 'ܐܪܡܝܐ (1885) ܩܘܕܫܐ ܟܬܒܐ (ܬܠܓܘܡ) ܥܡ ܦܘܫܩܐ ܣܦܪܐ 1-5 - ܩܘܕܫܐ ܟܬܒܐ', 'In the Syriac (Eastern Aramaic) language the Peshitta (Syriac: "common version") is the standard version of the Christian Bible. It continues to serve as the Bible of churches in the Syriac tradition (Church of the East, Chaldean Catholic, and Syriac Orthodox) to this day. The history of Christian Translations of the Bible into Syriac language includes the Diatessaron, the Old Syriac versions (Curetonian and Sinaitic), the Peshitto, the Philoxenian version, the Harklean Version and the recent United Bible Societies'' modern Aramaic New Testament.<br><br>About AD 500 a Christian Palestinian Aramaic version was made. It contains 2 Peter, 2-3 John, Jude, and Apocalypse. It is representative of the Caesarean text type and is a unique translation different from any other which was made into Syriac. These are among the manuscripts used by John Gwynn in 1893 to complete his edition of the Catholic Epistles. In 1892 Agnes Smith Lewis discovered the manuscript of the Palestinian Syriac lectionary in the library of Saint Catherine''s Monastery on Mount Sinai. It is designated by Syr.<br><br>The first revision of the New Testament from the Syriac into Turoyo language (Western Aramaic in Syriac and Latin script) was made by Malphono Yuhanun Üzel (Bar Shabo), Benjamin Bar Shabo, and Yahkup Bilgic in 2009 with notes from Harclean and Philoxenios. This commission "Sihto du Kthovo Qadisho Suryoyo" works especially to preach the Gospel in Aramaic all over the world.', 'historic', NULL, '220', 'aii', '1885', 'study', NULL, NULL, NULL, 'AII1885_DBS_HS/Aramaic-(1885)-Old-Testament-(Talgum)-with-Commentaries-vol-1-9-Old-Testmant', 'aii', 'assy1241', 'Assyrian Neo-Aramaic', 'Sūreṯ', 'L', 'IQ', '36.75', '43', '6b', NULL, '626000', 'Iraq', 'Northern Iraq, Baghdad, Basrah, Karkuk, Arbil. Also in Armenia, Australia, Austria, Azerbaijan, Belgium, Brazil, Canada, Cyprus, France, Georgia, Germany, Greece, Iran, Italy, Lebanon, Netherlands, New Zealand, Russian Federation (Europe), Sweden, Switzerland, Syria, Turkey (Asia), United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('204', 'English-1770-Worsley-New-Testament-Print', 'ENGWOR', 'English (1770) Worsley New Testament (Print)', NULL, 'The 1770 Worsley New Testament is a notable translation of the New Testament by John Worsley, printed in London by R. Hett. Titled "The New Testament or New Covenant of Our Lord and Saviour Jesus Christ," this translation was distinctive for its approach to aligning the text with the idiom of the English language of that time. Worsley''s work aimed to provide a translation that was both faithful to the Greek original and comprehensible in contemporary English.<br><br>One of the unique features of Worsley''s New Testament is the inclusion of notes and references throughout the text. These annotations were interspersed as needed to confirm and illustrate the translation choices made, particularly where literal or varying renderings were presented at the bottom of each page. This aspect of the translation was designed to enable even those who were not familiar with the original Greek to understand and appreciate the accuracy and appropriateness of Worsley''s translation.<br><br>Worsley''s translation reflects the evolving nature of biblical scholarship and translation in the 18th century. By focusing on the idiom and vernacular of the English language of his time, Worsley contributed to making the New Testament more accessible and relatable to the contemporary audience. His work remains an interesting example of the dynamic and interpretive nature of Bible translation.', 'modern', 'http://www.sbible.ru/engbible.htm', '3', 'eng', '1770', 'book', NULL, NULL, NULL, 'ENGWOR_DBS_HS/English-(1770)-Worsley-New-Testament-(Print)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('205', 'English-1859-Wellbeloved-Old-Testament-Vol.-1-3', 'ENGWELL', 'English (1859) Wellbeloved Old Testament (Vol. 1-3)', NULL, 'The "Holy Scriptures of the Old Covenant, in a Revised Translation" is a monumental work, spearheaded by three eminent scholars: Charles Wellbeloved, George Vance Smith, and John Scott Porter. Published in three volumes between 1859 and 1862 by Longman, Brown, Green, Longmans, and Roberts, this revision of the King James Version (KJV) of the Old Testament represents a significant contribution to biblical scholarship. <br><br>Volume 1, released in 1859, encompasses the Pentateuch, Joshua, Judges, and Ruth, showcasing Wellbeloved''s meticulous revision. The second volume, published in 1861, extends the scope to include the books of Samuel, Kings, Chronicles, Ezra, Nehemiah, Esther, Job, and Psalms. Finally, the third volume, completed in 1862, comprises Proverbs, Ecclesiastes, and the Prophets. The collaborative nature of this project is evident in the division of labor among the scholars. Wellbeloved, a revered figure in theological circles, revised the Pentateuch, Joshua, Judges, Ruth, Job, Psalms, Proverbs, Ecclesiastes, and the Minor Prophets. Smith, known for his scholarly acumen, undertook the revision of Samuel, Ezra, Nehemiah, Esther, Isaiah, Jeremiah, and the Lamentations. Porter, another distinguished scholar, was responsible for revising Kings, Chronicles, Ezekiel, and Daniel. <br><br>This comprehensive and meticulously revised translation is a testament to the scholarly dedication and expertise of Wellbeloved, Smith, and Porter. It remains a valuable resource for students of the Bible, offering a deeper understanding of the Old Testament through its careful and scholarly translation.', 'historic', NULL, '172', 'eng', '1859', 'scan', NULL, NULL, NULL, 'ENGWELL_DBS_HS/English-(1859)-Wellbeloved-Old-Testament-(Vol.-1-3)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('206', 'English-1914-Douay-Holy-Bible-Catholic', 'ENGCPDV', 'English (1914) Douay Holy Bible (Catholic)', NULL, 'The Douay–Rheims Bible, a pivotal translation in the history of English Bible translations, was a significant Catholic response to the Protestant Reformation. Crafted by members of the English College in Douai, it served the Catholic Church by translating the Bible from the Latin Vulgate into English. The New Testament was first published in Reims, France, in 1582, accompanied by extensive commentary and notes, while the Old Testament appeared in two volumes in 1609 and 1610, published by the University of Douai. The first volume covered Genesis through Job, and the second spanned from Psalms to 2 Maccabees, with the inclusion of three apocryphal books from the Vulgate''s appendix.<br><br>Characterized by its copious marginal notes, the Douay–Rheims Bible was distinct for its polemical and patristic nature, offering deep insights into translation issues and the Hebrew and Greek source texts of the Vulgate. The primary intent of this translation was to fortify Catholic tradition amidst the predominantly Protestant religious and academic milieu of Elizabethan England, thereby contributing to the Counter-Reformation efforts of English Catholics.<br><br>The New Testament saw several reprints in 1600, 1621, and 1633, while the Old Testament volumes were reprinted in 1635. William Fulke''s 1589 collation of the Rheims text and notes with the Bishops'' Bible in parallel columns proved influential in England, leading to multiple reissues until 1633 and significantly impacting 17th-century English Bible development. This translation remains a critical part of the Catholic tradition and the broader history of biblical translations.', 'historic', NULL, '268', 'eng', '1914', 'scan', 'James Cardinal Gibbons, P. J. Kenedy & Sons', NULL, NULL, 'ENGCPDV_DBS_HS/English-(1914)-Douay-Holy-Bible-(Catholic)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('207', 'English-1907-Interlinear-Study-Bible-KJV-and-RV', 'ENGREV', 'English (1907) Interlinear Study Bible (KJV and RV)', NULL, 'The 1907 Interlinear Study Bible is a remarkable artifact of American Bible printing history, encapsulating a period of significant transformation in the production and dissemination of religious texts. Throughout the seventeenth and early eighteenth centuries, the American Bible market was largely dependent on imports from British and European printers, but with technological advancements in printing and rising demand, the situation began to change notably. By the late eighteenth and into the early nineteenth century, cities like Boston, Philadelphia, and New York emerged as major hubs for Bible publishing in America.<br><br>As noted by Bible historian Paul Gutjahr, the Bible enjoyed immense popularity during this era, becoming the "most printed, most distributed, and most read written text in North America." This ubiquity was not just a testament to its spiritual significance but also to its role as a familial heirloom, linking generations and serving as a symbol of familial pride. Recognizing this, publishers started producing Bibles with ornate, sometimes colorful, covers and illustrations, turning them into prized possessions often displayed in homes. <br><br>The 1907 Interlinear Study Bible, showcasing the King James Version (KJV) and the Revised Version (RV) side by side, is a product of this rich publishing legacy. It reflects both the advancement of biblical scholarship and the desire to make these sacred texts more accessible and engaging for a broader audience.', 'historic', NULL, '352', 'eng', '1907', 'study', NULL, NULL, NULL, 'ENGREV_DBS_HS/English-(1907)-Interlinear-Study-Bible-(KJV-and-RV)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('208', 'English-1535-Coverdale-Bible', 'ENGCVD', 'English (1535) Coverdale Bible', NULL, 'The Coverdale Bible, compiled by Myles Coverdale and first published in 1535, holds the distinction of being the first complete Bible in Modern English, encompassing both the Old and New Testaments. This was a significant development, as it marked the first time a complete printed translation of the Bible was available in English, differentiating it from the manuscript-only Wycliffe''s Bible. The later editions printed in England in 1537, both folio and quarto, were the first complete Bibles printed in the country, with the 1537 folio edition being the first to carry a royal license, making it the first officially approved English Bible translation.<br><br>The publication location of the 1535 edition was long debated. Initially, it was thought to have been printed by Froschover in Zurich or by Cervicornus and Soter in Cologne or Marburg. However, in 1997, Guido Latré identified the printer as Merten de Keyser in Antwerp. The publication was financed in part by Jacobus van Meteren in Antwerp, whose sister-in-law Adriana de Weyden was married to John Rogers. Another financier was van Meteren’s nephew, Leonard Ortels, father of the renowned humanist geographer and cartographer Abraham Ortelius.<br><br>While Coverdale also contributed to the Great Bible of 1539, his eponymous Bible continued to be reprinted, with the last of over 20 editions appearing in 1553. For his translation, Coverdale based the New Testament on Tyndale’s work. For the Old Testament, he used Tyndale’s published Pentateuch and possibly Jonah, but did not use any of Tyndale’s other unpublished Old Testament materials. Instead, Coverdale translated the remaining books of the Old Testament and the Apocrypha himself, relying on his intermediate knowledge of Hebrew, Aramaic, and Greek, and working primarily from German translations (Luther’s Bible and the Zürich Bible of Zwingli and Leo Jud) as well as Latin sources, including the Vulgate. The Psalter from the Coverdale Bible was later included in the Anglican Book of Common Prayer from 1662 and in all editions of the Episcopal Book of Common Prayer until 1979.', 'historic', 'https://en.wikipedia.org/wiki/Coverdale_Bible', '87', 'eng', '1537', 'scan', NULL, NULL, NULL, 'ENGCVD_DBS_HS/English-(1535)-Coverdale-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('209', 'English-1526-Tyndale-New-Testament-Facsimilie', 'ENGTYN', 'English (1526) Tyndale New Testament (Facsimilie)', NULL, 'The Tyndale Bible generally refers to the body of biblical translations by William Tyndale (1494–1536). Tyndale''s Bible is credited with being the first English translation to work directly from Hebrew and Greek texts. Furthermore, it was the first English biblical translation that was mass-produced as a result of new advances in the art of printing.<br><br>The term Tyndale''s Bible is not strictly correct, because Tyndale never published a complete Bible. That task was completed by Miles Coverdale, who supplemented Tyndale''s translations with his own to produce the first complete printed Bible in English in 1535. Prior to his execution Tyndale had only finished translating the entire New Testament and roughly half of the Old Testament. Of the latter, the Pentateuch, Jonah and a revised version of the book of Genesis were published during his lifetime. His other Old Testament works were first used in the creation of the Matthew Bible and also heavily influenced every major English translation of the Bible that followed.<br><br>1525 Tyndale, William (The New Testament) [Cologne: Peter Quentell, 1525.][Only a fragment, ''The gospell of S. Mathew. The first Chapter [through] the xxii. Chapter.'', still remains in the Grenville Collection of the British Museum. 3,000 copies of the first ten sheets had been secretly printed before Tyndale had to flee Cologne to Worms, where he began his work afresh. Complete edition; Worms: Peter Quentell, 1526. Reprinted; New Testament translated by William Tyndale 1525. Facsimile of unique fragment of the uncompleted Cologne edition. Oxford: Clarendon Press, 1926.', 'historic', 'https://en.wikipedia.org/wiki/Tyndale_Bible', '15', 'eng', '1525', 'reprint', NULL, NULL, NULL, 'ENGTYN_DBS_HS/English-(1526)-Tyndale-New-Testament-(Facsimilie)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('210', 'English-1731-Wycliffe-New-Testament', 'ENGWYC', 'English (1731) Wycliffe New Testament', NULL, 'The Wycliffe New Testament, initially translated from the Latin Vulgate into English by John Wycliffe, is a historically significant text. The 1731 edition is particularly noteworthy as it represents the earliest printed edition of Wycliffe’s New Testament. The complete version of Wycliffe''s Bible, including the Old Testament, was not published until the mid-nineteenth century. Wycliffe''s translation is considered a pioneering work, likely being the first translation of the Bible into English. However, his efforts were not well received by the Catholics and Englishmen of his time. After his death, Wycliffe was declared a heretic, and his body and writings were burned.<br><br>This 1731 edition contains portraits of John Wycliffe and John Lewis, the publisher. It also includes an eight-page glossary of terms and several facsimiles from sixteenth-century Bibles. Notably, only 160 copies of this edition were issued, making it a rare and valuable piece of religious and historical literature. The publication of this edition signifies the enduring impact of Wycliffe''s work and the evolving perceptions of his contributions to biblical scholarship and translation.', 'historic', NULL, '48', 'eng', '1731', 'scan', NULL, NULL, NULL, 'ENGWYC_DBS_HS', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('211', 'English-1881-Samuel-Sharpe-New-Testament', 'ENGSHA', 'English (1881) Samuel Sharpe New Testament', NULL, 'Samuel Sharpe, an illustrious Egyptologist and a translator of the Bible, presents a unique figure in the history of biblical scholarship. His biography, as chronicled by P.W. Clayden, reveals Sharpe as a self-taught scholar and a multifaceted individual who diverged from traditional academic paths. Born on March 8, 1799, Sharpe''s journey into the world of biblical translation and Egyptology began remarkably early. At just 15 years old, he embarked on a career in banking, dedicating 47 years to this profession with notable success. Despite his busy career, Sharpe developed a fascination with the burgeoning field of Egyptology, influenced by the exciting discoveries of his time. He authored several books on the subject, becoming a respected name in Egyptological circles.<br><br>Sharpe''s inquisitive nature eventually led him to question the doctrines of the established Church. In 1821, he aligned with the Unitarian Church, setting the stage for his later biblical translation endeavors. In 1861, Sharpe retired from banking to devote himself entirely to biblical studies. His first notable work in this field was "The New Testament, Translated from the Text of J.J. Griesbach," published in 1840 by J. Green in London, which he undertook while still engaged in his banking career.<br><br>Following his retirement, Sharpe''s focus intensified, culminating in the publication of "The Hebrew Scriptures, Translated by Samuel Sharpe," a revision of the Authorized English Old Testament in three volumes in 1865. The Library of Congress Union Catalog of Bible Entries refers to this as a second edition, with subsequent editions released in 1871 and 1876. Sharpe''s commitment to refining his work led to multiple revisions across eight editions of the New Testament and four editions of the Old Testament. His final comprehensive work, "The Holy Bible, Translated by Samuel Sharpe," was a significant revision of the Authorized English Version, published in London and Edinburgh in 1881. The preface of this final edition, dated March 8, 1880, coincided with his eighty-first birthday.<br><br>In addition to his Bible translations, Sharpe made significant contributions to biblical scholarship with his works on specific books of the Bible, such as his translation of Micah in 1876 and his chronological arrangement and revised translation of "The Book of Isaiah" with historical notes in 1877. Sharpe''s journey from a bank employee to a renowned biblical translator and Egyptologist exemplifies the remarkable capacity for self-education and intellectual curiosity.', 'historic', NULL, '132', 'eng', '1881', 'scan', NULL, NULL, NULL, 'ENGSHA_DBS_HS/English-(1881)-Samuel-Sharpe-New-Testament', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('212', 'English-1824-Campbells-Gospels-Vol.-1-4', 'ENGCAM', 'English (1824) Campbells Gospels (Vol. 1-4)', NULL, 'English (1824) Campbell''s Gospels (Vol. 1-4) George Campbell (1719–96) was a minister of the Church of Scotland, theologian, and principal of Marischal College. He wrote a number of theological works, including a defense of miracles in response to David Hume, and was noted for originality of argument as well as charity towards his opponents. This translation of the Gospels was first published in England in 1789; the work consists of a preface and preliminary dissertations, the actual translation, and the notes, with the whole being very scholarly, resorting frequently to the Greek in the dissertations and notes.<br><br>George Campbell is now remembered primarily for The Philosophy of Rhetoric (1776). Here he employed the Scottish Enlightenment’s developing science of human nature to explain the effectiveness of the classical rules of rhetoric. He did this by relating the various ends of persuasive discourse to the natural faculties and propensities of the human mind. In his own time Campbell was better known as a religious apologist, using an enlightened theory of evidence in A Dissertation on Miracles (1762) to defend the believability of Christian miracles against the sceptical attack of David Hume.', 'historic', 'https://en.wikipedia.org/wiki/George_Campbell_(minister)', '262', 'eng', '1824', 'scan', NULL, NULL, NULL, 'ENGCAM_DBS_HS/English-(1824)-Campbells-Gospels-(Vol.-1-4)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('213', 'English-1881-Pictorial-Abbots-New-Testament-Study-Bible', 'ENGKJV', 'English (1881) Pictorial (Abbots) New Testament Study Bible', NULL, 'The 1881 Pictorial New Testament, annotated by the Abbotts — Rev. John S.C. Abbott, Rev. Jacob Abbott, and Rev. Lyman Abbott — is a noteworthy edition published by Henry S. Goodspeed & Co. This work is distinguished by its exquisite graphics, which serve to enrich the reader''s engagement with the New Testament texts.<br><br>The Abbotts, a prominent family in the world of religious scholarship and writing, brought a unique blend of theological insight and narrative flair to this project. Their annotations provide a deeper understanding of the New Testament, making this edition particularly valuable for both individual study and educational purposes.<br><br>Rev. John S.C. Abbott, known for his historical writings, and Rev. Jacob Abbott, a prolific author renowned for his works for young readers, alongside Rev. Lyman Abbott, a respected theologian and editor, combined their expertise to create an edition that is both informative and visually appealing. Their collaborative effort illustrates the significance of visual elements in enhancing biblical study, making complex theological concepts more accessible and engaging to a broader audience.<br><br>This edition, with its detailed illustrations and insightful commentary, not only serves as a valuable religious text but also as a piece of art. It reflects the late 19th-century trend of integrating visual art into religious publications, thereby transforming the experience of engaging with the sacred scriptures. The Pictorial New Testament is thus a testament to the Abbotts'' innovative approach to biblical scholarship and their commitment to making religious texts more appealing and understandable to the public.', 'historic', NULL, '127', 'eng', '1881', 'study', 'Henry S. Goodspeed & Co.', NULL, NULL, 'ENGKJV_DBS_HS/English-(1881)-Pictorial-(Abbots)-New-Testament-Study-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('214', 'English-1749-Challoner-DRV-New-Testament', 'ENGDRB', 'English (1749) Challoner DRV New Testament', NULL, 'The Challoner Douay-Rheims Version (DRV) New Testament, initially revised by Richard Challoner in 1749, is a significant development in English Bible translations. This work involved revising the original Douay-Rheims Bible, first published by the English College at Douay in 1609, to modernize and correct it according to the Clementine Edition of the Scriptures. It also included annotations to address difficulties in understanding Holy Writ. The revision history of the Challoner DRV includes: <br><br> 1749: The first revision of the New Testament by Challoner, incorporating changes from the 1738 edition (also by Richard Challoner and Francis Blyth).<br> 1750: The first revision of the Old Testament (in two volumes) and the second revision of the New Testament (in one volume).<br> 1752: The third revision of the New Testament (in two volumes).<br> 1763 - 1764: The second revision of the Old Testament (in four volumes).<br> 1764: The fourth revision of the New Testament.<br> 1772: The fifth revision of the New Testament.<br> 1790: The first American edition based on Challoner''s second edition (1763-64) was published in Philadelphia by Carey, Stewart & Co.<br> 1796: Another edition was published in Edinburgh by John Moir.<br> 1942: A New York edition by The Douay Bible House, using the 1752 revision by Dr. Challoner.<br><br> The 1942 edition is noted for being commended by the Pope as the best text in the American tradition. Challoner''s revisions of the Douay-Rheims Bible played a crucial role in making this translation more accessible and understandable to English-speaking Catholics, ensuring its continued use and significance in religious studies and practices.', 'historic', NULL, '103', 'eng', '1749', 'scan', NULL, NULL, NULL, 'ENGDRB_DBS_HS', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('215', 'English-1861-Pictorial-Bible-Vol.-3-Psalms-Malachi-Study', 'ENGPICT', 'English (1861) Pictorial Bible (Vol. 3) Psalms - Malachi (Study)', NULL, 'The 1861 edition of "The Pictorial Bible," edited by John Kitto, D.D., F.S.A., stands as a monumental work in the realm of biblical literature. This volume, part of a four-volume series, covers from Genesis to Joshua, providing a comprehensive visual and scholarly journey through these foundational books of the Old Testament. Kitto''s work is renowned for its integration of steel engravings and numerous woodcuts, which vividly depict landscape scenes, natural history, customs, and antiquities.<br><br>John Kitto, an eminent biblical scholar of his time, augmented the authorized version of the Bible with original notes that explain passages linked to the history, geography, natural history, literature, and antiquities of the Scriptures. These notes are particularly notable for their reliance on the discoveries of contemporary travelers and scholars, making this edition an invaluable resource for understanding the historical and cultural context of the biblical narrative.<br><br>Published in London by W. and R. Chambers, this new edition of "The Pictorial Bible" was aimed at bringing the biblical world to life for its readers. It was designed to be more than just a religious text; it was an educational tool that merged the sacred scriptures with the burgeoning fields of archaeology and oriental studies. The detailed illustrations and comprehensive notes provided a deeper, more textured understanding of the Bible, making it an essential addition to the libraries of scholars, clergy, and laypeople interested in a more profound comprehension of biblical times and teachings.', 'historic', NULL, '188', 'eng', '1861', 'study', 'W. and R.Chambers', NULL, NULL, 'ENGPICT_DBS_HS/English-(1861)-Pictorial-Bible-(Vol.-3)-Psalms-Malachi-(Study)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('216', 'English-1866-Anderson-New-Testament', 'ENGANT', 'English (1866) Anderson New Testament', NULL, 'The translation of the New Testament by Henry T. Anderson, a notable figure in the Campbellite "Disciples of Christ" denomination, is a remarkable example of scholarly dedication and religious commitment. Born in Virginia in 1812 and predominantly based in Kentucky, Anderson was both a schoolmaster and a preacher. <br><br> His translation journey began in 1861 and concluded in 1864 while he resided in Harrodsburg, Kentucky. The initial edition of his work, "The New Testament Translated from the Original Greek, by H.T. Anderson," was printed in 1864 at the Franklin Type Foundry in Cincinnati, Ohio, spanning 569 pages. Subsequently, in 1866, John P. Morton & Co. in Louisville, Kentucky, published a new edition of 568 pages and a smaller version of 408 pages. <br><br> Later, in 1918, The Standard Publishing Company in Cincinnati released "The New Testament Translated from the Sinaitic Manuscript discovered by Constantine Tischendorf at Mount Sinai," which Anderson purportedly prepared shortly before his death in 1872. Although this edition claimed to be a version of the Codex Sinaiticus, it was essentially a revision of Anderson''s earlier translation, adjusted according to some readings from the Codex. The specifics of Anderson''s source material for this revision remain unclear, as the preface of the publication does not detail the sources used. <br><br> Anderson''s translation efforts, described by his friend John Augustus Williams in a chapter of his "Reminiscences," underscore his profound dedication to providing an accessible and authentic rendition of the New Testament.', 'historic', NULL, '8', 'eng', '1866', 'scan', 'John P. Morton & Company', NULL, NULL, 'ENGANT_DBS_HS/English-(1866)-Anderson-New-Testament', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('217', 'English-1830-Common-Palfrey-New-Testamentpdf', 'ENGPAL', 'English (1830) Common (Palfrey) New Testament', NULL, 'English (1830) Common (Palfrey) New Testament John Gorham Palfrey, The New Testament in the common Version, conformed to Griesbach''s Standard Greek Text. Boston: Gray & Bowen, 1828. Third edition, 1830.<br><br>Palfrey, a Unitarian, published this version anonymously. It is a revision of the King James version in accordance with Griesbach 1805. This is perhaps the earliest example of a scholar''s attempt to fully inform the public at large of the results of the new textual criticism pioneered by Griesbach.', 'historic', NULL, '62', 'eng', '1830', 'scan', 'Gray and Bowen', NULL, NULL, 'ENGPAL_DBS_HS/English-(1830)-Common-(Palfrey)-New-Testamentpdf', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('218', 'Aramaic-1514-Complutensian-Polyglot-Bible-Vol-5-of-5-Grk-Heb-Lat-Aramaic-StudyWDL-10636', 'AII1514', 'Aramaic (1514) Complutensian Polyglot Bible (Vol 5 of 5) Grk-Heb-Lat-Aramaic Study(WDL-10636)', 'Vetus testamentū multiplici lingua nūc primo impressum, Et imprimis Pentateuchus Hebraico Greco atq[ue] Chaldaico idiomate', 'The fifth volume of the Complutensian Polyglot Bible, completed in 1514, represents the culmination of Cardinal Francisco Jiménez de Cisneros''s ambitious project to produce the first multilingual printed edition of the Bible. This volume, along with the rest of the set, was a monumental achievement in the history of printing and biblical scholarship, illustrating the height of Spanish typographic artistry of the 16th century. The effort to compile and print this work involved a significant collaboration among scholars and experts in Latin, Greek, Hebrew, and Aramaic, under the printing expertise of Arnaldo Guillén de Brocar. This volume is particularly notable for containing linguistic resources that were invaluable to scholars of the time, including a Hebrew and Aramaic dictionary, a Hebrew grammar, and a Greek dictionary. The creation of new and highly perfected typefaces for each language set a new standard in printing. Despite the challenges and the time-consuming process, the completion and subsequent distribution of the Complutensian Polyglot Bible in 1520, after papal authorization, marked a significant advancement in academic study, providing an essential resource for the comparative study of biblical texts.', 'historic', 'https://www.wdl.org/en/item/10636', '117', 'aii', '1514', 'study', 'Arnao Guillén de Brocar, Alcalá de Henares', NULL, 'World Digital Library', 'AII1514_DBS_HS/Aramaic-(1514)-Complutensian-Polyglot-Bible-(Vol-5-of-5)-Grk-Heb-Lat-Aramaic-Study(WDL-10636)', 'aii', 'assy1241', 'Assyrian Neo-Aramaic', 'Sūreṯ', 'L', 'IQ', '36.75', '43', '6b', NULL, '626000', 'Iraq', 'Northern Iraq, Baghdad, Basrah, Karkuk, Arbil. Also in Armenia, Australia, Austria, Azerbaijan, Belgium, Brazil, Canada, Cyprus, France, Georgia, Germany, Greece, Iran, Italy, Lebanon, Netherlands, New Zealand, Russian Federation (Europe), Sweden, Switzerland, Syria, Turkey (Asia), United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('219', 'English-1903-Holy-Bible-Improved-Edition-Bible-Union', 'ENGAME', 'English (1903) Holy Bible Improved Edition (Bible Union)', NULL, 'The American Bible Union''s "Holy Bible, Containing the Old and New Testaments, An Improved Edition" stands as a noteworthy chapter in the history of Bible translation, particularly in the context of revising the King James Version. Initially established with the primary aim of revising the King James Version, the American Bible Union embarked on its ambitious project by publishing a New Testament between 1862 and 1864. Post-1865, efforts were also extended towards revising the Old Testament, though a complete work was not published during this phase. <br><br> In 1883, after the dissolution of the Bible Union, its legacy and mission were inherited by The American Baptist Publication Society. This institution reignited the revision work, leading to the publication of a revised New Testament in 1891. Further, in 1912, it released an improved version of both the Old and New Testaments, reprinted a year later. This edition is significant for its reference to newly available manuscripts, likely including the Sinaiticus and Vaticanus, among others. Despite this, the translation predominantly adheres to the Textus Receptus. <br><br> Characterized by its literal translation approach, this edition is distinguished by its retention of the traditional ''thee'' and ''you'' forms, reflecting a balance between modernity and textual fidelity. As one of the last complete Bibles to enter the public domain, the "Improved Edition" marks a critical juncture in the journey of Bible translations, embodying a blend of historical reverence and progressive adaptation.', 'historic', NULL, '241', 'eng', '1903', 'scan', 'American Baptist Publication Society', 'american-baptist-mission-press', NULL, 'ENGAME_DBS_HS/English-(1903)-Holy-Bible-Improved-Edition-(Bible-Union)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('220', 'Hebrew-1890-Triglot-Bible-Vol.-1-2-Greek-Latin', 'HEBHEPT', 'Hebrew (1890) Triglot Bible (Heb Greek Latin)', 'עברית - תנ"ך משולש (1890, עברית-יוונית-לטינית)', 'The 1890 "Triglot Bible," published by R.D. Dickinson, is a comprehensive compilation of the Holy Scriptures, presenting the Old and New Testaments in their original tongues. This unique edition includes the Hebrew text of the Old Testament, the Greek text of the New Testament, the Greek Septuagint (an ancient Greek translation of the Hebrew Bible), the Syriac version of the New Testament, and the Latin Vulgate version. All these texts are thoughtfully arranged in parallel columns for ease of comparative study and analysis.<br><br>The Triglot Bible''s integration of multiple translations and versions into a single volume offers a unique resource for biblical scholars, theologians, and students. It facilitates an in-depth understanding of the textual variations and interpretations of biblical scriptures across different languages and traditions. The inclusion of a complete prolegomenon adds scholarly context to this edition, making the Triglot Bible a significant tool for those engaged in biblical studies and the history of biblical interpretation.', 'historic', NULL, '254', 'heb', '1890', 'study', 'Richard D. Dickinson', NULL, NULL, 'HEBHEX_DBS_HS/Hebrew-(1890)-Triglot-Bible-(Heb-Greek-Latin)', 'heb', 'hebr1245', 'Hebrew', 'Israeli Hebrew', 'L', 'IL', '31.10565', '35.01788', '1', 'he', '5000000', NULL, 'Also in Australia, Canada, Germany, Palestinian West Bank and Gaza, Panama, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('221', 'English-1764-Purver-Bible', 'ENGQKR', 'English (1764) Purver Bible', NULL, 'The 1764 Purver Bible, also known as "The Quaker Bible," is a translation of the Christian Bible into English by Anthony Purver (1702–1777), a member of the Quakers. Published in two volumes in London by W. Richardson and S. Clark, the full title of the work is "A new and literal translation of all the books of the Old and New Testament; with notes critical and explanatory." Despite its ambitious scope, the translation did not achieve widespread success or recognition.<br><br>Earlier, around 1742, a portion of Purver''s translation was published by Felix Farley of Bristol but received little support. Purver struggled to publish the entire text and did not gain significant backing, even from the Religious Society of Friends, to which he belonged. Ultimately, the full translation was published at the expense of Dr. John Fothergill, yet it still failed to make a significant impact.<br><br>The reasons for the limited success of Purver’s translation are varied. They include lack of publicity, the fact that it was a one-man translation without the backing of any church, including the Religious Society of Friends. Moreover, some critics regarded it as an unreliable translation. The Dictionary of National Biography noted that Purver would isolate himself for inspiration when faced with difficult passages. Charles Haddon Spurgeon, familiar with Purver’s version, described it as "often ungrammatical and unintelligible" and more curious than useful.<br><br>In 1763, Dr. John Fothergill purchased the copyright from Purver and published a folio edition, yet Purver''s Bible, despite being a unique contribution to English Bible translations, is more often remembered as an intriguing historical artifact than a significant literary or religious work.', 'historic', 'https://en.wikipedia.org/wiki/Quaker_Bible', '183', 'eng', '1764', 'scan', NULL, NULL, NULL, 'ENGQKR_DBS_HS/English-(1764)-Purver-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('222', 'English-1557-Geneva-Bible', 'ENGGNV', 'English (1557) Geneva Bible', NULL, 'The Geneva Bible, first printed in 1560, is a monumental translation of the Bible into English and was a precursor to the King James Version by 51 years. As the primary Bible for 16th-century English Protestantism, it significantly influenced figures such as William Shakespeare, Oliver Cromwell, John Knox, John Donne, and John Bunyan, the author of "The Pilgrim''s Progress" (1678). This Bible was also among those taken to America by the Mayflower passengers, as evidenced by collections at the Pilgrim Hall Museum.<br><br>Notably, the Geneva Bible was the first mechanically printed, mass-produced Bible accessible directly to the general public. It was furnished with a variety of study aids, including verse citations for cross-referencing, introductions to each book, maps, tables, woodcut illustrations, and indices. Its vigorous language made it more popular than the Great Bible, described by Cleland Boyd McAfee as having "driven the Great Bible off the field by the sheer power of excellence."<br><br>Following the Great Bible of 1539, the first authorized English Bible, the Geneva Bible was produced during Queen Mary I''s reign (1553–58) when Protestant scholars, including William Whittingham, Myles Coverdale, and others, fled to Geneva. Whittingham supervised the translation of the New Testament (published in 1557), while Gilby oversaw the Old Testament.<br><br>The first full edition appeared in 1560, but it wasn''t printed in England until 1575 (New Testament) and 1576 (complete Bible). Over 150 editions were issued, the last probably in 1644. The Geneva Bible was especially significant in Scotland, where its association with Knox and Calvin led to a 1579 law requiring households to own a copy.<br><br>Later editions included Laurence Tomson''s New Testament revisions and a new "Junius" version of the Book of Revelation. The annotations, reflecting Calvinist and Puritan views, were disliked by Anglicans and King James I, who commissioned the King James Bible as a replacement. Despite this, the Geneva Bible remained popular among Puritans and was widely used until after the English Civil War. Its notes even appeared in some editions of the King James version until 1715.', 'historic', 'https://en.wikipedia.org/wiki/Geneva_Bible', '29', 'eng', '1560', 'scan', NULL, NULL, NULL, 'ENGGNV_DBS_HS/English-(1557)-Geneva-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('223', 'English-1824-A-New-Family-Bible-Vol.-2-of-3-Boothroyd-Study', 'ENGNFB', 'English (1824) A New Family Bible (Vol. 2 of 3) Boothroyd (Study)', NULL, 'English (1824) A New Family Bible (Vol. 2 of 3) Boothroyd (Study) Bible. English. Boothroyd. 1824. New family Bible, and improved version, from corrected texts of the originals. Huddersfield : William Moore, 1824<br><br>“Boothroyd, Benjamin A New Family Bible, and improved version, from corrected texts of the originals; with notes critical and explanatory, and short practical reflections...with a general introduction...By the Rev. B. Boothroyd... 3 Vols. Huddersfield: Printed for the Author, and others, by William Moore, 1817 and again in 1824. New edition, revised, 1835. An Abridged Edition; London: James Duncan, 1836. Another edition; Translated from Corrected Texts. London: Partridge & Oakey, 1853.”<br><br>(From: William J. Chamberlin. “Catalogue of English Bible Translations”.<br><br>Benjamin Boothroyd (1768 – 8 September 1836) was an English Independent minister and Hebrew scholar. He had the degrees of D.D. and L.L.D. In 1818 Boothroyd (who had accepted the degree of LL.D.) became co-pastor at Highfield Chapel, Huddersfield, with the Rev. William Moorhouse. In 1818 Booth completed his New Family Bible and Improved Version in three vols. 4to, which had been suggested to him on a visit to York by Henry Tuke, a Quaker. He printed many copies of it at his own press. It contained notes, and in recognition of his achievement the university of Glasgow conferred on Boothroyd the degree of D.D. in 1824. In 1835 he completed an octavo edition of the Family Bible. On 10 January 1836 he went down with a violent illness; he died on 8 September and was buried at Huddersfield.', 'historic', 'https://en.wikipedia.org/wiki/Benjamin_Boothroyd', '220', 'eng', '1824', 'study', 'Rev. B. Boothroyd, L. L. D.', NULL, NULL, 'ENGNFB_DBS_HS/English-(1824)-A-New-Family-Bible-(Vol.-2-of-3)-Boothroyd-(Study)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('224', 'English-1899-Two-Version-Bible-KJV-and-RV-in-Margin', 'ENGREV', 'English (1899) Two Version Bible (KJV and RV in Margin)', NULL, 'The historical context of Bible printing in America is a fascinating journey through technological advancements and cultural shifts. Initially, during the seventeenth and early eighteenth centuries, the American landscape saw limited Bible printing. The majority of Bibles were either imported from European and British publishers or brought by immigrants. This scenario began to change significantly as the eighteenth century progressed, especially towards its latter half.<br><br>Advancements in printing technology, coupled with a growing demand, catalyzed a surge in Bible publishing across America. Major urban centers like Boston, Philadelphia, and New York emerged as prominent hubs for Bible production. As noted by Bible historian Paul Gutjahr, the Bible experienced an unprecedented level of popularity during the eighteenth century, becoming the most printed, distributed, and read text in North America.<br><br>This period saw the Bible evolving beyond a mere religious text; it became a familial heirloom, a symbol of spiritual commitment, and a connector to ancestral roots and distant relatives. Its significance was reflected in the way families treasured and displayed their Bibles. Recognizing the Bible''s multifaceted importance in American households, publishers started producing editions with ornate, sometimes embossed covers and elaborate illustrations, often in color. These visually striking Bibles were not just books of scripture; they were works of art, proudly displayed in homes as a testament to both faith and heritage. This trend highlights the integral role the Bible played in shaping the spiritual, cultural, and aesthetic aspects of American life.', 'historic', NULL, '221', 'eng', '1899', 'study', 'The University Press, Henry Frowde', NULL, NULL, 'ENGREV_DBS_HS/English-(1899)-Two-Version-Bible-(KJV-and-RV-in-Margin)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('225', 'Greek-English-1825-Scientia-Biblica-Parallel-Vol.-1-3-New-Testament', 'GRCTRE', 'Greek-English (1825) Scientia Biblica Parallel (Vol. 1-3) New Testament', 'Scientia Biblica (1825, Παράλληλη Καινή Διαθήκη, Τόμος 1-3)', 'The 1825 "Scientia Biblica" is a Greek-English parallel edition of the New Testament, published by W. Booth in London. This work is notable for its presentation of the New Testament in the original Greek alongside the English Vulgate. A distinguishing feature of this edition is its extensive and original collection of parallel passages, which are printed in full words, offering a comprehensive resource for comparative study and analysis.<br><br>This edition was revised by Dr. Blayney, under the direction of the Lord Chancellor and delegates of the Clarendon Press. A significant aspect of this revision was the meticulous examination and correction of the marginal references. Furthermore, an impressive number of new references, totaling thirty-thousand-four hundred, were added to the margins. This enhancement significantly broadens the scope of study and cross-referencing capabilities within the text.<br><br>"Scientia Biblica" stands out for its scholarly rigor and the depth of its cross-referential material. The parallel format, combined with the corrected and expanded marginal references, makes it a valuable tool for scholars, theologians, and students engaged in in-depth biblical studies, particularly those interested in the textual comparison and analysis of the New Testament.', 'historic', NULL, '121', 'grc', '1825', 'study', NULL, NULL, NULL, 'GRCTRE_DBS_HS/Greek-English-(1825)-Scientia-Biblica-Parallel-(Vol.-1-3)-New-Testament', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('226', 'English-1902-Godbey-New-Testament', 'ENGGOD', 'English (1902) Godbey New Testament', NULL, 'The 1902 Godbey New Testament represents a unique contribution to Biblical scholarship and translation, primarily for its approach to the synoptic Gospels and its reliance on critical Greek texts. In this edition, the Gospels are arranged as a synoptical harmony, with John''s Gospel included, allowing for a comparative reading of the Gospels, highlighting similarities and differences in the narratives. The text is presented in one to four columns, set paragraph-wise with superscriptions, enhancing readability and study.<br><br>Moreover, Godbey''s translation includes cross-references and alternate readings in the footnotes, providing deeper insight into the textual variations and scholarly interpretations. The Acts, Letters, and Revelation are presented in a single column with footnotes, maintaining a consistent and scholarly approach.<br><br>In the Prologue, Godbey reveals his primary source text: the critical Greek Testament based on the Sinaic manuscript by Tischendorf. This choice of source material underscores the translation''s academic rigor. With over forty years of engagement with the Greek New Testament, Godbey''s work is credible and thorough. He positions his translation as an aid to understanding, akin to the Revised Version.<br><br>Godbey''s translation, focusing on critical Greek sources and a comparative approach to the Gospels, offers a valuable resource for students and scholars of the Bible. His humble acknowledgment of the role of his translation in the broader landscape of Biblical studies exemplifies the continual journey of understanding and interpreting these ancient texts.', 'historic', NULL, '46', 'eng', '1902', 'scan', 'Rev. W. B. Godbey, A. M., M. W. Knapp', NULL, NULL, 'ENGGOD_DBS_HS/English-(1902)-Godbey-New-Testament', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('227', 'English-1530-Tyndale-Pentateuch-Bible-Portions', 'ENGTNT', 'English (1530) Tyndale Pentateuch Bible Portions', NULL, 'The English (1530) Tyndale Pentateuch refers to the portion of the Tyndale Bible encompassing the first five books of the Old Testament, translated by William Tyndale. These books, collectively known as the Pentateuch, include Genesis, Exodus, Leviticus, Numbers, and Deuteronomy. Tyndale''s work on the Pentateuch was pioneering, particularly as it was among the first English translations done directly from Hebrew, diverging from the traditional Latin Vulgate.<br><br>This direct approach to translation was aligned with the broader aims of the Reformation, which sought to make religious texts more accessible to the public, especially to those who only spoke and read English. The publication of Tyndale''s Pentateuch in 1530 was made possible by advancements in printing technology, significantly enhancing the distribution of these texts.<br><br>Tyndale''s translations had a lasting impact on the development of the English language and on subsequent English Bible translations, influencing the style and language of future versions, including the King James Bible. Despite facing severe opposition from the Church authorities, leading to his execution in 1536, Tyndale''s work on the Pentateuch and other biblical texts left an indelible mark on English religious and literary history.', 'historic', NULL, '44', 'eng', '1530', 'scan', 'GreatSite.com', NULL, NULL, 'ENGTNT_DBS_HS', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('228', 'Coptic-1898-New-Testament', 'COPSNT', 'Coptic (1898) New Testament', 'Ⲙⲉⲧⲛⲓⲙ ⲛ̀ⲛⲉⲛⲧⲟⲥ (1898)', 'The term ‘Coptic’ refers to the form of Egyptian in use after the establishment of Christianity in Egypt during the 3rd century. Sometimes called Neo-Egyptian, it is a development of Ancient Egyptian, in use until the 6th century B.C., and it''s later Hieratic and Demotic forms. These long succeeding periods made Coptic the living language with the longest recorded history. The few remaining Coptic speakers succumbed to the Arabic language in the 17th century.<br>Coptic was spoken in several dialects. Scriptures are extant in the Bohairic (Coastal, Lower Egypt); Fayumic or Bashmuric, Sub- Achmimic, and Middle Egyptian; and Sahidic and Achmimic (Upper Egyptian) dialects. Bohairic, earlier known as Memphitic, was the usage of Alexandria and hence survives as the ecclesiastical and liturgical language of the Coptic Church. However, it appears that Scriptures first appeared (3rd century) in Sahidic, because Lower Egypt had been Hellenized and the Greek Scriptures could be used there. Although considerable research remains to be done on the Coptic texts, these early versions cast light on the text used by the early Church.<br>The Coptic alphabet employs 24 Greek characters and 7 characters retained from Demotic script.', 'historic', NULL, '18', 'cop', '1898', 'scan', 'The Clarendon Press', NULL, 'Google', 'COPSNT_DBS_HS/Coptic-(1898)-New-Testament', 'cop', 'copt1239', 'Coptic', 'ϯⲙⲉⲧⲣⲉⲙⲛ̀ⲭⲏⲙⲓ ~ ⲧⲙⲛ̄ⲧⲣⲙ̄ⲛ̄ⲕⲏⲙⲉ', 'E', 'EG', '29.47203', '31.2053', '9', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('229', 'English-1898-Stevens-Epistles-Bible-Pauls-Epistles', 'ENGSTEV', 'English (1898) Stevens Epistles Bible - Pauls Epistles', NULL, '"The Epistles of Paul in Modern English: A Paraphrase," authored by George Barker Stevens and published in 1898 by Charles Scribner''s Sons, New York, is a notable work in the field of biblical scholarship. George Barker Stevens (July 13, 1854 - June 22, 1906), an American Congregational and Presbyterian clergyman, theologian, author, and educator, was renowned for his contributions as a professor at Yale Divinity School. Born in Spencer, New York, Stevens embarked on an academic journey that led him from the University of Rochester to the halls of Yale Divinity School, where he distinguished himself as a member of Phi Beta Kappa and Delta Kappa Epsilon fraternities.<br><br>Following his graduation in 1880, Stevens served as pastor in both Congregational and Presbyterian churches in New York. His academic pursuits continued at Syracuse University and in German universities, culminating in a Doctor of Sacred Theology degree from the University of Jena. Stevens was also recognized with honorary degrees from Illinois College and the University of Rochester.<br><br>In 1886, Stevens returned to Yale as a professor of New Testament criticism, later transitioning to the chair of systematic theology. His "Epistles of Paul" is a reflection of his profound understanding of biblical texts and his ability to contextualize them for modern readers. This work, a paraphrase of Paul''s letters, is a testament to Stevens'' commitment to making biblical teachings more accessible and relatable to contemporary audiences. His scholarly and pastoral experiences enrich this translation, offering a unique perspective on the Epistles of Paul. His death in New Haven in 1906 marked the loss of a significant figure in American religious education and biblical interpretation.', 'historic', NULL, '8', 'eng', '1898', 'scan', 'Charles Scribner''s Sons', NULL, NULL, 'ENGSTEV_DBS_HS/English-(1898)-Stevens-Epistles-Bible-Pauls-Epistles', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('230', 'English-1815-Synopsis-of-the-Gospels-Charles-Thompson-Gospels', 'ENGSCT', 'English (1815) Synopsis of the Gospels (Charles Thompson) Gospels', NULL, 'Charles Thomson, an American patriot and Secretary of the Continental Congress from 1774 to 1789, made significant contributions to biblical scholarship. Notably, Thomson was the first individual to translate the Greek Septuagint into English and was also the first American to translate the New Testament into English. His translation of the Bible was a remarkable achievement, especially considering the context of his time.<br><br>The publication of Thomson''s Bible translation in 1808 holds historical significance for several reasons. It was printed by Jane Aitken, who was not only the daughter of Robert Aitken (the printer of the first English Bible in America) but also the first woman to publish a Bible in America. This fact adds a unique dimension to the historical and cultural importance of Thomson''s work.<br><br>In 1815, Thomson further expanded his work in biblical translations by publishing a translation of the Gospels arranged as a harmony. This work offered a synchronized narrative of the Gospels, combining the accounts of Matthew, Mark, Luke, and John into a single, cohesive chronology. This approach to the Gospels provided readers with a more unified view of the life and teachings of Jesus Christ, making Thomson’s work not just a translation but an innovative way to study and understand the Gospels.<br><br>Charles Thomson''s efforts in translating the Bible and creating a harmonized version of the Gospels underscore his significant role in the development of biblical studies in the early United States, as well as his contribution to the broader field of religious scholarship.', 'historic', 'http://bibles.wikidot.com/thomson', '36', 'eng', '1815', 'scan', 'Charles Thomson', NULL, NULL, 'ENGSCT_DBS_HS/English-(1815)-Synopsis-of-the-Gospels-(Charles-Thompson)-Gospels', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('231', 'French-1846-Le-Nouveau-Testament-Du-Pere-Carrieres', 'FRAOST', 'French (1846) Le Nouveau Testament', 'Le Nouveau Testament (1846)', 'French (1846) Le Nouveau Testament, incorporating literal commentary from Father de Carrières along with moral and dogmatic explanatory notes, is designed to enhance understanding of the scriptures. This version of the New Testament, which encompasses the four Gospels, Acts, the Epistles, and the Apocalypse, focuses on the life and teachings of Jesus Christ and the written instructions of His Apostles. Highlighting the new covenant between God and humanity, it emphasizes the law of grace and love introduced by the Son of God. This edition positions the New Testament as the foundational text for Christians, emphasizing its role in defining the Christian law and ethos.', 'historic', NULL, '62', 'fra', '1846', 'scan', NULL, NULL, NULL, 'FRAOST_DBS_HS/French-(1846)-Le-Nouveau-Testament-(Du-Pere-Carrieres)', 'fra', 'stan1290', 'French', 'français', 'L', 'FR', '48', '2', '1', 'fr', '77200000', 'Andorra and France', 'Also in Algeria, Andorra, Austria, Belgium, Benin, Burkina Faso, Burundi, Cambodia, Cameroon, Canada, Central African Republic, Chad, Comoros, Congo, Côte d’Ivoire, Democratic Republic of the Congo, Djibouti, Equatorial Guinea, French Guiana, French Polynesia, Gabon, Guadeloupe, Guinea, Haiti, India, Israel, Italy, Lebanon, Libya, Luxembourg, Madagascar, Mali, Martinique, Mauritania, Mauritius, Mayotte, Monaco, Morocco, Mozambique, New Caledonia, Niger, Philippines, Puerto Rico, Réunion, Rwanda, Saint Pierre and Miquelon, Saudi Arabia, Senegal, Seychelles, South Africa, Switzerland, Togo, Tunisia, United Arab Emirates, United Kingdom, United States, U.S. Virgin Islands, Vanuatu, Wallis and Futuna.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('232', 'Hebrew-1908-Pentateuch-Hamishah-humshey-Torah-Ginsburg', 'HEBGINS', 'Hebrew (1908) Pentateuch (Hamishah humshey Torah) Ginsburg', 'עברית - חמשה חומשי תורה (1908, גינצבורג)', 'The 1908 Ginsburg edition of the Pentateuch, known in Hebrew as "Hamishah humshey Torah," forms part of the Hebrew Bible or Tanakh, which comprises the canonical collection of Hebrew scriptures. This includes the Torah (Law), Nevi''im (Prophets), and Ketuvim (Writings). Throughout history, different branches of Judaism and Samaritanism have maintained various versions of these canonical texts, each holding a unique place in religious practice and scholarship.<br><br>Notable among these versions are the 3rd-century Septuagint text used by Second-Temple Judaism, the Syriac language Peshitta, the Samaritan Pentateuch, the Dead Sea Scrolls, and the medieval Masoretic text from the 10th century, developed by the Masoretes. The Masoretic text is the primary version used in modern Rabbinic Judaism. It''s important to differentiate between the terms "Hebrew Bible" or "Hebrew Canon" and the Masoretic text; the latter is a medieval iteration and one of several authoritative texts in various Jewish traditions. The Masoretic text is predominantly in Biblical Hebrew, interspersed with passages in Biblical Aramaic, found in the books of Daniel and Ezra, as well as in Jeremiah 10:11. This diversity reflects the rich textual history and the evolution of Jewish scriptural traditions over the centuries.', 'historic', NULL, '18', 'heb', '1908', 'scan', 'The British and Foreign Bible Society', 'british-and-foreign-bible-society', NULL, 'HEBGINS_DBS_HS/Hebrew-(1908)-Pentateuch-(Hamishah-humshey-Torah)-Ginsburg', 'heb', 'hebr1245', 'Hebrew', 'Israeli Hebrew', 'L', 'IL', '31.10565', '35.01788', '1', 'he', '5000000', NULL, 'Also in Australia, Canada, Germany, Palestinian West Bank and Gaza, Panama, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('233', 'French-1731-Bible-de-Saurin-Commentry-Discours-historiques-critiques-théologiques-et-moraux-Vol-1-3', 'FRASAUR', 'French (1731) Bible de Saurin Commentry Discours historiques critiques théologiques et moraux (Vol 1 3)', 'Bible de Saurin (1731) Commentaire, Discours historiques, critiques, théologiques et moraux (Vol 1-3)', 'The "Discours historiques, critiques, théologiques et moraux sur les événements les plus mémorables du Vieux et du Nouveau Testament" (Historical, Critical, Theological, and Moral Discourses on the Most Memorable Events of the Old and New Testament) is a collection of sermons written by Jacques Saurin, a prominent French Protestant preacher of the late 17th and early 18th centuries. Born in 1677 in Nîmes, France, Saurin and his family fled to Geneva after the Revocation of the Edict of Nantes (1685), which led to the persecution of French Protestants (Huguenots). There, he studied theology and philosophy before becoming a pastor. <br><br>Originally published between 1720 and 1728, this work provides a detailed analysis of biblical narratives, combining historical context, theological reflection, moral teaching, and critical interpretation. The 1731 edition, spanning three volumes, offers a comprehensive collection of Saurin’s sermons, aiming to educate and inspire readers by drawing moral and spiritual lessons from both the Old and New Testaments.  <br><br>Saurin’s approach is characterized by intellectual depth, eloquence, and a commitment to Reformed Protestant theology. His work was widely appreciated for making biblical teachings accessible, relevant, and engaging for his audience.', 'historic', NULL, '1', 'fra', '1731', 'illuminated', NULL, NULL, NULL, NULL, 'fra', 'stan1290', 'French', 'français', 'L', 'FR', '48', '2', '1', 'fr', '77200000', 'Andorra and France', 'Also in Algeria, Andorra, Austria, Belgium, Benin, Burkina Faso, Burundi, Cambodia, Cameroon, Canada, Central African Republic, Chad, Comoros, Congo, Côte d’Ivoire, Democratic Republic of the Congo, Djibouti, Equatorial Guinea, French Guiana, French Polynesia, Gabon, Guadeloupe, Guinea, Haiti, India, Israel, Italy, Lebanon, Libya, Luxembourg, Madagascar, Mali, Martinique, Mauritania, Mauritius, Mayotte, Monaco, Morocco, Mozambique, New Caledonia, Niger, Philippines, Puerto Rico, Réunion, Rwanda, Saint Pierre and Miquelon, Saudi Arabia, Senegal, Seychelles, South Africa, Switzerland, Togo, Tunisia, United Arab Emirates, United Kingdom, United States, U.S. Virgin Islands, Vanuatu, Wallis and Futuna.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('234', 'English-1862-Sharpe-New-Testament-Griesbach', 'ENGSHA', 'English (1862) Sharpe New Testament (Griesbach)', NULL, 'Samuel Sharpe, an Egyptologist and Bible translator, is the subject of P. W. Clayden''s biography, "Samuel Sharpe, Egyptologist and Translator of the Bible" (London, 1883). Sharpe''s story is intriguing as he was neither a preacher nor an academic, but a banker without formal college or university education. Despite this, he made significant contributions to biblical scholarship.<br><br>Sharpe''s work in biblical translation includes "The Book of Isaiah Arranged Chronologically in a Revised Translation…with Historical Notes" (London, J.R. Smith, 1877) and a translation of Micah (J. Hall & Son, Cambridge, 1876). These publications came at a time when debates and efforts were intensifying for a general revision of the Bible. Sharpe, a Unitarian, was part of a group of scholars considered for collaboration with other denominations, including Presbyterian, Baptist, and Methodist scholars, for a project that eventually led to the 1881-85 Bible revision. However, Sharpe did not participate in this project.<br><br>The "Dictionary of National Biography" acknowledges Sharpe''s unique approach to Bible translation, noting his success in updating archaic language while preserving the revered quality of the English Bible. Unlike many translations of the period, Sharpe''s work is distinguished by its lack of notes, original readings, or references. In his preface, Sharpe states that his goal was to achieve precision in the text itself, incorporating nuances typically addressed in external notes and commentaries directly into his translation. This method underscores Sharpe''s commitment to both clarity and fidelity in conveying biblical texts.', 'historic', NULL, '57', 'eng', '1862', 'scan', 'J. Russell Smith', NULL, NULL, 'ENGSHA_DBS_HS/English-(1862)-Sharpe-New-Testament-(Griesbach)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('235', 'English-1837-Tyndales-New-Testament-1526-version', 'ENGTYN', 'English (1837) Tyndales New Testament (1526 version)', NULL, 'English (1837) Tyndale''s New Testament (1526 version): Tyndale''s New Testament, originally translated in 1526, was the first English translation of the New Testament to be printed. The 1837 edition marks the first American publication of this historic translation, featuring an introduction by J.A. Dabney. This edition is significant as it represents a key moment in the dissemination of the Bible in English, particularly in America. It''s a part of the wider historical context of making religious texts more accessible to the general public, a movement in which William Tyndale was a pivotal figure. His 1526 translation laid the foundation for subsequent English translations of the Bible, including the King James Version.', 'historic', NULL, '70', 'eng', '1837', 'scan', NULL, NULL, NULL, 'ENGTYN_DBS_HS/English-(1837)-Tyndales-New-Testament-(1526-version)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('236', 'English-1902-Weymouth-New-Testament', 'ENGWEY', 'English (1902) Weymouth New Testament', NULL, 'The Weymouth New Testament, formally known as "The New Testament in Modern Speech" or "The Modern Speech New Testament," stands as a significant contribution to biblical translations by Richard Francis Weymouth. Weymouth, renowned for his work "The Resultant Greek Testament," embarked on a mission to render the New Testament in nineteenth-century English, aiming to make it more accessible and comprehensible to the general populace. <br><br> His translation was not just a mere linguistic exercise but an attempt to convey Greek idioms and expressions into the vernacular of modern English. Weymouth''s approach was meticulous and scholarly; his source, "The Resultant Greek Testament," was an eclectic text drawing on readings from various esteemed textual critics of the eighteenth and nineteenth centuries, including Stephens, Lachmann, Tregelles, Tischendorf, Lightfoot, Ellicott, Alford, Weiss, the Bâle edition, Westcott and Hort, and the Revision Committee of London. In instances of disagreement among these sources, Weymouth judiciously selected readings that garnered majority support among editors. <br><br> Posthumously, the final publication of the text was overseen by his secretary, Reverend Ernest Hampden-Cook, in 1903. The translation was distinguished not only by its approach to language but also by its aim to provide a succinct and non-doctrinal commentary alongside the traditional texts. Subsequent editions and revisions, including those by James Alexander Robertson and others, have further cemented the Weymouth New Testament as a notable work in the realm of biblical translations, particularly for its efforts to bridge the gap between ancient scriptural texts and the linguistic understanding of a modern audience.', 'historic', NULL, '79', 'eng', '1902', 'scan', 'Richard Francis Weymouth, The Pilgrim Press, James Clarke & Co. LTD.', NULL, NULL, 'ENGWEY_DBS_HS/English-(1902)-Weymouth-New-Testament', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('237', 'Greek-1522-Erasmus-New-Testament', 'GRCERAS', 'Greek (1522) Erasmus New Testament', 'Καινή Διαθήκη του Έρασμου (1522)', 'The 1522 Erasmus New Testament is a testament to the enduring legacy of Erasmus of Rotterdam, a key Renaissance figure and the most distinguished scholar of his time in Europe. Erasmus, deeply committed to revitalizing the Church through what he called the "philosophy of Christ," focused his scholarly efforts on the Bible and early Church writings.<br><br>Erasmus worked for years on two major projects: compiling Greek texts and creating a refreshed Latin New Testament. Beginning in 1512, his work on the Latin New Testament involved gathering all available Vulgate manuscripts to produce a critical edition, along with refining the Latin language. He famously stated, "It is only fair that Paul should address the Romans in somewhat better Latin."<br><br>The inclusion of the Greek text alongside his Latin translation, though clearly intentional, had less clear motives initially. While some speculated that he aimed to produce a critical Greek text or to outpace the Complutensian Polyglot, no concrete evidence supports these theories. Erasmus himself wrote, "There remains the New Testament translated by me, with the Greek facing, and notes on it by me." He included the Greek text to enable readers to verify the accuracy of his Latin version, addressing frequent translation errors and textual corruptions caused by translator incompetence or scribe inattention.<br><br>By initially naming his work "Novum Instrumentum omne" ("All of the New Teaching") and later "Novum Testamentum omne" ("All of the New Testament"), Erasmus indicated his belief in the critical importance of a text where the Greek and Latin versions were directly comparable, thus forming the core of the Church''s New Testament tradition. His work greatly contributed to biblical studies and set a foundation for future scholarship and translations of biblical texts.', 'historic', NULL, '207', 'grc', '1522', 'scan', NULL, NULL, NULL, 'GRCERAS_DBS_HS/Greek-(1522)-Erasmus-New-Testament', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('238', 'English-1894-Great-Psalter-Bible-Psalms', 'ENGGRB', 'English (1894) Great Psalter Bible - Psalms', NULL, 'The 1894 edition of "The Psalter of the Great Bible of 1539" is a significant publication in the history of English biblical literature. This Psalter is a reprint of the one found in the Great Bible of 1539, which itself holds a prominent place in the annals of English Bible translations. Published by J. Murray in London, this edition serves as a testament to the enduring influence of the Great Bible on English literary and religious culture.<br><br>The Great Bible of 1539, commissioned during the reign of King Henry VIII, was the first authorized version of the Bible in English. Its Psalter, in particular, had a profound impact on the development of English religious prose and poetry. The 1894 reissue of this Psalter not only celebrates its historical and literary significance but also reflects the Victorian era''s deep interest in the roots of English Christianity and the development of the English language.<br><br>This edition, by bringing the Psalter of the Great Bible back into the public eye, provided scholars and lay readers alike with direct access to a pivotal work in the history of English religious texts. It showcases the linguistic beauty and theological depth of the Psalter, which had been a source of inspiration and devotion for centuries. The publication of this edition in 1894, thus, underscores the importance of historical biblical texts in understanding the evolution of English religious thought and expression.', 'historic', NULL, '38', 'eng', '1894', 'scan', 'John Murray', NULL, NULL, 'ENGGRB_DBS_HS/English-(1894)-Great-Psalter-Bible-Psalms', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('239', 'French-La-Sainte-Bible-Genesis-Portion', 'FRASYN', 'French La Sainte Bible Genesis Portion', 'La Sainte Bible - Genèse (Portion) ', 'LA SAINTE BIBLE. TRADUITE D''APRES LES TEXTES ORIGINAUX HEBREU ET GREC. Printed in Great Britain by Richard Clay.', 'historic', NULL, '303', 'fra', '1911', 'scan', NULL, NULL, 'The Long Now Foundation', 'FRASYN_DBS_HS/French-La-Sainte-Bible-Genesis-Portion', 'fra', 'stan1290', 'French', 'français', 'L', 'FR', '48', '2', '1', 'fr', '77200000', 'Andorra and France', 'Also in Algeria, Andorra, Austria, Belgium, Benin, Burkina Faso, Burundi, Cambodia, Cameroon, Canada, Central African Republic, Chad, Comoros, Congo, Côte d’Ivoire, Democratic Republic of the Congo, Djibouti, Equatorial Guinea, French Guiana, French Polynesia, Gabon, Guadeloupe, Guinea, Haiti, India, Israel, Italy, Lebanon, Libya, Luxembourg, Madagascar, Mali, Martinique, Mauritania, Mauritius, Mayotte, Monaco, Morocco, Mozambique, New Caledonia, Niger, Philippines, Puerto Rico, Réunion, Rwanda, Saint Pierre and Miquelon, Saudi Arabia, Senegal, Seychelles, South Africa, Switzerland, Togo, Tunisia, United Arab Emirates, United Kingdom, United States, U.S. Virgin Islands, Vanuatu, Wallis and Futuna.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('240', 'English-1911-Tercentenary-KJV-Bible-Vol-1-3', 'ENGKJV', 'English (1911) Tercentenary KJV Bible (Vol 1-3)', NULL, 'The 1911 Tercentenary KJV Bible, published by the New York Bible and Common Prayer Book Society, commemorates the 300th anniversary of the King James Bible. Reverend Henry Barker, a less-known but significant figure in the Church, authored the preface and provided an insightful historical account of the Bible''s manuscript origins. Barker delves into the formation of the biblical canon and the pioneering efforts of reformers like John Wyclif in the 14th century and William Tyndale in the 16th century to translate the Bible into vernacular languages, thus democratizing its content for the general populace.<br><br>Barker''s narrative not only traces the progression of the English Bible but also skillfully contextualizes it within the broader landscape of social and political upheaval that spurred the early translations. His comprehensive account sheds light on the multifaceted journey of the Bible in English, from its early manuscript forms to the celebrated King James Version. This volume serves as a testament to the enduring impact of the King James Bible, both as a religious text and a cornerstone of linguistic and cultural development. It offers readers a detailed exploration of the historical and theological significance of one of the most influential books in the English-speaking world, making it an invaluable resource for scholars, theologians, and anyone interested in the history of the Bible.', 'historic', NULL, '332', 'eng', '1911', 'scan', NULL, NULL, NULL, 'ENGKJV_DBS_HS/English-(1911)-Tercentenary-KJV-Bible-(Vol-1-3)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('241', 'English-1769-KJV-Oxford-Blayney-Edition', 'ENGKJV', 'English (1769) KJV Oxford Blayney Edition', NULL, 'In 1769, Dr. Benjamin Blayney completed a significant revision of the King James Bible, utilizing Dr. Samuel Johnson’s 1755 first edition of the Johnson Dictionary. This revision played a pivotal role in standardizing spelling, punctuation, and grammar in the English language, contributing to its establishment as a major language in communication, commerce, and education.<br><br>The 1769 Blayney edition of the King James Bible is essentially the first edition of the text as it is widely known and loved today. A notable feature of this edition is that it includes the 14 intertestamental books known as the "Apocrypha." King James had insisted on including these in his original 1611 edition, and they were present in nearly all Bibles up until the 1880s. Thus, the 1769 edition contains the full 80-book Bible (including the Apocrypha), unlike many King James Version Bibles printed from the 1880s onwards, which only contain the 66 canonical books.<br><br>Blayney''s revision involved extensive use of Dr. Johnson’s dictionary to bring uniform, modern spelling, punctuation, and grammar to the English language. Beyond correcting over 20,000 spelling and punctuation errors found in the 1611 King James Bible, such as updating "citie" to "city," Blayney also made more than 400 corrections to the wording.<br><br>Another significant improvement in the 1769 edition was the use of a Roman Typeface, which is more legible than the fancy, calligraphy-like ''Gothic Blackletter'' Typeface used in the 1611 edition. This change enhanced the readability of the King James Version, making it more accessible to a wider audience.', 'historic', NULL, '92', 'eng', '1769', 'scan', NULL, NULL, NULL, 'ENGKJV_DBS_HS', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('242', 'French-1899-La-Saitne-Bible-Louis-Segond', 'FRALSB', 'French (1899) La Saitne Bible (Louis Segond)', 'La Sainte Bible (1899, Louis Segond)', 'French (1899) La Saitne Bible (Louis Segond) Louis Segond (October 3, 1810 – June 18, 1885), was a Swiss theologian who translated the Bible into French from the original texts in Hebrew and Greek.<br><br>He was born in Plainpalais, near Geneva. After studying theology in Geneva, Strasbourg and Bonn, he was pastor of the Geneva National Church in Chêne-Bougeries, then from 1872, Professor of Old Testament in Geneva.<br><br>The translation of the Old Testament, commissioned by the Vénérable Compagnie des Pasteurs de Genève, was published in two volumes in 1871 (Meusel has 1874 as the publication date), followed by the New Testament, translated as a private venture, in 1880. The text was then reviewed by experts. The result is the 1910 revision that is now freely available on Internet.', 'historic', NULL, '108', 'fra', '1899', 'scan', 'Delessert', NULL, NULL, 'FRALSB_DBS_HS/French-(1899)-La-Saitne-Bible-(Louis-Segond)', 'fra', 'stan1290', 'French', 'français', 'L', 'FR', '48', '2', '1', 'fr', '77200000', 'Andorra and France', 'Also in Algeria, Andorra, Austria, Belgium, Benin, Burkina Faso, Burundi, Cambodia, Cameroon, Canada, Central African Republic, Chad, Comoros, Congo, Côte d’Ivoire, Democratic Republic of the Congo, Djibouti, Equatorial Guinea, French Guiana, French Polynesia, Gabon, Guadeloupe, Guinea, Haiti, India, Israel, Italy, Lebanon, Libya, Luxembourg, Madagascar, Mali, Martinique, Mauritania, Mauritius, Mayotte, Monaco, Morocco, Mozambique, New Caledonia, Niger, Philippines, Puerto Rico, Réunion, Rwanda, Saint Pierre and Miquelon, Saudi Arabia, Senegal, Seychelles, South Africa, Switzerland, Togo, Tunisia, United Arab Emirates, United Kingdom, United States, U.S. Virgin Islands, Vanuatu, Wallis and Futuna.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('243', 'English-1549-Matthew-Tyndale-Bible', 'ENGMTB', 'English (1549) Matthew-Tyndale Bible', NULL, 'The Matthew Bible, also known as Matthew''s Version, was first published in 1537 by John Rogers under the pseudonym "Thomas Matthew". It combined the New Testament of William Tyndale, and as much of the Old Testament as he had been able to translate before being captured and put to death. Myles Coverdale translated chiefly from German and Latin sources and completed the Old Testament and Biblical Apocrypha, except for the Prayer of Manasseh, which was Rogers'', into the Coverdale Bible. It is thus a vital link in the main sequence of English Bible translations.<br><br>This version of the Bible is significant for its role in consolidating the translations of Tyndale and Coverdale. Rogers, under his pseudonym, managed to bring together Tyndale''s translations of the New Testament and portions of the Old Testament with Coverdale''s additional translations from various sources. This amalgamation formed a more complete version of the Bible in English at a time when access to the scriptures in the vernacular was increasingly sought after. The Matthew Bible, therefore, stands as a crucial step in the evolution of Bible translations in English, bridging the gap between the early works of Tyndale and the more comprehensive translations that would follow in its wake.', 'historic', NULL, '554', 'eng', '1549', 'scan', 'GreatSite.com', NULL, NULL, 'ENGMTB_DBS_HS', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('244', 'English-1901-Scofield-Reference-Study-Bible', 'ENGKJV', 'English (1901) Scofield Reference Bible (Study)', NULL, 'The Scofield Reference Bible, meticulously edited and annotated by Cyrus I. Scofield, is a pivotal work in the realm of study Bibles, markedly influencing Christian theology in the early 20th century with its promotion of dispensationalism. This theological perspective interprets the Bible as segmented into distinct eras or ''dispensations'' in God''s approach to humanity, a concept that found widespread acceptance through this publication<br><br>The Bible, published by Oxford University Press and incorporating the full text of the traditional Protestant King James Version, debuted in 1909. It stood out not just as a collection of Biblical texts, but as an extensive tool for in-depth scriptural study. It includes detailed annotations, explanatory notes, cross-references, and introductions, offering readers an organized and profound understanding of Biblical passages<br><br>Scofield''s work underwent a revision in 1917, incorporating additional insights and clarifications. Beyond its significant role in propagating dispensationalism, the Scofield Reference Bible also set a precedent for study Bibles as instruments for scholarly research and personal devotion. Its systematic approach to scripture, with carefully chosen annotations and references, catered to both lay readers and scholars, facilitating the interpretation and comprehension of complex Biblical narratives and themes. Remaining a crucial contribution to Biblical literature, the Scofield Reference Bible continues to be an invaluable asset for students of the Bible worldwide.', 'historic', NULL, '63', 'eng', '1901', 'study', 'Oxfor University Press, Henry Frowde', NULL, NULL, 'ENGKJV_DBS_HS/English-(1901)-Scofield-Reference-Study-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('245', 'English-1777-The-Holy-Family-Bible-Study', 'ENGKJV', 'English (1777) The Holy Family Bible (Study)', NULL, 'The "Holy Family Bible," published in 1777 by Reverend Alexander Fortescu, D.D., Rector of Structor, is a comprehensive study Bible that includes the scriptures of the Old and New Testaments, as well as the Apocrypha. It features concise explanatory notes on all the difficult texts of Scripture, specifically addressing the objections of infidels and explaining obscure passages for easy understanding. The Bible is illustrated with copper plates, adding a visual dimension to the study. Printed and sold by J. Wilkes in Winchester by appointment of the proprietor, this Bible is in two volumes, providing a complete Bible experience. Reverend Fortescu, known for his works such as the "Devout Christian''s Family Instructor" and "Preparatory Devotions for the First Receiving the Lord''s Supper," aims to make the Bible accessible and comprehensible to a wide audience, enhancing religious education and countering skepticism. This edition is a valuable resource for deepening understanding and devotion among its readers.<br><br>Language: English<br>Notes & contents: 2 volumes in 1 (COMPLETE BIBLE)', 'historic', NULL, '1', 'eng', '1777', 'study', NULL, NULL, NULL, 'ENGKJV_DBS_HS/English-(1777)-The-Holy-Family-Bible-(Study)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('246', 'English-1861-Holy-Scriptures-of-the-Old-Covenant-Wellbeloved-OT-Portions', 'ENGWELL', 'English (1861) Holy Scriptures of the Old Covenant (Wellbeloved) - OT Portions', NULL, 'The 1861 volume of "The Holy Scriptures of the Old Covenant," part of a three-volume series, represents an ambitious project to revise the King James Version of the Old Testament. This collaborative effort, spearheaded by Charles Wellbeloved, George Vance Smith, and John Scott Porter, was published in London by Longman, Brown, Green, Longmans, and Roberts between 1859 and 1862.<br><br>The second volume, released in 1861, is a comprehensive collection that encompasses the books of Samuel, Kings, Chronicles, Ezra, Nehemiah, Esther, Job, and Psalms. This volume is notable for its meticulous revision work, which aimed to enhance the readability and accuracy of the biblical texts while remaining faithful to the essence of the original scriptures.<br><br>Charles Wellbeloved, a respected scholar, was responsible for revising significant portions of the Old Testament, including the Pentateuch, Joshua, Judges, Ruth, Job, Psalms, Proverbs, Ecclesiastes, and the Minor Prophets. George Vance Smith, renowned for his scholarly acumen, revised the books of Samuel, Ezra, Nehemiah, Esther, Isaiah, Jeremiah, and the Lamentations. John Scott Porter, another eminent figure in biblical studies, took charge of revising the books of Kings, Chronicles, Ezekiel, and Daniel.<br><br>This volume, along with its counterparts, reflects the intellectual rigor and collaborative spirit of its editors. Their work not only provided an updated version of the Old Testament but also contributed significantly to biblical scholarship, offering new perspectives and insights into the ancient texts. This series remains a valuable resource for scholars and students of the Bible, showcasing the evolving nature of biblical interpretation and translation.', 'historic', NULL, '87', 'eng', '1861', 'scan', 'Longman, Green, Longman, and Roberts', NULL, NULL, 'ENGWELL_DBS_HS/English-(1861)-Holy-Scriptures-of-the-Old-Covenant-(Wellbeloved)-OT-Portions', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('247', 'English-1400-Wycliffe-Purvey-Illuminated-Bible-NT', 'ENGWYC', 'English (1400) Wycliffe - Purvey Illuminated Bible - New Testament', NULL, 'John Purvey, a vital figure in the religious and literary landscape of medieval England, was closely associated with John Wycliffe, a key reformist and theologian. Purvey, who served as Wycliffe''s personal secretary, shared lodgings with him at the rectory, and worked as a curate in Lutterworth, played a crucial role in assisting Wycliffe with his extensive literary endeavors. His intimate knowledge of Wycliffe''s thoughts and teachings made him an invaluable contributor to the translation of the Bible into English, particularly in the revision of the Wycliffe Bible completed in 1388, often referred to as the Purvey revision.<br><br>Besides his contributions to biblical translation, Purvey was also recognized as a preacher. His sermons, known for their reformist tone, attracted the attention and ire of church authorities, leading to his imprisonment in 1390. During his incarceration, Purvey composed a commentary on the Apocalypse, primarily based on Wycliffe''s lectures. His fate took a dramatic turn in 1401; three days after the first martyr for Wycliffite beliefs was executed, Purvey recanted his views, an act that led to his release and the award of a vicarage. However, his conscience eventually prevailed, leading him to resign from his church position and fade into obscurity. Purvey reemerged in 1421, once again facing imprisonment for his preaching, after which no further records of his life are known. His contributions to religious thought and the English Bible translation, however, remain significant.', 'historic', NULL, '102', 'eng', '1400', 'illuminated', NULL, NULL, NULL, 'ENGWYC_DBS_HS', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('248', 'French-1839-Martin-La-Sainte-Bible-La-Sainte-Bible-qui-Contient-Le-Vieux-et-Le-Nouveau-Testament-David-Martin', 'FRAMAR', 'French (1839) Martin La Sainte Bible David Martin', 'La Sainte Bible (1839, David Martin)', 'French (1839) Martin La Sainte Bible David Martin The Bible of Diodati, Genesis 1644; of Desmarets, Amst. 1669; of Martin, Utr. (N.T.) 1696, (Bible) 1707, 2 volumes, fol.; of Roques, Basle, 1744; Osterwald, Amast. 1724; Neufch. 1744, are revisions of Olivetan''s text undertaken by individuals. Of these, Osterwald''s is the most thorough and may be viewed as occupying the place in the French Protestant Church of an authorized version, though Martin''s is the one most esteemed by the score orthodox of its members, while that of Desmarets is, sought by those who attach much value to fine paper and printing. A carefully revised edition of Osterwald''s Bible, with parallels by the Reverend W. Mackenzie, has been issued by the French Bible Society, Paris, 1861.', 'historic', NULL, '629', 'fra', '1839', 'scan', 'The American Bible Society', 'american-bible-society', NULL, 'FRAMAR_DBS_HS/French-(1839)-Martin-La-Sainte-Bible-(La-Sainte-Bible-qui-Contient-Le-Vieux-et-Le-Nouveau-Testament)-David-Martin', 'fra', 'stan1290', 'French', 'français', 'L', 'FR', '48', '2', '1', 'fr', '77200000', 'Andorra and France', 'Also in Algeria, Andorra, Austria, Belgium, Benin, Burkina Faso, Burundi, Cambodia, Cameroon, Canada, Central African Republic, Chad, Comoros, Congo, Côte d’Ivoire, Democratic Republic of the Congo, Djibouti, Equatorial Guinea, French Guiana, French Polynesia, Gabon, Guadeloupe, Guinea, Haiti, India, Israel, Italy, Lebanon, Libya, Luxembourg, Madagascar, Mali, Martinique, Mauritania, Mauritius, Mayotte, Monaco, Morocco, Mozambique, New Caledonia, Niger, Philippines, Puerto Rico, Réunion, Rwanda, Saint Pierre and Miquelon, Saudi Arabia, Senegal, Seychelles, South Africa, Switzerland, Togo, Tunisia, United Arab Emirates, United Kingdom, United States, U.S. Virgin Islands, Vanuatu, Wallis and Futuna.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('249', 'English-1804-Blackader-Study-Bible', NULL, NULL, NULL, 'The 1804 Blackader Study Bible, titled "The Chronological Bible, Containing the Old and New Testaments, According to the Authorized Version," represents a distinctive approach to biblical presentation and study. This Bible is set apart by its organization and additional features designed to enhance the reader''s understanding of the Scriptures.<br><br>In this edition, the biblical text is newly divided into paragraphs and sections, making it more reader-friendly and easier to navigate. A unique aspect of this Bible is the inclusion of dates and places of transactions, which provides a chronological context to the biblical events, aiding readers in better understanding the sequence and historical setting of the narratives.<br><br>Each book of the Bible is introduced with concise introductions, offering an overview and insights into the content and significance of the book. These introductions are valuable for readers, whether they are approaching the Bible for the first time or looking to deepen their understanding.<br><br>Additionally, the Blackader Study Bible includes notes that are illustrative of the chronology, history, and geography of the sacred Scriptures. These annotations are particularly useful for readers seeking to connect the biblical text with historical and geographical realities.<br><br>This Bible, with its focus on chronological arrangement and contextual understanding, is a significant tool for both personal study and teaching. It reflects an early 19th-century effort to make the Bible more accessible and comprehensible, particularly for readers interested in the historical and chronological aspects of the biblical narrative.', NULL, NULL, NULL, 'eng', NULL, NULL, NULL, NULL, NULL, NULL, 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, 'ENGKJV', 'English (1804) Blackader Study Bible', 'English-1804-Blackader-Study-Bible.jpg', '1804', 'study', 'Robert B. Blackader', NULL, 'ENGKJV_DBS_HS/English-(1804)-Blackader-Study-Bible', NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('250', 'English-1846-The-Illuminated-Bible-Study', 'ENGKJV', 'English (1846) The Illuminated Bible (Study)', NULL, 'English (1846) The Illuminated Bible: Harper’s Illuminated Bible, published in 1846, stands out for its unique and exquisite design. Each floriated initial in this Bible is distinct and intricately detailed, with the letter A alone featuring over 353 different engravings. The Bible contains 185 large illustrations, complemented by more than 1,400 wood engravings created by John Chapman, an artist whose work is also featured in the rotunda of the U.S. Capitol building in Washington, D.C. Due to its elaborate and costly production process, the publishers released it in fifty-four monthly installments. Today, only one hundred complete sets of this edition are known to exist.', 'historic', NULL, '372', 'eng', '1846', 'study', 'Harper & Brothers', NULL, NULL, 'ENGKJV_DBS_HS/English-(1846)-The-Illuminated-Bible-(Study)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('251', 'Hebrew-1485-Pentateuch-with-Haftarah-David-ZekhariahWDL-11365', 'HEBMASP', 'Hebrew (1485) Pentateuch with Haftarah (David Zekhariah)(WDL-11365)', 'עברית - חמשה חומשי תורה עם הפטרות (1485, דוד זכריה) (WDL-11365)', 'The Hebrew Pentateuch with Haftarot, created in 1485 in Sana''a, Yemen, is a significant manuscript that embodies the rich tradition of Jewish scripture and scholarship. This manuscript, crafted by David ben Benayah ben Saadiah ben Zekhariah, a member of a renowned family of Yemeni scribes, integrates the Pentateuch (the first five books of the Hebrew Bible) with Haftarot (readings from the Prophets, typically read in synagogues on Sabbaths and holidays following the Torah portion).<br><br>Notable for its comprehensive features, the manuscript includes full vocalization, accentuation, and Masorah annotation, ensuring accurate transmission and interpretation of the text. The Haftarot sections are accompanied by the Targum, providing an Aramaic translation of each verse. Additionally, preceding the Torah text, the manuscript contains two grammatical treatises common in Yemen, spanning 15 leaves in total. Written on paper in Yemenite square script, the text is organized in two columns per page, with 25 lines per column.<br><br>Owned by the Hibshoosh family since 1910, this manuscript is a testament to the historical continuity and preservation of Jewish scriptures. The Masorah annotations, compiled between the 7th and 10th centuries by Jewish scribes known as the Masoretes, highlight the manuscript''s significance as an authoritative source for the written and vocalized transmission of the Hebrew Bible.', 'historic', 'https://www.wdl.org/en/item/11365', '347', 'heb', '1485', 'scan', 'World Digital Library', NULL, 'World Digital Library', 'HEBMASP_DBS_HS/Hebrew-(1485)-Pentateuch-with-Haftarah-(David-Zekhariah)(WDL-11365)', 'heb', 'hebr1245', 'Hebrew', 'Israeli Hebrew', 'L', 'IL', '31.10565', '35.01788', '1', 'he', '5000000', NULL, 'Also in Australia, Canada, Germany, Palestinian West Bank and Gaza, Panama, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('252', 'English-1850-Wycliffe-Bible-Forshall-Madden-Edition', 'ENGW850', 'English (1850) Wycliffe Bible (Forshall Madden Edition)', NULL, 'English (1850) Wycliffe Bible (Forshall Madden Edition): The 1850 Forshall-Madden edition of the Wycliffe Bible is a significant achievement in biblical scholarship, meticulously compiled by Josiah Forshall and Frederic Madden. Forshall, an Oxford graduate and expert in mathematics and literae humaniores, joined the British Museum as an assistant librarian in 1824, rising to the position of department keeper within three years. His academic prowess was further acknowledged when he was elected a Fellow of the Royal Society in 1828.<br><br>The Forshall-Madden edition marked the first complete publication of the Wycliffe Bible in English, a monumental work that took two decades to complete. This translation, originally crafted in the late 14th century, was the first full Bible available in English. Its publication in 1850 opened a new chapter in the study of English religious texts and language.<br><br>Forshall''s contributions to biblical studies extended beyond this project. He published editions of the Gospels of St. Mark, St. Luke, and St. John, each meticulously arranged and annotated. His posthumous works on The Lord''s Prayer and the first twelve chapters of St. Matthew provided critical insights into these biblical texts. Through these works, Forshall not only enhanced the understanding of early English biblical translations but also established himself as a key figure in the field of biblical manuscripts and scholarship.', 'historic', NULL, '475', 'eng', '1850', 'reprint', 'The University Press', NULL, NULL, 'ENGW850_DBS_HS/English-(1850)-Wycliffe-Bible-(Forshall-Madden-Edition)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('253', 'English-1540-Great-Bible', 'ENGGRB', 'English (1540) Great Bible', NULL, 'The Great Bible of 1539, known as the first authorized edition of the Bible in English, was a significant milestone in religious history, sanctioned by King Henry VIII for use in Church of England services. This authorization marked a crucial shift in religious practice, making scripture accessible in the vernacular to English congregants. Myles Coverdale, under the commission of Thomas Cromwell, King Henry VIII''s Secretary and Vicar General, was responsible for its preparation.<br><br>In 1538, Cromwell issued a directive to the clergy to provide a "one book of the Bible of the largest volume in English" in churches for parishioners to read. This Bible incorporated much from William Tyndale''s translation, revising parts deemed objectionable. Coverdale completed the Tyndale Bible by translating the remaining books of the Old Testament and Apocrypha from the Latin Vulgate and German translations, as Tyndale''s work was incomplete and not entirely derived from the original Greek, Hebrew, and Aramaic texts.<br><br>The Great Bible is known by several names: the Cromwell Bible, in honor of Thomas Cromwell''s role in its publication; Whitchurch''s Bible, after its first English printer; and the Chained Bible, as it was often chained in churches to prevent theft. It is sometimes inaccurately referred to as Cranmer''s Bible because, although Thomas Cranmer was not responsible for the translation, his preface appeared in the second edition. The Great Bible''s title page read: "The Byble in Englyſhe, that is to ſaye the content of all the holy ſcrypture, bothe of yͤ olde and newe teſtament, truly tranſlated after the veryte of the Hebrue and Greke textes, by yͤ Dylygent ſtudye of dyuerſe excellent learned men, expert in the forſayde tonges."', 'historic', 'https://en.wikipedia.org/wiki/Great_Bible', '375', 'eng', '1557', 'scan', NULL, NULL, NULL, 'ENGGRB_DBS_HS/English-(1540)-Great-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('254', 'English-1833-Webster''s-Bible', 'ENGWBR', 'English (1833) Webster''s Bible', NULL, 'English (1833) Webster''s Bible Noah Webster''s 1833 limited revision of the King James Version, more commonly called the Webster Bible, focused mainly on replacing archaic words and making simple grammatical changes. For example, "why" was used instead of "wherefore", "its" instead of "his" for nonliving things, and "male child" instead of "manchild". Webster introduced euphemisms, changing terms like "whore" to "lewd woman". He also modified the spelling to reflect American usage, differentiating it from British English. Overall, the changes were minimal, making the Webster Bible almost indistinguishable from the King James Version. It is sometimes referred to as the Common Version, not to be confused with the Common Bible of 1973, which is an ecumenical edition of the Revised Standard Version.', 'historic', NULL, '206', 'eng', '1833', 'scan', NULL, NULL, NULL, 'ENGWBR_DBS_HS/English-(1833)-Webster''s-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('255', 'English-1852-Jewish-School-Family-Bible-Vol.-1-4-OT', 'ENGJSF', 'English (1852) Jewish School Family Bible Vol. 1-4 - OT', NULL, 'English (1852) Jewish School and Family Bible Vol. 1-4 - OT: Abraham Benisch''s Jewish School and Family Bible, published between 1851 and 1856, represents a significant milestone in Jewish biblical scholarship. As an independent Jewish translation of the Hebrew Bible into English, Benisch''s work offered the modern reader an accessible and culturally resonant rendition of the Old Testament. This translation was particularly notable for its intent to provide the Jewish community with an English version of the Scriptures that was both faithful to the original Hebrew texts and cognizant of contemporary linguistic nuances.<br><br>Abraham Benisch (1811–1878), a renowned scholar in Hebrew literature, embarked on this ambitious project to bridge the gap between ancient biblical texts and the modern English-speaking Jewish community. His dedication to Jewish education and culture was also evident in his two-decade tenure as the editor of the Jewish Chronicle. Benisch''s translation not only facilitated a deeper understanding of the Scriptures among English-speaking Jews but also contributed significantly to the broader discourse on Jewish theology and biblical studies. His Jewish School and Family Bible remains a testament to his scholarly rigor and his commitment to making Jewish teachings more accessible.', 'historic', NULL, '324', 'eng', '1852', 'study', 'James Darling', NULL, NULL, 'ENGJSF_DBS_HS/English-(1852)-Jewish-School-Family-Bible-Vol.-1-4-OT', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('256', 'English-1560-Geneva-Bible', 'ENGGNV', 'English (1560) Geneva Bible', NULL, 'The Geneva Bible is one of the most historically significant translations of the Bible into English, preceding the King James Version by 51 years. It was the primary Bible of 16th-century English Protestantism and was used by William Shakespeare, Oliver Cromwell, John Knox, John Donne, and John Bunyan, author of The Pilgrim''s Progress (1678). It was one of the Bibles taken to America on the Mayflower (Pilgrim Hall Museum has collected several Bibles of Mayflower passengers). The Geneva Bible was used by many English Dissenters, and it was still respected by Oliver Cromwell''s soldiers at the time of the English Civil War, in the booklet "Cromwell''s Soldiers'' Pocket Bible".<br><br>This version of the Bible is significant because, for the very first time, a mechanically printed, mass-produced Bible was made available directly to the general public which came with a variety of scriptural study guides and aids (collectively called an apparatus), which included verse citations that allow the reader to cross-reference one verse with numerous relevant verses in the rest of the Bible, introductions to each book of the Bible that acted to summarize all of the material that each book would cover, maps, tables, woodcut illustrations, and indices.<br><br>Because the language of the Geneva Bible was more forceful and vigorous, most readers strongly preferred this version to the Great Bible. In the words of Cleland Boyd McAfee, "it drove the Great Bible off the field by the sheer power of excellence".<br><br>The Geneva Bible followed the Great Bible of 1539, the first authorized Bible in English, which was the authorized Bible of the Church of England.<br><br>During the reign of Queen Mary I of England (1553–58), a number of Protestant scholars fled from England to Geneva, Switzerland, which was then ruled as a republic in which John Calvin and, later, Theodore Beza, provided the primary spiritual and theological leadership. Among these scholars was William Whittingham, who supervised the translation now known as the Geneva Bible, in collaboration with Myles Coverdale, Christopher Goodman, Anthony Gilby, Thomas Sampson, and William Cole; several of these groups later became prominent figures in the Vestments controversy. Whittingham was directly responsible for the New Testament, which was complete and published in 1557, while Gilby oversaw the Old Testament.<br><br>The first full edition of this Bible, with a further revised New Testament, appeared in 1560, but it was not printed in England until 1575 (New Testament) and 1576 (complete Bible). Over 150 editions were issued; the last probably in 1644. The first Bible printed in Scotland was the Geneva Bible, which was first issued in 1579. In fact, the involvement of Knox and Calvin in the creation of the Geneva Bible made it especially appealing in Scotland, where a law was passed in 1579 requiring every household of sufficient means to buy a copy.<br><br>Some editions from 1576 onwards included Laurence Tomson''s revisions of the New Testament. Some editions from 1599 onwards used a new "Junius" version of the Book of Revelation, in which the notes were translated from a new Latin commentary by Franciscus Junius.<br><br>The annotations which are an important part of the Geneva Bible were Calvinist and Puritan in character, and as such, they were disliked by the ruling pro-government Anglicans of the Church of England, as well as King James I, who commissioned the "Authorized Version", or King James Bible, in order to replace it. The Geneva Bible also motivated the earlier production of the Bishops'' Bible under Elizabeth I, for the same reason, and the later Rheims-Douai edition by the Catholic community. The Geneva Bible remained popular among Puritans and remained in widespread use until after the English Civil War. The Geneva notes were surprisingly included in a few editions of the King James version, even as late as 1715. (Wikipedia)', 'historic', 'https://en.wikipedia.org/wiki/Geneva_Bible', '259', 'eng', '1568', 'reprint', NULL, NULL, NULL, 'ENGGNV_DBS_HS/English-(1560)-Geneva-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('257', 'French-1771-Ostervald-Old-Testament-La-Sainte-Bible', 'FRAOST', 'French (1771) Ostervald Old Testament', 'Ancien Testament (1771, Ostervald)', 'French (1771) Ostervald Old Testament The 1771 Ostervald Bible, a Protestant edition, includes the Old and New Testaments, revised and corrected on the original text by pastors and professors of the Church of Geneva. It features chapter arguments and reflections authored by J. F. Ostervald, Pastor of the Church of Neuchâtel. This edition, marked as the third revised and corrected version, was published in Bienne by the Heilmann Library, and in Neuchâtel by S. Fauche & Company.<br><br>Ostervald''s work is noted for its clarity and insightful commentary, making it a valuable resource for both religious studies and personal edification. Its publication reflects the ongoing efforts of Protestant scholars to provide accessible and accurate translations of biblical texts during this period. The Ostervald Bible holds significance in the history of French Protestantism and biblical scholarship.', 'historic', NULL, '133', 'fra', '1771', 'scan', NULL, NULL, NULL, 'FRAOST_DBS_HS/French-(1771)-Ostervald-Old-Testament-(La-Sainte-Bible)', 'fra', 'stan1290', 'French', 'français', 'L', 'FR', '48', '2', '1', 'fr', '77200000', 'Andorra and France', 'Also in Algeria, Andorra, Austria, Belgium, Benin, Burkina Faso, Burundi, Cambodia, Cameroon, Canada, Central African Republic, Chad, Comoros, Congo, Côte d’Ivoire, Democratic Republic of the Congo, Djibouti, Equatorial Guinea, French Guiana, French Polynesia, Gabon, Guadeloupe, Guinea, Haiti, India, Israel, Italy, Lebanon, Libya, Luxembourg, Madagascar, Mali, Martinique, Mauritania, Mauritius, Mayotte, Monaco, Morocco, Mozambique, New Caledonia, Niger, Philippines, Puerto Rico, Réunion, Rwanda, Saint Pierre and Miquelon, Saudi Arabia, Senegal, Seychelles, South Africa, Switzerland, Togo, Tunisia, United Arab Emirates, United Kingdom, United States, U.S. Virgin Islands, Vanuatu, Wallis and Futuna.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('258', 'Assyrian-John-book', 'AIIWBT', 'Assyrian - John (Book)', 'ܐܬܘܪܝܐ - ܝܘܚܢܢ (ܟܬܒܐ)', 'An Assyrian translation of the book of John. Neo-Assurian, or Suret, is a language spoken in Iraq, Iran, and Syria. ', 'modern', NULL, '1', 'aii', '1905', 'book', NULL, NULL, NULL, 'AIIAPNT_DBS_HS/Assyrian-John-(book)', 'aii', 'assy1241', 'Assyrian Neo-Aramaic', 'Sūreṯ', 'L', 'IQ', '36.75', '43', '6b', NULL, '626000', 'Iraq', 'Northern Iraq, Baghdad, Basrah, Karkuk, Arbil. Also in Armenia, Australia, Austria, Azerbaijan, Belgium, Brazil, Canada, Cyprus, France, Georgia, Germany, Greece, Iran, Italy, Lebanon, Netherlands, New Zealand, Russian Federation (Europe), Sweden, Switzerland, Syria, Turkey (Asia), United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('259', 'English-1767-Liberal-Translation-of-the-New-Testament-Vol-1-2', 'ENGLIB', 'English (1767) Liberal Translation of the New Testament (Vol 1-2)', NULL, 'Edward Harwood''s "A Liberal Translation of the New Testament," published in 1768, is a distinctive work in the history of biblical translations. Harwood, a classical scholar, aimed to translate the New Testament with the same freedom, impartiality, and elegance applied to translations of Greek classics. His objective, as stated in the preface, was to express the ideas and doctrines of the Apostles with clarity and appropriateness, as if they had written in contemporary English.<br><br>Harwood''s paraphrase is characterized by the verbose and ornate style of eighteenth-century English prose. However, it has often been criticized for its poor taste and inappropriate treatment of Scripture. Shortly after its publication, James Boswell described it as a “ridiculous work.” Other critics have labeled it as “turgid,” “absurd,” and even worse. Richard C. Trench, discussing various English versions, referred to Harwood''s translation as folly, bordering on blasphemy, and declined to provide examples due to their nature. J. Isaacs noted that Harwood’s version is one of the most discussed and insulted translations of the eighteenth century.<br><br>An often-cited example of Harwood''s unique approach is his rendering of the Lord''s Prayer in Matthew 6, which exemplifies his liberal and stylistically distinct translation method. Despite its notoriety and the criticisms it attracted, Harwood''s translation remains a notable part of the history of English New Testament translations, reflecting the diverse approaches to biblical interpretation and translation during the eighteenth century.', 'historic', 'http://www.bible-researcher.com/harwood.html', '51', 'eng', '1767', 'scan', NULL, NULL, NULL, 'ENGLIB_DBS_HS/English-(1767)-Liberal-Translation-of-the-New-Testament-(Vol-1-2)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('260', 'English-1594-Geneva-Breeches-Bible', 'ENGGNV', 'English (1594) Geneva Breeches Bible', NULL, 'The Geneva Bible, first printed in 1560, is one of the most historically significant translations of the Bible into English, predating the King James Version by 51 years. It was the primary Bible for English Protestantism in the 16th century and was used by William Shakespeare, Oliver Cromwell, John Knox, John Donne, and John Bunyan, author of "The Pilgrim''s Progress" (1678). This Bible was also among those taken to America on the Mayflower, as evidenced by collections at the Pilgrim Hall Museum.<br><br>This version was groundbreaking as it was the first mechanically printed, mass-produced Bible available directly to the general public. It included a comprehensive apparatus for scriptural study, such as verse citations for cross-referencing, book introductions, maps, tables, woodcut illustrations, and indices. Its forceful and vigorous language made it more popular than the Great Bible, leading Cleland Boyd McAfee to state that it "drove the Great Bible off the field by the sheer power of excellence."<br><br>Created during Queen Mary I''s reign (1553–58), the Geneva Bible was the work of Protestant scholars who fled England for Geneva, Switzerland. There, under the spiritual leadership of John Calvin and Theodore Beza, William Whittingham supervised the Geneva Bible''s translation, collaborating with Myles Coverdale and others. Whittingham was responsible for the New Testament (published in 1557), while Gilby oversaw the Old Testament.<br><br>The first full edition of the Geneva Bible appeared in 1560, but it wasn''t printed in England until 1575 (New Testament) and 1576 (complete Bible). Over 150 editions were issued, the last probably in 1644. The first Bible printed in Scotland was the Geneva Bible, issued in 1579. Later editions included Laurence Tomson''s revisions of the New Testament and a new "Junius" version of the Book of Revelation.<br><br>The Geneva Bible''s Calvinist and Puritan annotations were disliked by the Church of England and King James I, who commissioned the King James Bible as a replacement. The Geneva Bible influenced the production of the Bishops'' Bible and the later Rheims-Douai edition by the Catholic community. It remained popular among Puritans and in use until after the English Civil War, with its notes even appearing in some editions of the King James version as late as 1715.', 'historic', NULL, '185', 'eng', '1594', 'scan', 'GreatSite.com', NULL, NULL, 'ENGGNV_DBS_HS', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('261', 'Greek-Modern-1991-New-Testament-book', 'ELLTGV', 'Greek Modern (1991) New Testament (Book)', 'Ελληνικά (1991) Καινή Διαθήκη (Βιβλίο)', 'Modern Greek, generally referred to by speakers simply as Greek (Ελληνικά, Elliniká), refers collectively to the dialects of the Greek language spoken in the modern era, including the official standardized form of the languages sometimes referred to as Standard Modern Greek. The end of the Medieval Greek period and the beginning of Modern Greek is often symbolically assigned to the fall of the Byzantine Empire in 1453, even though that date marks no clear linguistic boundary and many characteristic features of the modern language arose centuries earlier, beginning around the fourth century AD.', 'modern', NULL, '6', 'ell', '1991', 'book', 'G. F. Bunce', NULL, NULL, 'ELLTGV_DBS_HS/Greek-Modern-(1991)-New-Testament-(book)', 'ell', 'mode1248', 'Modern Greek (1453-)', 'Νέα Ελληνικά', 'L', 'GR', '42.322386', '24.869938', '1', 'el', '13500000', 'Cyprus', 'Widespread, especially in Greek Macedonia. Also in Albania, Armenia, Australia, Austria, Bahamas, Bulgaria, Canada, Congo, Cyprus, Czech Republic, Democratic Republic of the Congo, Djibouti, Egypt, France, Georgia, Germany, Hungary, Italy, Jordan, Kazakhstan, Libya, Macedonia, Malawi, Mozambique, Paraguay, Poland, Romania, Russian Federation (Europe), Sierra Leone, South Africa, Sweden, Tunisia, Turkey (Europe), Ukraine, United Arab Emirates, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('262', 'Greek-1857-Tregelless-New-Testament-Vol-1-6', 'GRCTREG', 'Greek (1857) Tregelless New Testament (Vol 1-6)', 'Καινή Διαθήκη του Tregelles (1857, Τόμος 1-6)', 'The 1857 "Tregelles New Testament" is a significant scholarly work by Samuel Prideaux Tregelles, an esteemed English biblical scholar, lexicographer, Christian Hebraist, textual critic, and theologian. Born on January 30, 1813, Tregelles was dedicated to creating a new version of the Greek text of the New Testament, grounded in ancient manuscripts and the citations of early Church Fathers. His work was in many ways parallel to that of the German philologist and textual critic, Karl Lachmann.<br><br>Tregelles first gained recognition with his 1844 publication "Book of Revelation in Greek Edited from Ancient Authorities," which announced his intention to prepare a new Greek New Testament. In 1845, he embarked on a journey to collate ancient manuscripts, starting in Rome with the Vatican''s codex. Despite being restricted from copying the manuscript, he noted significant readings. His journey took him to Florence, Modena, Venice, Munich, Basel, and then back to England, where he continued his work at the British Museum. Tregelles also visited Paris, Hamburg, Berlin (meeting Lachmann), Leipzig (collaborating with Constantin von Tischendorf), Dresden, Wolfenbüttel, and Utrecht.<br><br>His extensive travels and meticulous collation of manuscripts resulted in a Greek New Testament that challenged the Textus Receptus and offered a text based on more ancient and authoritative sources. Tregelles'' contribution to biblical scholarship, particularly in the realm of textual criticism, is highly regarded and continues to influence the field of New Testament studies.', 'historic', NULL, '76', 'grc', '1857', 'scan', NULL, NULL, 'Google', 'GRCTREG_DBS_HS/Greek-(1857)-Tregelless-New-Testament-(Vol-1-6)', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('263', 'Aramaic-1885-Old-Testament-Talgum-with-Commentaries-vol-6-9-Old-Testament', 'AII1885', 'Aramaic (1885) Old Testament (Talgum) with Commentaries vol 1-9 - Old Testament', 'ܐܪܡܝܐ (1885) ܩܘܕܫܐ ܟܬܒܐ (ܬܠܓܘܡ) ܥܡ ܦܘܫܩܐ ܣܦܪܐ 1-9 - ܩܘܕܫܐ ܟܬܒܐ', 'In the Syriac (Eastern Aramaic) language the Peshitta (Syriac: "common version") is the standard version of the Christian Bible. It continues to serve as the Bible of churches in the Syriac tradition (Church of the East, Chaldean Catholic, and Syriac Orthodox) to this day. The history of Christian Translations of the Bible into Syriac language includes the Diatessaron, the Old Syriac versions (Curetonian and Sinaitic), the Peshitto, the Philoxenian version, the Harklean Version and the recent United Bible Societies'' modern Aramaic New Testament.<br><br>About AD 500 a Christian Palestinian Aramaic version was made. It contains 2 Peter, 2-3 John, Jude, and Apocalypse. It is representative of the Caesarean text type and is a unique translation different from any other which was made into Syriac. These are among the manuscripts used by John Gwynn in 1893 to complete his edition of the Catholic Epistles. In 1892 Agnes Smith Lewis discovered the manuscript of the Palestinian Syriac lectionary in the library of Saint Catherine''s Monastery on Mount Sinai. It is designated by Syr.<br><br>The first revision of the New Testament from the Syriac into Turoyo language (Western Aramaic in Syriac and Latin script) was made by Malphono Yuhanun Üzel (Bar Shabo), Benjamin Bar Shabo, and Yahkup Bilgic in 2009 with notes from Harclean and Philoxenios. This commission "Sihto du Kthovo Qadisho Suryoyo" works especially to preach the Gospel in Aramaic all over the world.', 'historic', NULL, '125', 'aii', '1885', 'study', NULL, NULL, NULL, 'AII1885_DBS_HS/Aramaic-(1885)-Old-Testament-(Talgum)-with-Commentaries-vol-1-9-Old-Testmant', 'aii', 'assy1241', 'Assyrian Neo-Aramaic', 'Sūreṯ', 'L', 'IQ', '36.75', '43', '6b', NULL, '626000', 'Iraq', 'Northern Iraq, Baghdad, Basrah, Karkuk, Arbil. Also in Armenia, Australia, Austria, Azerbaijan, Belgium, Brazil, Canada, Cyprus, France, Georgia, Germany, Greece, Iran, Italy, Lebanon, Netherlands, New Zealand, Russian Federation (Europe), Sweden, Switzerland, Syria, Turkey (Asia), United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('264', 'Greek-1930-Robertson-Expositers-New-Testament-Vol-1-5', 'GRCRENT', 'Greek (1930) Robertson Expositers New Testament (Vol 1-5)', 'Expositors Καινή Διαθήκη του Robertson (1930, Τόμος 1-5)', 'The "Expositor’s Greek Testament," published around 1930 and edited by William Robertson Nicoll, is a monumental work in the field of New Testament studies. Spanning five volumes, this commentary stands out as one of the most significant contributions to the study of the Greek text of the New Testament from the 19th century.<br><br>This comprehensive reference work was the result of the collective scholarship of twenty contributors, each bringing their expertise to the analysis of the Greek New Testament. The Expositor’s Greek Testament is particularly noted for its detailed textual, literary, and grammatical commentary on nearly every Greek word across the entire New Testament, making it an invaluable resource for in-depth biblical study and exegesis.<br><br>Each book of the New Testament is introduced with extensive overviews, providing insights into their literary and interpretative history. These introductions also delve into the historical context of each book, offering readers a deeper understanding of the background and circumstances surrounding their composition. Additionally, the work includes an extensive bibliography, further supporting academic research and study.<br><br>The Expositor’s Greek Testament, under Nicoll''s editorship, has been a vital tool for scholars, theologians, and students, offering a rich and comprehensive exploration of the Greek New Testament. Its scholarly rigor and depth make it a timeless resource in the field of biblical studies.', 'historic', NULL, '242', 'grc', '1930', 'study', 'George H. Doran Company', NULL, 'Microsoft', 'GRCRENT_DBS_HS/Greek-(1930)-Robertson-Expositers-New-Testament-(Vol-1-5)', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('265', 'English-1550-John-Cheke-Matthew-1843-Reprint', 'ENGCHE', 'English (1550) John Cheke Matthew (1843 Reprint)', NULL, 'Sir John Cheke (Cheek) (16 June 1514 – 13 September 1557) was a distinguished English classical scholar and statesman, renowned for being the first Regius Professor of Greek at the University of Cambridge. His significant contributions to the revival of Greek learning in England marked him as one of the leading educators of his time. Cheke served as tutor to Prince Edward, who would later become King Edward VI, and occasionally to Princess Elizabeth. With strong Reformist leanings in religious matters, his public career included roles as provost of King''s College, Cambridge, Member of Parliament, and, briefly, Secretary of State during the reign of King Edward.<br><br>However, the ascent of Queen Mary in 1553 dramatically altered his trajectory. His Reformist sympathies at odds with the new regime, Cheke chose voluntary exile abroad, initially with royal permission. His situation worsened when he overstayed this licence, leading to his capture and imprisonment in 1556. Faced with the threat of execution, possibly by burning, Cheke made a forced public recantation, aligning himself with the Church of Rome. This decision, born from fear, haunted him until his death shortly thereafter, as he grappled with remorse for abandoning his true beliefs. Despite this troubled end, Cheke''s character, teachings, and reputation continued to be held in high regard and admiration.', 'historic', NULL, '2', 'eng', '1550', 'scan', NULL, NULL, NULL, 'ENGCHE_DBS_HS/English-(1550)-John-Cheke-Matthew-(1843-Reprint)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('266', 'English-1863-Holy-Gospels-Brameld-Gospels', 'ENGBRAM', 'English (1863) Holy Gospels (Brameld) Gospels', NULL, 'The "Brameld Gospels: The Holy Gospels" represents a noteworthy effort in biblical translation and textual criticism, focusing on the four Gospels of the New Testament. Published in 1863, this translation distinctively aims to purify the text by expunging spurious passages, bracketing doubtful sections, and thoroughly revising the content based on the foundational texts of several leading biblical scholars of the 19th century.<br><br>This translation takes its cues from the critical works of renowned textual critics like Johann Jakob Griesbach, Karl Lachmann, Constantin von Tischendorf, Henry Alford, and Samuel Prideaux Tregelles. Each of these scholars made significant contributions to the field of New Testament textual criticism, and their collective works laid the groundwork for modern biblical scholarship. Griesbach, for instance, is known for his pioneering work in categorizing manuscript evidence, while Lachmann''s methodological approach to text criticism sought to reconstruct the earliest attainable text. Tischendorf is famed for discovering the Codex Sinaiticus, one of the oldest complete manuscripts of the Bible.<br><br>The Brameld Gospels thus stand as a culmination of these critical efforts, seeking to present the Gospels in their most authentic and historically accurate form. By expunging and bracketing certain passages, the translation endeavors to offer a clearer view of the original texts, making it a valuable resource for scholars and readers interested in a critical understanding of the New Testament. This approach reflects a growing 19th-century emphasis on historical-critical methods in biblical studies, marking a significant shift in how the scriptures were read and understood.', 'historic', NULL, '36', 'eng', '1863', 'scan', 'Longman, Green, Longman, Roberts and Green', NULL, NULL, 'ENGBRAM_DBS_HS/English-(1863)-Holy-Gospels-(Brameld)-Gospels', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('267', 'English-1583-Geneva-Noblest-Bible', 'ENGGNV', 'English (1583) Geneva Noblest Bible', NULL, 'The Geneva Bible, first printed in 1560, is a landmark in the history of English Bible translations, preceding the King James Version by 51 years. It became the primary Bible for English Protestantism in the 16th century and was widely used by influential figures like William Shakespeare, Oliver Cromwell, John Knox, John Donne, and John Bunyan, the author of "The Pilgrim''s Progress" (1678). It also holds the distinction of being one of the Bibles taken to America on the Mayflower, as evidenced by collections at the Pilgrim Hall Museum.<br><br>This Bible was groundbreaking as it was the first mechanically printed, mass-produced Bible available directly to the general public. It included a comprehensive set of study aids such as verse citations for cross-referencing, introductions summarizing each book, maps, tables, woodcut illustrations, and indices. Its vigorous and forceful language made it more popular than the Great Bible, leading Cleland Boyd McAfee to remark that it "drove the Great Bible off the field by the sheer power of excellence."<br><br>Created during Queen Mary I''s reign (1553–58), the Geneva Bible was the work of Protestant scholars who fled to Geneva, Switzerland. This group included William Whittingham (responsible for the New Testament), Myles Coverdale, and others, with John Calvin and Theodore Beza providing spiritual leadership in Geneva. The first full edition, with a revised New Testament, appeared in 1560, but it wasn''t printed in England until 1575 (New Testament) and 1576 (complete Bible). Over 150 editions were issued, the last probably in 1644.<br><br>The Geneva Bible was particularly influential in Scotland, where a 1579 law required every capable household to own a copy. Its annotations, reflecting Calvinist and Puritan views, were disliked by the Church of England and King James I, leading to the commissioning of the King James Bible. Despite this, the Geneva Bible remained popular among Puritans and was widely used until after the English Civil War. Some of its notes even found their way into editions of the King James version as late as 1715.', 'historic', NULL, '458', 'eng', '1583', 'scan', 'GreatSite.com', NULL, NULL, 'ENGGNV_DBS_HS', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('268', 'Hebrew-1901-New-Testament', 'HEBN01', 'Hebrew (1901) New Testament', 'עברית - הברית החדשה (1901)', 'The 1901 Hebrew New Testament is a notable edition within the broader context of the Hebrew Bible or Tanakh, which is the canonical collection of Hebrew scriptures in Judaism. This collection comprises the Torah (Law), Nevi''im (Prophets), and Ketuvim (Writings). Over the centuries, different branches of Judaism and Samaritanism have maintained various versions of this canon, reflecting the diverse traditions and interpretations within these communities.<br><br>Significant versions include the 3rd-century Septuagint text used by Second-Temple Judaism, the Syriac language Peshitta, the Samaritan Pentateuch, the Dead Sea Scrolls, and the medieval Masoretic text from the 10th century, developed by the Masoretes and used in modern Rabbinic Judaism. It''s important to note that while the terms "Hebrew Bible" or "Hebrew Canon" are often associated with the Masoretic text, this is just one of several texts considered authoritative in different Jewish traditions over time. The Masoretic text is primarily in Biblical Hebrew, with some sections in Biblical Aramaic, notably in the books of Daniel and Ezra, and in Jeremiah 10:11. The 1901 Hebrew New Testament reflects this rich textual tradition and the ongoing evolution of biblical scholarship.', 'historic', NULL, '810', 'heb', '1901', 'scan', NULL, NULL, NULL, 'HEBN01_DBS_HS/Hebrew-(1901)-New-Testament', 'heb', 'hebr1245', 'Hebrew', 'Israeli Hebrew', 'L', 'IL', '31.10565', '35.01788', '1', 'he', '5000000', NULL, 'Also in Australia, Canada, Germany, Palestinian West Bank and Gaza, Panama, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('269', 'English-1879-Wycliffe-Purvey-New-Testament', 'ENGWYC', 'English (1879) Wycliffe (Purvey) New Testament', NULL, 'The Wycliffe Bible, attributed to the visionary John Wycliffe and his associates, represents a pivotal moment in the history of Bible translations. Emerging between approximately 1382 and 1395, these translations into Middle English catalyzed the Lollard movement, a significant precursor to the Reformation, challenging numerous doctrines of the Roman Catholic Church.<br><br>Long credited to Wycliffe himself, modern scholarship now recognizes the Wycliffe Bible as a collaborative effort, possibly involving figures such as Nicholas of Hereford, John Purvey, and John Trevisa. This series of translations was more than a mere linguistic endeavor; it was an act of religious and social defiance, bringing the scriptures into the vernacular at a time when Latin dominated religious texts. The impact of these translations was profound, democratizing religious knowledge and laying the groundwork for subsequent reformist movements.<br><br>Contrary to earlier beliefs that Wycliffe single-handedly produced these texts, the current understanding acknowledges a group effort, reflecting the collective yearning for accessible religious texts. The Wycliffe Bible thus stands not just as a historical artifact but as a testament to the enduring power of collaborative intellectual and spiritual inquiry, significantly influencing the trajectory of Christian thought and practice in the Western world.', 'historic', NULL, '63', 'eng', '1879', 'scan', 'Wycliffe and Purvey', 'wycliffe-bible-translators-inc', NULL, 'ENGWYC_DBS_HS/English-(1879)-Wycliffe-(Purvey)-New-Testament', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('270', 'Greek-1844-Catenae-Graecorum-Patrum-Novum-Testamentum-Cramer-Vol-1-8', 'GRCCRAM', 'Greek (1844) Catenae Graecorum Patrum - Novum Testamentum (Cramer) Vol 1-8', 'Catenae Graecorum Patrum - Novum Testamentum (1844, Cramer, Τόμος 1-8)', 'John Antony Cramer, an English classical scholar and geographer born in Switzerland in 1793, made a notable contribution to biblical studies with his work "Catenae Graecorum Patrum in Novum Testamentum," published between 1838 and 1844. Educated at Westminster and Christ Church, Oxford, Cramer spent a significant part of his life in Oxford, where he held several prestigious positions. He was a public orator, principal of New Inn Hall from 1831 to 1847, and Regius Professor of Modern History from 1842 until his death in 1848.<br><br>Cramer''s "Catenae Graecorum Patrum in Novum Testamentum" is a collection of commentaries on the New Testament by Greek Fathers of the Church. This eight-volume work is significant for its comprehensive compilation of patristic interpretations and thoughts on the New Testament scriptures. Catenae, meaning "chains," refers to the method of linking various commentaries and expositions by early Church Fathers on biblical texts, providing a continuous and cohesive exegetical tradition.<br><br>Cramer’s contribution is particularly valuable for scholars studying the history of biblical interpretation and the early Church''s theological perspectives. His compilation not only preserves the insights of early Christian thinkers but also provides a critical resource for understanding the development of Christian theology and exegesis. His other accomplishments, including the construction of the Cramer Building at New Inn Hall (later part of St Peter''s College) and his tenure as the dean of Carlisle Cathedral, further attest to his varied and impactful career.', 'historic', NULL, '137', 'grc', '1844', 'scan', 'J. A. Cramer, S. T. P.', NULL, 'Google', 'GRCCRAM_DBS_HS/Greek-(1844)-Catenae-Graecorum-Patrum-Novum-Testamentum-(Cramer)-Vol-1-8', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('271', 'Syriac-1941-Gospels-and-Commentary-WDL-7070', 'SYROLD', 'Syriac (1941) Gospels and Commentary (WDL-7070)', 'ܣܘܪܝܝܐ (1941) ܐܘܢܓܠܝܘܢ ܘܦܘܫܩܐ', 'Syriac (1941) Gospels and Commentary (WDL-7070) This 20th-century manuscript is a copy of Dionysius Bar Salibi''s "Pušāqā d-ewangelyon qaddišā" (Gospel commentary). Bar Salibi, who died in 1171, was a prominent Assyrian metropolitan bishop born in Melitene. He is highly regarded for his extensive literary contributions, including poems, prayers, a treatise against heresy, and translations of Aristotle''s works into Syriac. His biblical commentaries are particularly well-preserved with significant manuscript evidence. This manuscript, written in Serto script, a Syriac script that developed in the 8th century, is a testament to the enduring tradition of manuscript production among West Syriac scribes. Serto, meaning “line,” became the most-used Syriac script. Syriac, an eastern dialect of Aramaic, was spoken by Christians in regions between the Roman Empire and the Arabian Sea from the 1st to the 12th century.', 'historic', 'https://www.wdl.org/en/item/7070', '130', 'syr', '1941', 'study', 'World Digital Library', NULL, 'World Digital Library', 'SYROLD_DBS_HS/Syriac-(1941)-Gospels-and-Commentary-(WDL-7070)', 'syr', 'syr', 'Syriac', NULL, 'L', 'IQ', NULL, NULL, NULL, NULL, '858080', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('272', 'Coptic-Northern-1898-New-Testament-GW-Horner-Vol-1-4', 'COPNNT', 'Coptic Northern (1898) New Testament (GW Horner) Vol 1-4', 'Ⲙⲉⲧⲛⲓⲙ ⲛ̀ⲛⲉⲛⲧⲟⲥ (1898) (GW Horner) Ⲛⲁⲩ 1-4', 'The term ‘Coptic’ refers to the form of Egyptian in use after the establishment of Christianity in Egypt during the 3rd century. Sometimes called Neo-Egyptian, it is a development of Ancient Egyptian, in use until the 6th century B.C., and it''s later Hieratic and Demotic forms. These long succeeding periods made Coptic the living language with the longest recorded history. The few remaining Coptic speakers succumbed to the Arabic language in the 17th century.<br>Coptic was spoken in several dialects. Scriptures are extant in the Bohairic (Coastal, Lower Egypt); Fayumic or Bashmuric, Sub- Achmimic, and Middle Egyptian; and Sahidic and Achmimic (Upper Egyptian) dialects. Bohairic, earlier known as Memphitic, was the usage of Alexandria and hence survives as the ecclesiastical and liturgical language of the Coptic Church. However, it appears that Scriptures first appeared (3rd century) in Sahidic, because Lower Egypt had been Hellenized and the Greek Scriptures could be used there. Although considerable research remains to be done on the Coptic texts, these early versions cast light on the text used by the early Church.<br>The Coptic alphabet employs 24 Greek characters and 7 characters retained from Demotic script.', 'historic', NULL, '158', 'cop', '1898', 'scan', 'Henry Frowde-University of Oxford', NULL, NULL, 'COPNNT_DBS_HS/Coptic-Northern-(1898)-New-Testament-(GW-Horner)-Vol-1-4', 'cop', 'copt1239', 'Coptic', 'ϯⲙⲉⲧⲣⲉⲙⲛ̀ⲭⲏⲙⲓ ~ ⲧⲙⲛ̄ⲧⲣⲙ̄ⲛ̄ⲕⲏⲙⲉ', 'E', 'EG', '29.47203', '31.2053', '9', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('273', 'Greek-1881-Scrivener-NT', 'GRCSCRI', 'Greek (1881) Scrivener New Testament', 'Καινή Διαθήκη του Scrivener (1881)', 'In 1881, F. H. A. Scrivener undertook the meticulous task of reproducing the Greek text underlying the Authorised Version (AV) of 1611 as accurately as possible. His work was a significant endeavor in biblical scholarship, as the AV was not translated from a single printed edition of the Greek text. Instead, the AV translators drew heavily upon William Tyndale''s work and other English Bible editions, leading to instances where the Greek basis of the New Testament was unclear.<br><br>Scrivener''s approach involved starting with the Beza edition of 1598 and meticulously identifying where the English text diverged from the Greek. He conducted an extensive examination of eighteen editions of the Textus Receptus to determine the correct Greek renderings and adapted his Greek text accordingly. Through this rigorous process, Scrivener succeeded in creating an edition of the Greek New Testament that more closely aligns with the text of the AV than any other single edition of the Textus Receptus. His work provided a vital tool for understanding the textual basis of the AV and contributed significantly to the field of textual criticism and biblical studies.', 'modern', NULL, '26', 'grc', '1881', 'book', NULL, NULL, NULL, 'GRCSCRI_DBS_HS', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('274', 'English-1526-Tyndale''s-New-Testament-reprint', 'ENGTYN', 'English (1526) Tyndale''s New Testament (reprint)', NULL, 'The Tyndale Bible generally refers to the body of biblical translations by William Tyndale (1494–1536). Tyndale''s Bible is credited with being the first English translation to work directly from Hebrew and Greek texts. Furthermore, it was the first English biblical translation that was mass-produced as a result of new advances in the art of printing.<br><br>The term Tyndale''s Bible is not strictly correct, because Tyndale never published a complete Bible. That task was completed by Miles Coverdale, who supplemented Tyndale''s translations with his own to produce the first complete printed Bible in English in 1535. Prior to his execution Tyndale had only finished translating the entire New Testament and roughly half of the Old Testament. Of the latter, the Pentateuch, Jonah and a revised version of the book of Genesis were published during his lifetime. His other Old Testament works were first used in the creation of the Matthew Bible and also heavily influenced every major English translation of the Bible that followed.<br><br>1525 Tyndale, William (The New Testament) [Cologne: Peter Quentell, 1525.][Only a fragment, ''The gospell of S. Mathew. The first Chapter [through] the xxii. Chapter.'', still remains in the Grenville Collection of the British Museum. 3,000 copies of the first ten sheets had been secretly printed before Tyndale had to flee Cologne to Worms, where he began his work afresh. Complete edition; Worms: Peter Quentell, 1526. Reprinted; New Testament translated by William Tyndale 1525. Facsimile of unique fragment of the uncompleted Cologne edition. Oxford: Clarendon Press, 1926.', 'historic', 'https://en.wikipedia.org/wiki/Tyndale_Bible', '26', 'eng', '1525', 'reprint', NULL, NULL, NULL, 'ENGTYN_DBS_HS/English-(1526)-Tyndale''s-New-Testament-(reprint)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('275', 'Greek-1280-ca.-Marginal-Psalter-Walters-Museum-WDL-13016', 'GRCMARG', 'Greek (1280 ca.) Marginal Psalter - Walters Museum (WDL-13016)', 'Οριακός Ψαλτήρας (1280 περ.) - Walters Museum (WDL-13016)', 'The Marginal Psalter housed at the Walters Museum, dating to around 1280, is a rare and exquisite example of a "marginal psalter," distinguished by its 155 marginal paintings that offer a pictorial commentary on the Biblical text. This manuscript is part of a select group of surviving psalters that integrate imagery directly into the margins as a form of visual exegesis, enhancing the understanding and interpretation of the Psalms.<br><br>Notable examples of other marginal psalters include the Khludov Psalter (circa 850, Moscow), the Barberini Psalter (circa 1050, Vatican City), the Theodore Psalter (1066, London), and a Cyrillic psalter made in Kiev (1397, Saint Petersburg). The Walters Museum Marginal Psalter shares a notable similarity in iconography with the Saint Petersburg Cyrillic psalter, suggesting that both were likely copied from the same 11th-century model. This similarity provides valuable insights into the transmission and evolution of psalter illustration and design in medieval manuscript culture.<br><br>The Marginal Psalter is not only a significant artifact for its artistic value but also for its role in illustrating the Biblical narrative, making it an important resource for scholars studying medieval art, biblical exegesis, and manuscript history. The integration of visual elements into the scriptural text in such psalters demonstrates the interplay between image and word in medieval religious and cultural contexts.', 'historic', 'https://www.wdl.org/en/item/13009', '51', 'grc', '1280', 'scan', 'World Digital Library', NULL, 'World Digital Library', 'GRCMARG_DBS_HS/Greek-(1280-ca.)-Marginal-Psalter-Walters-Museum-(WDL-13016)', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('276', 'English-1893-Rotherham-New-Testmant', 'ENGROT', 'English (1893) Rotherham New Testmant', NULL, 'The 1893 Rotherham New Testament stands as a remarkable accomplishment in the field of biblical translation, spearheaded by the eminent scholar Joseph B. Rotherham. This translation is distinguished by its reliance on the Greek text of Tregelles, a renowned biblical scholar and text critic. Rotherham''s work is characterized by its ''emphasized'' approach, aiming to reflect the logical idiom of the original Greek text in a manner that is both accurate and accessible to the English reader.<br><br>Rotherham''s introduction and occasional notes provide valuable insights, enhancing the reader''s understanding of the text. His method of emphasizing not just the words but the underlying structure and logic of the Greek language offers a unique perspective, bridging the gap between ancient scripture and modern interpretation. This approach reflects a deep respect for the original text and a commitment to conveying its nuanced meanings as faithfully as possible.<br><br>The progression of editions, from the second edition in 1878 to the fifth edition in 1923, marks the evolution and refinement of Rotherham''s work. Each edition builds upon the previous, incorporating new findings and critical insights, demonstrating Rotherham''s dedication to continual improvement. The third edition in 1897 and the fourth edition, which was part of the complete Bible in 1902/03, are testament to the enduring impact and relevance of his translation.<br><br>Rotherham''s New Testament is not just a translation; it is a scholarly endeavor that combines linguistic precision with theological depth, offering readers a window into the world of the early Christian texts and their profound spiritual and historical significance.', 'historic', NULL, '82', 'eng', '1893', 'scan', 'Samuel Bagster and Sons', NULL, NULL, 'ENGROT_DBS_HS/English-(1893)-Rotherham-New-Testmant', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('277', 'English-1751-Samuel-Clarke-Gospels-A-paraphrase-on-the-four-evangelists-Vol.-1-2', 'ENGSCB', 'English (1751) Samuel Clarke Gospels (A paraphrase on the four evangelists) Vol. 1-2', NULL, 'Samuel Clarke, born on October 11, 1675, and passing on May 17, 1729, was an influential English philosopher and alderman, known for his representation of Norwich in Parliament. Educated at the free school of Norwich and at Caius College, Cambridge, Clarke made significant contributions to religious literature. In 1699, he published "Three Practical Essays on Baptism, Confirmation and Repentance" and "Some Reflections on that part of a book called Amyntor, or a Defence of Milton''s Life," which relates to the Writings of the Primitive Fathers and the Canon of the New Testament.<br><br>In 1701, Clarke began a series of paraphrases on the Gospels, starting with the Gospel of St Matthew. This work was followed by paraphrases on the Gospels of St Mark and St Luke in 1702, and shortly afterwards by a volume on St John. These works were later compiled and printed together in two volumes, which have gone through several editions since their initial publication.<br><br>Clarke had ambitions to paraphrase the remaining books of the New Testament in a similar manner. However, this goal remained unfulfilled at the time of his passing. His paraphrases on the four evangelists are remembered for their clarity and insight, reflecting his profound understanding of biblical texts and contributing to theological and biblical studies.', 'historic', NULL, '335', 'eng', '1751', 'scan', NULL, NULL, NULL, 'ENGSCB_DBS_HS/English-(1751)-Samuel-Clarke-Gospels-(A-paraphrase-on-the-four-evangelists)-Vol.-1-2', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('278', 'Greek-1516-Erasmus-New-Testament', 'GRCERAS', 'Greek (1516) Erasmus New Testament', 'Καινή Διαθήκη του Έρασμου (1516)', 'The 1516 Erasmus New Testament marked a significant milestone in biblical scholarship, spearheaded by Erasmus of Rotterdam, a leading figure of the Renaissance and a celebrated scholar across Europe. Dedicated to revitalizing the Church through the true "philosophy of Christ," Erasmus focused his studies on the Bible and early Church writings.<br><br>Erasmus''s major projects included collating Greek texts and developing a fresh Latin New Testament. Starting in 1512, he aimed to create a critical edition of the Latin New Testament, meticulously collecting Vulgate manuscripts and refining the language. He emphasized the need for a more polished Latin, stating, "It is only fair that Paul should address the Romans in somewhat better Latin."<br><br>The rationale behind including the Greek text in his work was not immediately apparent. While some hypothesized that Erasmus aimed to produce a critical Greek text or outpace the Complutensian Polyglot, no concrete evidence supports these theories. Erasmus''s own words, "There remains the New Testament translated by me, with the Greek facing, and notes on it by me," suggest his intent to enable readers to assess the accuracy of his Latin version against the Greek. He included the Greek text to address the issues of translation errors and textual corruption, often caused by the incompetence or inattention of translators and scribes.<br><br>By initially naming his work "Novum Instrumentum omne" ("All of the New Teaching") and later "Novum Testamentum omne" ("All of the New Testament"), Erasmus underscored his belief in the importance of a text where the Greek and Latin versions were directly comparable, viewing this as the foundational core of the church''s New Testament tradition. His work greatly contributed to the understanding and study of biblical texts, setting a precedent for future biblical scholarship and translations.', 'historic', NULL, '39', 'grc', '1516', 'scan', NULL, NULL, NULL, 'GRCERAS_DBS_HS/Greek-(1516)-Erasmus-New-Testament', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('279', 'Syriac-1890-Triglot-Bible-Vol.-1-2-Greek-Latin-Hebrew', 'SYROLD', 'Syriac (1890) Triglot Bible Vol.-1-2 Greek Latin Hebrew', 'ܣܘܪܝܝܐ (1890) ܒܝܒܠܝܐ ܬܪܝܓܠܘܛ', 'Syriac (1890) Triglot Bible Vol 1 - Old Testament The Syriac language, also known as Syriac Aramaic (Syrian Aramaic, Syro-Aramaic) and Classical Syriac ܠܫܢܐ ܥܬܝܩܐ (in its literary and liturgical form), is an Aramaic dialect that emerged during the first century AD from a local Aramaic dialect that was spoken by Arameans in the ancient Aramean kingdom of Osroene, centered in the city of Edessa. During the Early Christian period, it became the main literary language of various Aramaic-speaking Christian communities in the historical region of Ancient Syria and throughout the Near East. As a liturgical language of Syriac Christianity, it gained a prominent role among Eastern Christian communities that used both Eastern Syriac and Western Syriac rites. Following the spread of Syriac Christianity, it also became a liturgical language of eastern Christian communities as far as India and China. It flourished from the 4th to the 8th century and continued to have an important role during the next centuries, but by the end of the Middle Ages it was gradually reduced to liturgical use since the role of vernacular language among its native speakers was overtaken by several emerging Neo-Aramaic dialects.<br><br>Script is indicated as follows: (E) Estrangelo;(J) Jacobite;(H) Hebrew; (N) Nestorian; 1555 New Testament (J) Zimmermann, ViennaEditedfrom Ms. Peshitta texts by Johann A. Widmanstadt; 1569 New Testament (H) Stephanus, GenevaEdited by Immanuel Tremcllius and published with Greek and Latin texts. Syriac versions appeared in other Polyglots: 1575, Antwerp; H99, Niirnherg; also the Paris and London Polyglots (see below); 1625 Psalms(J) ParisEdited by Gabriel Sionita, a Maronite. In the same year a SyriacPsalter was published in Leiden, edited by T. Erpenius; 1627 Revelation (J & H); 1630 2 Peter 2-3JohnJude (J & H) LeidenThefirst publication of these Books which are omitted from the Syriaccanon; edited by E. Pococke; 1629-1645 Bible (J) Paris: The Paris Polyglot contained the first complete Syriac printed Bible, edited by G. Sionita; 1655-1657 Bible(J) LondonThe London Polyglot, edited by Brian Walton and others. Numerous editions appeared during the 17th and centuries, based on the texts of these prestigious polyglot Bibles; 1708 New Testament(J) LeidenAn early critical edition, prepared by J. Leusden and C. Schaaf. The Gospels were reprinted by the BFBS in 1815; 1778 Gospels(J); 1799-1803 Acts Epistles(J) OxfordThe Philoxenian and/or Harkleian recension, edited byJoseph White; 1816 NewTestament(J); 1822 Psalms (J); 1823 Old Testament(J) BFBS, LondonEditedfor the BFBS by S. Lee, and based on the London Polyglot; 1820 Psalms (J) MilanThe Syro-Hcxaplar text, edited by C. Bugatus. This version, prepared by Paul of Telia (617 A.D.), is a translation of the Septuagint into Syriac. Other portions of the Syro-Hcxaplar had appeared earlier; 1828 New Testament(J) Bagster, London Edited by William Greenfield; 1835 2 Kings Job Proverbs-Isaiah Lamentations Hosea—Malachi(J) BerlinThe Syro-Hcxaplar, edited by Heinrich Middeldorpf In 1858-1860 Judges and Ruth from the Syro-Hexaplar, edited by T. Skat Rordatn, were published in Copenhagen; 1836 New Testament (H) London Jews Society, London Edited for the LJS in the hope that similarity of usage with that of the Zohar would encourage interest in Jewish readers; 1841 Bible (N) American Board of Commissioners for Foreign Missions, UrumiaThe first edition of the Scriptures prepared for the use of the Nestorian Christian communities. In 1846 a N. T. with Modern Syriac text was also published by the ABCFM; O.T., 1852. A Liturgical Psalter was published in Mosul, in 1866. In 1913 the Trinitarian BS published the O. T. in Ancient Syriac only,', 'historic', NULL, '254', 'syr', '1890', 'scan', 'Richard D. Dickinson', NULL, NULL, 'SYROLD_DBS_HS/Syriac-(1890)-Triglot-Bible-Vol-1-Old-Testament', 'syr', 'syr', 'Syriac', NULL, 'L', 'IQ', NULL, NULL, NULL, NULL, '858080', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('280', 'English-1795-Samuel-Clarke-Acts-and-Epistles-A-paraphrase-with-notes-Thomas-Pyle-Vol-1-2', 'ENGSCB', 'English (1795) Samuel Clarke Acts and Epistles Vol. 1-2', NULL, 'Samuel Clarke, an English philosopher and alderman born on October 11, 1675, and who passed away on May 17, 1729, represented Norwich in parliament and was educated at the free school of Norwich and Caius College, Cambridge. In 1699, he published two treatises, "Three Practical Essays on Baptism, Confirmation and Repentance," and "Some Reflections on that part of a book called Amyntor, or a Defence of Milton''s Life," which discussed the writings of the Primitive Fathers and the Canon of the New Testament. Clarke''s significant contributions to biblical literature began in 1701 with "A Paraphrase upon the Gospel of St Matthew," followed by paraphrases on the Gospels of St Mark and St Luke in 1702, and a volume on St John shortly afterward. These works were later printed together in two volumes, going through several editions. Clarke''s paraphrases aimed to make the Gospels more accessible and understandable, though his plan to paraphrase the entire New Testament remained unfulfilled. His works are an important part of early 18th-century religious literature, reflecting the era''s theological and intellectual currents.', 'historic', NULL, '321', 'eng', '1795', 'scan', NULL, NULL, NULL, 'ENGSCB_DBS_HS/English-(1795)-Samuel-Clarke-Acts-and-Epistles-(A-paraphrase-with-notes-Thomas-Pyle)-Vol-1-2', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('281', 'Greek-1751-He-Kaine-Diatheke-Gospels', 'GRCDIAT', 'Greek (1751) He Kaine Diatheke - Gospels', 'Η Καινή Διαθήκη (1751, Ευαγγέλια)', 'The 1751 Greek New Testament, titled "He Kaine Diatheke. Novum Testamentum Graecum Editionis Receptae Cum Lectionibus Variantibus. NEC Non Commentario Pleniore Opera Joannis-Jacobi Wetstenii," is a significant publication in biblical scholarship. This work was compiled and edited by Johann Jakob Wettstein, a notable Swiss theologian and biblical scholar.<br><br>Wettstein''s edition of the Greek New Testament is particularly distinguished for its incorporation of the Textus Receptus, or the "received text," which was the Greek text predominantly used in the Protestant church since its publication in the 16th century. This edition is also notable for including various textual variants, offering a broader view of the scriptural text and its transmission. Furthermore, Wettstein''s comprehensive commentary provides in-depth scholarly insight into the New Testament.<br><br>Wettstein''s work represents a significant step forward in the critical study of the New Testament text, particularly in its detailed attention to variant readings. His compilation and analysis have been influential in the field of biblical textual criticism, aiding scholars in understanding the complexities and history of the New Testament text.', 'historic', NULL, '85', 'grc', '1751', 'scan', NULL, NULL, NULL, 'GRCDIAT_DBS_HS/Greek-(1751)-He-Kaine-Diatheke-Gospels', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('282', 'English-1861-Literal-Translation-of-Vatican-Manuscripts-Heinfetter-Vol.1-2-NT-Portions', 'ENGLTVM', 'English (1861) Literal Translation of Vatican Manuscripts (Heinfetter) Vol.1-2 - NT Portions', NULL, 'The 1861 work "A Literal Translation of the Vatican Manuscript''s Acts of the Apostles" represents a pivotal moment in biblical translation and textual analysis. This groundbreaking project focused on providing a direct English translation of the Acts of the Apostles as found in the renowned Vatican Manuscripts. It adheres to strict rules of translation to ensure the closest possible fidelity to the original text.<br><br>This volume is distinguished by its unique approach: it juxtaposes the newly translated text with the Authorized English Version, allowing for a detailed comparison and study of the two versions. Such a side-by-side arrangement not only highlights the differences between the literal translation and the more traditional interpretation but also offers a deeper understanding of the nuances and complexities inherent in the process of translating ancient religious texts.<br><br>The significance of this work lies in its meticulous adherence to the original manuscript, providing readers and scholars with a more unvarnished glimpse into the early texts of the Christian tradition. This approach marks a shift towards a more rigorous and scholarly treatment of biblical translation, emphasizing the importance of textual accuracy and historical context.<br><br>The publication of this translation was a major contribution to biblical scholarship, offering an invaluable resource for those seeking a more literal understanding of the Vatican Manuscripts. It remains an essential reference for anyone interested in the intricacies of biblical translation and the historical evolution of religious texts.', 'historic', NULL, '50', 'eng', '1861', 'scan', 'American Bible Union Collection', NULL, NULL, 'ENGLTVM_DBS_HS/English-(1861)-Literal-Translation-of-Vatican-Manuscripts-(Heinfetter)-Vol.1-2-NT-Portions', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('283', 'Greek-English-1896-Englishman''s-New-Testament-Stephens-and-KJV', 'GRCSTEP', 'Greek-English (1896) Englishman''s New Testament (Stephens and KJV)', 'Η Καινή Διαθήκη του Englishman (1896, Stephens και KJV)', 'The 1896 "Englishman''s Greek New Testament" is a significant bilingual edition that presents the Greek text of the 1550 Stephens New Testament alongside the Authorized King James Version (KJV) of the Bible. This work bridges the gap between the original Greek text and one of the most influential English translations of the Bible.<br><br>The Greek text in this edition is based on the 1550 version by Robert Stephens, a renowned 16th-century printer and scholar. Stephens'' Greek text played a pivotal role in biblical scholarship, particularly influencing the development and standardization of the Greek New Testament.<br><br>By presenting the Stephens text alongside the KJV, the "Englishman''s Greek New Testament" provides a unique tool for comparative study. This parallel format allows readers and scholars to compare the original Greek with its translation in the KJV, offering insights into the translation process, textual variations, and the interpretation of biblical texts.<br><br>This edition serves not only as a valuable resource for students of biblical languages but also for those interested in the history of biblical translation. The combination of the influential Stephens Greek text with the equally significant KJV makes this work a critical resource for understanding the development and impact of biblical texts in both the original Greek and in English translation.', 'historic', NULL, '400', 'grc', '1896', 'study', 'Hinds, Noble & Eldredge', NULL, NULL, 'GRCSTEP_DBS_HS/Greek-English-(1896)-Englishman''s-New-Testament-(Stephens-and-KJV)', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('284', 'English-1885-Revised-Version', 'ENGREV', 'English (1885) Revised Version', NULL, 'The Revised Version (RV) of the Bible, completed in 1885, stands as a monumental achievement in the history of English Bible translation. It emerged as the only officially authorised revision of the King James Version (KJV), also known as the Authorised Version (AV), and represented a significant step forward in biblical scholarship. The revision process was entrusted to around fifty eminent scholars from various Christian denominations across Great Britain. In a groundbreaking move, American scholars were also involved, contributing via correspondence.<br><br>The guiding principle for the revisers was to make alterations only when necessary to stay true to the original texts. This meticulous approach led to more than 30,000 changes in the New Testament alone, with over 5,000 of these changes based on improved Greek texts. The New Testament revision was completed in 1881, and the full RV, including both the Old and New Testaments, was published on 19th May 1885, printed by the prestigious Oxford and Cambridge Universities.<br><br>The American edition of the RV, known as the American Standard Version (ASV), was published in 1901. While based on the RV, the ASV did not include the Apocrypha, distinguishing it from its British counterpart. The RV and its American adaptation marked a new era in biblical translation, characterized by rigorous academic scholarship and a commitment to fidelity to the original Hebrew, Aramaic, and Greek texts. These versions have significantly influenced subsequent Bible translations and continue to be valued for their scholarly accuracy and contribution to biblical studies.', 'historic', NULL, '388', 'eng', '1885', 'scan', NULL, NULL, NULL, 'ENGREV_DBS_HS/English-(1885)-Revised-Version', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('285', 'English-1557-Geneva-NT', 'ENGGNV', 'English (1557) Geneva New Testament', NULL, 'The Geneva Bible is one of the most historically significant translations of the Bible into English, preceding the King James Version by 51 years. It was the primary Bible of 16th-century English Protestantism and was used by William Shakespeare, Oliver Cromwell, John Knox, John Donne, and John Bunyan, author of The Pilgrim''s Progress (1678). It was one of the Bibles taken to America on the Mayflower (Pilgrim Hall Museum has collected several Bibles of Mayflower passengers). The Geneva Bible was used by many English Dissenters, and it was still respected by Oliver Cromwell''s soldiers at the time of the English Civil War, in the booklet "Cromwell''s Soldiers'' Pocket Bible".<br><br>This version of the Bible is significant because, for the very first time, a mechanically printed, mass-produced Bible was made available directly to the general public which came with a variety of scriptural study guides and aids (collectively called an apparatus), which included verse citations that allow the reader to cross-reference one verse with numerous relevant verses in the rest of the Bible, introductions to each book of the Bible that acted to summarize all of the material that each book would cover, maps, tables, woodcut illustrations, and indices.<br><br>Because the language of the Geneva Bible was more forceful and vigorous, most readers strongly preferred this version to the Great Bible. In the words of Cleland Boyd McAfee, "it drove the Great Bible off the field by the sheer power of excellence".<br><br>The Geneva Bible followed the Great Bible of 1539, the first authorized Bible in English, which was the authorized Bible of the Church of England.<br><br>During the reign of Queen Mary I of England (1553–58), a number of Protestant scholars fled from England to Geneva, Switzerland, which was then ruled as a republic in which John Calvin and, later, Theodore Beza, provided the primary spiritual and theological leadership. Among these scholars was William Whittingham, who supervised the translation now known as the Geneva Bible, in collaboration with Myles Coverdale, Christopher Goodman, Anthony Gilby, Thomas Sampson, and William Cole; several of these groups later became prominent figures in the Vestments controversy. Whittingham was directly responsible for the New Testament, which was complete and published in 1557, while Gilby oversaw the Old Testament.<br><br>The first full edition of this Bible, with a further revised New Testament, appeared in 1560, but it was not printed in England until 1575 (New Testament) and 1576 (complete Bible). Over 150 editions were issued; the last probably in 1644. The first Bible printed in Scotland was the Geneva Bible, which was first issued in 1579. In fact, the involvement of Knox and Calvin in the creation of the Geneva Bible made it especially appealing in Scotland, where a law was passed in 1579 requiring every household of sufficient means to buy a copy.<br><br>Some editions from 1576 onwards included Laurence Tomson''s revisions of the New Testament. Some editions from 1599 onwards used a new "Junius" version of the Book of Revelation, in which the notes were translated from a new Latin commentary by Franciscus Junius.<br><br>The annotations which are an important part of the Geneva Bible were Calvinist and Puritan in character, and as such, they were disliked by the ruling pro-government Anglicans of the Church of England, as well as King James I, who commissioned the "Authorized Version", or King James Bible, in order to replace it. The Geneva Bible also motivated the earlier production of the Bishops'' Bible under Elizabeth I, for the same reason, and the later Rheims-Douai edition by the Catholic community. The Geneva Bible remained popular among Puritans and remained in widespread use until after the English Civil War. The Geneva notes were surprisingly included in a few editions of the King James version, even as late as 1715. (Wikipedia)', 'historic', NULL, '238', 'eng', '1557', 'reprint', 'GreatSite.com', NULL, NULL, 'ENGGNV_DBS_HS', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('286', 'Greek-English-1894-New-Testament-Interlinear', 'GRCTXR', 'Greek-English (1894) New Testament Interlinear', 'Διαγλωσσική Καινή Διαθήκη (1894)', 'The 1894 "Interlinear Literal Translation of The Greek New Testament" is a comprehensive work that provides a valuable tool for biblical scholars and students. Published by Arthur Hinds and Company, this edition presents a literal interlinear translation of the Greek New Testament, with the Authorized King James Version (KJV) conveniently placed in the margins for easy reference and comparison.<br><br>A key feature of this edition is the inclusion of various readings from significant textual scholars and editions of the Greek New Testament. It incorporates the textual variations from the Elzevir 1624 edition, as well as the critical works of Griesbach, Lachmann, Tischendorf, Tregelles, Alford, and Wordsworth. This breadth of sources provides a comprehensive view of the textual differences and scholarly interpretations of the New Testament.<br><br>The parallel format of the Greek text with the KJV in the margins allows readers to easily compare the original language with its English translation. This setup is particularly useful for those studying the translation process, textual criticism, and the interpretation of biblical texts. The edition is an invaluable resource for anyone looking to deepen their understanding of the New Testament in its original Greek, alongside one of the most influential English translations.', 'historic', NULL, '1', 'grc', '1894', 'study', 'Samuel Bagster and Sons', NULL, NULL, 'GRCTXR_DBS_HS/Greek-English-(1894)-New-Testament-Interlinear', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('287', 'Greek-1877-Tischendorf-Novum-Testamentum-8th-edition', 'GRCTISH', 'Greek (1877) Tischendorf Novum Testamentum (8th edition)', 'Novum Testamentum του Tischendorf (1877, 8η Έκδοση)', 'The 1877 Tischendorf Novum Testamentum (8th edition), also known as the Editio octava critica maior (1869-1872), represents a pinnacle in the field of biblical textual scholarship. Constantine Tischendorf, a renowned biblical scholar, is celebrated for his critical Greek New Testament, which remains highly valued for its exhaustive detail in textual readings and witness to the text.<br><br>Tischendorf''s discovery and extensive work on the Codex Sinaiticus, one of the oldest and most complete manuscripts of the Greek Bible, are particularly well-known. Throughout his career, he published eight major editions of the Greek New Testament, along with abridged editions, collations, and facsimiles. However, his most significant and enduring work is undoubtedly the Editio octava critica maior.<br><br>This edition, which took several years to complete, remains unparalleled as a comprehensive edition of the New Testament text. Tischendorf''s meticulous approach and dedication to detail in this edition have made it an essential resource for biblical scholars and theologians, continuing to influence the field of New Testament textual criticism to this day.', 'historic', NULL, '62', 'grc', '1877', 'scan', 'J. C. Hinrichs Bibliopola', NULL, 'Google', 'GRCTISH_DBS_HS/Greek-(1877)-Tischendorf-Novum-Testamentum-(8th-edition)', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('288', 'Hebrew-1888-Holy-Bible-in-Hebrew-Greek', 'HEBHEPT', 'Hebrew (1888) Holy Bible in Hebrew - Greek', 'עברית - התנ"ך הקדוש (1888, עברית-יוונית)', 'The 1888 edition of "The Holy Bible in the Original Hebrew and Greek" combines the Hebrew Old Testament edited by Meir (Max) Letteris with the Greek New Testament in the edition by Brooke Foss Westcott and Fenton John Anthony Hort. This compilation is notable for providing scholars and students with the biblical texts in their original languages. Letteris''s version of the Hebrew Old Testament is a traditional and respected text, while the Westcott and Hort edition of the Greek New Testament is renowned for its critical approach to the Greek manuscripts. The merging of these two authoritative texts in one volume highlights the significance of studying the Bible in its original languages, offering a deeper understanding of the meanings and nuances in the texts. This edition serves as a crucial resource in biblical scholarship, bridging historical and contemporary studies of these foundational religious scriptures.', 'historic', NULL, '45', 'heb', '1888', 'study', NULL, NULL, 'Google', 'HEBHEX_DBS_HS/Hebrew-(1888)-Holy-Bible-in-Hebrew-Greek', 'heb', 'hebr1245', 'Hebrew', 'Israeli Hebrew', 'L', 'IL', '31.10565', '35.01788', '1', 'he', '5000000', NULL, 'Also in Australia, Canada, Germany, Palestinian West Bank and Gaza, Panama, United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('289', 'English-1599-Geneva-Bible', 'ENGGNV', 'English (1599) Geneva Bible', NULL, 'The Geneva Bible, first printed in 1560, is one of the most historically significant translations of the Bible into English, predating the King James Version by 51 years. It was the primary Bible for English Protestantism in the 16th century and was used by William Shakespeare, Oliver Cromwell, John Knox, John Donne, and John Bunyan, author of "The Pilgrim''s Progress" (1678). This Bible was also among those taken to America on the Mayflower, as evidenced by collections at the Pilgrim Hall Museum.<br><br>This version was groundbreaking as it was the first mechanically printed, mass-produced Bible available directly to the general public. It included a comprehensive apparatus for scriptural study, such as verse citations for cross-referencing, book introductions, maps, tables, woodcut illustrations, and indices. Its forceful and vigorous language made it more popular than the Great Bible, leading Cleland Boyd McAfee to state that it "drove the Great Bible off the field by the sheer power of excellence."<br><br>Created during Queen Mary I''s reign (1553–58), the Geneva Bible was the work of Protestant scholars who fled England for Geneva, Switzerland. There, under the spiritual leadership of John Calvin and Theodore Beza, William Whittingham supervised the Geneva Bible''s translation, collaborating with Myles Coverdale and others. Whittingham was responsible for the New Testament (published in 1557), while Gilby oversaw the Old Testament.<br><br>The first full edition of the Geneva Bible appeared in 1560, but it wasn''t printed in England until 1575 (New Testament) and 1576 (complete Bible). Over 150 editions were issued, the last probably in 1644. The first Bible printed in Scotland was the Geneva Bible, issued in 1579. Later editions included Laurence Tomson''s revisions of the New Testament and a new "Junius" version of the Book of Revelation.<br><br>The Geneva Bible''s Calvinist and Puritan annotations were disliked by the Church of England and King James I, who commissioned the King James Bible as a replacement. The Geneva Bible influenced the production of the Bishops'' Bible and the later Rheims-Douai edition by the Catholic community. It remained popular among Puritans and in use until after the English Civil War, with its notes even appearing in some editions of the King James version as late as 1715.', 'historic', 'https://en.wikipedia.org/wiki/Geneva_Bible', '125', 'eng', '1599', 'reprint', NULL, NULL, NULL, 'ENGGNV_DBS_HS/English-(1599)-Geneva-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('290', 'French-1896-Gospels-Louis-Claude-Fillion-Gospels', 'FRALCF', 'French (1896) Gospels (Louis-Claude Fillion) - Gospels', 'Évangiles (1896, Louis-Claude Fillion)', 'French (1896) Gospels (Louis-Claude Fillion) - Gospels Louis-Claude Fillion, a prominent figure in biblical scholarship, was born in 1843 and passed away in 1927. Ordained as a priest in 1867, he later became a distinguished professor, specializing in Scripture and Hebrew studies. His academic journey led him to the Catholic Institute of Paris in October 1893, where he was appointed as the chair of exegesis of Scripture. His expertise and contributions to the field were further recognized in 1903 when he was appointed as a member of the Pontifical Biblical Commission. Fillion''s work in the area of biblical exegesis was instrumental in advancing the understanding and interpretation of Scripture, particularly in the context of the Catholic tradition. His deep knowledge of Hebrew and scriptural studies enriched his teachings and writings, making a significant impact on biblical scholarship during his time.', 'historic', NULL, '20', 'fra', '1896', 'scan', 'Letouzey Et Ane Editeurs ', NULL, NULL, 'FRALCF_DBS_HS/French-(1896)-Gospels-(Louis-Claude-Fillion)-Gospels', 'fra', 'stan1290', 'French', 'français', 'L', 'FR', '48', '2', '1', 'fr', '77200000', 'Andorra and France', 'Also in Algeria, Andorra, Austria, Belgium, Benin, Burkina Faso, Burundi, Cambodia, Cameroon, Canada, Central African Republic, Chad, Comoros, Congo, Côte d’Ivoire, Democratic Republic of the Congo, Djibouti, Equatorial Guinea, French Guiana, French Polynesia, Gabon, Guadeloupe, Guinea, Haiti, India, Israel, Italy, Lebanon, Libya, Luxembourg, Madagascar, Mali, Martinique, Mauritania, Mauritius, Mayotte, Monaco, Morocco, Mozambique, New Caledonia, Niger, Philippines, Puerto Rico, Réunion, Rwanda, Saint Pierre and Miquelon, Saudi Arabia, Senegal, Seychelles, South Africa, Switzerland, Togo, Tunisia, United Arab Emirates, United Kingdom, United States, U.S. Virgin Islands, Vanuatu, Wallis and Futuna.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('291', 'English-1870-Emphatic-Diaglott-New-Testament-with-Greek-Study-Bible', 'ENGKJV', 'English (1870) Emphatic Diaglott New Testament (with Greek) Study Bible', NULL, 'The Emphatic Diaglott, first published in 1864 by Benjamin Wilson, is a notable contribution to biblical translations and studies. It is a diaglot - a polyglot translation - of the New Testament, offering a unique approach by presenting an interlinear translation. On the left column of each page, readers find the original Greek text juxtaposed with a precise word-for-word English translation, while the right column features a full English translation. This layout facilitates a deeper understanding of the Greek text and its nuances in translation. <br><br> Wilson''s work draws its Greek text from Johann Jakob Griesbach''s recension, respected for its scholarly rigor. The English translation is notable for its use of "Jehovah" in places where the New Testament writers quoted Hebrew scriptures using "Kyrios" (the Lord). This choice reflects in passages like Luke 20:42-43, where the Psalm 110:1 quotation reads, "Jehovah said to my Lord, sit thou at my Right hand, ''till I put thine enemies underneath thy feet." Such renderings offer a distinct perspective in the translation of divine names. <br><br> The Emphatic Diaglott also includes valuable footnotes, references, and an alphabetical appendix, enhancing its utility for study and reference. The original title page of the 1865 Fowler and Wells edition eloquently summarizes its content and purpose, underscoring its significance as a comprehensive and enlightening resource for those studying the New Testament.', 'historic', NULL, '133', 'eng', '1870', 'study', 'Samuel R. Wells', NULL, NULL, 'ENGKJV_DBS_HS/English-(1870)-Emphatic-Diaglott-New-Testament-(with-Greek)-Study-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('292', 'Syriac-1588-Gospel-Lectionary-Illuminated-WDL-7068', 'SYRGOSP', 'Syriac (1588) Gospel Lectionary - Illuminated(WDL-7068)', 'ܦܘܪܫ ܩܪ̈ܝܢܐ ܕܛܛܪܐ ܐܘܢܓܠܝܘܢ', 'Syriac (1588) Gospel Lectionary - Illuminated (WDL-7068) This Syriac manuscript, a Gospel lectionary from the 16th century, is a Purāš qeryānē d-ṭeṭrā ewangelyon, containing scripture lessons for specific divine services. The manuscript, written in Serto script for the main text and Estrangela for section titles, features two columns per page with 22 lines each. The black ink used for letters and red for titles and diacritical points has remained crisp over time, with little fading. The Estrangela script, the oldest Syriac script, occasionally appears in blue ink. The manuscript includes colorful tables with circular designs for the readings, and an ornately designed title page. Syriac, an eastern Aramaic dialect, was the language of Christians in regions stretching from the Roman Empire to the Arabian Sea from the first to the 12th century.', 'historic', 'https://www.wdl.org/en/item/7068', '97', 'syr', '1588', 'illuminated', 'World Digital Library', NULL, 'World Digital Library', 'SYRGOSP_DBS_HS/Syriac-(1588)-Gospel-Lectionary-Illuminated(WDL-7068)', 'syr', 'syr', 'Syriac', NULL, 'L', 'IQ', NULL, NULL, NULL, NULL, '858080', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('293', 'French-English-1817-New-Testament-Diglot-Le-Nouveau-Testament-de-notre-seigneur-Jesus-Christ', 'FRAOST', 'French-English (1817) New Testament Diglot', 'Le Nouveau Testament de notre seigneur Jésus-Christ', 'French-English (1817) New Testament Diglot, printed by Tilling and Hughes for the British and Foreign Bible Society, represents an early 19th-century effort to provide bilingual access to the New Testament scriptures. This edition facilitated comparative study and reading for those interested in both languages, serving educational purposes and aiding missionaries and bilingual speakers in their spiritual practices. The production of such diglots was part of the broader mission of the British and Foreign Bible Society to increase the availability of the Bible in multiple languages, thereby promoting both literacy and religious education. The choice of French alongside English reflects the significant linguistic and cultural connections between Britain and France during this period, as well as the recognition of French as a lingua franca in education and diplomacy.', 'historic', NULL, '1', 'fra', '1817', 'scan', 'The British and Foreign Bible Society', 'british-and-foreign-bible-society', NULL, 'FRAOST_DBS_HS/French-English-(1817)-New-Testament-Diglot-(Le-Nouveau-Testament-de-notre-seigneur-Jesus-Christ)', 'fra', 'stan1290', 'French', 'français', 'L', 'FR', '48', '2', '1', 'fr', '77200000', 'Andorra and France', 'Also in Algeria, Andorra, Austria, Belgium, Benin, Burkina Faso, Burundi, Cambodia, Cameroon, Canada, Central African Republic, Chad, Comoros, Congo, Côte d’Ivoire, Democratic Republic of the Congo, Djibouti, Equatorial Guinea, French Guiana, French Polynesia, Gabon, Guadeloupe, Guinea, Haiti, India, Israel, Italy, Lebanon, Libya, Luxembourg, Madagascar, Mali, Martinique, Mauritania, Mauritius, Mayotte, Monaco, Morocco, Mozambique, New Caledonia, Niger, Philippines, Puerto Rico, Réunion, Rwanda, Saint Pierre and Miquelon, Saudi Arabia, Senegal, Seychelles, South Africa, Switzerland, Togo, Tunisia, United Arab Emirates, United Kingdom, United States, U.S. Virgin Islands, Vanuatu, Wallis and Futuna.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('294', 'English-1902-The-Old-Testament-in-Art-Shaw', 'ENGSHAW', 'English (1902) The Old Testament in Art (Shaw)', NULL, 'The 1902 publication "The Old Testament in Art" by Walter Shaw Sparrow stands as a notable intersection of art and biblical studies. Walter Shaw Sparrow (1862–1940), a Welsh writer renowned for his expertise in art and architecture, brings a unique perspective to the exploration of biblical themes through visual art. Sparrow, with his deep interest in British sporting artists, extended his scholarly purview to encompass the rich tapestry of the Old Testament as depicted in various art forms.<br><br>Sparrow''s work in "The Old Testament in Art" is part of his broader contribution to the "Art and Life Library," a series that spanned over thirty years, reflecting his extensive knowledge in art, architecture, and furniture. This particular work delves into how artists have historically interpreted and visually represented stories and characters from the Old Testament, offering insights into the cultural and historical contexts of these artworks.<br><br>As a prolific writer, Sparrow also contributed numerous articles to magazines and newspapers, further establishing his reputation as an authority in his field. His ability to bridge the gap between the academic study of the Bible and the artistic representation of its narratives makes "The Old Testament in Art" a valuable resource for those interested in the intersection of religion, history, and art. Sparrow''s work remains a testament to the enduring power of the Old Testament narratives and their ability to inspire artistic expression across centuries.', 'historic', NULL, '27', 'eng', '1902', 'illuminated', 'Hodder & Stoughton', NULL, NULL, 'ENGSHAW_DBS_HS/English-(1902)-The-Old-Testament-in-Art-(Shaw)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('295', 'Aramaic-1514-Complutensian-Polyglot-Bible-Vol-2-of-5-Grk-Heb-Lat-Aramaic-StudyWDL-10636', 'AII1514', 'Aramaic (1514) Complutensian Polyglot Bible (Vol 2 of 5) Grk-Heb-Lat-Aramaic Study(WDL-10636)', 'Vetus testamentū multiplici lingua nūc primo impressum, Et imprimis Pentateuchus Hebraico Greco atq[ue] Chaldaico idiomate', 'The second volume of the Complutensian Polyglot Bible, completed in 1514 but distributed in 1520, is part of the first multilingual printed Bible, encompassing texts in Hebrew, Greek, Latin, and Aramaic. This ambitious project, led by Cardinal Francisco Jiménez de Cisneros, aimed to facilitate advanced scriptural studies at the newly revitalized University of Alcalá de Henares. The printing, executed by Arnaldo Guillén de Brocar, required the creation of new typefaces, particularly noted for the beauty of the Greek characters. Volumes two and three of the Bible include the remainder of the Old Testament, presented in parallel columns of Greek, Latin, and Hebrew, underscoring the work''s scholarly and typographic significance. This polyglot Bible marked a significant advancement in biblical scholarship, offering scholars unprecedented access to scriptural texts in their original languages alongside their translations, fostering a deeper understanding and study of the Bible during the Renaissance. The inclusion of Aramaic translations, such as the Targum Onkelos, and comprehensive dictionaries for Hebrew, Aramaic, and Greek in the later volumes, further contributed to the work''s utility for scholarly biblical study.', 'historic', 'https://www.wdl.org/en/item/10636', '223', 'aii', '1514', 'study', 'Arnao Guillén de Brocar, Alcalá de Henares', NULL, 'World Digital Library', 'AII1514_DBS_HS/Aramaic-(1514)-Complutensian-Polyglot-Bible-(Vol-2-of-5)-Grk-Heb-Lat-Aramaic-Study(WDL-10636)', 'aii', 'assy1241', 'Assyrian Neo-Aramaic', 'Sūreṯ', 'L', 'IQ', '36.75', '43', '6b', NULL, '626000', 'Iraq', 'Northern Iraq, Baghdad, Basrah, Karkuk, Arbil. Also in Armenia, Australia, Austria, Azerbaijan, Belgium, Brazil, Canada, Cyprus, France, Georgia, Germany, Greece, Iran, Italy, Lebanon, Netherlands, New Zealand, Russian Federation (Europe), Sweden, Switzerland, Syria, Turkey (Asia), United Kingdom, United States.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('296', 'English-1846-Phonotypic-New-Testament-Thi-Nu-Testament-ov-owr-Lord-and-savyur-Jizus-Crist', 'ENGPHO', 'English (1846) Phonotypic New Testament', NULL, 'English (1846) Phonotypic New Testament: Dr. Andrew Comstock, a physician and professor of elocution, created the “Fonetik” New Testament in 1846. His phonetic alphabet was designed to assist his students, especially those with speech impediments, in improving their speech. Comstock’s version of the New Testament was translated from the original Greek and compared with other translations for accuracy and revision. He believed his phonetic alphabet was superior among the seven known phonetic systems at that time. Comstock''s aim with this translation extended beyond speech improvement; he also hoped it would facilitate evangelism among non-native English speakers, including "the heathen." A rare first edition, as noted by Dr. Paul Keen, it includes a table within the text explaining the phonetic characters and the sounds they represent.', 'historic', NULL, '36', 'eng', '1846', 'scan', 'Zac Pitmun', NULL, NULL, 'ENGPHO_DBS_HS/English-(1846)-Phonotypic-New-Testament-(Thi-Nu-Testament-ov-owr-Lord-and-savyur-Jizus-Crist)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('297', 'English-1782-Robert-Aitken-KJV-Bible', 'ENGKJV', 'English (1782) Robert Aitken KJV Bible', NULL, 'The 1782 Robert Aitken KJV Bible holds a special place in American history as the first complete English Bible printed in the United States. This milestone was achieved in the aftermath of the War of Independence, a time when there was a notable shortage of Bibles in America. Published by Robert Aitken and printed in Philadelphia, this edition of the King James translation was unique in that it carried an American imprint. <br><br>Prior to American independence, Great Britain had prohibited the American colonies from printing copies of the Bible. However, the newfound independence allowed for the publication of Bibles in America. The Aitken Bible was not only printed locally but also received approval and recommendation from the chaplains of the United States Congress, both the Senate and the House. This Bible is noted for its translation from the original Greek and its comparison with other English translations. An interesting aspect of the Aitken Bible is that the text of the New Testament is not paginated in the traditional sense; it flows continuously from book to book. Additionally, there are a few textual errors within this edition. Despite these minor issues, the Robert Aitken KJV Bible remains a significant historical artifact, symbolizing both American independence and the growing importance of religious freedom in the new nation.', 'historic', NULL, '245', 'eng', '1782', 'scan', NULL, NULL, NULL, 'ENGKJV_DBS_HS', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('298', 'English-1552-Jugge''s-Tynalde-NT', 'ENGTYN', 'English (1552) Jugge''s Tynalde New Testament', NULL, 'Richard Jugge, believed to have been born in Waterbeach, Cambridgeshire, was an eminent figure in the early history of English printing. Educated at Eton and King''s College, Cambridge, Jugge became a freeman of the Stationers'' Company in 1541 and began his notable work in printing the New Testament in English, dated 1550. His contributions to printing were not just technical but also artistic, as Joseph Ames in Typographical Antiquities notes, Jugge was "very curious, in his editions of both the Old and New Testament, bestowing not only a good letter, but many elegant initial letters and fine wooden cuts."<br><br>A foundational member of the Stationers'' Company, Jugge held significant positions within the organization, serving as Warden in 1560, 1563, and 1566, and as Master in 1568, 1569, 1573, and 1574. With the accession of Queen Elizabeth, Jugge, alongside John Cawood, was appointed Royal Printer. After Cawood''s passing, Jugge briefly enjoyed the sole privileges of this patent but soon found the responsibility burdensome, particularly in producing Bibles.<br><br>Jugge''s struggle with the volume of work required for Bible production is evident in his output. It took him two years to complete an octavo Testament, and he managed only two folio Bibles in the same period that his predecessors, Richard Grafton and Edward Whitchurch, had produced seven. This slow rate of production was a concern for both the Government and the Church. Consequently, after extensive deliberations over these grievances, Jugge was instructed to limit his printing to the quarto Bible and the Testament in sextodecimo.', 'historic', NULL, '209', 'eng', '1552', 'illuminated', 'GreatSite.com', NULL, NULL, 'ENGTYN_DBS_HS', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('299', 'English-1425-Wycliffe-New-Testament', 'ENGWYC', 'English (1425) Wycliffe New Testament', NULL, 'The Wycliffe Bible, named after the influential theologian John Wycliffe, is a collection of Bible translations into Middle English carried out from around 1382 to 1395. These translations played a pivotal role in the genesis of the Lollard movement, a precursor to the Reformation, which challenged many doctrines of the Roman Catholic Church. During the early Middle Ages, Western Christians primarily experienced the Bible through Latin oral recitations, homilies, mystery plays, and iconography. However, literacy was limited, prompting Wycliffe to advocate for a vernacular Bible, believing it would make the Gospel more accessible to the common people.<br><br>Initially credited solely to Wycliffe, these translations are now understood to be collaborative efforts involving several translators, including Nicholas of Hereford, John Purvey, and possibly John Trevisa. They encompassed not only canonical texts but also those later termed ''Apocrypha'' by Protestants (or ''deuterocanonical'' by Catholics) and books like 3 Esdras (now known as 2 Esdras) and Paul’s epistle to the Laodiceans.<br><br>The Wycliffe Bible, despite being unauthorized, gained substantial popularity. It became the most widespread manuscript literature in Middle English, with over 250 surviving copies, one of which fetched US$1,692,500 at a 2016 auction.<br><br>The association of the Wycliffe Bible with Lollardy led to severe suppression efforts by the English monarchy and the Catholic Church. Henry IV, Archbishop Thomas Arundel, and Henry Knighton were among those who criticized the translations and implemented strict religious censorship laws. Even two decades after Wycliffe''s death, the Oxford Convocation of 1408 decreed that no new Bible translations were to be made without approval. However, since these translations were based on the Latin Vulgate and contained no heterodox content, ecclesiastical authorities struggled to distinguish the banned versions. This ambiguity led many 15th and 16th-century Catholic commentators, including Thomas More, to mistakenly consider these manuscripts as representing an earlier, orthodox translation. As a result, manuscripts of the Wycliffe Bible, often falsely dated before the 1409 ban, circulated widely and were frequently used by both clergy and laity.', 'historic', 'https://en.wikipedia.org/wiki/Wycliffe%27s_Bible', '10', 'eng', '1425', 'scan', NULL, NULL, NULL, 'ENGWYC_DBS_HS/English-(1425)-Wycliffe-New-Testament', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('300', 'English-1890-Newberry-Study-Bible-KJV', 'ENGKJV', 'English (1890) Newberry Study Bible (KJV)', NULL, 'The 1890 Newberry Study Bible represents a pivotal moment in the evolution of Bible printing and distribution in America, a period marked by both technological advancements and a burgeoning public demand. Initially, the American landscape for Bible printing was sparse, predominantly reliant on imports from British and European sources. However, by the late eighteenth and early nineteenth centuries, significant advancements in printing technology catalyzed a surge in domestic Bible production. Metropolitan hubs like Boston, Philadelphia, and New York emerged as primary centers for Bible publishing, effectively revolutionizing the availability of this sacred text in the United States.<br><br>Paul Gutjahr, a renowned Bible historian, notes that during the eighteenth century, the Bible was not just a religious artifact but a cultural phenomenon, widely regarded as the "most printed, most distributed, and most read written text in North America." Its ubiquity in American homes transcended mere spiritual devotion; it became a cherished familial heirloom, linking generations and preserving ancestral ties. This deep personal connection spurred publishers to produce editions that were not only textual but also artistic masterpieces. Ornate, sometimes vividly colored covers and intricate illustrations became commonplace, transforming the Bible into a symbol of both piety and familial pride. These exquisitely crafted editions often found a place of honor in family homes, displayed prominently as a testament to both faith and heritage. The Newberry Study Bible, in this context, stands as a testament to America''s deep-seated reverence for the Bible and its evolving role in both religious and familial life.', 'historic', NULL, '290', 'eng', '1890', 'study', NULL, NULL, NULL, 'ENGKJV_DBS_HS/English-(1890)-Newberry-Study-Bible-(KJV)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('301', 'English-1886-Parallel-Bible-KJV-and-RV', 'ENGREV', 'English (1886) Parallel Bible (KJV and RV)', NULL, 'The 1886 Parallel-Column Edition Holy Bible presents a unique and insightful way to study the scriptures by juxtaposing two significant versions of the Bible: the King James Version (KJV) and the Revised Version (RV). This edition allows readers to compare and contrast these two influential texts side by side, offering a deeper understanding of the nuances and evolution of biblical translation.<br><br>The King James Version, completed in 1611, is renowned for its majestic language and has had a profound influence on English literature and religious life. The Revised Version, completed in 1885, was the first major revision of the KJV, undertaken by British scholars who sought to correct and update the language and to incorporate findings from more recent biblical scholarship and manuscripts discoveries.<br><br>By placing these versions in parallel columns, this edition provides a fascinating perspective on the development of biblical language and interpretation. It enables readers to see how certain passages and phrases have been rendered differently over time, reflecting changes in language, culture, and understanding of the biblical texts. This Parallel-Column Edition is not only a valuable tool for study and comparison but also serves as a testament to the enduring nature of the Bible and its continuous relevance in changing times.', 'historic', NULL, '323', 'eng', '1886', 'scan', 'University Press', NULL, NULL, 'ENGREV_DBS_HS/English-(1886)-Parallel-Bible-(KJV-and-RV)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('302', 'Greek-0320-Codex-Sinaiticus-facsimile-manuscript', 'GRCSINA', 'Greek (0320) Codex Sinaiticus facsimile manuscript', 'Κώδικας Σιναϊτικός (0320, χειρόγραφο ομοίωμα)', 'The Codex Sinaiticus, dating to around 320–350 AD, is one of the oldest and most complete manuscripts of the Christian Bible in Greek. Written on vellum (parchment) in uncial script, it contains large portions of both the Old Testament (Septuagint) and the New Testament, making it a critical resource for biblical scholarship and the study of early Christianity.<br><br>The manuscript was discovered in the mid-19th century at Saint Catherine’s Monastery on Mount Sinai by Constantin von Tischendorf, a German biblical scholar. It is considered one of the four great uncial codices, alongside Codex Vaticanus, Codex Alexandrinus, and Codex Ephraemi Rescriptus. Unlike later medieval manuscripts, Codex Sinaiticus does not follow the Byzantine text-type, but rather exhibits a more diverse and ancient textual tradition, making it invaluable for reconstructing the earliest forms of the Bible.<br><br>A facsimile edition of Codex Sinaiticus refers to a precise reproduction of the original manuscript, allowing scholars, institutions, and collectors to study its contents without needing access to the fragile and priceless original. These facsimiles are produced using high-resolution photography and meticulous printing techniques, ensuring that even damaged sections, corrections, and marginal notes remain visible.<br><br>The manuscript originally contained the entire Bible, but over the centuries, some portions have been lost. It is written in four columns per page, an unusual format for ancient biblical manuscripts, suggesting that it was a lavish and expensive production, possibly commissioned for imperial or ecclesiastical use. It also includes books not found in later biblical canons, such as the Shepherd of Hermas and the Epistle of Barnabas, highlighting the diversity of early Christian scripture.<br><br>Today, Codex Sinaiticus is split across multiple locations: the British Library (London), Leipzig University Library, the National Library of Russia (St. Petersburg), and Saint Catherine’s Monastery. Digital facsimiles are now widely available, allowing scholars and the public to explore this foundational biblical manuscript, which continues to shape textual criticism, theology, and the understanding of early Christian scripture.', 'historic', NULL, '53', 'grc', '320', 'manuscript', NULL, NULL, NULL, NULL, 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('303', 'Greek-1896-Swete-Old-Testament-Septuagint-Vol-1-3-OT', 'GRCSWET', 'Greek (1896) Swete Old Testament (Septuagint) Vol 1-3 - OT', 'Παλαιά Διαθήκη του Swete (1896, Σεπτουαγίντα, Τόμος 1-3)', 'The "Old Testament in Greek according to the Septuagint" by Henry Barclay Swete, published between 1887 and 1894, is a critical work in biblical scholarship. Henry Barclay Swete, an eminent English biblical scholar born on March 14, 1835, in Bristol, became the Regius Professor of Divinity at Cambridge in 1890. He is particularly renowned for his 1906 commentary on the Book of Revelation and other significant works of exegesis.<br><br>Swete''s contribution to the study of biblical texts is highly regarded. His edition of the Greek text of the Old Testament, completed in a series by 1894 (with a third edition in 1901-1907), is a monumental work. This edition presents the Old Testament as translated into Greek in the ancient text known as the Septuagint. The Septuagint is a crucial source for understanding the textual history and interpretation of the Old Testament, particularly in the context of early Christianity and Hellenistic Judaism.<br><br>In addition to his work on the Septuagint, Swete also published the Greek text of the Gospel of St. Mark with notes and introduction in 1898 (second edition in 1902) and that of the Apocalypse of St. John in 1906 (second edition in 1907). His scholarly efforts have made significant contributions to the field of biblical studies, providing valuable resources for both theological scholarship and the study of ancient texts.', 'historic', NULL, '149', 'grc', '1896', 'scan', 'The University Press', NULL, NULL, 'GRCSWET_DBS_HS/Greek-(1896)-Swete-Old-Testament-(Septuagint)-Vol-1-3-OT', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('304', 'English-1810-Wycliffe-New-Testament-Henry-Baber-Edition', 'ENGWY1810', 'English (1810) Wycliffe New Testament (Henry Baber Edition)', NULL, 'The 1810 edition of the New Testament translated by John Wycliffe, often referred to as the Wycliffe New Testament, is a significant historical publication in the realm of biblical translations. Wycliffe, a prominent theologian of the 14th century, completed his translation around 1380, marking it as one of the earliest versions of the New Testament in English. This particular edition, reprinted from the later Wycliffite version, was edited by Reverend Henry Hervey Baber, an Assistant Librarian of the British Museum.<br><br>Baber''s edition not only provided a reprint of the translation as edited by Lewis in 1731 but also included new preliminary materials. These additions comprised memoirs of the life, opinions, and writings of Dr. John Wycliffe, as well as an historical account of the Saxon and English versions of the Scriptures up to the fifteenth century. Baber’s work offered valuable insights into the context and significance of Wycliffe''s translation in the history of English Bible translations.<br><br>The 1810 edition is notable for featuring a portrait of John Wycliffe as its frontispiece, further emphasizing the historical importance of Wycliffe''s work. Wycliffe''s translation, carried out during a time when Latin was the dominant language for scriptural texts, played a crucial role in making the scriptures more accessible to the English-speaking lay population, and paved the way for subsequent translations.', 'historic', 'https://greatsite.com/ancient-rare-bibles-books/bibles/w1810es/', '88', 'eng', '1810', 'scan', 'The Rev. Henry Hervey Baber, M. A.', NULL, NULL, 'ENGWY1810_DBS_HS/English-(1810)-Wycliffe-New-Testament-(Henry-Baber-Edition)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('305', 'Greek-1906-Old-Testament-in-Greek-Codex-Vaticanus-Vol-1-9-OT', 'GRCVATI', 'Greek (1906) Old Testament in Greek (Codex Vaticanus) Vol 1-9 - OT', 'Παλαιά Διαθήκη στα Ελληνικά (1906, Κώδικας Βατικανός, Τόμος 1-9)', 'The 1906 publication "The Old Testament in Greek," edited by Alan England Brooke, D.D., is a significant scholarly work focused on the Greek translation of the Old Testament, known as the Septuagint. Brooke, an English academic and theologian, utilized the text of the Codex Vaticanus, one of the oldest and most important extant Greek manuscripts of the Bible, as the primary source for this work. Additionally, he supplemented the text with readings from other uncial manuscripts.<br><br>The critical apparatus accompanying the text in this nine-volume series presents the variants of the chief ancient authorities for the text of the Septuagint. This feature makes the work an invaluable resource for scholars engaged in textual criticism and the study of the Septuagint.<br><br>Alan England Brooke, born in 1863 and educated at Eton College and King''s College, Cambridge, had a distinguished academic career. He was a Fellow of King''s College from 1889 to 1926 and later served as its Provost from 1926 to 1933. Ordained as a priest in the Church of England in 1904, Brooke also held positions as Ely Professor of Divinity from 1916 to 1926 and Canon of Ely during the same period. Additionally, he served as an Honorary Chaplain to the King from 1918 until his death in 1939.<br><br>Brooke''s work on the Old Testament in Greek according to the Codex Vaticanus is a testament to his scholarly rigor and dedication to the study of biblical texts. His edition remains a critical resource for understanding the Septuagint and the textual history of the Old Testament.', 'historic', NULL, '111', 'grc', '1906', 'study', 'Cambridge University Press', NULL, NULL, 'GRCVATI_DBS_HS/Greek-(1906)-Old-Testament-in-Greek-(Codex-Vaticanus)-Vol-1-9-OT', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('306', 'English-1905-Samuel-Loyd-Corrected-English-New-Testament', 'ENGLOYD', 'English (1905) Samuel Loyd Corrected English New Testament', NULL, 'The 1905 "Corrected English New Testament," edited by Samuel Lloyd, stands as a unique contribution to the field of biblical translation. As a wealthy Quaker and a life governor of the British and Foreign Bible Society, Lloyd embarked on this revision project without formal academic credentials, yet with a dedication to scholarly rigor. His work was not officially sponsored by the British and Foreign Bible Society, a fact contrary to what the title might suggest.<br><br>Lloyd''s revision relied on Nestle''s resultant text, reflecting the evolving biblical scholarship of the time. He collaborated with eminent scholars to ensure accuracy and scholarly depth. The preface by the Bishop of Durham added ecclesiastical weight to the work. Published in London by Samuel Bagster in 1905, this version was part of Lloyd''s effort to commemorate the centenary of the British and Foreign Bible Society in 1904. This venture highlights the significant role individuals outside traditional academic and religious circles can play in the dynamic world of biblical interpretation and translation.', 'historic', NULL, '84', 'eng', '1905', 'scan', NULL, NULL, NULL, 'ENGLOYD_DBS_HS/English-(1905)-Samuel-Loyd-Corrected-English-New-Testament', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('307', 'French-1839-New-Testament-Antoine-Eugene-Genoude', 'FRAOST', 'French (1839) New Testament', 'Nouveau Testament (1839)', 'French (1839) New Testament Antoine Godeau, the Bishop of Grasse, released a French New Testament translation from the Vulgate in 1668, spanning two octavo volumes. Godeau''s work is recognized for balancing between a direct translation and paraphrase, offering a unique take on the scriptures. Nicolas Legros later published an anonymous translation in Cologne, 1739, which, when reissued with his name, faced criticism from prominent Catholic figures like Bossuet and Cardinal de Noailles for alleged Socinian tendencies. This edition highlights the complexities of translating sacred texts in a period marked by religious and doctrinal scrutiny.', 'historic', NULL, '80', 'fra', '1839', 'scan', NULL, NULL, 'Google', 'FRAOST_DBS_HS/French-(1839)-New-Testament-(Antoine-Eugene-Genoude)', 'fra', 'stan1290', 'French', 'français', 'L', 'FR', '48', '2', '1', 'fr', '77200000', 'Andorra and France', 'Also in Algeria, Andorra, Austria, Belgium, Benin, Burkina Faso, Burundi, Cambodia, Cameroon, Canada, Central African Republic, Chad, Comoros, Congo, Côte d’Ivoire, Democratic Republic of the Congo, Djibouti, Equatorial Guinea, French Guiana, French Polynesia, Gabon, Guadeloupe, Guinea, Haiti, India, Israel, Italy, Lebanon, Libya, Luxembourg, Madagascar, Mali, Martinique, Mauritania, Mauritius, Mayotte, Monaco, Morocco, Mozambique, New Caledonia, Niger, Philippines, Puerto Rico, Réunion, Rwanda, Saint Pierre and Miquelon, Saudi Arabia, Senegal, Seychelles, South Africa, Switzerland, Togo, Tunisia, United Arab Emirates, United Kingdom, United States, U.S. Virgin Islands, Vanuatu, Wallis and Futuna.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('308', 'Greek-1890-Triglot-Bible-Vol.-1-2-Hebrew-Latin', 'GRCTRIG', 'Greek (1890) Triglot Bible (Vol. 1-2) Hebrew Latin', 'Τριγλωττίκη Βίβλος (1890, Τόμος 1-2, Εβραϊκά-Λατινικά)', 'The 1890 "Triglot Bible," published in two volumes by R.D. Dickinson, is an extensive compilation that brings together the Holy Scriptures of the Old and New Testaments in multiple languages. This edition is particularly notable for including texts in their original tongues, along with significant translations, arranged in parallel columns for comparative study.<br><br>The Triglot Bible contains the original Hebrew text of the Old Testament, the Greek text of the New Testament, and the Greek Septuagint, which is an ancient Greek translation of the Hebrew Bible. Additionally, it includes the Syriac version of the New Testament and the Latin Vulgate version, which has been a pivotal text in the history of Christianity, especially in the Western Church.<br><br>This arrangement allows readers to compare the texts side-by-side, offering valuable insights into the translation and interpretation of biblical texts across different languages and traditions. The inclusion of a complete prolegomenon provides further context and scholarly background, enhancing the study experience.<br><br>The Triglot Bible is a significant resource for scholars, theologians, and students of biblical languages and texts. It serves as a comprehensive tool for understanding the nuances and variations in the translation and transmission of the biblical scriptures throughout history.', 'historic', NULL, '254', 'grc', '1890', 'study', 'Richard D. Dickinson', NULL, NULL, 'GRCTRIG_DBS_HS/Greek-(1890)-Triglot-Bible-(Vol.-1-2)-Hebrew-Latin', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('309', 'English-1568-Bishops-Bible', 'ENGBSB', 'English (1568) Bishops Bible (Text)', NULL, 'The Bishops'' Bible, an English translation produced under the authority of the Church of England, was first published in 1568 and significantly revised in 1572. The 1602 edition of this Bible was used as the base text for the King James Bible, completed in 1611. It succeeded the Great Bible of 1539, the first authorized English Bible, and the Geneva Bible of 1557-1560.<br><br>The Calvinistic leanings of the Geneva Bible, particularly evident in its marginal notes, were a point of contention for the high-church party of the Church of England, to which most bishops adhered. They sought to replace the Geneva translation, perceived as favoring Presbyterianism over Episcopalian church governance, with their own version, which became known as the "Bishops'' Bible."<br><br>Archbishop of Canterbury Matthew Parker was the driving force behind this translation. The early editions carried the initials of the translating bishops, a measure intended by Parker to ensure accountability. However, the lack of a supervisory editor led to inconsistent translation practices across different books.<br><br>Interestingly, the Bishops'' Bible portrayed Queen Elizabeth I flanked by allegorical figures of Faith and Charity, representing Hope, with a Latin text from Romans 1:16 beneath her portrait. The Apocrypha in this Bible, largely unchanged from the Great Bible and translated from the Latin Vulgate, suggested that it was not entirely translated from original tongues.<br><br>The 1572 revision saw alterations toward more ecclesiastical language and attempts to align with the Geneva Bible. The Bishops'' Bible was intended for use in churches rather than as a domestic Bible. Its grandiloquent style differed from the Geneva Bible, and while it included 124 full-page illustrations in its first edition, later editions were smaller and mostly illustration-free. The Bishops'' Bible did not replace the Geneva Bible in popularity but went through over 50 editions, compared to the Geneva Bible''s over 150 reprints. The last complete edition of the Bishops'' Bible was in 1602, although the New Testament continued to be reissued until at least 1617. William Fulke''s parallel editions, contrasting it with the Rheims New Testament, were published until 1633.', 'historic', 'https://en.wikipedia.org/wiki/Bishops%27_Bible#References', '149', 'eng', '1572', 'reprint', NULL, NULL, NULL, 'ENGBSB_DBS_HS/English-(1568)-Bishops-Bible', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('310', 'English-1869-Noyles-New-Testament-Tischendorf', 'ENGNOY', 'English (1869) Noyles New Testament (Tischendorf)', NULL, 'The 1869 publication of George R. Noyes'' translation of the New Testament, based on the Greek text of Tischendorf, is a noteworthy contribution to biblical scholarship. Published posthumously by the American Unitarian Association, this work is the culmination of Noyes'' lifelong dedication to biblical literature and translation. <br><br> George Rapall Noyes (1798-1868), a Harvard University professor, was renowned for his expertise in Hebrew and his insightful lectures on Biblical literature. Prior to his New Testament translation, Noyes had published annotated translations of several Old Testament books, starting with Job, Ecclesiastes, and the Canticles in 1828, followed by Psalms and Proverbs in 1830, and the Prophets in 1833, with subsequent revised editions. <br><br> Noyes'' New Testament is a revision of the King James Version, meticulously aligned with Tischendorf''s Greek text. It is characterized by its conservative approach, maintaining a balance between literal accuracy and readability, avoiding the pitfalls of over-interpretation while ensuring critical accuracy. The translation does not exhibit a discernible Unitarian bias, contrary to what might be expected given Noyes'' affiliation. This lack of bias underscores Noyes'' commitment to scholarly integrity over doctrinal influence. <br><br> Edited by his Harvard colleague Ezra Abbott, Noyes'' New Testament stands as a testament to his scholarly rigor. It offers a valuable resource for serious Bible students, providing a version that is both more intelligible and critically accurate than its predecessors. Michael Marlowe’s assessment in March 2012 appreciates this translation''s honest and helpful nature, despite some interpretative liberties. This translation remains a significant scholarly work, bridging the gap between the original text and contemporary understanding.', 'historic', NULL, '87', 'eng', '1869', 'scan', 'American Unitarian Association', NULL, NULL, 'ENGNOY_DBS_HS/English-(1869)-Noyles-New-Testament-(Tischendorf)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('311', 'English-1851-Commonly-Received-New-Testament', 'ENGCOM', 'English (1851) Commonly Received New Testament', NULL, 'English (1851) Commonly Received New Testament: The 1850 edition of the New Testament, known as the "Commonly Received Version," holds a unique place in the history of biblical translations. Edited by Spencer H. Cone and William H. Wyckoff, this version represents a moderate revision of the King James Version (KJV) New Testament. It was a product of the American and Foreign Bible Society, an organization founded by American Baptists in 1837 to support Baptist missionary translators.<br><br>The production of this edition was surrounded by internal debates within the Society about the appropriateness and necessity of revising the KJV. Eventually, the decision to proceed with a provisional edition came at the suggestion of a Society member. This initiative was further supported by Deacon William Colgate, the Society''s Treasurer, who personally financed the creation of the plates and printing. Cone and Wyckoff’s efforts were not intended for immediate adoption by the Society but were rather a demonstration of potential emendations to the existing KJV.<br><br>This edition is notable for its preface, where the editors clarified their intentions - not to offer a final product for the Society''s use but to present a sample of possible changes. The plates of this provisional edition were offered to the Society if found desirable. The edition serves as a fascinating example of the evolving views on biblical translation within 19th-century American religious circles, highlighting the tensions between tradition and the desire for modernization in scriptural interpretation.', 'historic', NULL, '51', 'eng', '1851', 'scan', 'E. H. Tripp', NULL, NULL, 'ENGCOM_DBS_HS/English-(1851)-Commonly-Received-New-Testament', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('312', 'English-1853-Tanach-Hebrew-Bible-Leeser', 'ENGTHB', 'English (1853) Tanach Hebrew Bible (Leeser)', NULL, 'The Twenty-four Books of the Holy Scriptures: Carefully Translated According to the Massoretic Text, On the Basis of the English Version, After the Best Jewish Authorities; and supplied with short explanatory notes. By Isaac Leeser. Philadelphia, 1853.<br><br>Isaac Leeser (1806-1868) was a leading figure among American Jews during the 1840’s and 50’s. He was born in Germany, and came to America at the age of seventeen. He was a devout Jew, and became the cantor of his congregation, and shortly thereafter the regular preacher. He was the first to preach sermons in English from the lecturn. He devoted himself to educational projects, became prominent as a writer and publisher of Jewish books, and, perhaps most important of all, founded and edited a monthly Jewish magazine, called The Occident and American Jewish Advocate. His Twenty-four Books of the Holy Scriptures (published by himself in 1853) was a revision of the King James Version, in which he aimed to substitute Jewish for Christian interpretations, and generally to improve the accuracy of the version.', 'historic', NULL, '33', 'eng', '1853', 'scan', 'Hebrew Publishing Company', NULL, NULL, 'ENGTHB_DBS_HS/English-(1853)-Tanach-Hebrew-Bible-(Leeser)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('313', 'English-1861-Pictorial-Bible-Vol.-2-Judges-Job-Study', 'ENGPICT', 'English (1861) Pictorial Bible (Vol. 2) Judges - Job (Study)', NULL, 'The 1861 edition of "The Pictorial Bible," edited by John Kitto, D.D., F.S.A., stands as a monumental work in the realm of biblical literature. This volume, part of a four-volume series, covers from Genesis to Joshua, providing a comprehensive visual and scholarly journey through these foundational books of the Old Testament. Kitto''s work is renowned for its integration of steel engravings and numerous woodcuts, which vividly depict landscape scenes, natural history, customs, and antiquities.<br><br>John Kitto, an eminent biblical scholar of his time, augmented the authorized version of the Bible with original notes that explain passages linked to the history, geography, natural history, literature, and antiquities of the Scriptures. These notes are particularly notable for their reliance on the discoveries of contemporary travelers and scholars, making this edition an invaluable resource for understanding the historical and cultural context of the biblical narrative.<br><br>Published in London by W. and R. Chambers, this new edition of "The Pictorial Bible" was aimed at bringing the biblical world to life for its readers. It was designed to be more than just a religious text; it was an educational tool that merged the sacred scriptures with the burgeoning fields of archaeology and oriental studies. The detailed illustrations and comprehensive notes provided a deeper, more textured understanding of the Bible, making it an essential addition to the libraries of scholars, clergy, and laypeople interested in a more profound comprehension of biblical times and teachings.', 'historic', NULL, '191', 'eng', '1861', 'study', 'W. and R.Chambers', NULL, NULL, 'ENGPICT_DBS_HS/English-(1861)-Pictorial-Bible-(Vol.-2)-Judges-Job-(Study)', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('314', 'English-1837-Four-Gospels-Translation-Campbell-Bible-Vol.1-2-Gospels', 'ENGCAM', 'English (1837) Four Gospels Translation (Campbell) Bible - Vol.1-2 Gospels', NULL, 'English (1837) Four Gospels Translation (Campbell) Bible - Vol.1-2 Gospels: Alexander Campbell, an early leader of the Restoration Movement, edited and published "The Sacred Writings of the Apostles and Evangelists of Jesus Christ, Commonly Styled The New Testament."<br><br>This translation was based on the works of George Campbell, James MacKnight, and Philip Doddridge, who were all doctors of the Church of Scotland.<br><br>The translation included prefaces to the historical and epistolary books, as well as an appendix with critical notes and various translations of difficult passages.<br><br>The first edition was published in Buffaloe, Virginia (now Bethany, West Virginia) in 1826, followed by subsequent editions in 1828, 1832, and 1835.<br><br>The work was frequently reprinted, with recent reprints by the Gospel Advocate Co. in 1974.<br><br>Most printings were titled "The Living Oracles," which became the common name for this version.<br><br>The fourth edition in 1835 corrected an earlier error regarding Doddridge''s affiliation and indicated that the translations by the three doctors had been revised by Alexander Campbell.<br><br>This edition was titled “The Sacred Writings of the Apostles and Evangelists of Jesus Christ, Translated from the Original Greek by Doctors George Campbell, James MacKnight, and Philip Doddridge. With Prefaces, Various Emendations, and an Appendix. By Alexander Campbell” and was printed by M’Vay & Ewing in Bethany, Virginia.', 'historic', NULL, '189', 'eng', '1837', 'scan', 'Gould and Newman', NULL, NULL, 'ENGCAM_DBS_HS/English-(1837)-Four-Gospels-Translation-(Campbell)-Bible-Vol.1-2-Gospels', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('315', 'Greek-Latin-1519-Erasmus-Greek-Latin-NT', 'GRCERAS', 'Greek - Latin (1519) Erasmus Greek Latin New Testament', 'Ελληνική-Λατινική Καινή Διαθήκη του Έρασμου (1519)', 'Erasmus of Rotterdam, a central figure in the Renaissance movement and the greatest scholar of his day, played a pivotal role in biblical studies. His work, the Greek-Latin New Testament, first printed in 1519, marked a significant step in returning to the original sources of Christian knowledge. Erasmus believed in the transformative power of what he termed the "philosophy of Christ" and dedicated his life to the study and publication of the Bible and early Church writings.<br><br>Erasmus''s Greek New Testament, titled "Novum Instrumentum," included his own Latin translation alongside the Greek text. This edition highlighted weaknesses in the Latin Vulgate, which had been the primary Bible of the Church for over a millennium. By dedicating this New Testament to Pope Leo X, Erasmus sought papal endorsement, potentially to shield against criticism. He viewed his work as a new tool for the revival of Christian spirituality, emphasizing a return to the biblical roots of faith.<br><br>Martin Luther, during his time at Wartburg Castle, utilized Erasmus''s second edition for his German translation of the Bible. Luther often preferred Erasmus’s Greek readings over the Vulgate. This had a ripple effect, influencing many vernacular translations across Europe, including Dutch, English, Swedish, Danish, and Finnish versions, which either directly translated from or referenced Luther''s German text. Erasmus’s work thus became instrumental in shaping the translation and understanding of the Bible in various European languages.', 'historic', NULL, '209', 'grc', '1519', 'study', NULL, NULL, NULL, 'GRCERAS_DBS_HS', 'grc', 'anci1242', 'Ancient Greek', 'ἙλληνικήHellēnikḗ', 'H', 'GR', '39.8155', '21.91293', '10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bible_history (_id, id, abbr, title, title_vernacular, description, collections, ref, filesize, iso, year, type, provider, org_id, digitizer, archive_id, language_iso, language_glotto_id, language_name, language_autonym, language_level, language_country_id, language_latitude, language_longitude, language_status_id, language_iso1, language_population, language_location, language_area, abr, tt, description_vernacular, dt, tp, pro, dg, aid, language_bibles, language_films, language_resources) VALUES ('316', 'English-1898-Young''s-Literal-Translation-of-the-Holy-Scriptures', 'ENGYLT', 'English (1898) Young''s Literal Translation of the Holy Scriptures', NULL, 'The English Bible translation known as Young''s Literal Translation (YLT) holds a unique place in the history of biblical translations. Crafted by Robert Young, the skilled compiler behind Young''s Analytical Concordance to the Bible and Concise Critical Comments on the New Testament, the YLT was first published in 1862. Robert Young''s approach to translation was driven by a commitment to textual fidelity. He primarily utilized the Textus Receptus (TR) for the New Testament and the Masoretic Text (MT) for the Old Testament. Young’s guiding principle, as he articulated in the preface to the first edition, was a strict adherence to the received texts, avoiding the conflation of translation with textual criticism. This approach was a conscious choice to keep the translation process distinct from the evolving field of textual criticism, a domain that requires a different set of scholarly skills.<br><br>In 1887, Young released a "Revised Version" of his translation. This revision remained faithful to the Received Text, reflecting Young''s belief in the separation of the translator''s role from that of the textual critic. The preface to this Revised Edition echoes his conviction, emphasizing the importance of transparency in the translation process, particularly when it comes to textual alterations.<br><br>After Young''s death on October 14, 1888, a further Revised Edition was published in 1898. This edition continued to rely on the Textus Receptus, as evidenced by specific word choices in Revelation 1:5 and 20:5. The 1898 revision, as outlined in the "Publishers'' Note to the Third Edition," sought to refine the translation further while maintaining its foundational principles. This effort to enhance accuracy while preserving the translation''s original approach underscores Young''s lasting influence in the realm of biblical translations.', 'historic', NULL, '156', 'eng', '1898', 'scan', 'G. A. Young & Co, Bible Publishers', NULL, NULL, 'ENGYLT_DBS_HS/English-(1898)-Young''s-Literal-Translation-of-the-Holy-Scriptures', 'eng', 'stan1293', 'English', NULL, 'L', 'GB', '53', '-1', NULL, 'en', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
