ase, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('22', 'ENGWORR', 'Worrell New Testament Bible', 'eng', 'Latn', '1904', 'US', 'Public Domain', NULL, '[1 items in bible_links.csv]', NULL, 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United States', 'The United States of America', '334998398', 'English', 'eng', 'USA', 'NA', '840', '506', 'Christianity', 'Britain''s American colonies broke with the mother country in 1776 and were recognized as the new nation of the United States of America following the Treaty of Paris in 1783. During the 19th and 20th centuries 37 new states were added to the original 13 as the nation expanded across the North American continent and acquired a number of overseas possessions. The two most traumatic experiences in the nation''s history were the Civil War (1861-65) in which a northern Union of states defeated a secessionist Confederacy of 11 southern slave states and the Great Depression of the 1930s an economic downturn during which about a quarter of the labor force lost its jobs. Buoyed by victories in World Wars I and II and the end of the Cold War in 1991 the US remains the world''s most powerful nation state. Since the end of World War II the economy has achieved relatively steady growth low unemployment and inflation and rapid advances in technology.', '''The U.S. is a country of 50 states covering a vast swath of North America with Alaska in the northwest and Hawaii extending the nation’s presence into the Pacific Ocean. Major Atlantic Coast cities are New York a global finance and culture center and capital Washington DC. Midwestern metropolis Chicago is known for influential architecture and on the west coast Los Angeles'''' Hollywood is famed for filmmaking.''', '1', '9147420', '213000000', '65', '20', '45', '341711', '954806', '0.59', '36', '38', '83', '99', '12', '21', 'Northern America', 'https://en.wikipedia.org/wiki/United_States', 'https://www.britannica.com/place/United-States', 'http://www.americanbible.org/', 'https://unitedbiblesocieties.org/locations/american-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-states/', 'https://images.bible.cloud/maps/summary/US-summary.pdf', NULL, 'https://www.nationsonline.org/oneworld/united_states.htm', 'https://curlie.org/Regional/North_America/United_States', 'https://operationworld.org/locations/united-states-of-america', NULL, 'https://joshuaproject.net/countries/US', 'https://prayercast.com/usa.html', 'https://player.vimeo.com/video/23173134', 'http://www.prayercast.com/downloads/direct_download.php?file=USA_dload_hi.mov', 'Worrell was brought up as a Landmark Baptist, but later in life converted to Pentecostalism. His translation reflects both traditions.<br><br>A. S. Worrell sought to update the accuracy and grammar of the King James Version in his translation of the New Testament and included his personal study notes in it as well.<br><br>Worrell introduced the work as follows:<br><br>This translation is the outgrowth of a solemn conviction that such a work was required of the writer by Him Whose he is, and Whom he seeks to serve. The translator, A. S. Worrell, spent two and one-half years devoted to the work. It was done with the view of pleasing the Supreme Critic, at Whose judgment bar he will have to account for the manner in which he has handled His word.<br><br>The work was begun and prosecuted under the distinct conviction that these New Testament Scriptures are the veritable word of God – His last revelation to this sin-cursed world. The translator believed that these Scriptures contain nothing but "live matter"; and that they are as true now and as applicable to man''s needs as a tripartite being as they ever were.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bibles (_id, abbr, title, iso, script, year, country_id, copyright, copyright_type, bible_links, bible_equivalents, language_iso, language_glotto_id, language_iso1, language_name, language_level, language_country_id, language_latitude, language_longitude, language_population, country_name, country_name_long, country_population, country_official_language, country_official_language_iso, country_iso_a3, country_continent_id, country_iso_num, country_language_count, country_religion_primary, country_introduction, country_overview, country_independent, country_landmass_km, country_population_christian, country_population_christian_percentage, country_population_catholic_percentage, country_population_protestant_percentage, country_population_refugee, country_population_migration, country_population_year_change, country_population_density_km, country_population_average_age, country_population_urban_percentage, country_population_literacy_percentage, country_region_code, country_region_id, country_region_name, country_url_wiki, country_url_britannica, country_url_national_society, country_url_ubs, country_url_factbook, country_url_factbook_pdf, country_url_human_development, country_url_nations_online, country_url_odp, country_url_operation_world, country_url_religious_freedom, country_url_joshua, country_url_prayercast, country_url_prayercast_video, country_url_prayercast_download, description, bible_pod, id, parent_bible_id, uuid, title_vernacular, description_short, description_vernacular, date, alphabet_name, alphabet_script, alphabet_fonts, pod, links, publishers, providers, equivalents, books, gbc, guid, description_reviewed, versification, numeral_system_id, reviewed, isbn13, back_text, cover, questionable, alphabet_unicode_pdf, alphabet_family, alphabet_type, alphabet_white_space, alphabet_open_type_tag, alphabet_complex_positioning, alphabet_requires_font, alphabet_unicode, alphabet_diacritics, alphabet_contextual_forms, alphabet_reordering, alphabet_case, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('23', 'ENGCHE', 'John Cheke Matthew', 'eng', 'Latn', '1550', 'GB', 'Public Domain', NULL, '[1 items in bible_links.csv]', NULL, 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United Kingdom', 'The United Kingdom of Great Britain and Northern Ireland', '67081000', 'English', 'eng', 'GBR', 'EU', '826', '101', 'Christianity', 'The United Kingdom has historically played a leading role in developing parliamentary democracy and in advancing literature and science. At its zenith in the 19th century the British Empire stretched over one-fourth of the earth''s surface. The first half of the 20th century saw the UK''s strength seriously depleted in two world wars and the Irish Republic''s withdrawal from the union. The second half witnessed the dismantling of the Empire and the UK rebuilding itself into a modern and prosperous European nation. As one of five permanent members of the UN Security Council and a founding member of NATO and the Commonwealth the UK pursues a global approach to foreign policy. The UK is also an active member of the EU although it chose to remain outside the Economic and Monetary Union. The Scottish Parliament the National Assembly for Wales and the Northern Ireland Assembly were established in 1999. The latter was suspended until May 2007 due to wrangling over the peace process but devolution was fully completed in March 2010.', 'The United Kingdom made up of England Scotland Wales and Northern Ireland is an island nation in northwestern Europe. England – birthplace of Shakespeare and The Beatles – is home to the capital London a globally influential centre of finance and culture. England is also site of Neolithic Stonehenge Bath’s Roman spa and centuries-old universities at Oxford and Cambridge.', '1', '241930', '33200000', '59.3', '8.9', '50', '133094', '260650', '0.53', '281', '40', '83', '99', '10', '154', 'Northern Europe', 'https://en.wikipedia.org/wiki/United_Kingdom', 'https://www.britannica.com/place/United-Kingdom', 'https://www.biblesociety.org.uk/', 'https://unitedbiblesocieties.org/locations/british-and-foreign-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-kingdom/', 'https://images.bible.cloud/maps/summary/UK-summary.pdf', 'https://hdr.undp.org/data-center/specific-country-data#/countries/USA', 'https://www.nationsonline.org/oneworld/united_kingdom.htm', 'https://curlie.org/Regional/Europe/United_Kingdom', 'https://operationworld.org/locations/united-kingdom-of-gb-ni', 'https://www.state.gov/countries-areas/united-kingdom/', 'https://joshuaproject.net/countries/GB', 'https://prayercast.com/england.html', 'https://player.vimeo.com/video/37676816', 'http://www.prayercast.com/downloads/direct_download.php?file=England_dload_hi.mov', 'Sir John Cheke (Cheek) (1514 – 1557) was an English classical scholar and statesman. One of the foremost teachers of his age, and the first Regius Professor of Greek at the University of Cambridge, he played a great part in the revival of Greek learning in England. He was tutor to Prince Edward, the future King Edward VI, and also sometimes to Princess Elizabeth. Of strongly Reformist sympathy in religious affairs, his public career as provost of King''s College, Cambridge, Member of Parliament and briefly as Secretary of State during King Edward''s reign was brought to a close by the accession of Queen Mary in 1553. He went into voluntary exile abroad, at first under royal licence (which he overstayed). He was captured and imprisoned in 1556, and under threat or apprehension of execution by the fire made a forced public recantation and affiliated himself to the Church of Rome. He died not long afterwards, filled with remorse for having forsworn his true belief from the infirmity of fear. His character, teaching and reputation were, however, admiringly and honourably upheld.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
