ase, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('24', 'ENGTYN', 'Tyndale New Testament', 'eng', 'Latn', '1522', 'GB', 'Public Domain', NULL, '[6 items in bible_links.csv]', '[1 items in bible_equivalents.csv]', 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United Kingdom', 'The United Kingdom of Great Britain and Northern Ireland', '67081000', 'English', 'eng', 'GBR', 'EU', '826', '101', 'Christianity', 'The United Kingdom has historically played a leading role in developing parliamentary democracy and in advancing literature and science. At its zenith in the 19th century the British Empire stretched over one-fourth of the earth''s surface. The first half of the 20th century saw the UK''s strength seriously depleted in two world wars and the Irish Republic''s withdrawal from the union. The second half witnessed the dismantling of the Empire and the UK rebuilding itself into a modern and prosperous European nation. As one of five permanent members of the UN Security Council and a founding member of NATO and the Commonwealth the UK pursues a global approach to foreign policy. The UK is also an active member of the EU although it chose to remain outside the Economic and Monetary Union. The Scottish Parliament the National Assembly for Wales and the Northern Ireland Assembly were established in 1999. The latter was suspended until May 2007 due to wrangling over the peace process but devolution was fully completed in March 2010.', 'The United Kingdom made up of England Scotland Wales and Northern Ireland is an island nation in northwestern Europe. England – birthplace of Shakespeare and The Beatles – is home to the capital London a globally influential centre of finance and culture. England is also site of Neolithic Stonehenge Bath’s Roman spa and centuries-old universities at Oxford and Cambridge.', '1', '241930', '33200000', '59.3', '8.9', '50', '133094', '260650', '0.53', '281', '40', '83', '99', '10', '154', 'Northern Europe', 'https://en.wikipedia.org/wiki/United_Kingdom', 'https://www.britannica.com/place/United-Kingdom', 'https://www.biblesociety.org.uk/', 'https://unitedbiblesocieties.org/locations/british-and-foreign-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-kingdom/', 'https://images.bible.cloud/maps/summary/UK-summary.pdf', 'https://hdr.undp.org/data-center/specific-country-data#/countries/USA', 'https://www.nationsonline.org/oneworld/united_kingdom.htm', 'https://curlie.org/Regional/Europe/United_Kingdom', 'https://operationworld.org/locations/united-kingdom-of-gb-ni', 'https://www.state.gov/countries-areas/united-kingdom/', 'https://joshuaproject.net/countries/GB', 'https://prayercast.com/england.html', 'https://player.vimeo.com/video/37676816', 'http://www.prayercast.com/downloads/direct_download.php?file=England_dload_hi.mov', 'The Tyndale Bible generally refers to the body of biblical translations by William Tyndale (c. 1494–1536). Tyndale''s Bible is credited with being the first English translation to work directly from Hebrew and Greek texts. Furthermore, it was the first English biblical translation that was mass-produced as a result of new advances in the art of printing.<br><br>The term Tyndale''s Bible is not strictly correct, because Tyndale never published a complete Bible. That task was completed by Miles Coverdale, who supplemented Tyndale''s translations with his own to produce the first complete printed Bible in English in 1535. Prior to his execution Tyndale had only finished translating the entire New Testament and roughly half of the Old Testament. Of the latter, the Pentateuch, Jonah and a revised version of the book of Genesis were published during his lifetime. His other Old Testament works were first used in the creation of the Matthew Bible and also heavily influenced every major English translation of the Bible that followed.<br><br>1525 Tyndale, William (The New Testament) [Cologne: Peter Quentell, 1525.]<br>[Only a fragment, ''The gospell of S. Mathew. The first Chapter [through] the xxii. Chapter.'', still remains in the Grenville Collection of the British Museum. 3,000 copies of the first ten sheets had been secretly printed before Tyndale had to flee Cologne to Worms, where he began his work afresh.]<br>Complete edition; Worms: Peter Quentell, 1526. Reprinted; New Testament translated by William Tyndale 1525. Facsimile of unique fragment of the uncompleted Cologne edition. Oxford: Clarendon Press, 1926.<br><br> (Wikipedia)', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
