ase, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('30', 'ENGSTEV', 'Stevens Epistles Bible - Pauls Epistles', 'eng', 'Latn', '1898', 'US', 'Public Domain', NULL, '[1 items in bible_links.csv]', NULL, 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United States', 'The United States of America', '334998398', 'English', 'eng', 'USA', 'NA', '840', '506', 'Christianity', 'Britain''s American colonies broke with the mother country in 1776 and were recognized as the new nation of the United States of America following the Treaty of Paris in 1783. During the 19th and 20th centuries 37 new states were added to the original 13 as the nation expanded across the North American continent and acquired a number of overseas possessions. The two most traumatic experiences in the nation''s history were the Civil War (1861-65) in which a northern Union of states defeated a secessionist Confederacy of 11 southern slave states and the Great Depression of the 1930s an economic downturn during which about a quarter of the labor force lost its jobs. Buoyed by victories in World Wars I and II and the end of the Cold War in 1991 the US remains the world''s most powerful nation state. Since the end of World War II the economy has achieved relatively steady growth low unemployment and inflation and rapid advances in technology.', '''The U.S. is a country of 50 states covering a vast swath of North America with Alaska in the northwest and Hawaii extending the nation’s presence into the Pacific Ocean. Major Atlantic Coast cities are New York a global finance and culture center and capital Washington DC. Midwestern metropolis Chicago is known for influential architecture and on the west coast Los Angeles'''' Hollywood is famed for filmmaking.''', '1', '9147420', '213000000', '65', '20', '45', '341711', '954806', '0.59', '36', '38', '83', '99', '12', '21', 'Northern America', 'https://en.wikipedia.org/wiki/United_States', 'https://www.britannica.com/place/United-States', 'http://www.americanbible.org/', 'https://unitedbiblesocieties.org/locations/american-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-states/', 'https://images.bible.cloud/maps/summary/US-summary.pdf', NULL, 'https://www.nationsonline.org/oneworld/united_states.htm', 'https://curlie.org/Regional/North_America/United_States', 'https://operationworld.org/locations/united-states-of-america', NULL, 'https://joshuaproject.net/countries/US', 'https://prayercast.com/usa.html', 'https://player.vimeo.com/video/23173134', 'http://www.prayercast.com/downloads/direct_download.php?file=USA_dload_hi.mov', 'George Barker Stevens (1854-1906) was a professor at Yale when he published this paraphrase of Paul’s Epistles.<br><br>His college course was begun at Cornell, and completed at Rochester, where he graduated in 1877. After a year of theological study in the Baptist Seminary at Rochester, he came to New Haven, and graduated from Yale Divinity School in 1880. He was pastor of the First Congregational Church in Buffalo for two years, and then for three years of the First Presbyterian Church in Watertown, N.Y. In 1883 he gained the degree of Ph.D. from Syracuse University. The years 1885-6 he spent as a student in Germany; and earned the degree of D.D. at Jena, where he studied especially under Lipsius. He was then called to the chair of New Testament criticism and interpretation at Yale, succeeding Dr. Dwight, who entered on the presidency of the university, in 1886. This chair he held until 1895, when he was chosen to succeed the late Dr. Samuel Harris as Dwight professor of systematic theology.<br><br>In 1892 Stevens had published a major study of Pauline theology, 2 and we might naturally expect to find in this paraphrase of Paul’s epistles a reflection of the interpretations set forth in his earlier treatise. In fact we do find such a relationship in places, but it is most striking how the whole rationale of the paraphrase really contradicts what Stevens says in Pauline theology about the importance of taking seriously the forms of expression used by Paul, as indispensible keys to the true apprehension of his meaning:<br><br>Of greater importance for our present purpose than the consideration of Paul’s style is the study of the characteristics of his thinking and his favorite modes of presenting his thoughts, in order to gain a just conception of his teaching upon special subjects. By this study is meant something more than an examination of style; it includes the thought-forms which lie behind style,—the moulds into which ideas are run.<br><br>This subject has never received sufficient attention. Interpreters have too often taken up the Pauline letters without reference to the environment in which they were produced, the peculiarities of the writer, or the special ends contemplated in his writings. Upon his words have been put meanings which belong to opinions and speculations which he never entertained, and around his teaching have been thrown associations wholly foreign to his own type of thought. Paul has been read as if he had written in the nineteenth century (or more commonly as if he had written in the fifth or seventeenth), and as if his writings had no peculiarities arising from his own time, education, and mental constitution.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
