INSERT INTO bibles (_id, abbr, title, iso, script, year, country_id, copyright, copyright_type, bible_links, bible_equivalents, language_iso, language_glotto_id, language_iso1, language_name, language_level, language_country_id, language_latitude, language_longitude, language_population, country_name, country_name_long, country_population, country_official_language, country_official_language_iso, country_iso_a3, country_continent_id, country_iso_num, country_language_count, country_religion_primary, country_introduction, country_overview, country_independent, country_landmass_km, country_population_christian, country_population_christian_percentage, country_population_catholic_percentage, country_population_protestant_percentage, country_population_refugee, country_population_migration, country_population_year_change, country_population_density_km, country_population_average_age, country_population_urban_percentage, country_population_literacy_percentage, country_region_code, country_region_id, country_region_name, country_url_wiki, country_url_britannica, country_url_national_society, country_url_ubs, country_url_factbook, country_url_factbook_pdf, country_url_human_development, country_url_nations_online, country_url_odp, country_url_operation_world, country_url_religious_freedom, country_url_joshua, country_url_prayercast, country_url_prayercast_video, country_url_prayercast_download, description, bible_pod, id, parent_bible_id, uuid, title_vernacular, description_short, description_vernacular, date, alphabet_name, alphabet_script, alphabet_fonts, pod, links, publishers, providers, equivalents, books, gbc, guid, description_reviewed, versification, numeral_system_id, reviewed, isbn13, back_text, cover, questionable, alphabet_unicode_pdf, alphabet_family, alphabet_type, alphabet_white_space, alphabet_open_type_tag, alphabet_complex_positioning, alphabet_requires_font, alphabet_unicode, alphabet_diacritics, alphabet_contextual_forms, alphabet_reordering, alphabet_case, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('52', 'ENGMTB', 'Matthew''s Bible', 'eng', 'Latn', '1537', 'GB', 'Public Domain', 'OPEN', '[3 items in bible_links.csv]', NULL, 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United Kingdom', 'The United Kingdom of Great Britain and Northern Ireland', '67081000', 'English', 'eng', 'GBR', 'EU', '826', '101', 'Christianity', 'The United Kingdom has historically played a leading role in developing parliamentary democracy and in advancing literature and science. At its zenith in the 19th century the British Empire stretched over one-fourth of the earth''s surface. The first half of the 20th century saw the UK''s strength seriously depleted in two world wars and the Irish Republic''s withdrawal from the union. The second half witnessed the dismantling of the Empire and the UK rebuilding itself into a modern and prosperous European nation. As one of five permanent members of the UN Security Council and a founding member of NATO and the Commonwealth the UK pursues a global approach to foreign policy. The UK is also an active member of the EU although it chose to remain outside the Economic and Monetary Union. The Scottish Parliament the National Assembly for Wales and the Northern Ireland Assembly were established in 1999. The latter was suspended until May 2007 due to wrangling over the peace process but devolution was fully completed in March 2010.', 'The United Kingdom made up of England Scotland Wales and Northern Ireland is an island nation in northwestern Europe. England – birthplace of Shakespeare and The Beatles – is home to the capital London a globally influential centre of finance and culture. England is also site of Neolithic Stonehenge Bath’s Roman spa and centuries-old universities at Oxford and Cambridge.', '1', '241930', '33200000', '59.3', '8.9', '50', '133094', '260650', '0.53', '281', '40', '83', '99', '10', '154', 'Northern Europe', 'https://en.wikipedia.org/wiki/United_Kingdom', 'https://www.britannica.com/place/United-Kingdom', 'https://www.biblesociety.org.uk/', 'https://unitedbiblesocieties.org/locations/british-and-foreign-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-kingdom/', 'https://images.bible.cloud/maps/summary/UK-summary.pdf', 'https://hdr.undp.org/data-center/specific-country-data#/countries/USA', 'https://www.nationsonline.org/oneworld/united_kingdom.htm', 'https://curlie.org/Regional/Europe/United_Kingdom', 'https://operationworld.org/locations/united-kingdom-of-gb-ni', 'https://www.state.gov/countries-areas/united-kingdom/', 'https://joshuaproject.net/countries/GB', 'https://prayercast.com/england.html', 'https://player.vimeo.com/video/37676816', 'http://www.prayercast.com/downloads/direct_download.php?file=England_dload_hi.mov', 'The Matthew Bible, also known as Matthew''s Version, was first published in 1537 by John Rogers, under the pseudonym "Thomas Matthew". It combined the New Testament of William Tyndale, and as much of the Old Testament as he had been able to translate before being captured and put to death. Myles Coverdale''s translations, chiefly from German and Latin sources, completed the Old Testament and Biblical apocrypha, except for the Prayer of Manasseh, which was Rogers''. It is thus a vital link in the main sequence of English Bible translations.<br><br>Matthew''s Bible was the combined work of three individuals, working from numerous sources in at least five different languages.<br><br>The entire New Testament (first published in 1526, later revised, 1534 and 1535), the Pentateuch, Jonah and in David Daniell''s view, the Book of Joshua, Judges, Ruth, First and Second Samuel, First and Second Kings, and First and Second Chronicles, were the work of William Tyndale. Tyndale worked directly from the Hebrew and Greek, occasionally consulting the Vulgate and Erasmus’s Latin version, and he used Luther''s Bible for the prefaces, marginal notes and the biblical text. The use of the pseudonym "Thomas Matthew" resulted possibly from the need to conceal from Henry VIII the participation of Tyndale in the translation. A theory exists that indicates the name Thomas Matthew, which in Greek means "A twin to the original gift from God", may have been chosen to indicate that the largest contributing author was indeed William Tyndale and that his writings were preserved.<br><br>The remaining books of the Old Testament and the Apocrypha were the work of Myles Coverdale. Coverdale translated primarily from German and Latin sources. Historians often tend to treat Coverdale and Tyndale like competitors in a race to complete the monumental and arduous task of translating the biblical text. One is often credited to the exclusion of the other. In reality they knew each other and occasionally worked together. Contemporary historian John Foxe states that they were in Hamburg translating the Pentateuch together as early as 1529.<br><br>The Prayer of Manasseh was the work of John Rogers. Rogers translated from a French Bible printed two years earlier (in 1535). Rogers compiled the completed work and added the preface, some marginal notes, a calendar and an almanac.<br><br>Of the three translators, two were burned at the stake. Tyndale was burned on 6 October 1536 in Vilvoorde, Belgium. John Rogers was "tested by fire" on 4 February 1555 at Smithfield, England; the first to meet this fate under Mary I of England. Myles Coverdale was employed by Cromwell to work on the Great Bible of 1539, the first officially authorized English translation of the Bible.<br><br>Time and extensive scholastic scrutiny have judged Tyndale the most gifted of the three translators. Dr. Westcott (in his History of the English Bible) states that "The history of our English Bible begins with the work of Tyndale and not with that of Wycliffe." The quality of his translations has also stood the test of time, coming relatively intact even into modern versions of the Bible. A. S. Herbert, Bible cataloguer, says of the Matthew Bible, "this version, which welds together the best work of Tyndale and Coverdale, is generally considered to be the real primary version of our English Bible", upon which later editions were based, including the Geneva Bible and King James Version. Professor David Daniell recounts that, "New Testament scholars Jon Nielson and Royal Skousen observed that previous estimates of Tyndale''s contribution to the KJV ''have run from a high of up to 90% (Westcott) to a low of 18% (Butterworth)''. By a statistically accurate and appropriate method of sampling, based on eighteen portions of the Bible, they concluded that for the New Testament Tyndale''s contribution is about 83% of the text, and in the Old Testament 76%. Thus the Matthew Bible, though largely unrecognized, significantly shaped and influenced English Bible versions in the centuries that followed its first appearance. (Wikipedia)', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
