ase, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('85', 'ENGZZZP', 'Khualsim Holy Bible', 'eng', 'Latn', NULL, 'MM', NULL, NULL, NULL, '[2 items in bible_equivalents.csv]', 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'Myanmar', 'The Republic of the Union of Myanmar', '57069099', 'Burmese', 'mya', 'MMR', 'AS', '104', '149', 'Buddhism', 'Various ethnic Burmese and ethnic minority city-states or kingdoms occupied the present borders through the 19th century. Over a period of 62 years (1824-1886) Britain conquered Burma and incorporated the country into its Indian Empire. Burma was administered as a province of India until 1937 when it became a separate self-governing colony; in 1948 Burma attained independence from the British Commonwealth. Gen. NE WIN dominated the government from 1962 to 1988 first as military ruler then as self-appointed president and later as political kingpin. In response to widespread civil unrest NE WIN resigned in 1988 but within months the military crushed student-led protests and took power. ++ Multiparty legislative elections in 1990 resulted in the main opposition party - the National League for Democracy (NLD) - winning a landslide victory. Instead of handing over power the junta placed NLD leader (and 1991 Nobel Peace Prize recipient) AUNG SAN SUU KYI under house arrest from 1989 to 1995 2000 to 2002 and from May 2003 to November 2010. In late September 2007 the ruling junta brutally suppressed protests over increased fuel prices led by prodemocracy activists and Buddhist monks killing an unknown number of people and arresting thousands for participating in the demonstrations. In early May 2008 Burma was struck by Cyclone Nargis which left over 138000 dead and tens of thousands injured and homeless. Despite this tragedy the junta proceeded with its May constitutional referendum the first vote in Burma since 1990. Legislative elections held in November 2010 which the NLD boycotted and were considered flawed by many in the international community saw the ruling Union Solidarity and Development Party garner over 75% of the contested seats. ++ The national legislature convened in January 2011 and selected former Prime Minister THEIN SEIN as president. Although the vast majority of national-level appointees named by THEIN SEIN were former or current military officers the government initiated a series of political and economic reforms leading to a substantial opening of the long-isolated country. These reforms included releasing hundreds of political prisoners signing a nationwide cease-fire with several of the country''s ethnic armed groups pursuing legal reform and gradually reducing restrictions on freedom of the press association and civil society. At least due in part to these reforms AUNG SAN SUU KYI was elected to the national legislature in April 2012 and became chair of the Committee for Rule of Law and Tranquility. Burma served as chair of the Association of Southeast Asian Nations (ASEAN) for 2014. In a flawed but largely credible national legislative election in November 2015 featuring more than 90 political parties the NLD again won a landslide victory. Using its overwhelming majority in both houses of parliament the NLD elected HTIN KYAW AUNG SAN SUU KYI’s confidant and long-time NLD supporter as president. Burma''s first credibly elected civilian government after more than five decades of military dictatorship was sworn into office on 30 March 2016.', '''Myanmar (formerly Burma) is a Southeast Asian nation of more than 100 ethnic groups bordering India Bangladesh China Laos and Thailand. Yangon (formerly Rangoon) the country''''s largest city is home to bustling markets numerous parks and lakes and the towering gilded Shwedagon Pagoda which contains Buddhist relics and dates to the 6th century.''', '1', '653290', '3790000', '6.2', '1', '5.2', NULL, '-163313', '0.67', '83', '29', '31', '93', '2', '35', 'South-eastern Asia', 'https://en.wikipedia.org/wiki/Myanmar', 'https://www.britannica.com/place/Myanmar', 'http://www.myanmarbible.com/', 'https://unitedbiblesocieties.org/locations/bible-society-of-myanmar/', NULL, NULL, 'https://hdr.undp.org/data-center/specific-country-data#/countries/MMR', 'https://www.nationsonline.org/oneworld/myanmar.htm', 'https://curlie.org/Regional/Asia/Myanmar', 'https://operationworld.org/locations/myanmar', 'https://www.state.gov/countries-areas/burma/', 'https://joshuaproject.net/countries/MM', 'https://prayercast.com/myanmar-(burma).html', 'https://player.vimeo.com/video/22584597', 'http://www.prayercast.com/downloads/direct_download.php?file=Myanmar_Burma2_dload_hi.mp4', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bibles (_id, abbr, title, iso, script, year, country_id, copyright, copyright_type, bible_links, bible_equivalents, language_iso, language_glotto_id, language_iso1, language_name, language_level, language_country_id, language_latitude, language_longitude, language_population, country_name, country_name_long, country_population, country_official_language, country_official_language_iso, country_iso_a3, country_continent_id, country_iso_num, country_language_count, country_religion_primary, country_introduction, country_overview, country_independent, country_landmass_km, country_population_christian, country_population_christian_percentage, country_population_catholic_percentage, country_population_protestant_percentage, country_population_refugee, country_population_migration, country_population_year_change, country_population_density_km, country_population_average_age, country_population_urban_percentage, country_population_literacy_percentage, country_region_code, country_region_id, country_region_name, country_url_wiki, country_url_britannica, country_url_national_society, country_url_ubs, country_url_factbook, country_url_factbook_pdf, country_url_human_development, country_url_nations_online, country_url_odp, country_url_operation_world, country_url_religious_freedom, country_url_joshua, country_url_prayercast, country_url_prayercast_video, country_url_prayercast_download, description, bible_pod, id, parent_bible_id, uuid, title_vernacular, description_short, description_vernacular, date, alphabet_name, alphabet_script, alphabet_fonts, pod, links, publishers, providers, equivalents, books, gbc, guid, description_reviewed, versification, numeral_system_id, reviewed, isbn13, back_text, cover, questionable, alphabet_unicode_pdf, alphabet_family, alphabet_type, alphabet_white_space, alphabet_open_type_tag, alphabet_complex_positioning, alphabet_requires_font, alphabet_unicode, alphabet_diacritics, alphabet_contextual_forms, alphabet_reordering, alphabet_case, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('86', 'ENGWELL', 'Wellbeloved Old Testament', 'eng', 'Latn', '1859', 'GB', 'Public Domain', NULL, '[2 items in bible_links.csv]', NULL, 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United Kingdom', 'The United Kingdom of Great Britain and Northern Ireland', '67081000', 'English', 'eng', 'GBR', 'EU', '826', '101', 'Christianity', 'The United Kingdom has historically played a leading role in developing parliamentary democracy and in advancing literature and science. At its zenith in the 19th century the British Empire stretched over one-fourth of the earth''s surface. The first half of the 20th century saw the UK''s strength seriously depleted in two world wars and the Irish Republic''s withdrawal from the union. The second half witnessed the dismantling of the Empire and the UK rebuilding itself into a modern and prosperous European nation. As one of five permanent members of the UN Security Council and a founding member of NATO and the Commonwealth the UK pursues a global approach to foreign policy. The UK is also an active member of the EU although it chose to remain outside the Economic and Monetary Union. The Scottish Parliament the National Assembly for Wales and the Northern Ireland Assembly were established in 1999. The latter was suspended until May 2007 due to wrangling over the peace process but devolution was fully completed in March 2010.', 'The United Kingdom made up of England Scotland Wales and Northern Ireland is an island nation in northwestern Europe. England – birthplace of Shakespeare and The Beatles – is home to the capital London a globally influential centre of finance and culture. England is also site of Neolithic Stonehenge Bath’s Roman spa and centuries-old universities at Oxford and Cambridge.', '1', '241930', '33200000', '59.3', '8.9', '50', '133094', '260650', '0.53', '281', '40', '83', '99', '10', '154', 'Northern Europe', 'https://en.wikipedia.org/wiki/United_Kingdom', 'https://www.britannica.com/place/United-Kingdom', 'https://www.biblesociety.org.uk/', 'https://unitedbiblesocieties.org/locations/british-and-foreign-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-kingdom/', 'https://images.bible.cloud/maps/summary/UK-summary.pdf', 'https://hdr.undp.org/data-center/specific-country-data#/countries/USA', 'https://www.nationsonline.org/oneworld/united_kingdom.htm', 'https://curlie.org/Regional/Europe/United_Kingdom', 'https://operationworld.org/locations/united-kingdom-of-gb-ni', 'https://www.state.gov/countries-areas/united-kingdom/', 'https://joshuaproject.net/countries/GB', 'https://prayercast.com/england.html', 'https://player.vimeo.com/video/37676816', 'http://www.prayercast.com/downloads/direct_download.php?file=England_dload_hi.mov', 'Charles Wellbeloved, George Vance Smith, and John Scott Porter, The Holy Scriptures of the Old Covenant, in a Revised Translation, by the late Rev. Charles Wellbeloved, the Rev. George Vance Smith, B.A., the Rev. John Scott Porter. 3 volumes. London: Longman, Brown, Green, Longmans, and Roberts, 1859-1862. A limited revision of the KJV. Volume 1 (1859) contains the Pentateuch, Joshua, Judges, and Ruth. Vol. 2 (1861) contains the books of Samuel, Kings, Chronicles, Ezra, Nehemiah, Esther, Job and Psalms. Vol. 3 (1862) contains Proverbs, Ecclesiastes, and the Prophets. Wellbeloved is the reviser of the Pentateuch, Joshua, Judges, Ruth, Job, Psalms, Proverbs, Ecclesiastes, and the Minor Prophets. Smith is the reviser of Samuel, Ezra, Nehemiah, Esther, Isaiah, Jeremiah, and the Lamentations. Porter is the reviser of Kings, Chronicles, Ezekiel and Daniel.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
