ase, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('92', 'ENGPICT', 'Pictorial Bible', 'eng', 'Latn', '1861', 'GB', 'Public Domain', NULL, '[4 items in bible_links.csv]', NULL, 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United Kingdom', 'The United Kingdom of Great Britain and Northern Ireland', '67081000', 'English', 'eng', 'GBR', 'EU', '826', '101', 'Christianity', 'The United Kingdom has historically played a leading role in developing parliamentary democracy and in advancing literature and science. At its zenith in the 19th century the British Empire stretched over one-fourth of the earth''s surface. The first half of the 20th century saw the UK''s strength seriously depleted in two world wars and the Irish Republic''s withdrawal from the union. The second half witnessed the dismantling of the Empire and the UK rebuilding itself into a modern and prosperous European nation. As one of five permanent members of the UN Security Council and a founding member of NATO and the Commonwealth the UK pursues a global approach to foreign policy. The UK is also an active member of the EU although it chose to remain outside the Economic and Monetary Union. The Scottish Parliament the National Assembly for Wales and the Northern Ireland Assembly were established in 1999. The latter was suspended until May 2007 due to wrangling over the peace process but devolution was fully completed in March 2010.', 'The United Kingdom made up of England Scotland Wales and Northern Ireland is an island nation in northwestern Europe. England – birthplace of Shakespeare and The Beatles – is home to the capital London a globally influential centre of finance and culture. England is also site of Neolithic Stonehenge Bath’s Roman spa and centuries-old universities at Oxford and Cambridge.', '1', '241930', '33200000', '59.3', '8.9', '50', '133094', '260650', '0.53', '281', '40', '83', '99', '10', '154', 'Northern Europe', 'https://en.wikipedia.org/wiki/United_Kingdom', 'https://www.britannica.com/place/United-Kingdom', 'https://www.biblesociety.org.uk/', 'https://unitedbiblesocieties.org/locations/british-and-foreign-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-kingdom/', 'https://images.bible.cloud/maps/summary/UK-summary.pdf', 'https://hdr.undp.org/data-center/specific-country-data#/countries/USA', 'https://www.nationsonline.org/oneworld/united_kingdom.htm', 'https://curlie.org/Regional/Europe/United_Kingdom', 'https://operationworld.org/locations/united-kingdom-of-gb-ni', 'https://www.state.gov/countries-areas/united-kingdom/', 'https://joshuaproject.net/countries/GB', 'https://prayercast.com/england.html', 'https://player.vimeo.com/video/37676816', 'http://www.prayercast.com/downloads/direct_download.php?file=England_dload_hi.mov', 'The Pictorial Bible Being the Old and New Testaments according to the Authorised version, illustrated with many hundred woodcuts representing the historical events, after celebrated pictures; the landscape scenes from original drawings or from authentic engravings; and the subjects of natural history, costume and antiquities from the best sources. To which are added original notes chiefly explanatory of the engravings and of such passages connected with the history geography, natural history, antiquities of the sacred scriptures as require observation.<br><br>Charles Knight seems to have published several versions and offshoots of this edition. The Western Antiquary mentionsOffsite Link a 4-volume version published in 1838-1839. Between 1847 and 1849 Knight published in 4 volumes a "new edition" in which "the notes are much augmented, and completely revised."Offsite Link In this edition John Kitto was credited as editor and writer of the notes. For this edition the text was reset into two columns.  In 1855-56 W & R Chambers issued a new edition in London, 1855-56. The work was revised by T. R. Birks and published in London by James Sangster 1871-76, having been published in 56 parts. Kitto''s notes and commentaries on the Bible texts were so extensive that in 1840 Knight issued the notes and commentary without the Bible text in 5 large 8vo volumes containing well over 1000 pages as The Illustrated Commentary on the Old and New Testament...being a republication of the notes of the Pictorial Bible (5 vols.).<br><br>"Charles Knight''s publication of the lavishly illustrated Pictorial Bible (1836-380 transformed the established format of illustrated Bibles. The project was driven by a desire for popular education and reflected Knight''s wider editorial concerns, evident in the Penny Magazine and his involvement with the Society for the Diffusion of Useful Knowledge. During the 1830s the typical illustrated Bible contained on average thirty illustrations. Their selection followed a pattern that had been established i the 1790s and included engravings after works by canonical masters such as Raphael, Rose, Reni, Domenichino, the Carracci, Rubens and Pousin. While in Knight''s Pictorial Bible the selection of illustrations showing biblical events remained virtually unchanged, the volumes were teeming with completely new types of illsutration, which were broadly speaking scientific and historical. They showed the fauna and flora, architecture, customs and dresses and the landscapes of the Bible. The Pictorial Bible was intended to ''make the ojbects described or referred to in the Holy Scriptures familiar to the eye of the general reader" (Giebelhausen, Painting the Bible: Representation and Belief in Mid-Victorian Britain [2006] 135).', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
