ase, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('105', 'ENGCCS', 'Critical Commentary Study Bible Patrick', 'eng', 'Latn', '1822', 'US', 'Public Domain', NULL, '[2 items in bible_links.csv]', NULL, 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United States', 'The United States of America', '334998398', 'English', 'eng', 'USA', 'NA', '840', '506', 'Christianity', 'Britain''s American colonies broke with the mother country in 1776 and were recognized as the new nation of the United States of America following the Treaty of Paris in 1783. During the 19th and 20th centuries 37 new states were added to the original 13 as the nation expanded across the North American continent and acquired a number of overseas possessions. The two most traumatic experiences in the nation''s history were the Civil War (1861-65) in which a northern Union of states defeated a secessionist Confederacy of 11 southern slave states and the Great Depression of the 1930s an economic downturn during which about a quarter of the labor force lost its jobs. Buoyed by victories in World Wars I and II and the end of the Cold War in 1991 the US remains the world''s most powerful nation state. Since the end of World War II the economy has achieved relatively steady growth low unemployment and inflation and rapid advances in technology.', '''The U.S. is a country of 50 states covering a vast swath of North America with Alaska in the northwest and Hawaii extending the nation’s presence into the Pacific Ocean. Major Atlantic Coast cities are New York a global finance and culture center and capital Washington DC. Midwestern metropolis Chicago is known for influential architecture and on the west coast Los Angeles'''' Hollywood is famed for filmmaking.''', '1', '9147420', '213000000', '65', '20', '45', '341711', '954806', '0.59', '36', '38', '83', '99', '12', '21', 'Northern America', 'https://en.wikipedia.org/wiki/United_States', 'https://www.britannica.com/place/United-States', 'http://www.americanbible.org/', 'https://unitedbiblesocieties.org/locations/american-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-states/', 'https://images.bible.cloud/maps/summary/US-summary.pdf', NULL, 'https://www.nationsonline.org/oneworld/united_states.htm', 'https://curlie.org/Regional/North_America/United_States', 'https://operationworld.org/locations/united-states-of-america', NULL, 'https://joshuaproject.net/countries/US', 'https://prayercast.com/usa.html', 'https://player.vimeo.com/video/23173134', 'http://www.prayercast.com/downloads/direct_download.php?file=USA_dload_hi.mov', 'The Holy Bible. A Critical Commentary and Paraphrase on the Old and New Testament, and the Apocrypha. By Patrick, Lowth, Arnold, Whitby, and Lowman. A New Edition, with the Text Printed at Large. To be Completed in Sixty numbers at Twenty-Five Cents Each. The Whole to Form Four Imperial Octavo Volumes, Containing Upwards of 4300 Pages. Philadelphia: Cary and Hart, 18?? CD Only Another; The Holy Bible. A Critical Commentary and Paraphrase on the Old and New Testament, and the Apocrypha. By Patrick, Lowth, Arnold, Whitby, and Lowman. A New Edition, Corrected by the Rev. J. R. Pitman. . . In Six Volumes. London: Printed by J. F. Dove, for Richard Priestley, 1822. <br><br>(From: Introduction to the Study of the Bible; Thomas Horne; 1827) <br>Divines of every denomination concur in pronouncing Dr. Whitby''s commentary to be, upon the whole, the best upon the New Testament, that is extant in the English language. It is inserted in almost every list of books that we have seen recommended to stu dents, and it is here noticed on account of the very valuable dissert ations on various subjects which it contains, and which are referred to by most modern commentators. This commentary first appeared in 1703, and has since been frequently printed with Bp. Patrick''s Paraphrase and Commentary on the Historical and Poetical Books, and Mr. Lowth''s Paraphrase, &c. on the Prophetical Books of the Qld Testament. The two last-mentioned works would have been inserted in the present list, but that the most valuable of their anno tations are included in Dr. D''Oyly''s and Bp. Mant''s Commentary already noticed. (From: Introduction to the Study of the Bible; Thomas Horne; 1827)', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
