ase, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('119', 'ENGKENT', 'Shorter Kent New Testament', 'eng', 'Latn', '1918', 'US', 'Public Domain', NULL, '[2 items in bible_links.csv]', NULL, 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United States', 'The United States of America', '334998398', 'English', 'eng', 'USA', 'NA', '840', '506', 'Christianity', 'Britain''s American colonies broke with the mother country in 1776 and were recognized as the new nation of the United States of America following the Treaty of Paris in 1783. During the 19th and 20th centuries 37 new states were added to the original 13 as the nation expanded across the North American continent and acquired a number of overseas possessions. The two most traumatic experiences in the nation''s history were the Civil War (1861-65) in which a northern Union of states defeated a secessionist Confederacy of 11 southern slave states and the Great Depression of the 1930s an economic downturn during which about a quarter of the labor force lost its jobs. Buoyed by victories in World Wars I and II and the end of the Cold War in 1991 the US remains the world''s most powerful nation state. Since the end of World War II the economy has achieved relatively steady growth low unemployment and inflation and rapid advances in technology.', '''The U.S. is a country of 50 states covering a vast swath of North America with Alaska in the northwest and Hawaii extending the nation’s presence into the Pacific Ocean. Major Atlantic Coast cities are New York a global finance and culture center and capital Washington DC. Midwestern metropolis Chicago is known for influential architecture and on the west coast Los Angeles'''' Hollywood is famed for filmmaking.''', '1', '9147420', '213000000', '65', '20', '45', '341711', '954806', '0.59', '36', '38', '83', '99', '12', '21', 'Northern America', 'https://en.wikipedia.org/wiki/United_States', 'https://www.britannica.com/place/United-States', 'http://www.americanbible.org/', 'https://unitedbiblesocieties.org/locations/american-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-states/', 'https://images.bible.cloud/maps/summary/US-summary.pdf', NULL, 'https://www.nationsonline.org/oneworld/united_states.htm', 'https://curlie.org/Regional/North_America/United_States', 'https://operationworld.org/locations/united-states-of-america', NULL, 'https://joshuaproject.net/countries/US', 'https://prayercast.com/usa.html', 'https://player.vimeo.com/video/23173134', 'http://www.prayercast.com/downloads/direct_download.php?file=USA_dload_hi.mov', 'The Shorter Bible The Old Testament Translated and arranged by Charles Foster Kent. Charles Foster Kent (August 13, 1867 - May 2, 1925) was an American Old Testament scholar.<br>He was born at Palmyra, New York, and educated at Yale (A.B., 1889; Ph.D., 1891). He studied at the University of Berlin (1891–92).<br>He was an instructor at the University of Chicago 1893-95 and then professor of Biblical literature at Brown. After 1901, he was Woolsey Professor of Biblical Literature at Yale.<br>Kent was the founding president of the American Academy of Religion from 1910 to 1925.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
