ase, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('128', 'ENGEEB', 'EasyEnglish Bible', 'eng', 'Latn', '2001', 'GB', '© MissionAssist 2018', NULL, '[4 items in bible_links.csv]', '[2 items in bible_equivalents.csv]', 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United Kingdom', 'The United Kingdom of Great Britain and Northern Ireland', '67081000', 'English', 'eng', 'GBR', 'EU', '826', '101', 'Christianity', 'The United Kingdom has historically played a leading role in developing parliamentary democracy and in advancing literature and science. At its zenith in the 19th century the British Empire stretched over one-fourth of the earth''s surface. The first half of the 20th century saw the UK''s strength seriously depleted in two world wars and the Irish Republic''s withdrawal from the union. The second half witnessed the dismantling of the Empire and the UK rebuilding itself into a modern and prosperous European nation. As one of five permanent members of the UN Security Council and a founding member of NATO and the Commonwealth the UK pursues a global approach to foreign policy. The UK is also an active member of the EU although it chose to remain outside the Economic and Monetary Union. The Scottish Parliament the National Assembly for Wales and the Northern Ireland Assembly were established in 1999. The latter was suspended until May 2007 due to wrangling over the peace process but devolution was fully completed in March 2010.', 'The United Kingdom made up of England Scotland Wales and Northern Ireland is an island nation in northwestern Europe. England – birthplace of Shakespeare and The Beatles – is home to the capital London a globally influential centre of finance and culture. England is also site of Neolithic Stonehenge Bath’s Roman spa and centuries-old universities at Oxford and Cambridge.', '1', '241930', '33200000', '59.3', '8.9', '50', '133094', '260650', '0.53', '281', '40', '83', '99', '10', '154', 'Northern Europe', 'https://en.wikipedia.org/wiki/United_Kingdom', 'https://www.britannica.com/place/United-Kingdom', 'https://www.biblesociety.org.uk/', 'https://unitedbiblesocieties.org/locations/british-and-foreign-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-kingdom/', 'https://images.bible.cloud/maps/summary/UK-summary.pdf', 'https://hdr.undp.org/data-center/specific-country-data#/countries/USA', 'https://www.nationsonline.org/oneworld/united_kingdom.htm', 'https://curlie.org/Regional/Europe/United_Kingdom', 'https://operationworld.org/locations/united-kingdom-of-gb-ni', 'https://www.state.gov/countries-areas/united-kingdom/', 'https://joshuaproject.net/countries/GB', 'https://prayercast.com/england.html', 'https://player.vimeo.com/video/37676816', 'http://www.prayercast.com/downloads/direct_download.php?file=England_dload_hi.mov', 'The purpose of the EasyEnglish Bible is to make the Bible as clear as possible in simple English. We have used a basic vocabulary of 1200 well-known English words. It is a very good Bible for anyone who is learning English or speaks English as a foreign language.  EasyEnglish Website: To help you even more, the EasyEnglish Bible website – www.easyenglish.bible – has Commentaries and Bible Studies to help you understand the message of the Bible and apply it to your life.  Translation Principles: To make the Bible as easy as possible to understand, we have used: Short sentences, Short paragraphs, Simple grammar. We have avoided things that can be hard to understand, so we have used: No passive verbs, No idioms, No split infinitives, No rhetorical questions. The EasyEnglish Bible is a “meaning-for-meaning” translation not a “word-for-word” translation.  It expresses the meaning of the original message in the most clear, accurate and natural way possible in simple English. It changes the order of words if that makes the meaning clearer in English. It translates the meaning of idioms rather than the literal words. It uses British spelling, grammar and punctuation. These translation principles have been developed by Wycliffe Bible Translators (WBT) and SIL.  EasyEnglish Translation Team: The EasyEnglish Bible has been translated by MissionAssist, which is a Christian charity based in the United Kingdom. MissionAssist is part of the Wycliffe Global Alliance (WGA) and a member of Global Connections.  The EasyEnglish Bible translation team includes:  Linguistic Checkers - People who check the linguistic consistency of the work. Our linguistic checkers normally have a degree in Linguistics or English (or similar) and a TEFL qualification. Theological Checkers - People who check the theological accuracy of the work. Our theological checkers have a degree in theology (or a similar qualification). Style Checkers - People who check drafts and final output for accuracy, consistency and conformance to EasyEnglish principles. The Base Text We have used a range of English Bible translations as a base. Where English versions have a different understanding of the original text, we have referred to the Hebrew or Greek text, using the texts published and updated by United Bible Societies (UBS):  Old Testament: Biblia Hebraica “Masoretic Text” New Testament: The Nestle-Aland “Novum Testamentum Graece” We also use the resources provided by Wycliffe Bible Translators to help translators and checkers understand the issues involved in translating the original texts.  Copyright Information Copyright © MissionAssist 2018 – Charitable Incorporated Organisation 1162807  The copyright of the EasyEnglish Bible and all other material on this website is owned by MissionAssist.  MissionAssist is a member of the Wycliffe Global Alliance and is based in the UK.  MissionAssist, PO Box 257, Evesham, Worcestershire, England. WR11 9AW  ', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
