ase, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('133', 'ENGLIB', 'Liberal Translation of the New Testament', 'eng', 'Latn', '1767', 'GB', 'Public Domain', NULL, '[1 items in bible_links.csv]', NULL, 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United Kingdom', 'The United Kingdom of Great Britain and Northern Ireland', '67081000', 'English', 'eng', 'GBR', 'EU', '826', '101', 'Christianity', 'The United Kingdom has historically played a leading role in developing parliamentary democracy and in advancing literature and science. At its zenith in the 19th century the British Empire stretched over one-fourth of the earth''s surface. The first half of the 20th century saw the UK''s strength seriously depleted in two world wars and the Irish Republic''s withdrawal from the union. The second half witnessed the dismantling of the Empire and the UK rebuilding itself into a modern and prosperous European nation. As one of five permanent members of the UN Security Council and a founding member of NATO and the Commonwealth the UK pursues a global approach to foreign policy. The UK is also an active member of the EU although it chose to remain outside the Economic and Monetary Union. The Scottish Parliament the National Assembly for Wales and the Northern Ireland Assembly were established in 1999. The latter was suspended until May 2007 due to wrangling over the peace process but devolution was fully completed in March 2010.', 'The United Kingdom made up of England Scotland Wales and Northern Ireland is an island nation in northwestern Europe. England – birthplace of Shakespeare and The Beatles – is home to the capital London a globally influential centre of finance and culture. England is also site of Neolithic Stonehenge Bath’s Roman spa and centuries-old universities at Oxford and Cambridge.', '1', '241930', '33200000', '59.3', '8.9', '50', '133094', '260650', '0.53', '281', '40', '83', '99', '10', '154', 'Northern Europe', 'https://en.wikipedia.org/wiki/United_Kingdom', 'https://www.britannica.com/place/United-Kingdom', 'https://www.biblesociety.org.uk/', 'https://unitedbiblesocieties.org/locations/british-and-foreign-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-kingdom/', 'https://images.bible.cloud/maps/summary/UK-summary.pdf', 'https://hdr.undp.org/data-center/specific-country-data#/countries/USA', 'https://www.nationsonline.org/oneworld/united_kingdom.htm', 'https://curlie.org/Regional/Europe/United_Kingdom', 'https://operationworld.org/locations/united-kingdom-of-gb-ni', 'https://www.state.gov/countries-areas/united-kingdom/', 'https://joshuaproject.net/countries/GB', 'https://prayercast.com/england.html', 'https://player.vimeo.com/video/37676816', 'http://www.prayercast.com/downloads/direct_download.php?file=England_dload_hi.mov', 'Edward Harwood, A Liberal Translation of the New Testament; being An Attempt to translate the Sacred Writings with the same Freedom, Spirit, and Elegance, With which other English Translations from the Greek Classics have lately been executed: the Design and Scope of each Author being strictly and impartially explored, the True Signification and Force of the Original critically observed, and, as much as possible, transfused into our Language, and the Whole elucidated and explained upon a new and rational Plan: with select Notes, Critical and Explanatory. 2 Vols. London: for T. Becket and Others, 1768.<br><br>This is a paraphrase of the New Testament done by a classical scholar, Edward Harwood (1729-1794). His object was “To translate the sacred writers of the New Testament with the same freedom, impartiality, and elegance, with which other translations from the Greek classics have lately been executed, and to cloathe the genuine ideas and doctrines of the Apostles with that propriety and perspicuity, in which they themselves, I apprehend, would have exhibited them had they now lived and written in our language.” (Preface).<br><br>Harwood’s paraphrase imitates the verbose and ornate style of writing typical of much English prose of the eighteenth century, and has often been cited as an outstanding example of poor taste and inappropriate handling of Scripture. Shortly after its publication James Boswell called it a “ridiculous work.” 1 Others have called it “turgid,” “absurd,” and worse. In a discussion of the qualities of various English versions, Richard C. Trench wrote, “Of Harwood’s Liberal Translation of the New Testament (London, 1768), and the follies of it, not very far from blasphemous, it is unnecessary to give any specimens.” 2 J. Isaacs observes that Harwood’s version is “one of the most discussed and insulted” versions of the eighteenth century. 3 A specimen often quoted is the rendering of the Lord’s Prayer in Matthew 6.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
