ase, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('143', 'ENGKJVA', 'Authorized King James Version', 'eng', 'Latn', '1611', 'GB', 'Public Domain', 'OPEN', NULL, NULL, 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United Kingdom', 'The United Kingdom of Great Britain and Northern Ireland', '67081000', 'English', 'eng', 'GBR', 'EU', '826', '101', 'Christianity', 'The United Kingdom has historically played a leading role in developing parliamentary democracy and in advancing literature and science. At its zenith in the 19th century the British Empire stretched over one-fourth of the earth''s surface. The first half of the 20th century saw the UK''s strength seriously depleted in two world wars and the Irish Republic''s withdrawal from the union. The second half witnessed the dismantling of the Empire and the UK rebuilding itself into a modern and prosperous European nation. As one of five permanent members of the UN Security Council and a founding member of NATO and the Commonwealth the UK pursues a global approach to foreign policy. The UK is also an active member of the EU although it chose to remain outside the Economic and Monetary Union. The Scottish Parliament the National Assembly for Wales and the Northern Ireland Assembly were established in 1999. The latter was suspended until May 2007 due to wrangling over the peace process but devolution was fully completed in March 2010.', 'The United Kingdom made up of England Scotland Wales and Northern Ireland is an island nation in northwestern Europe. England – birthplace of Shakespeare and The Beatles – is home to the capital London a globally influential centre of finance and culture. England is also site of Neolithic Stonehenge Bath’s Roman spa and centuries-old universities at Oxford and Cambridge.', '1', '241930', '33200000', '59.3', '8.9', '50', '133094', '260650', '0.53', '281', '40', '83', '99', '10', '154', 'Northern Europe', 'https://en.wikipedia.org/wiki/United_Kingdom', 'https://www.britannica.com/place/United-Kingdom', 'https://www.biblesociety.org.uk/', 'https://unitedbiblesocieties.org/locations/british-and-foreign-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-kingdom/', 'https://images.bible.cloud/maps/summary/UK-summary.pdf', 'https://hdr.undp.org/data-center/specific-country-data#/countries/USA', 'https://www.nationsonline.org/oneworld/united_kingdom.htm', 'https://curlie.org/Regional/Europe/United_Kingdom', 'https://operationworld.org/locations/united-kingdom-of-gb-ni', 'https://www.state.gov/countries-areas/united-kingdom/', 'https://joshuaproject.net/countries/GB', 'https://prayercast.com/england.html', 'https://player.vimeo.com/video/37676816', 'http://www.prayercast.com/downloads/direct_download.php?file=England_dload_hi.mov', 'The King James Version (KJV), also the King James Bible (KJB) and the Authorized Version, is an English translation of the Christian Bible for the Church of England, which was commissioned in 1604 and published in 1611, by sponsorship of King James VI and I. The books of the King James Version include the 39 books of the Old Testament, an intertestamental section containing 14 books of the Apocrypha, and the 27 books of the New Testament. Noted for its "majesty of style", the King James Version has been described as one of the most important books in English culture and a driving force in the shaping of the English-speaking world.<br>.By the first half of the 18th century, the Authorized Version had become effectively unchallenged as the English translation used in Anglican and other English Protestant churches, except for the Psalms and some short passages in the Book of Common Prayer of the Church of England. Over the course of the 18th century, the Authorized Version supplanted the Latin Vulgate as the standard version of scripture for English-speaking scholars. With the development of stereotype printing at the beginning of the 19th century, this version of the Bible became the most widely printed book in history, almost all such printings presenting the standard text of 1769 extensively re-edited by Benjamin Blayney at Oxford, and nearly always omitting the books of the Apocrypha. Today the unqualified title "King James Version" usually indicates this Oxford standard text.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
