ase, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('182', 'ENGPSB', 'Epistles of Paul Belsham Study Bible', 'eng', 'Latn', '1822', 'GB', 'Public Domain', NULL, '[1 items in bible_links.csv]', NULL, 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United Kingdom', 'The United Kingdom of Great Britain and Northern Ireland', '67081000', 'English', 'eng', 'GBR', 'EU', '826', '101', 'Christianity', 'The United Kingdom has historically played a leading role in developing parliamentary democracy and in advancing literature and science. At its zenith in the 19th century the British Empire stretched over one-fourth of the earth''s surface. The first half of the 20th century saw the UK''s strength seriously depleted in two world wars and the Irish Republic''s withdrawal from the union. The second half witnessed the dismantling of the Empire and the UK rebuilding itself into a modern and prosperous European nation. As one of five permanent members of the UN Security Council and a founding member of NATO and the Commonwealth the UK pursues a global approach to foreign policy. The UK is also an active member of the EU although it chose to remain outside the Economic and Monetary Union. The Scottish Parliament the National Assembly for Wales and the Northern Ireland Assembly were established in 1999. The latter was suspended until May 2007 due to wrangling over the peace process but devolution was fully completed in March 2010.', 'The United Kingdom made up of England Scotland Wales and Northern Ireland is an island nation in northwestern Europe. England – birthplace of Shakespeare and The Beatles – is home to the capital London a globally influential centre of finance and culture. England is also site of Neolithic Stonehenge Bath’s Roman spa and centuries-old universities at Oxford and Cambridge.', '1', '241930', '33200000', '59.3', '8.9', '50', '133094', '260650', '0.53', '281', '40', '83', '99', '10', '154', 'Northern Europe', 'https://en.wikipedia.org/wiki/United_Kingdom', 'https://www.britannica.com/place/United-Kingdom', 'https://www.biblesociety.org.uk/', 'https://unitedbiblesocieties.org/locations/british-and-foreign-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-kingdom/', 'https://images.bible.cloud/maps/summary/UK-summary.pdf', 'https://hdr.undp.org/data-center/specific-country-data#/countries/USA', 'https://www.nationsonline.org/oneworld/united_kingdom.htm', 'https://curlie.org/Regional/Europe/United_Kingdom', 'https://operationworld.org/locations/united-kingdom-of-gb-ni', 'https://www.state.gov/countries-areas/united-kingdom/', 'https://joshuaproject.net/countries/GB', 'https://prayercast.com/england.html', 'https://player.vimeo.com/video/37676816', 'http://www.prayercast.com/downloads/direct_download.php?file=England_dload_hi.mov', '[Thomas Belsham et al.,] The New Testament, in an Improved Version, upon the Basis of Archbishop Newcome’s New Translation: with a Corrected Text, and Notes Critical and Explanatory. London: Richard Taylor & Co., 1808. An American edition was distributed by William Wells of Boston in 1809. A fourth London edition “with corrections and additions” was printed by Richard and Arthur Taylor in 1817. These three editions were published online by Google Books in 2007-2008: London, 1808; Boston, 1809; London, 1817<br><br>This “Improved” version of the New Testament was a revision of Newcome’s version (1796), and was published anonymously, by what the title page called “A Society for Promoting Christian Knowledge and the Practice of Virtue by the Distribution of Books.” The publisher’s use of the phrase “Society for Promoting Christian Knowledge” was apparently designed to give people the impression that the version was published by the well-known Anglican organization of that name founded by Thomas Bray in 1698, whose mission was to make inexpensive editions of uncontroversial, orthodox Christian books available to poor churches abroad. The Introduction neglects to mention the fact that the “Society” referred to on the title page was actually the Unitarian Society, and that the sole purpose of the version was to promote Unitarian ideas. The concealment of its true purpose was deliberate, as its principal editor later explained: “the editors … thought it needless to insert the word Unitarian in the title page, which would deter some ignorant and prejudiced people from looking into a work from which they might otherwise derive instruction.” It soon became known, however, that the version was financed by the Unitarians and done mainly by Thomas Belsham, a notorious Unitarian controversialist. <br><br>Belsham, in an article published in 1820, explained that the “main object” of the version was “to serve as a sort of common-place book to the New Testament, by exhibiting to the inquiring and serious reader a plain and faithful account of the manner in which the most learned and approved Unitarian writers translate and explain the texts upon which the Unitarian controversy hinges, and the grounds of their interpretation.” This statement of the version’s purpose was also rather misleading, however, because Unitarianism, though it ostensibly based its doctrine upon interpretations of biblical texts, was not really based upon the Bible at all. (Bible Researcher)', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
