ase, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('183', 'ENGQKR', 'Purver Quaker Bible', 'eng', 'Latn', '1764', 'GB', 'Public Domain', 'OPEN', '[1 items in bible_links.csv]', NULL, 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United Kingdom', 'The United Kingdom of Great Britain and Northern Ireland', '67081000', 'English', 'eng', 'GBR', 'EU', '826', '101', 'Christianity', 'The United Kingdom has historically played a leading role in developing parliamentary democracy and in advancing literature and science. At its zenith in the 19th century the British Empire stretched over one-fourth of the earth''s surface. The first half of the 20th century saw the UK''s strength seriously depleted in two world wars and the Irish Republic''s withdrawal from the union. The second half witnessed the dismantling of the Empire and the UK rebuilding itself into a modern and prosperous European nation. As one of five permanent members of the UN Security Council and a founding member of NATO and the Commonwealth the UK pursues a global approach to foreign policy. The UK is also an active member of the EU although it chose to remain outside the Economic and Monetary Union. The Scottish Parliament the National Assembly for Wales and the Northern Ireland Assembly were established in 1999. The latter was suspended until May 2007 due to wrangling over the peace process but devolution was fully completed in March 2010.', 'The United Kingdom made up of England Scotland Wales and Northern Ireland is an island nation in northwestern Europe. England – birthplace of Shakespeare and The Beatles – is home to the capital London a globally influential centre of finance and culture. England is also site of Neolithic Stonehenge Bath’s Roman spa and centuries-old universities at Oxford and Cambridge.', '1', '241930', '33200000', '59.3', '8.9', '50', '133094', '260650', '0.53', '281', '40', '83', '99', '10', '154', 'Northern Europe', 'https://en.wikipedia.org/wiki/United_Kingdom', 'https://www.britannica.com/place/United-Kingdom', 'https://www.biblesociety.org.uk/', 'https://unitedbiblesocieties.org/locations/british-and-foreign-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-kingdom/', 'https://images.bible.cloud/maps/summary/UK-summary.pdf', 'https://hdr.undp.org/data-center/specific-country-data#/countries/USA', 'https://www.nationsonline.org/oneworld/united_kingdom.htm', 'https://curlie.org/Regional/Europe/United_Kingdom', 'https://operationworld.org/locations/united-kingdom-of-gb-ni', 'https://www.state.gov/countries-areas/united-kingdom/', 'https://joshuaproject.net/countries/GB', 'https://prayercast.com/england.html', 'https://player.vimeo.com/video/37676816', 'http://www.prayercast.com/downloads/direct_download.php?file=England_dload_hi.mov', 'The Quaker Bible, officially A new and literal translation of all the books of the Old and New Testament; with notes critical and explanatory, is the 1764 translation of the Christian Bible into English by Anthony Purver (1702–1777), a Quaker. The translation was published in two Volumes in London by W. Richardson and S. Clark in 1764, but is not generally regarded as successful.<br><br>A portion of Purver''s translation was published in parts about 1742 by Felix Farley of Bristol, but the publication received little support. Purver failed to get the whole text published, and gained no backing for his venture, even by the Religious Society of Friends. Even when the Manuscript was published by Dr. John Fothergill at his own expense, the full translation also failed to make any impression.<br><br>Various reasons can be advanced for the failure of Purver’s translation; lack of publicity; the fact that it lacked authority (a one-man translation) and it had not been backed by any Church, not even the Religious Society of Friends, to which Purver belonged. Yet the failure to make its mark may owe itself to the deficiencies of his translation.<br><br>By some it is held to be an unreliable translation; the Dictionary of National Biography records that Purver "…on arriving at a difficult passage, he would shut himself up for two or three days and nights, waiting for inspiration" Charles Haddon Spurgeon, who was acquainted with Purver’s version remarks "A Quaker Translation. Often ungrammatical and unintelligible. Not without its good points, but much more curious than useful."  (Wikipedia)<br><br>“1764 Purver, Anthony A new and literal translation of all the books of the Old and New Testament; with notes critical and explanatory. By Anthony Purver... 2 Vols. London: Printed by W. Richardson and S. Clark; and sold by William Johnston, 1764.<br><br>[A portion of Purver''s translation was published in parts about 1742 by Felix Farley, but received little support. In 1763, Dr. John Fothergill purchased the copyright from Purver, and published a folio.]<br><br>[Purver''s Bible is often referred to as "The Quaker Bible".)”<br><br>Excerpt From: William J. Chamberlin. “Catalogue of English Bible Translations: A Classified Bibliography of Versions and Editions Including Books, Parts, and Old and New Testament Apocrypha ... and Indexes in Religious Studies).” Kindle Books. ', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
