ase, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('188', 'ENGKNT', 'Kneeland New Testament', 'eng', 'Latn', '1823', 'US', 'Public Domain', NULL, '[1 items in bible_links.csv]', NULL, 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United States', 'The United States of America', '334998398', 'English', 'eng', 'USA', 'NA', '840', '506', 'Christianity', 'Britain''s American colonies broke with the mother country in 1776 and were recognized as the new nation of the United States of America following the Treaty of Paris in 1783. During the 19th and 20th centuries 37 new states were added to the original 13 as the nation expanded across the North American continent and acquired a number of overseas possessions. The two most traumatic experiences in the nation''s history were the Civil War (1861-65) in which a northern Union of states defeated a secessionist Confederacy of 11 southern slave states and the Great Depression of the 1930s an economic downturn during which about a quarter of the labor force lost its jobs. Buoyed by victories in World Wars I and II and the end of the Cold War in 1991 the US remains the world''s most powerful nation state. Since the end of World War II the economy has achieved relatively steady growth low unemployment and inflation and rapid advances in technology.', '''The U.S. is a country of 50 states covering a vast swath of North America with Alaska in the northwest and Hawaii extending the nation’s presence into the Pacific Ocean. Major Atlantic Coast cities are New York a global finance and culture center and capital Washington DC. Midwestern metropolis Chicago is known for influential architecture and on the west coast Los Angeles'''' Hollywood is famed for filmmaking.''', '1', '9147420', '213000000', '65', '20', '45', '341711', '954806', '0.59', '36', '38', '83', '99', '12', '21', 'Northern America', 'https://en.wikipedia.org/wiki/United_States', 'https://www.britannica.com/place/United-States', 'http://www.americanbible.org/', 'https://unitedbiblesocieties.org/locations/american-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-states/', 'https://images.bible.cloud/maps/summary/US-summary.pdf', NULL, 'https://www.nationsonline.org/oneworld/united_states.htm', 'https://curlie.org/Regional/North_America/United_States', 'https://operationworld.org/locations/united-states-of-america', NULL, 'https://joshuaproject.net/countries/US', 'https://prayercast.com/usa.html', 'https://player.vimeo.com/video/23173134', 'http://www.prayercast.com/downloads/direct_download.php?file=USA_dload_hi.mov', 'This rare translation was first published in Philadelphia in two volumes, the Gospels in 1822, and Acts-Revelation in 1823. This first two-volume edition contains both the Greek text and Kneeland’s own translation on each page. In his preface, he claims that he is the first to publish “a Greek and English testament.” The Greek text is that of Griesbach, which, according to Kneeland, was in his day “the most correct Greek text, as acknowledged by all.” A one-volume edition of the English translation alone appeared in 1823. Kneeland lived from 1774-1844.<br><br>Reflecting the scholarship of the time, frequent references are made throughout the notes to the translations of George Campbell, Wakefield, Scarlett, MacKnight, Charles Thomson, and the 1808 Improved Version. Parkhurst’s Greek lexicon is also referenced regularly.<br><br>Kneeland himself was a story of continually developing liberalism. In 1803 he became a Universalist after spending a few years as a Baptist preacher. He stayed a Universalist for 26 years. It was during this period that his friend, Hosea Ballou, helped allay his doubts about the inspiration of Scripture, leading to his producing this translation. In 1829, he left the Universalists, moved to Boston, and founded a group of freethinkers. Here he enjoyed the friendship of men such as William Ellery Channing, Ralph Walso Emerson, Theodore Parker, and William Lloyd Garrison. In 1834 he was tried and convicted for blashphemy. After 4 years of appeals and litigation, he served 60 days. Simms says his trial and conviction were “utter absurdities, growing out of the narrowness of the day.” In 1839, hoping to found a freethinker colony, he moved to Iowa where he died in 1844. Throughout his life, he was an avid writer and publisher. (Society of Bible Collectors)', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bibles (_id, abbr, title, iso, script, year, country_id, copyright, copyright_type, bible_links, bible_equivalents, language_iso, language_glotto_id, language_iso1, language_name, language_level, language_country_id, language_latitude, language_longitude, language_population, country_name, country_name_long, country_population, country_official_language, country_official_language_iso, country_iso_a3, country_continent_id, country_iso_num, country_language_count, country_religion_primary, country_introduction, country_overview, country_independent, country_landmass_km, country_population_christian, country_population_christian_percentage, country_population_catholic_percentage, country_population_protestant_percentage, country_population_refugee, country_population_migration, country_population_year_change, country_population_density_km, country_population_average_age, country_population_urban_percentage, country_population_literacy_percentage, country_region_code, country_region_id, country_region_name, country_url_wiki, country_url_britannica, country_url_national_society, country_url_ubs, country_url_factbook, country_url_factbook_pdf, country_url_human_development, country_url_nations_online, country_url_odp, country_url_operation_world, country_url_religious_freedom, country_url_joshua, country_url_prayercast, country_url_prayercast_video, country_url_prayercast_download, description, bible_pod, id, parent_bible_id, uuid, title_vernacular, description_short, description_vernacular, date, alphabet_name, alphabet_script, alphabet_fonts, pod, links, publishers, providers, equivalents, books, gbc, guid, description_reviewed, versification, numeral_system_id, reviewed, isbn13, back_text, cover, questionable, alphabet_unicode_pdf, alphabet_family, alphabet_type, alphabet_white_space, alphabet_open_type_tag, alphabet_complex_positioning, alphabet_requires_font, alphabet_unicode, alphabet_diacritics, alphabet_contextual_forms, alphabet_reordering, alphabet_case, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('189', 'ENG1650', 'Metrical Psalms 1650', 'eng', 'Latn', '1650', 'GB', 'Public Domain', 'OPEN', '[12 items in bible_links.csv]', '[2 items in bible_equivalents.csv]', 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United Kingdom', 'The United Kingdom of Great Britain and Northern Ireland', '67081000', 'English', 'eng', 'GBR', 'EU', '826', '101', 'Christianity', 'The United Kingdom has historically played a leading role in developing parliamentary democracy and in advancing literature and science. At its zenith in the 19th century the British Empire stretched over one-fourth of the earth''s surface. The first half of the 20th century saw the UK''s strength seriously depleted in two world wars and the Irish Republic''s withdrawal from the union. The second half witnessed the dismantling of the Empire and the UK rebuilding itself into a modern and prosperous European nation. As one of five permanent members of the UN Security Council and a founding member of NATO and the Commonwealth the UK pursues a global approach to foreign policy. The UK is also an active member of the EU although it chose to remain outside the Economic and Monetary Union. The Scottish Parliament the National Assembly for Wales and the Northern Ireland Assembly were established in 1999. The latter was suspended until May 2007 due to wrangling over the peace process but devolution was fully completed in March 2010.', 'The United Kingdom made up of England Scotland Wales and Northern Ireland is an island nation in northwestern Europe. England – birthplace of Shakespeare and The Beatles – is home to the capital London a globally influential centre of finance and culture. England is also site of Neolithic Stonehenge Bath’s Roman spa and centuries-old universities at Oxford and Cambridge.', '1', '241930', '33200000', '59.3', '8.9', '50', '133094', '260650', '0.53', '281', '40', '83', '99', '10', '154', 'Northern Europe', 'https://en.wikipedia.org/wiki/United_Kingdom', 'https://www.britannica.com/place/United-Kingdom', 'https://www.biblesociety.org.uk/', 'https://unitedbiblesocieties.org/locations/british-and-foreign-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-kingdom/', 'https://images.bible.cloud/maps/summary/UK-summary.pdf', 'https://hdr.undp.org/data-center/specific-country-data#/countries/USA', 'https://www.nationsonline.org/oneworld/united_kingdom.htm', 'https://curlie.org/Regional/Europe/United_Kingdom', 'https://operationworld.org/locations/united-kingdom-of-gb-ni', 'https://www.state.gov/countries-areas/united-kingdom/', 'https://joshuaproject.net/countries/GB', 'https://prayercast.com/england.html', 'https://player.vimeo.com/video/37676816', 'http://www.prayercast.com/downloads/direct_download.php?file=England_dload_hi.mov', 'The Bay Psalm Book is a metrical Psalter first printed in 1640 in Cambridge, Massachusetts. It was the first book printed in British North America. The Psalms in it are metrical translations into English. The translations are not particularly polished, and not one has remained in use, although some of the tunes to which they were sung have survived (for instance, "Old 100th"). However, its production, just 20 years after the Pilgrims'' arrival at Plymouth, Massachusetts, represents a considerable achievement. It went through several editions and remained in use for well over a century.<br><br>In November 2013, one of eleven known surviving copies of the first edition sold at auction for $14.2 million, a record for a printed book.<br><br>The early residents of the Massachusetts Bay Colony brought with them several books of psalms: the Ainsworth Psalter (1612), compiled by Henry Ainsworth for use by Puritan "separatists" in Holland; the Ravenscroft Psalter (1621); and the Sternhold and Hopkins Psalter (1562), of which there were several editions. Evidently they were dissatisfied with the translations from Hebrew in these several psalters and wished for some that were closer to the original. They hired "thirty pious and learned Ministers", including Richard Mather, Thomas Mayhew, and John Eliot, to undertake a new translation, which they presented here. The tunes to be sung to the new translations were the familiar ones from their existing psalters.<br><br>The first printing was the third product of the Stephen Day (sometimes spelled Daye) press, and consisted of a 148 small quarto leaves, including a 12-page preface, "The Psalmes in Metre", "An Admonition to the Reader", and an extensive list of errata headed "Faults escaped in printing". As with subsequent editions of the book, Day printed the book for sale by the first bookseller in British America, Hezekiah Usher, whose shop at that time was also located in Cambridge. An estimated 1,700 copies of the first edition were printed.<br><br>The third edition (1651) was extensively revised by Henry Dunster and Richard Lyon. The revision was entitled The Psalms, hymns and spiritual songs of the Old and New Testament, faithfully translated into English metre. This revision was the basis for all subsequent editions, and was popularly known as the New England Psalter or New England Version. The ninth edition (1698), the first to contain music, included 13 tunes from John Playford''s A Breefe Introduction to the Skill of Musick (London, 1654).<br><br>The expansion of the neoclassical movement in England led to an evolution in the singing of psalms. These changes found their way to America and subsequently new psalm versions were written. In the early part of the 18th century several updated psalms, notably those written by Tate and Brady and by Isaac Watts, were published. Shortly thereafter several congregations in New England elected to replace the Bay Psalm Book with these new titles.<br><br>In 1718, Cotton Mather undertook the revision of the original Bay Psalm Book which he had studied since youth. Two subsequent revisions were published in 1752, by John Barnard of Marblehead and in 1758 by Thomas Prince. Prince was a clergyman at the Old South Church in Boston. He convinced the members of the congregation of the need to produce a revised, more scholarly, edition of the Bay Psalm Book. Unfortunately, Prince’s version was not accepted outside of his membership and in 1789, the Old South Church reverted to the earlier edition published by Isaac Watts.  (Wikipedia)', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
