ase, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('197', 'ENGTOE', 'Targum Onkelos', 'eng', 'Latn', '1865', 'IL', 'Public Domain', 'OPEN', '[2 items in bible_links.csv]', NULL, 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'Israel', 'The State of Israel', '8787045', 'Hebrew', 'heb', 'ISR', 'AS', '376', '57', 'Ethnic Religions', 'Following World War II Britain withdrew from its mandate of Palestine and the UN proposed partitioning the area into Arab and Jewish states an arrangement rejected by the Arabs. Nonetheless an Israeli state was declared in 1948 and Israel subsequently defeated the Arab armies in a series of wars that did not end deep tensions between the two sides. (The territories Israel has occupied since the 1967 war are not included in the Israel country profile unless otherwise noted.) On 25 April 1982 Israel withdrew from the Sinai Peninsula pursuant to the 1979 Israel-Egypt Peace Treaty. In keeping with the framework established at the Madrid Conference in October 1991 Israel conducted bilateral negotiations with Palestinian representatives and Syria to achieve a permanent settlement with each. Israel and Palestinian officials on 13 September 1993 signed a Declaration of Principles (also known as the \"Oslo Accords\") enshrining the idea of a two-state solution to their conflict and guiding an interim period of Palestinian self-rule. The parties achieved six additional significant interim agreements between 1994 and 1999 aimed at creating the conditions for a two-state solution but most were never fully realized. Outstanding territorial and other disputes with Jordan were resolved in the 26 October 1994 Israel-Jordan Peace Treaty. ++ Progress toward a final status agreement with the Palestinians was undermined by Israeli-Palestinian violence between 2001 and February 2005. Israel in 2005 unilaterally disengaged from the Gaza Strip evacuating settlers and its military while retaining control over most points of entry into the Gaza Strip. The election of HAMAS to head the Palestinian Legislative Council in 2006 temporarily froze relations between Israel and the Palestinian Authority (PA). Israel engaged in a 34-day conflict with Hizballah in Lebanon from July-August 2006 and a 23-day conflict with HAMAS in the Gaza Strip from December 2008-January 2009. In November 2012 Israel engaged in a seven-day conflict with HAMAS in the Gaza Strip. Direct talks with the Palestinians most recently launched in July 2013 but were suspended in April 2014. The talks represented the fourth concerted effort to resolve final status issues between the sides since they were first discussed at Camp David in 2000. Three months later HAMAS and other militant groups launched rockets into Israel which led to a 51-day conflict between Israel and militants in Gaza.', '''Israel a Middle Eastern country on the Mediterranean Sea is regarded by Jews Christians and Muslims as the biblical Holy Land. Its most sacred sites are in Jerusalem. Within its Old City the Temple Mount complex includes the Dome of the Rock shrine the historic Western Wall Al-Aqsa Mosque and the Church of the Holy Sepulchre. Israel''''s financial hub Tel Aviv is known for its Bauhaus architecture and beaches.''', '1', '21640', '266000', '3.5', NULL, '3.5', '16121', '10000', '1.6', '400', '30', '93', '98', '6', '145', 'Western Asia', 'https://en.wikipedia.org/wiki/Israel', 'https://www.britannica.com/place/Israel', 'http://www.biblesocietyinisrael.com/', 'https://unitedbiblesocieties.org/locations/bible-society-in-israel/', 'https://www.cia.gov/the-world-factbook/countries/israel/', 'https://images.bible.cloud/maps/summary/IS-summary.pdf', 'https://hdr.undp.org/data-center/specific-country-data#/countries/ISR', 'https://www.nationsonline.org/oneworld/israel.htm', 'https://curlie.org/Regional/Middle_East/Israel', 'https://operationworld.org/locations/israel', 'https://www.state.gov/countries-areas/israel/', 'https://joshuaproject.net/countries/IL', 'https://prayercast.com/israel.html', 'https://player.vimeo.com/video/22404182', 'http://www.prayercast.com/downloads/direct_download.php?file=Israel2_dload_hi.mp4', 'The Targums of Onkelos and Jonathan Ben Uzziel On the Pentateuch With The Fragments of the Jerusalem Targum From the Chaldee by J. W. Etheridge, M.A. First Published 1862-65.', '[1 items in bible_pod.csv]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
