ase, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('207', 'ENGILU', 'The Illuminated Bible', 'eng', 'Latn', '1846', 'US', 'Public Domain', NULL, NULL, NULL, 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United States', 'The United States of America', '334998398', 'English', 'eng', 'USA', 'NA', '840', '506', 'Christianity', 'Britain''s American colonies broke with the mother country in 1776 and were recognized as the new nation of the United States of America following the Treaty of Paris in 1783. During the 19th and 20th centuries 37 new states were added to the original 13 as the nation expanded across the North American continent and acquired a number of overseas possessions. The two most traumatic experiences in the nation''s history were the Civil War (1861-65) in which a northern Union of states defeated a secessionist Confederacy of 11 southern slave states and the Great Depression of the 1930s an economic downturn during which about a quarter of the labor force lost its jobs. Buoyed by victories in World Wars I and II and the end of the Cold War in 1991 the US remains the world''s most powerful nation state. Since the end of World War II the economy has achieved relatively steady growth low unemployment and inflation and rapid advances in technology.', '''The U.S. is a country of 50 states covering a vast swath of North America with Alaska in the northwest and Hawaii extending the nation’s presence into the Pacific Ocean. Major Atlantic Coast cities are New York a global finance and culture center and capital Washington DC. Midwestern metropolis Chicago is known for influential architecture and on the west coast Los Angeles'''' Hollywood is famed for filmmaking.''', '1', '9147420', '213000000', '65', '20', '45', '341711', '954806', '0.59', '36', '38', '83', '99', '12', '21', 'Northern America', 'https://en.wikipedia.org/wiki/United_States', 'https://www.britannica.com/place/United-States', 'http://www.americanbible.org/', 'https://unitedbiblesocieties.org/locations/american-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-states/', 'https://images.bible.cloud/maps/summary/US-summary.pdf', NULL, 'https://www.nationsonline.org/oneworld/united_states.htm', 'https://curlie.org/Regional/North_America/United_States', 'https://operationworld.org/locations/united-states-of-america', NULL, 'https://joshuaproject.net/countries/US', 'https://prayercast.com/usa.html', 'https://player.vimeo.com/video/23173134', 'http://www.prayercast.com/downloads/direct_download.php?file=USA_dload_hi.mov', 'Harper’s Illuminated Bible was first published in 1846. This Bible is unique and beautiful in many ways. The floriated initials are each unique and quite elaborate. For example, the letter A has over 353 different engravings. Throughout the book there are 185 large illustrations, and there are over 1,400 wood engravings done by John Chapman, whose art is featured in the rotunda of the capitol building in Washington, D.C. As might be expected, this Bible was quite expensive to produce, so the publishers had to print it in fifty-four monthly installments. There are only one hundred complete sets known.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
