ase, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('214', 'ENGCEB', 'Common English Bible', 'eng', 'Latn', '2011', 'GB', '© 2011, Common English Bible', NULL, '[7 items in bible_links.csv]', '[3 items in bible_equivalents.csv]', 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United Kingdom', 'The United Kingdom of Great Britain and Northern Ireland', '67081000', 'English', 'eng', 'GBR', 'EU', '826', '101', 'Christianity', 'The United Kingdom has historically played a leading role in developing parliamentary democracy and in advancing literature and science. At its zenith in the 19th century the British Empire stretched over one-fourth of the earth''s surface. The first half of the 20th century saw the UK''s strength seriously depleted in two world wars and the Irish Republic''s withdrawal from the union. The second half witnessed the dismantling of the Empire and the UK rebuilding itself into a modern and prosperous European nation. As one of five permanent members of the UN Security Council and a founding member of NATO and the Commonwealth the UK pursues a global approach to foreign policy. The UK is also an active member of the EU although it chose to remain outside the Economic and Monetary Union. The Scottish Parliament the National Assembly for Wales and the Northern Ireland Assembly were established in 1999. The latter was suspended until May 2007 due to wrangling over the peace process but devolution was fully completed in March 2010.', 'The United Kingdom made up of England Scotland Wales and Northern Ireland is an island nation in northwestern Europe. England – birthplace of Shakespeare and The Beatles – is home to the capital London a globally influential centre of finance and culture. England is also site of Neolithic Stonehenge Bath’s Roman spa and centuries-old universities at Oxford and Cambridge.', '1', '241930', '33200000', '59.3', '8.9', '50', '133094', '260650', '0.53', '281', '40', '83', '99', '10', '154', 'Northern Europe', 'https://en.wikipedia.org/wiki/United_Kingdom', 'https://www.britannica.com/place/United-Kingdom', 'https://www.biblesociety.org.uk/', 'https://unitedbiblesocieties.org/locations/british-and-foreign-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-kingdom/', 'https://images.bible.cloud/maps/summary/UK-summary.pdf', 'https://hdr.undp.org/data-center/specific-country-data#/countries/USA', 'https://www.nationsonline.org/oneworld/united_kingdom.htm', 'https://curlie.org/Regional/Europe/United_Kingdom', 'https://operationworld.org/locations/united-kingdom-of-gb-ni', 'https://www.state.gov/countries-areas/united-kingdom/', 'https://joshuaproject.net/countries/GB', 'https://prayercast.com/england.html', 'https://player.vimeo.com/video/37676816', 'http://www.prayercast.com/downloads/direct_download.php?file=England_dload_hi.mov', 'The Common English Bible is unlike any other translation. It’s uncommon in that it’s the newest translation by the largest number of biblical scholars & church leaders in words 21st century readers use every day, aligning academic rigor with modern understandability, proven through extensive affirmation with, and acting on feedback from, hundreds of readers. The new Common English Bible is the only translation to combine and balance highly respected ecumenical biblical scholarship necessary for serious study with responsiveness to 21st century clear communication requirements for comprehensive clarity.<br>The Common English Bible is the result of collaboration between opposites: scholars working with average readers; conservatives working with liberals; teens working with retirees; men working with women; many denominations and many ethnicities coming together around the common goal of creating a translation that unites rather than divides, with the ultimate goal of mutually accomplishing God’s overall work in the world.<br>Combining scholarly accuracy with vivid language, the Common English Bible is the work of 120 biblical scholars from 24 denominations in American, African, Asian, European, and Latino communities, representing such academic institutions as Asbury Theological Seminary, Azusa Pacific University, Bethel Seminary, Denver Seminary, Princeton Theological Seminary, Seattle Pacific University, Wheaton College, Yale University, and many others. They meticulously translated the Bible into English directly from the original Hebrew, Aramaic, and Greek texts.<br>Additionally, more than 500 readers in 77 groups field-tested the translation. Every verse was read aloud in the reading groups, where potentially confusing passages were identified. The translators considered the groups'' responses and, where necessary, reworked those passages to clarify in English their meaning from the original languages. In total, more than 600 people worked jointly to bring the Common English Bible to fruition.<br>In 2010 the New Testament was published. In 2011 the complete Bible was published with the Old Testament and the availability of the Apocrypha.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
