ase, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('218', 'ENGDRB', 'Douay–Rheims Bible', 'eng', 'Latn', '1582', 'GB', 'Public Domain', 'OPEN', '[3 items in bible_links.csv]', NULL, 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United Kingdom', 'The United Kingdom of Great Britain and Northern Ireland', '67081000', 'English', 'eng', 'GBR', 'EU', '826', '101', 'Christianity', 'The United Kingdom has historically played a leading role in developing parliamentary democracy and in advancing literature and science. At its zenith in the 19th century the British Empire stretched over one-fourth of the earth''s surface. The first half of the 20th century saw the UK''s strength seriously depleted in two world wars and the Irish Republic''s withdrawal from the union. The second half witnessed the dismantling of the Empire and the UK rebuilding itself into a modern and prosperous European nation. As one of five permanent members of the UN Security Council and a founding member of NATO and the Commonwealth the UK pursues a global approach to foreign policy. The UK is also an active member of the EU although it chose to remain outside the Economic and Monetary Union. The Scottish Parliament the National Assembly for Wales and the Northern Ireland Assembly were established in 1999. The latter was suspended until May 2007 due to wrangling over the peace process but devolution was fully completed in March 2010.', 'The United Kingdom made up of England Scotland Wales and Northern Ireland is an island nation in northwestern Europe. England – birthplace of Shakespeare and The Beatles – is home to the capital London a globally influential centre of finance and culture. England is also site of Neolithic Stonehenge Bath’s Roman spa and centuries-old universities at Oxford and Cambridge.', '1', '241930', '33200000', '59.3', '8.9', '50', '133094', '260650', '0.53', '281', '40', '83', '99', '10', '154', 'Northern Europe', 'https://en.wikipedia.org/wiki/United_Kingdom', 'https://www.britannica.com/place/United-Kingdom', 'https://www.biblesociety.org.uk/', 'https://unitedbiblesocieties.org/locations/british-and-foreign-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-kingdom/', 'https://images.bible.cloud/maps/summary/UK-summary.pdf', 'https://hdr.undp.org/data-center/specific-country-data#/countries/USA', 'https://www.nationsonline.org/oneworld/united_kingdom.htm', 'https://curlie.org/Regional/Europe/United_Kingdom', 'https://operationworld.org/locations/united-kingdom-of-gb-ni', 'https://www.state.gov/countries-areas/united-kingdom/', 'https://joshuaproject.net/countries/GB', 'https://prayercast.com/england.html', 'https://player.vimeo.com/video/37676816', 'http://www.prayercast.com/downloads/direct_download.php?file=England_dload_hi.mov', 'The Douay–Rheims Bible (also known as the Rheims–Douai Bible or Douai Bible, and abbreviated as D–R and DRB) is a translation of the Bible from the Latin Vulgate into English made by members of the English College, Douai, in the service of the Catholic Church. The New Testament portion was published in Reims, France, in 1582, in one volume with extensive commentary and notes. The Old Testament portion was published in two volumes twenty-seven years later in 1609 and 1610 by the University of Douai. The first volume, covering Genesis through Job, was published in 1609; the second, covering Psalms to 2 Machabees plus the deuterocanonical books of the Vulgate, was published in 1610. Marginal notes took up the bulk of the volumes and had a strong polemical and patristic character. They offered insights on issues of translation, and on the Hebrew and Greek source texts of the Vulgate.<br><br>The purpose of the version, both the text and notes, was to uphold Catholic tradition in the face of the Protestant Reformation which up till then had dominated Elizabethan religion and academic debate. As such it was an effort by English Catholics to support the Counter-Reformation. The New Testament was reprinted in 1600, 1621 and 1633. The Old Testament volumes were reprinted in 1635 but neither thereafter for another hundred years. In 1589, William Fulke collated the complete Rheims text and notes in parallel columns with those of the Bishops'' Bible. This work sold widely in England, being re-issued in three further editions to 1633. It was predominantly through Fulke''s editions that the Rheims New Testament came to exercise a significant influence on the development of 17th century English.<br><br>Much of the text of the 1582/1610 bible employed a densely Latinate vocabulary, making it extremely difficult to read the text in places. Consequently, this translation was replaced by a revision undertaken by bishop Richard Challoner; the New Testament in three editions of 1749, 1750, and 1752; the Old Testament (minus the Vulgate apocrypha), in 1750. Although retaining the title Douay–Rheims Bible, the Challoner revision was a new version, tending to take as its base text the King James Version rigorously checked and extensively adjusted for improved readability and consistency with the Clementine edition of the Vulgate. Subsequent editions of the Challoner revision, of which there have been very many, reproduce his Old Testament of 1750 with very few changes. Challoner''s New Testament was, however, extensively revised by Bernard MacMahon in a series of Dublin editions from 1783 to 1810. These Dublin versions are the source of some Challoner bibles printed in the United States in the 19th century. Subsequent editions of the Challoner Bible printed in England most often follow Challoner''s earlier New Testament texts of 1749 and 1750, as do most 20th-century printings and on-line versions of the Douay–Rheims bible circulating on the internet.<br><br>Although the Jerusalem Bible, New American Bible Revised Edition, Revised Standard Version Catholic Edition, and New Revised Standard Version Catholic Edition are the most commonly used Bibles in English-speaking Catholic churches, the Challoner revision of the Douay–Rheims often remains the Bible of choice of more-traditional English-speaking Catholics. (Wikipedia)<br><br><br>Language: Early Modern (Renaissance) English for original using Late Middle English reduced character set. Modern English use for subsequent editions.<br>OT published: 1609–1610<br>NT published: 1582<br>Authorship: English College at Rheims and Douay<br>Derived from: Vulgate<br>Textual basis: NT: Vulgate. OT: Vulgate.<br>Translation type: Formal equivalence translation of the Jerome Vulgate compared with Hebrew and Greek sources for accuracy. Subsequent editions use the Sixto-Clementine Vulgate. Used as interlinear bibles in diglots for the respective Vulgate versions.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
