ase, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('232', 'ENGBSB', 'Berean Study Bible', 'eng', 'Latn', '2020', 'GB', '© Bible Hub, 2020', NULL, NULL, NULL, 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United Kingdom', 'The United Kingdom of Great Britain and Northern Ireland', '67081000', 'English', 'eng', 'GBR', 'EU', '826', '101', 'Christianity', 'The United Kingdom has historically played a leading role in developing parliamentary democracy and in advancing literature and science. At its zenith in the 19th century the British Empire stretched over one-fourth of the earth''s surface. The first half of the 20th century saw the UK''s strength seriously depleted in two world wars and the Irish Republic''s withdrawal from the union. The second half witnessed the dismantling of the Empire and the UK rebuilding itself into a modern and prosperous European nation. As one of five permanent members of the UN Security Council and a founding member of NATO and the Commonwealth the UK pursues a global approach to foreign policy. The UK is also an active member of the EU although it chose to remain outside the Economic and Monetary Union. The Scottish Parliament the National Assembly for Wales and the Northern Ireland Assembly were established in 1999. The latter was suspended until May 2007 due to wrangling over the peace process but devolution was fully completed in March 2010.', 'The United Kingdom made up of England Scotland Wales and Northern Ireland is an island nation in northwestern Europe. England – birthplace of Shakespeare and The Beatles – is home to the capital London a globally influential centre of finance and culture. England is also site of Neolithic Stonehenge Bath’s Roman spa and centuries-old universities at Oxford and Cambridge.', '1', '241930', '33200000', '59.3', '8.9', '50', '133094', '260650', '0.53', '281', '40', '83', '99', '10', '154', 'Northern Europe', 'https://en.wikipedia.org/wiki/United_Kingdom', 'https://www.britannica.com/place/United-Kingdom', 'https://www.biblesociety.org.uk/', 'https://unitedbiblesocieties.org/locations/british-and-foreign-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-kingdom/', 'https://images.bible.cloud/maps/summary/UK-summary.pdf', 'https://hdr.undp.org/data-center/specific-country-data#/countries/USA', 'https://www.nationsonline.org/oneworld/united_kingdom.htm', 'https://curlie.org/Regional/Europe/United_Kingdom', 'https://operationworld.org/locations/united-kingdom-of-gb-ni', 'https://www.state.gov/countries-areas/united-kingdom/', 'https://joshuaproject.net/countries/GB', 'https://prayercast.com/england.html', 'https://player.vimeo.com/video/37676816', 'http://www.prayercast.com/downloads/direct_download.php?file=England_dload_hi.mov', 'The Berean Study Bible (BSB) is a completely new translation of the Holy Bible, effective for public reading, study, memorization, and evangelism. Based on the best available manuscripts and sources, each word is connected back to the Greek or Hebrew text to produce a transparent text that can be studied for its root meanings. The BSB represents a single tier of the Berean Bible. This printing contains the full BSB text, footnotes, section headings, and cross references. Additional components, including translation tables, lexicons, outlines, and summaries, are free online and in a variety of apps and software. The Berean Bible Translation Committee has employed an open process where translation tables are freely available and all comments are welcomed and considered. These sources may also be downloaded and shared freely. Please see the Berean Bible website for a full description of the translation committee and process.', NULL, NULL, NULL, NULL, 'English: Berean Study Bible', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bibles (_id, abbr, title, iso, script, year, country_id, copyright, copyright_type, bible_links, bible_equivalents, language_iso, language_glotto_id, language_iso1, language_name, language_level, language_country_id, language_latitude, language_longitude, language_population, country_name, country_name_long, country_population, country_official_language, country_official_language_iso, country_iso_a3, country_continent_id, country_iso_num, country_language_count, country_religion_primary, country_introduction, country_overview, country_independent, country_landmass_km, country_population_christian, country_population_christian_percentage, country_population_catholic_percentage, country_population_protestant_percentage, country_population_refugee, country_population_migration, country_population_year_change, country_population_density_km, country_population_average_age, country_population_urban_percentage, country_population_literacy_percentage, country_region_code, country_region_id, country_region_name, country_url_wiki, country_url_britannica, country_url_national_society, country_url_ubs, country_url_factbook, country_url_factbook_pdf, country_url_human_development, country_url_nations_online, country_url_odp, country_url_operation_world, country_url_religious_freedom, country_url_joshua, country_url_prayercast, country_url_prayercast_video, country_url_prayercast_download, description, bible_pod, id, parent_bible_id, uuid, title_vernacular, description_short, description_vernacular, date, alphabet_name, alphabet_script, alphabet_fonts, pod, links, publishers, providers, equivalents, books, gbc, guid, description_reviewed, versification, numeral_system_id, reviewed, isbn13, back_text, cover, questionable, alphabet_unicode_pdf, alphabet_family, alphabet_type, alphabet_white_space, alphabet_open_type_tag, alphabet_complex_positioning, alphabet_requires_font, alphabet_unicode, alphabet_diacritics, alphabet_contextual_forms, alphabet_reordering, alphabet_case, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('233', 'ENGWHS', 'Primitive New Testament Whiston', 'eng', 'Latn', '1752', 'GB', 'Public Domain', NULL, '[1 items in bible_links.csv]', NULL, 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United Kingdom', 'The United Kingdom of Great Britain and Northern Ireland', '67081000', 'English', 'eng', 'GBR', 'EU', '826', '101', 'Christianity', 'The United Kingdom has historically played a leading role in developing parliamentary democracy and in advancing literature and science. At its zenith in the 19th century the British Empire stretched over one-fourth of the earth''s surface. The first half of the 20th century saw the UK''s strength seriously depleted in two world wars and the Irish Republic''s withdrawal from the union. The second half witnessed the dismantling of the Empire and the UK rebuilding itself into a modern and prosperous European nation. As one of five permanent members of the UN Security Council and a founding member of NATO and the Commonwealth the UK pursues a global approach to foreign policy. The UK is also an active member of the EU although it chose to remain outside the Economic and Monetary Union. The Scottish Parliament the National Assembly for Wales and the Northern Ireland Assembly were established in 1999. The latter was suspended until May 2007 due to wrangling over the peace process but devolution was fully completed in March 2010.', 'The United Kingdom made up of England Scotland Wales and Northern Ireland is an island nation in northwestern Europe. England – birthplace of Shakespeare and The Beatles – is home to the capital London a globally influential centre of finance and culture. England is also site of Neolithic Stonehenge Bath’s Roman spa and centuries-old universities at Oxford and Cambridge.', '1', '241930', '33200000', '59.3', '8.9', '50', '133094', '260650', '0.53', '281', '40', '83', '99', '10', '154', 'Northern Europe', 'https://en.wikipedia.org/wiki/United_Kingdom', 'https://www.britannica.com/place/United-Kingdom', 'https://www.biblesociety.org.uk/', 'https://unitedbiblesocieties.org/locations/british-and-foreign-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-kingdom/', 'https://images.bible.cloud/maps/summary/UK-summary.pdf', 'https://hdr.undp.org/data-center/specific-country-data#/countries/USA', 'https://www.nationsonline.org/oneworld/united_kingdom.htm', 'https://curlie.org/Regional/Europe/United_Kingdom', 'https://operationworld.org/locations/united-kingdom-of-gb-ni', 'https://www.state.gov/countries-areas/united-kingdom/', 'https://joshuaproject.net/countries/GB', 'https://prayercast.com/england.html', 'https://player.vimeo.com/video/37676816', 'http://www.prayercast.com/downloads/direct_download.php?file=England_dload_hi.mov', '1745 Whiston, William Mr. Whiston''s Primitive New Testament. Part I. containing the Four Gospels, with the Acts of the Apostles. Part II. containing XIV. Epistles of Paul. Part III. containing VII. Catholick Epistles. Part IV. containing the Revelation of John. Stamford & London: for the author, 1745. <br><br>"Printed for the Author, and Sold by the Booksellers of London and Westminster. M.DCC.XLV. According to the Greek of the Clermont Manuscript, now probably between 1400 and 1500 Years old, in the King of France''s Library at Paris: According to the Collation in Dr. Mill''s New Testament: the Latin of which Copy is Part of the Old Italick Version, made early in the Second Century.""<br><br>This work follows the KJV except where Greek manuscripts dictate a difference in wording, or addition, or omission. Whiston published his Primitive New Testament on the basis of Codex Bezae and Codex Claromontanus.<br><br>William Whiston founded a society for promoting primitive Christianity, lecturing in support of his theories in halls and coffee-houses at London, Bath, and Tunbridge Wells. Those he involved included Thomas Chubb, Thomas Emlyn, John Gale, Benjamin Hoadley, Arthur Onslow, and Thomas Rundle. There were meetings at Whiston''s house from 1715 to 1717; Hoadley avoided coming, as did Samuel Clarke, though invited. A meeting with Clarke, Hoadley, John Craig and Gilbert Burnet the younger had left these leading latitudinarians unconvinced about Whiston''s reliance on the Apostolical Constitutions.<br><br>Franz Wokenius wrote a 1728 Latin work on Whiston''s view of primitive Christianity. His challenge to the teachings of Athanasius meant that Whiston was commonly considered heretical on many points. On the other hand, he was a firm believer in supernatural aspects of Christianity. He defended prophecy and miracle. He supported anointing the sick and touching for the king''s evil. His dislike of rationalism in religion also made him one of the numerous opponents of Hoadley''s Plain Account of the Nature and End of the Sacrament. He was fervent in his views of ecclesiastical government and discipline, derived from the Apostolical Constitutions.<br><br>About 1747 Whiston finally left the Anglican communion for the Baptists. He quit the church literally as well as figuratively, as the clergyman began to read the Athanasian Creed.  (Wikipedia)', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bibles (_id, abbr, title, iso, script, year, country_id, copyright, copyright_type, bible_links, bible_equivalents, language_iso, language_glotto_id, language_iso1, language_name, language_level, language_country_id, language_latitude, language_longitude, language_population, country_name, country_name_long, country_population, country_official_language, country_official_language_iso, country_iso_a3, country_continent_id, country_iso_num, country_language_count, country_religion_primary, country_introduction, country_overview, country_independent, country_landmass_km, country_population_christian, country_population_christian_percentage, country_population_catholic_percentage, country_population_protestant_percentage, country_population_refugee, country_population_migration, country_population_year_change, country_population_density_km, country_population_average_age, country_population_urban_percentage, country_population_literacy_percentage, country_region_code, country_region_id, country_region_name, country_url_wiki, country_url_britannica, country_url_national_society, country_url_ubs, country_url_factbook, country_url_factbook_pdf, country_url_human_development, country_url_nations_online, country_url_odp, country_url_operation_world, country_url_religious_freedom, country_url_joshua, country_url_prayercast, country_url_prayercast_video, country_url_prayercast_download, description, bible_pod, id, parent_bible_id, uuid, title_vernacular, description_short, description_vernacular, date, alphabet_name, alphabet_script, alphabet_fonts, pod, links, publishers, providers, equivalents, books, gbc, guid, description_reviewed, versification, numeral_system_id, reviewed, isbn13, back_text, cover, questionable, alphabet_unicode_pdf, alphabet_family, alphabet_type, alphabet_white_space, alphabet_open_type_tag, alphabet_complex_positioning, alphabet_requires_font, alphabet_unicode, alphabet_diacritics, alphabet_contextual_forms, alphabet_reordering, alphabet_case, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('234', 'ENGBISH', 'Bishops'' Bible', 'eng', 'Latn', '1568', 'GB', 'Public Domain', 'OPEN', '[7 items in bible_links.csv]', '[2 items in bible_equivalents.csv]', 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United Kingdom', 'The United Kingdom of Great Britain and Northern Ireland', '67081000', 'English', 'eng', 'GBR', 'EU', '826', '101', 'Christianity', 'The United Kingdom has historically played a leading role in developing parliamentary democracy and in advancing literature and science. At its zenith in the 19th century the British Empire stretched over one-fourth of the earth''s surface. The first half of the 20th century saw the UK''s strength seriously depleted in two world wars and the Irish Republic''s withdrawal from the union. The second half witnessed the dismantling of the Empire and the UK rebuilding itself into a modern and prosperous European nation. As one of five permanent members of the UN Security Council and a founding member of NATO and the Commonwealth the UK pursues a global approach to foreign policy. The UK is also an active member of the EU although it chose to remain outside the Economic and Monetary Union. The Scottish Parliament the National Assembly for Wales and the Northern Ireland Assembly were established in 1999. The latter was suspended until May 2007 due to wrangling over the peace process but devolution was fully completed in March 2010.', 'The United Kingdom made up of England Scotland Wales and Northern Ireland is an island nation in northwestern Europe. England – birthplace of Shakespeare and The Beatles – is home to the capital London a globally influential centre of finance and culture. England is also site of Neolithic Stonehenge Bath’s Roman spa and centuries-old universities at Oxford and Cambridge.', '1', '241930', '33200000', '59.3', '8.9', '50', '133094', '260650', '0.53', '281', '40', '83', '99', '10', '154', 'Northern Europe', 'https://en.wikipedia.org/wiki/United_Kingdom', 'https://www.britannica.com/place/United-Kingdom', 'https://www.biblesociety.org.uk/', 'https://unitedbiblesocieties.org/locations/british-and-foreign-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-kingdom/', 'https://images.bible.cloud/maps/summary/UK-summary.pdf', 'https://hdr.undp.org/data-center/specific-country-data#/countries/USA', 'https://www.nationsonline.org/oneworld/united_kingdom.htm', 'https://curlie.org/Regional/Europe/United_Kingdom', 'https://operationworld.org/locations/united-kingdom-of-gb-ni', 'https://www.state.gov/countries-areas/united-kingdom/', 'https://joshuaproject.net/countries/GB', 'https://prayercast.com/england.html', 'https://player.vimeo.com/video/37676816', 'http://www.prayercast.com/downloads/direct_download.php?file=England_dload_hi.mov', 'After King Henry VIII broke away from the Catholic Church in 1534, the new faith found itself in the position to continue a work it had so long suppressed, the translation of the English Bible. The Bishop’s Bible, published in the same year of the schism, sought to reconcile the nation’s variety of Protestant convictions into one Bible and was. Consequently, it was almost universally panned. David Daniel the preface to his seminal edition of the William Tyndale New Testament, says that the Bishops'' Bible "was, and is, not loved. Where it reprints Geneva it is acceptable, but most of the original work is incompetent, both in its scholarship and its verbosity." After a period of heavy revision, it was supplanted by the King James Bible in 1611.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bibles (_id, abbr, title, iso, script, year, country_id, copyright, copyright_type, bible_links, bible_equivalents, language_iso, language_glotto_id, language_iso1, language_name, language_level, language_country_id, language_latitude, language_longitude, language_population, country_name, country_name_long, country_population, country_official_language, country_official_language_iso, country_iso_a3, country_continent_id, country_iso_num, country_language_count, country_religion_primary, country_introduction, country_overview, country_independent, country_landmass_km, country_population_christian, country_population_christian_percentage, country_population_catholic_percentage, country_population_protestant_percentage, country_population_refugee, country_population_migration, country_population_year_change, country_population_density_km, country_population_average_age, country_population_urban_percentage, country_population_literacy_percentage, country_region_code, country_region_id, country_region_name, country_url_wiki, country_url_britannica, country_url_national_society, country_url_ubs, country_url_factbook, country_url_factbook_pdf, country_url_human_development, country_url_nations_online, country_url_odp, country_url_operation_world, country_url_religious_freedom, country_url_joshua, country_url_prayercast, country_url_prayercast_video, country_url_prayercast_download, description, bible_pod, id, parent_bible_id, uuid, title_vernacular, description_short, description_vernacular, date, alphabet_name, alphabet_script, alphabet_fonts, pod, links, publishers, providers, equivalents, books, gbc, guid, description_reviewed, versification, numeral_system_id, reviewed, isbn13, back_text, cover, questionable, alphabet_unicode_pdf, alphabet_family, alphabet_type, alphabet_white_space, alphabet_open_type_tag, alphabet_complex_positioning, alphabet_requires_font, alphabet_unicode, alphabet_diacritics, alphabet_contextual_forms, alphabet_reordering, alphabet_case, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('235', 'ENGFAM', 'Family Expositer New Testament Doddridge', 'eng', 'Latn', '1825', 'GB', 'Public Domain', NULL, '[1 items in bible_links.csv]', NULL, 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United Kingdom', 'The United Kingdom of Great Britain and Northern Ireland', '67081000', 'English', 'eng', 'GBR', 'EU', '826', '101', 'Christianity', 'The United Kingdom has historically played a leading role in developing parliamentary democracy and in advancing literature and science. At its zenith in the 19th century the British Empire stretched over one-fourth of the earth''s surface. The first half of the 20th century saw the UK''s strength seriously depleted in two world wars and the Irish Republic''s withdrawal from the union. The second half witnessed the dismantling of the Empire and the UK rebuilding itself into a modern and prosperous European nation. As one of five permanent members of the UN Security Council and a founding member of NATO and the Commonwealth the UK pursues a global approach to foreign policy. The UK is also an active member of the EU although it chose to remain outside the Economic and Monetary Union. The Scottish Parliament the National Assembly for Wales and the Northern Ireland Assembly were established in 1999. The latter was suspended until May 2007 due to wrangling over the peace process but devolution was fully completed in March 2010.', 'The United Kingdom made up of England Scotland Wales and Northern Ireland is an island nation in northwestern Europe. England – birthplace of Shakespeare and The Beatles – is home to the capital London a globally influential centre of finance and culture. England is also site of Neolithic Stonehenge Bath’s Roman spa and centuries-old universities at Oxford and Cambridge.', '1', '241930', '33200000', '59.3', '8.9', '50', '133094', '260650', '0.53', '281', '40', '83', '99', '10', '154', 'Northern Europe', 'https://en.wikipedia.org/wiki/United_Kingdom', 'https://www.britannica.com/place/United-Kingdom', 'https://www.biblesociety.org.uk/', 'https://unitedbiblesocieties.org/locations/british-and-foreign-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-kingdom/', 'https://images.bible.cloud/maps/summary/UK-summary.pdf', 'https://hdr.undp.org/data-center/specific-country-data#/countries/USA', 'https://www.nationsonline.org/oneworld/united_kingdom.htm', 'https://curlie.org/Regional/Europe/United_Kingdom', 'https://operationworld.org/locations/united-kingdom-of-gb-ni', 'https://www.state.gov/countries-areas/united-kingdom/', 'https://joshuaproject.net/countries/GB', 'https://prayercast.com/england.html', 'https://player.vimeo.com/video/37676816', 'http://www.prayercast.com/downloads/direct_download.php?file=England_dload_hi.mov', 'Doddridge, Philip The New Testament with Paraphrase and Notes. 6 Vols. London: J. Wilson, 1739-1756. First published 1739. Another Edition; 6 Vols. London: Printed by Assignment from the Author''s window..., 1761. <br>Also; A new translation of the New Testament... extracted from the paraphrase of the late Philip Doddridge, D.D., and carefully revised. With an introduction and notes [by Samuel Palmer). London: For J. Rivington, W. Johnston, R. Baldwin and C. Rivington, 1765. <br>Another edition; The Family Expositor; or a Paraphrase and Version of the New Testament; With Critical Notes, and a Practical Improvement of each Section. In six Volumes... by P. Doddridge, D.D. To which is prefixed, A Life of the Author, by Andrew Kippis... Etheridge''s Edition, from the Eighth London Edition. Charlestown, Massachusetts: S. Etheridge, Printer; Sold by him at Washington Head Bookstore. Sold also by said Etheridge and Company, in Boston. 1807. [This harmonized the Gospels. The New Testament paraphrase, separate from the commentary and notes, was published. In 1833, a 1 Vol. Edition of this work, along with a memoir of the Author was Published at Amherst. This was a very popular work and was reprinted many times in various forms.] First American Edition; Abridged. 2 Vols. Edited by S.Palmer. Hartford: Printed by Lincoln & Gleason, 1807. Also; 1 Vol. Edition. New York: Robert Carter & Bros., 1857.<br>Chamberlin, W. J. (1991). Catalogue of English Bible Translations: A Classified Bibliography of Versions and Editions Including Books, Parts, and Old and New Testament Apocrypha and Apocryphal Books. New York: Greenwood Press.<br><br>Philip Doddridge was an early 18th century non-conformist pastor, and like Matthew Henry, he spent much of his free time writing his commentary. Doddridge notes in the preface that he intended this commentary to be used by families at the dinner table. The forgotten practice of family worship is a great way to use this commentary; the expanded translation, and the devotions at the end of each section (see below) work together seamlessly as a perfect tool for family devotional reading and discussion. This may well be the book that Jonathan Edwards used for his family devotions.<br><br>The Family Expositor is an extraordinary work. Doddridge deems it “a paraphrase,” but it is much more than that. Really it’s three works in one. It is a puritan translation and expansion on the text, a puritan commentary on the text, and a puritan devotional work on the text. Doddridge combines these three to make a truly great puritan companion to the New Testament. ', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO bibles (_id, abbr, title, iso, script, year, country_id, copyright, copyright_type, bible_links, bible_equivalents, language_iso, language_glotto_id, language_iso1, language_name, language_level, language_country_id, language_latitude, language_longitude, language_population, country_name, country_name_long, country_population, country_official_language, country_official_language_iso, country_iso_a3, country_continent_id, country_iso_num, country_language_count, country_religion_primary, country_introduction, country_overview, country_independent, country_landmass_km, country_population_christian, country_population_christian_percentage, country_population_catholic_percentage, country_population_protestant_percentage, country_population_refugee, country_population_migration, country_population_year_change, country_population_density_km, country_population_average_age, country_population_urban_percentage, country_population_literacy_percentage, country_region_code, country_region_id, country_region_name, country_url_wiki, country_url_britannica, country_url_national_society, country_url_ubs, country_url_factbook, country_url_factbook_pdf, country_url_human_development, country_url_nations_online, country_url_odp, country_url_operation_world, country_url_religious_freedom, country_url_joshua, country_url_prayercast, country_url_prayercast_video, country_url_prayercast_download, description, bible_pod, id, parent_bible_id, uuid, title_vernacular, description_short, description_vernacular, date, alphabet_name, alphabet_script, alphabet_fonts, pod, links, publishers, providers, equivalents, books, gbc, guid, description_reviewed, versification, numeral_system_id, reviewed, isbn13, back_text, cover, questionable, alphabet_unicode_pdf, alphabet_family, alphabet_type, alphabet_white_space, alphabet_open_type_tag, alphabet_complex_positioning, alphabet_requires_font, alphabet_unicode, alphabet_diacritics, alphabet_contextual_forms, alphabet_reordering, alphabet_case, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('236', 'ENGCSPB', 'Christian Soldiers Penny Bible', 'eng', 'Latn', '1862', 'US', 'Public Domain', NULL, '[1 items in bible_links.csv]', NULL, 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53', '-1', '379000000', 'United States', 'The United States of America', '334998398', 'English', 'eng', 'USA', 'NA', '840', '506', 'Christianity', 'Britain''s American colonies broke with the mother country in 1776 and were recognized as the new nation of the United States of America following the Treaty of Paris in 1783. During the 19th and 20th centuries 37 new states were added to the original 13 as the nation expanded across the North American continent and acquired a number of overseas possessions. The two most traumatic experiences in the nation''s history were the Civil War (1861-65) in which a northern Union of states defeated a secessionist Confederacy of 11 southern slave states and the Great Depression of the 1930s an economic downturn during which about a quarter of the labor force lost its jobs. Buoyed by victories in World Wars I and II and the end of the Cold War in 1991 the US remains the world''s most powerful nation state. Since the end of World War II the economy has achieved relatively steady growth low unemployment and inflation and rapid advances in technology.', '''The U.S. is a country of 50 states covering a vast swath of North America with Alaska in the northwest and Hawaii extending the nation’s presence into the Pacific Ocean. Major Atlantic Coast cities are New York a global finance and culture center and capital Washington DC. Midwestern metropolis Chicago is known for influential architecture and on the west coast Los Angeles'''' Hollywood is famed for filmmaking.''', '1', '9147420', '213000000', '65', '20', '45', '341711', '954806', '0.59', '36', '38', '83', '99', '12', '21', 'Northern America', 'https://en.wikipedia.org/wiki/United_States', 'https://www.britannica.com/place/United-States', 'http://www.americanbible.org/', 'https://unitedbiblesocieties.org/locations/american-bible-society/', 'https://www.cia.gov/the-world-factbook/countries/united-states/', 'https://images.bible.cloud/maps/summary/US-summary.pdf', NULL, 'https://www.nationsonline.org/oneworld/united_states.htm', 'https://curlie.org/Regional/North_America/United_States', 'https://operationworld.org/locations/united-states-of-america', NULL, 'https://joshuaproject.net/countries/US', 'https://prayercast.com/usa.html', 'https://player.vimeo.com/video/23173134', 'http://www.prayercast.com/downloads/direct_download.php?file=USA_dload_hi.mov', 'The Souldier’s Pocket Bible has a fascinating history connecting the American and English Civil Wars.  Originally published in 1643 during the English Civil war, the booklet is a collection of 125 verses from the Geneva Bible translation to encourage soldiers in Oliver Cromwell’s army.  Only three original copies of this pamphlet are known.  Antiquarian George Livermore discovered one in 1854; he later reprinted it for use by soldiers in the American Civil War.<br><br>The Christian Soldiers Penny Bible is for the most part the same as The Souldier’s Pocket Bible, though somewhat enlarged and with a different title.  in The Penny Bible, the texts are quoted from the King Jame Bible, with some slight alterations.<br><br>Numerous organizations worked to provide Bibles and spiritual nourishment to the troops, North and South.  At its annual meeting, May 9, 1861, President Frelinghuysen of the American Bible Society (ABS) stated: “While there is much to alarm and afflict us in the political agitations of our country, on thing is our special comfort in the cause of the Bible Society: We are still one, bound together by the bonds of Christian kindness, animated by like hopes, earnest in like purposes and cheered by the same sympathies.”<br><br>The ABS had 16 printing presses operating in New York.  The first year of the war the society printed 370,000 more Bibles than the previous year.  During the war the ABS distributed a total of 760,773 Scriptures to the armed services and 823,566 additional Scriptures through the Christian Commission.  Some 300,000 Bibles, New Testaments, or portions were distributed throughout the South, though the wartime blockade often hindered distribution in the South.<br><br>This 1861 New Testament is the first edition printed by the American Bible Society specifically for distribution among Civil war Troops.  Knowing Soldiers would have difficulty carrying about the normal size Bible, the ABS printed user-friendly pocket size New Testaments.  During the Civil War, the ABS distributed over 1.5 million Bibles to both Union and Confederate soldiers.  ', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
