INSERT INTO bibles (_id, abbr, title, iso, script, year, country_id, copyright, copyright_type, bible_links, bible_equivalents, language_iso, language_glotto_id, language_iso1, language_name, language_level, language_country_id, language_latitude, language_longitude, language_population, country_name, country_name_long, country_population, country_official_language, country_official_language_iso, country_iso_a3, country_continent_id, country_iso_num, country_language_count, country_religion_primary, country_introduction, country_overview, country_independent, country_landmass_km, country_population_christian, country_population_christian_percentage, country_population_catholic_percentage, country_population_protestant_percentage, country_population_refugee, country_population_migration, country_population_year_change, country_population_density_km, country_population_average_age, country_population_urban_percentage, country_population_literacy_percentage, country_region_code, country_region_id, country_region_name, country_url_wiki, country_url_britannica, country_url_national_society, country_url_ubs, country_url_factbook, country_url_factbook_pdf, country_url_human_development, country_url_nations_online, country_url_odp, country_url_operation_world, country_url_religious_freedom, country_url_joshua, country_url_prayercast, country_url_prayercast_video, country_url_prayercast_download, description, bible_pod, id, parent_bible_id, uuid, title_vernacular, description_short, description_vernacular, date, alphabet_name, alphabet_script, alphabet_fonts, pod, links, publishers, providers, equivalents, books, gbc, guid, description_reviewed, versification, numeral_system_id, reviewed, isbn13, back_text, cover, questionable, alphabet_unicode_pdf, alphabet_family, alphabet_type, alphabet_white_space, alphabet_open_type_tag, alphabet_complex_positioning, alphabet_requires_font, alphabet_unicode, alphabet_diacritics, alphabet_contextual_forms, alphabet_reordering, alphabet_case, alphabet_split_graphs, alphabet_status, alphabet_baseline, alphabet_ligatures, alphabet_direction, alphabet_direction_notes, alphabet_sample, alphabet_sample_img, alphabet_description, children, language_glotto_family, language_autonym, language_macroarea, language_development, language_use, language_location, language_area, language_progress, language_typology, language_writing, language_description, language_status_id, language_status_notes, language_redirect_to_iso, country_hidden, country_autonym, country_fips, country_wfb, country_wfb_pdf, country_sil_language_count, country_land_mass_km, country_landmass, country) VALUES ('240', NULL, 'Hexaglot Bible', 'eng', 'Latn', NULL, NULL, 'Public Domain', 'OPEN', NULL, NULL, 'eng', 'stan1293', 'en', 'English', 'L', 'GB', '53.000000', '-1.000000', '379000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ENGHEX', NULL, NULL, NULL, NULL, NULL, '1906', 'Latin', 'Latn', NULL, '[]', '[]', NULL, NULL, NULL, NULL, NULL, NULL, '0', NULL, 'default', '0', NULL, NULL, NULL, NULL, NULL, 'European', 'alphabet', 'between words', 'latn', 'yes', 'False', 'True', 'True', 'False', 'False', NULL, 'False', 'Current', 'bottom', 'optional', 'ltr', NULL, NULL, NULL, '<p>The Latin script (also called the Roman script) is the most widely used writing system in the world, being the script of the English language, spoken by over 300,000,000 people worldwide. It is also the script used for writing a number of Romance, Germanic, Baltic and non-Indo-European languages, as well as the <a href=http://scriptsource.org/entry/ucgb77fkvh>International Phonetic Alphabet (IPA)</a>.</p> <p>The script was derived from the Western variant of the Greek alphabet. The earliest extant inscription, an engraved brooch now in the ‘Museo Nazionale Preistorico Etnografico Luigi Pigorini’ in Rome, has been dated to the 7th century BC. The script developed slowly over the next thousand years, and by the 4th century AD many of the modern forms had been developed, and writing had settled into a consistent left to right direction. The Latin script was disseminated throughout western, northern and central Europe and the Baltic countries along with the Christian religion. However it was not until the colonization of the Americas, Australia, and parts of Asia, Africa and the Pacific that the script began to spread outside of Europe, carried by the English, Spanish, Portuguese, French, and Dutch languages.</p> <p>As the script spread around the world, a number of language-specific amendments were made in order to accurately represent the sounds of various languages. These included ligatures, for example the German <span class=Em>esszett</span> ß, and a number of diacritics. Some languages also adapted the alphabet by the addition of entirely new letters, such as <span class=Em>eth</span> Ðð used in Faroese and Icelandic or <span class=Em>epsilon</span> Ɛɛ used in many Niger-Congo orthographies.</p> <p>The Latin script is bicameral; it is written using both upper- and lower-case letters. It is written horizontally from left to right. Each letter sits on the baseline, with some letters having descenders hanging below the baseline, and some having ascenders protruding beyond the x-height. The script also uses a set of punctuation, which is almost entirely consistent across European languages. Exceptions to this include different syles of quotation marks (“ ” and « »), the Greek question mark, which is identical to the semicolon in many other languages (;), and the Spanish inverted question/exclamation marks (¿ and ¡).</p> <p>Digits from 0-9 are used. These can be combined to represent larger numbers.</p>', '[]', NULL, NULL, NULL, NULL, NULL, 'Cook Islands', NULL, 'Full Bible
